const scene = new THREE.Scene();
scene.background = new THREE.Color(DEFAULT_STAGE_CONFIG.background);

const viewportSize = getViewportSize();
const camera = new THREE.PerspectiveCamera(CAMERA_FOV, viewportSize.width / viewportSize.height, CAMERA_NEAR, CAMERA_FAR);
camera.position.set(0, 1.35, 2.6);

// WebGL対応確認
if (!canvas.getContext('webgl2') && !canvas.getContext('webgl')) {
  document.getElementById('webgl-fallback')?.removeAttribute('style');
  throw new Error('WebGL未対応環境です。アプリを起動できません。');
}

const renderer = new THREE.WebGLRenderer({
  canvas,
  antialias: true,
  alpha: false,
});
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(viewportSize.width, viewportSize.height, false);
renderer.outputColorSpace = THREE.LinearSRGBColorSpace; // OutputPass handles sRGB conversion
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.6;
renderer.shadowMap.enabled = DEFAULT_STAGE_CONFIG.shadows.enabled;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;

// ── Postprocessing: EffectComposer ────────────────────────────────────────────
const _compRenderPass = new RenderPass(scene, camera);
const _compOutputPass = new OutputPass();
const composer = new EffectComposer(renderer);
composer.addPass(_compRenderPass);
composer.addPass(_compOutputPass);

// ── Render style presets ──────────────────────────────────────────────────────
