let _composerHasEffects = false; // true when passes beyond RenderPass+OutputPass are active
let _rsOutlinePass = null;
let _rsPixelPass = null;
let _rsDotPass = null;
let _rsFilmPass = null;
let _rsBloomPass = null;

function _updateOutlineSelection() {
  if (!_rsOutlinePass) return;
  if (_rsOutlinePass && currentModelRoot) {
    _rsOutlinePass.selectedObjects = [currentModelRoot];
  }
}

function applyRenderStyle(name) {
  if (!renderer || !scene || !camera || !composer) return;
  if (!(name in RENDER_STYLES)) name = 'standard';
  activeRenderStyle = name;
  try { localStorage.setItem('avatar.renderStyle', name); } catch { /* ignore storage errors */ }

  // Rebuild pass list
  composer.passes.length = 0;
  composer.addPass(_compRenderPass);
  _rsOutlinePass = null; _rsPixelPass = null; _rsDotPass = null;
  _rsFilmPass = null; _rsBloomPass = null;

  const cfg = RENDER_STYLES[name];
  renderer.domElement.style.filter = cfg.cssFilter ?? '';

  // Scanline / vignette overlay
  const overlay = document.getElementById('rs-overlay');
  if (overlay) {
    overlay.className = '';
    if (name === 'cyber') overlay.classList.add('rs-overlay-cyber');
    else if (name === 'horror') overlay.classList.add('rs-overlay-horror');
  }

  const sz = new THREE.Vector2(
    renderer.domElement.width || renderer.domElement.clientWidth || 800,
    renderer.domElement.height || renderer.domElement.clientHeight || 600
  );

  if (name === 'anime') {
    _rsOutlinePass = new OutlinePass(sz, scene, camera);
    _rsOutlinePass.edgeStrength = 4.0;
    _rsOutlinePass.edgeGlow = 0;
    _rsOutlinePass.edgeThickness = 2.5;
    _rsOutlinePass.pulsePeriod = 0;
    _rsOutlinePass.visibleEdgeColor.set('#000000');
    _rsOutlinePass.hiddenEdgeColor.set('#222222');
    _rsOutlinePass.selectedObjects = currentModelRoot ? [currentModelRoot] : [];
    composer.addPass(_rsOutlinePass);
  }

  if (name === 'pixel') {
    _rsPixelPass = new RenderPixelatedPass(7, scene, camera);
    composer.addPass(_rsPixelPass);
  }

  if (name === 'manga') {
    _rsDotPass = new DotScreenPass();
    _rsDotPass.uniforms['scale'].value = 1.2;
    composer.addPass(_rsDotPass);
  }

  if (name === 'retro') {
    _rsFilmPass = new FilmPass(0.4);
    composer.addPass(_rsFilmPass);
  }

  if (name === 'watercolor' || name === 'dream') {
    const strength  = name === 'dream' ? BLOOM_STRENGTH_DREAM  : BLOOM_STRENGTH_WATERCOLOR;
    const radius    = name === 'dream' ? BLOOM_RADIUS_DREAM    : BLOOM_RADIUS_WATERCOLOR;
    const threshold = name === 'dream' ? BLOOM_THRESHOLD_DREAM : BLOOM_THRESHOLD_WATERCOLOR;
    _rsBloomPass = new UnrealBloomPass(sz, strength, radius, threshold);
    composer.addPass(_rsBloomPass);
  }

  composer.addPass(_compOutputPass);
  _composerHasEffects = composer.passes.length > 2;

  document.querySelectorAll('.cm-style-btn').forEach((btn) => {
    btn.classList.toggle('is-active', btn.dataset.style === name);
  });
}

