function setFadeOpacity(v) {
  v = Math.max(0, Math.min(1, Number(v) || 0));
  fadeOpacity = Math.max(0, Math.min(1, v));
  if (fadeOverlayEl) fadeOverlayEl.style.opacity = String(fadeOpacity);
}

let _fadeAnimId = null;
function fadeOverlayTo(targetOpacity, durationMs) {
  targetOpacity = Math.max(0, Math.min(1, Number(targetOpacity) || 0));
  durationMs = Math.max(0, Number(durationMs) || 300);
  if (_fadeAnimId !== null) { cancelAnimationFrame(_fadeAnimId); _fadeAnimId = null; }
  return new Promise((resolve) => {
    const start = performance.now();
    const from = fadeOpacity;
    const diff = targetOpacity - from;
    function step(now) {
      const t = Math.min(1, (now - start) / durationMs);
      setFadeOpacity(from + diff * t);
      if (t < 1) { _fadeAnimId = requestAnimationFrame(step); } else { _fadeAnimId = null; resolve(); }
    }
    _fadeAnimId = requestAnimationFrame(step);
  });
}

