function readStoredJson(key, fallback) {
  try {
    const raw = window.localStorage.getItem(key);
    if (!raw) {
      return fallback;
    }
    return JSON.parse(raw);
  } catch {
    return fallback;
  }
}

function writeStoredJson(key, value) {
  try {
    window.localStorage.setItem(key, JSON.stringify(value));
  } catch (error) {
    console.warn(`localStorage保存失敗: ${key}`, error);
    // ストレージ容量超過をユーザーに通知
    if (error?.name === 'QuotaExceededError' || error?.code === 22) {
      setStatus('ストレージ容量が不足しています。不要なプロジェクトやカスタムモーションを削除してください。', 'error');
    }
  }
}

function getStoredString(key, fallback = '') {
  if (!key || typeof key !== 'string') return fallback;
  try {
    const v = window.localStorage.getItem(key);
    return v !== null ? v : fallback;
  } catch {
    return fallback;
  }
}

function setStoredString(key, value) {
  if (!key || typeof key !== 'string') return;
  try {
    window.localStorage.setItem(key, String(value ?? ''));
  } catch (error) {
    console.warn(`localStorage保存失敗: ${key}`, error);
  }
}

function sanitizeMotionUrl(url) {
  if (!url) return '';
  const s = String(url).trim();
  return s.length > 2048 ? s.slice(0, 2048) : s;
}

function sanitizeFilename(name) {
  if (!name || typeof name !== 'string') return 'file';
  return String(name)
    .replace(/[<>:"/\\|?*\x00-\x1f-]/g, '_')
    .replace(/^\.+/, '_')
    .trim()
    .slice(0, 200) || 'file';
}

