const _CNAMES_KEY = 'avatar.motionCustomNames';
const _CMOTIONS_KEY = 'avatar.customMotions';

function _loadCustomNames() {
  try { return JSON.parse(localStorage.getItem(_CNAMES_KEY) ?? '{}'); } catch { return {}; }
}
function _saveCustomNames(obj) { try { localStorage.setItem(_CNAMES_KEY, JSON.stringify(obj)); } catch { /* storage quota exceeded */ } }

function _loadCustomMotions() {
  try { return JSON.parse(localStorage.getItem(_CMOTIONS_KEY) ?? '[]'); } catch { return []; }
}
function _saveCustomMotions(arr) {
  try { localStorage.setItem(_CMOTIONS_KEY, JSON.stringify(arr)); } catch { /* quota */ }
  // カスタムモーション変更時はLLMシステムプロンプトキャッシュを無効化
  if (typeof _llmSystemPromptCache !== 'undefined') _llmSystemPromptCache = null;
}

const _motionRuntimeMap = new Map();

function _rebuildRuntimeMap() {
  _motionRuntimeMap.clear();
  // custom motion limit
  const _customs = _loadCustomMotions();
  if (_customs.length > 500) console.warn('[motionLib] custom motions exceed 500:', _customs.length);
  for (const m of _loadCustomMotions()) _motionRuntimeMap.set(m.url, { ...m });
  const names = _loadCustomNames();
  for (const [url, displayName] of Object.entries(names)) {
    const base = MOTION_URL_TO_ENTRY.get(url) ?? _motionRuntimeMap.get(url);
    if (base) _motionRuntimeMap.set(url, { ...base, displayName });
    else _motionRuntimeMap.set(url, { id: url, url, displayName, label: displayName, category: 'custom' });
  }
}
_rebuildRuntimeMap();

function _getRuntimeEntry(url) {
  return _motionRuntimeMap.get(url) ?? MOTION_URL_TO_ENTRY.get(url) ?? null;
}

function _getMotionDisplayName(motion) {
  return (_motionRuntimeMap.get(motion.url)?.displayName) ?? motion.displayName ?? motion.label ?? '';
}

function _getFullMotionLibrary() {
  return [...MOTION_LIBRARY, ..._loadCustomMotions()];
}

function _isCustomMotion(url) {
  return _loadCustomMotions().some((m) => m.url === url);
}

// Motion thumbnail capture (stored per URL as dataURL in localStorage)
const _MOTION_THUMB_KEY = 'avatar.motionThumbs';
function _loadMotionThumbs() {
  try { return JSON.parse(localStorage.getItem(_MOTION_THUMB_KEY) ?? '{}'); } catch { return {}; }
}
function _saveMotionThumb(url, dataUrl) {
  if (!url || !dataUrl) return;
  const obj = _loadMotionThumbs();
  const keys = Object.keys(obj);
  if (keys.length > 100) {
    const toDelete = keys.slice(0, keys.length - 80);
    toDelete.forEach((k) => delete obj[k]);
  }
  obj[url] = dataUrl;
  try { localStorage.setItem(_MOTION_THUMB_KEY, JSON.stringify(obj)); } catch { /* quota */ }
}
function captureMotionThumb(url) {
  if (!url || !currentVrm || !renderer?.domElement) return;
  setTimeout(() => {
    try {
      const cvs = document.createElement('canvas');
      cvs.width = 80; cvs.height = 80;
      const ctx = cvs.getContext('2d');
      if (!ctx) return;
      const dw = renderer.domElement.width || renderer.domElement.clientWidth;
      const dh = renderer.domElement.height || renderer.domElement.clientHeight;
      if (!dw || !dh) return;
      ctx.drawImage(renderer.domElement, 0, 0, dw, dh, 0, 0, 80, 80);
      const dataUrl = cvs.toDataURL('image/jpeg', 0.7);
      _saveMotionThumb(url, dataUrl);
      const _escaped = typeof CSS?.escape === 'function' ? CSS.escape(url) : url.replace(/'/g, "\'");
      document.querySelectorAll(`.motion-card[data-motion-url="${_escaped}"] .motion-card-thumb`).forEach((el) => {
        el.style.backgroundImage = `url("${dataUrl}")`;
        el.textContent = '';
      });
    } catch {}
  }, 800);
}

