function motionMetaFromUrl(url) {
  if (!url || typeof url !== 'string') return { displayName: '未選択', category: 'custom', tags: [] };
  const u = sanitizeMotionUrl(url);
  return _motionRuntimeMap.get(u) ?? MOTION_URL_TO_ENTRY.get(u) ?? {
    id: u || 'custom',
    label: basenameFromUrl(url),
    displayName: basenameFromUrl(url),
    category: 'custom',
    url: u,
  };
}

function motionCategoryOrder(category) {
  const order = ['idle', 'walk', 'run', 'gesture', 'talk', 'dance', 'locomotion', 'emotion', 'action', 'expression', 'custom', 'debug'];
  const index = order.indexOf(String(category ?? 'custom').toLowerCase());
  return index >= 0 ? index : order.length - 1;
}

function loadMotionFavorites() {
  const stored = readStoredJson(STORAGE_KEYS.favoriteMotions, []);
  motionFavorites = new Set(Array.isArray(stored) ? stored.filter((item) => typeof item === 'string') : []);
}

function saveMotionFavorites() {
  writeStoredJson(STORAGE_KEYS.favoriteMotions, [...motionFavorites]);
}

function loadMotionLoops() {
  const stored = readStoredJson(STORAGE_KEYS.motionLoopByUrl, {});
  motionLoopByUrl = new Map(
    Object.entries(stored).filter(([, value]) => typeof value === 'boolean'),
  );
}

function saveMotionLoops() {
  writeStoredJson(STORAGE_KEYS.motionLoopByUrl, Object.fromEntries(motionLoopByUrl.entries()));
}

function getMotionLoopEnabled(url) {
  if (!url || typeof url !== 'string') return true;
  const normalizedUrl = sanitizeMotionUrl(url);
  if (!normalizedUrl) {
    return true;
  }
  return motionLoopByUrl.get(normalizedUrl) ?? true;
}

function setMotionLoopEnabled(url, enabled) {
  const normalizedUrl = sanitizeMotionUrl(url);
  if (!normalizedUrl) {
    return;
  }
  motionLoopByUrl.set(normalizedUrl, Boolean(enabled));
  saveMotionLoops();
  const _loopLabel = basenameFromUrl(url).slice(0, 60);
  setStatus(`ループ${enabled ? 'ON' : 'OFF'}: ${_loopLabel}`);
}

function isMotionFavorite(url) {
  if (!url) return false;
  return motionFavorites.has(sanitizeMotionUrl(url));
}

function setMotionFavorite(url, enabled) {
  const normalizedUrl = sanitizeMotionUrl(url);
  if (!normalizedUrl) {
    return;
  }
  const _favLabel = basenameFromUrl(url).slice(0, 60);
  if (enabled) {
    motionFavorites.add(normalizedUrl);
    setStatus(`お気に入り追加: ${_favLabel}`);
  } else {
    motionFavorites.delete(normalizedUrl);
    setStatus(`お気に入り削除: ${_favLabel}`);
  }
  saveMotionFavorites();
}

function loadRecentMotions() {
  const stored = readStoredJson(STORAGE_KEYS.recentMotions, []);
  motionRecentUrls = Array.isArray(stored)
    ? stored
        .filter((item) => item && typeof item === 'string' && item.length < 2048)
        .map((item) => sanitizeMotionUrl(item))
        .filter(Boolean)
        .slice(0, 20)
    : [];
}

function saveRecentMotions() {
  writeStoredJson(STORAGE_KEYS.recentMotions, motionRecentUrls.slice(0, 20));
}

function pushRecentMotion(url) {
  if (!url || typeof url !== 'string') return;
  const normalizedUrl = sanitizeMotionUrl(url);
  if (!normalizedUrl) {
    return;
  }
  motionRecentUrls = [normalizedUrl, ...motionRecentUrls.filter((item) => item && typeof item === 'string' && item.length < 2048 && item !== normalizedUrl)].slice(0, 20);
  saveRecentMotions();
}

function currentMotionLoopEnabled() {
  return getMotionLoopEnabled(selectedBodyMotionUrl);
}

function normalizeModelKey(value) {
  if (value == null || value === '') return '';
  return String(value)
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '_')
    .slice(0, 120);
}

function loadModelSettings() {
  return readStoredJson(STORAGE_KEYS.modelSettingsByKey, {});
}

function saveModelSettings(settingsMap) {
  if (!settingsMap || typeof settingsMap !== 'object' || Array.isArray(settingsMap)) return;
  writeStoredJson(STORAGE_KEYS.modelSettingsByKey, settingsMap);
}

function getModelSettingsForKey(key) {
  const settingsMap = loadModelSettings();
  const profile = getModelProfileForKey(key);
  return {
    groundOffset: 0,
    scale: 1,
    yPosition: 0,
    cameraHeight: 0,
    rotationY: 0,
    rightFootFix: false,
    notes: '',
    ...(settingsMap[key] ?? {}),
    ...profile,
  };
}

function persistCurrentModelSettings() {
  const key = currentModelKey || normalizeModelKey(currentModelLabel);
  if (!key) return;
  const settingsMap = loadModelSettings();
  settingsMap[key] = { ...currentModelSettings };
  saveModelSettings(settingsMap);
}

async function loadModelProfiles() {
  let baseProfiles = {};
  try {
    const response = await fetch('/model_profiles.json', { cache: 'no-store' });
    if (response.ok) {
      baseProfiles = await response.json();
    }
  } catch (error) {
    console.warn('model_profiles.json読込失敗', error);
    setActionLog(`model_profiles.json読込失敗: ${error.message}`);
  }
  const overrides = readStoredJson(STORAGE_KEYS.modelProfilesOverride, {});
  modelProfiles = {
    ...baseProfiles,
    ...overrides,
  };
}

function saveModelProfileOverride(key, profile) {
  if (!key || typeof key !== 'string') return;
  const storedOverrides = readStoredJson(STORAGE_KEYS.modelProfilesOverride, {});
  storedOverrides[key] = profile;
  writeStoredJson(STORAGE_KEYS.modelProfilesOverride, storedOverrides);
  modelProfiles = {
    ...modelProfiles,
    [key]: profile,
  };
}

function getModelProfileForKey(key) {
  return modelProfiles[key] ?? {
    groundOffset: 0,
    scale: 1,
    yPosition: 0,
    cameraHeight: 0,
    rotationY: 0,
    rightFootFix: false,
    notes: '',
  };
}

function collectCurrentModelProfile() {
  return {
    groundOffset: Number(modelGroundOffsetInput?.value ?? 0) || 0,
    scale: Number(modelScaleInput?.value ?? 1) || 1,
    yPosition: Number(modelYPositionInput?.value ?? 0) || 0,
    cameraHeight: Number(modelCameraHeightInput?.value ?? 0) || 0,
    rotationY: Number(modelRotationYInput?.value ?? 0) || 0,
    rightFootFix: Boolean(modelRightFootFixInput?.checked),
    notes: String(modelNotesInput?.value ?? ''),
  };
}

function applyModelProfileToUi(profile) {
  if (!profile) {
    return;
  }
  if (modelGroundOffsetInput) {
    modelGroundOffsetInput.value = String(profile.groundOffset ?? 0);
  }
  if (modelScaleInput) {
    modelScaleInput.value = String(profile.scale ?? 1);
  }
  if (modelYPositionInput) {
    modelYPositionInput.value = String(profile.yPosition ?? 0);
  }
  if (modelCameraHeightInput) {
    modelCameraHeightInput.value = String(profile.cameraHeight ?? 0);
  }
  if (modelRotationYInput) {
    modelRotationYInput.value = String(profile.rotationY ?? 0);
  }
  if (modelRightFootFixInput) {
    modelRightFootFixInput.checked = Boolean(profile.rightFootFix);
  }
  if (modelNotesInput) {
    modelNotesInput.value = String(profile.notes ?? '');
  }
  if (modelProfileStatusEl) {
    modelProfileStatusEl.textContent = '読み込み済み';
  }
}

function setScenePresetDirty(value) {
  scenePresetDirty = Boolean(value);
  try { updateSceneStateUi(); } catch { /* ignore */ }
}

function updateSceneStateUi() {
  const label = scenePresetDirty ? '変更あり' : '保存済み';
  try {
    if (sceneStateEl) sceneStateEl.textContent = label;
    if (sceneStateRightEl) sceneStateRightEl.textContent = label;
  } catch { /* DOM not ready */ }
}

function getExpressionManager() {
  return currentVrm?.expressionManager ?? currentVrm?.blendShapeProxy ?? null;
}

function setExpressionValue(name, value) {
  if (!name || typeof name !== 'string') return;
  const manager = getExpressionManager();
  if (!manager) return;
  const v = Number.isFinite(Number(value)) ? Number(value) : 0;
  if (typeof manager.setValue === 'function') {
    manager.setValue(name, clampNumber(v, 0, 1));
  }
}

function updateExpressionManager() {
  const manager = getExpressionManager();
  if (manager && typeof manager.update === 'function') {
    try { manager.update(); } catch (e) { console.warn('[expr] update error:', e); }
  }
}

function triggerBlink(duration = 0.14) {
  if (!currentVrm) return;
  const now = performance.now();
  facialState.eye.mode = 'blink';
  facialState.eye.blinkUntil = now + Math.max(duration, 0.05) * 1000;
  facialState.eye.nextBlinkAt = now + 2400 + Math.random() * 1600;
  setScenePresetDirty(true);
  updateFacialUi();
}

function setFaceMode(mode) {
  if (mode !== null && mode !== undefined && typeof mode !== 'string') mode = String(mode);
  const _validModes = ['neutral', 'happy', 'sad', 'angry', 'surprised', 'relaxed', 'smile', 'thinking', 'blink'];
  facialState.face.mode = _validModes.includes(mode) ? mode : 'neutral';
  if (mode === 'smile') {
    facialState.face.weight = 0.75;
  } else if (mode === 'happy') {
    facialState.face.weight = 1;
  } else if (mode === 'thinking') {
    facialState.face.weight = 0.35;
  } else if (mode === 'sad') {
    facialState.face.weight = 1;
  } else if (mode === 'angry') {
    facialState.face.weight = 1;
  } else if (mode === 'surprised') {
    facialState.face.weight = 1;
  } else if (mode === 'relaxed') {
    facialState.face.weight = 0.8;
  } else {
    facialState.face.weight = 0;
  }
  setScenePresetDirty(true);
  updateFacialUi();
}

function setEyeMode(mode) {
  const _validEyeModes = ['auto', 'open', 'blink', 'half'];
  facialState.eye.mode = _validEyeModes.includes(mode) ? mode : 'auto';
  if (mode === 'blink') {
    triggerBlink();
    facialState.eye.mode = 'auto';
  } else if (mode === 'auto') {
    facialState.eye.nextBlinkAt = performance.now() + 800 + Math.random() * 1600;
  }
  setScenePresetDirty(true);
  updateFacialUi();
}

function setLipMode(mode) {
  const _validLipModes = ['neutral', 'talk', 'aa', 'ih', 'ou', 'ee', 'oh'];
  facialState.lip.mode = _validLipModes.includes(mode) ? mode : 'neutral';
  facialState.lip.aa = mode === 'aa' ? 1 : mode === 'talk' ? 0.75 : 0;
  facialState.lip.ih = mode === 'ih' ? 1 : 0;
  facialState.lip.ou = mode === 'ou' ? 1 : 0;
  facialState.lip.talkPhase = 0;
  setScenePresetDirty(true);
  updateFacialUi();
}

function applyEmotionToFacialState(emotion) {
  if (emotion !== null && emotion !== undefined && typeof emotion !== 'string') {
    emotion = String(emotion);
  }
  const normalized = String(emotion ?? '').trim().toLowerCase();
  if (!normalized || normalized === 'neutral') { setFaceMode('neutral'); return; }
  if (normalized === 'happy' || normalized.includes('joy') || normalized.includes('greet')) { setFaceMode('happy'); return; }
  if (normalized === 'sad' || normalized.includes('sorrow') || normalized.includes('cry')) { setFaceMode('sad'); return; }
  if (normalized === 'angry' || normalized.includes('anger') || normalized.includes('furious')) { setFaceMode('angry'); return; }
  if (normalized === 'surprised' || normalized.includes('surprise') || normalized.includes('shock')) { setFaceMode('surprised'); return; }
  if (normalized === 'relaxed' || normalized.includes('relax') || normalized.includes('calm')) { setFaceMode('relaxed'); return; }
  if (normalized.includes('smile')) { setFaceMode('smile'); return; }
  if (normalized.includes('think')) { setFaceMode('thinking'); return; }
  if (normalized.includes('talk') || normalized.includes('speech')) { setLipMode('talk'); }
}

document.getElementById('motion-add-btn')?.addEventListener('click', () => openMotionAddModal());

const autoLipSyncToggle = document.querySelector('#auto-lipsync-toggle');
if (autoLipSyncToggle) {
  autoLipSyncToggle.checked = ((() => { try { return localStorage.getItem('avatar.autoLipSync'); } catch { return null; } })() ?? 'false') === 'true';
  autoLipSyncToggle.addEventListener('change', () => {
    try { localStorage.setItem('avatar.autoLipSync', String(autoLipSyncToggle.checked)); } catch { /* ignore */ }
    if (!autoLipSyncToggle.checked) setLipMode('neutral');
  });
}

function applySpeechToFacialState(speech) {
  if (speech !== null && speech !== undefined && typeof speech !== 'string') speech = String(speech);
  const normalized = String(speech ?? '').trim();
  if (!normalized) {
    setLipMode('neutral');
    return;
  }
  const autoLip = document.querySelector('#auto-lipsync-toggle');
  if (!autoLip?.checked) return;
  facialState.lip.mode = 'talk';
  facialState.lip.aa = 0.7;
  facialState.lip.ih = 0.2;
  facialState.lip.ou = 0.25;
  setScenePresetDirty(true);
  updateFacialUi();
}

function updateFacialUi() {
  if (faceMotionStateEl) {
    faceMotionStateEl.textContent = `${facialState.face.mode} / ${facialState.face.weight.toFixed(2)}`;
  }
  if (eyeMotionStateEl) {
    eyeMotionStateEl.textContent = facialState.eye.mode === 'auto'
      ? '自動まばたき'
      : facialState.eye.mode;
  }
  if (lipMotionStateEl) {
    lipMotionStateEl.textContent = facialState.lip.mode === 'talk'
      ? '話す'
      : `${facialState.lip.mode} あ=${facialState.lip.aa.toFixed(2)} い=${facialState.lip.ih.toFixed(2)} う=${facialState.lip.ou.toFixed(2)}`;
  }
  faceActionButtons.forEach((btn) => {
    btn.classList.toggle('is-active', btn.dataset.faceAction === facialState.face.mode);
  });
}

function readFacialState() {
  return {
    face: { mode: facialState.face.mode, weight: facialState.face.weight },
    eye: { mode: facialState.eye.mode, blinkUntil: facialState.eye.blinkUntil, nextBlinkAt: facialState.eye.nextBlinkAt },
    lip: { mode: facialState.lip.mode, aa: facialState.lip.aa, ih: facialState.lip.ih, ou: facialState.lip.ou, talkPhase: 0 },
  };
}

function restoreFacialState(payload = {}) {
  const face = payload.face ?? {};
  const eye = payload.eye ?? {};
  const lip = payload.lip ?? {};
  facialState.face.mode = String(face.mode ?? 'neutral');
  facialState.face.weight = clampNumber(Number(face.weight ?? 0), 0, 1);
  facialState.eye.mode = String(eye.mode ?? 'auto');
  facialState.eye.blinkUntil = Number(eye.blinkUntil ?? 0) || 0;
  facialState.eye.nextBlinkAt = Number(eye.nextBlinkAt ?? (performance.now() + 2400)) || (performance.now() + 2400);
  facialState.lip.mode = String(lip.mode ?? 'neutral');
  facialState.lip.aa = Number(lip.aa ?? 0) || 0;
  facialState.lip.ih = Number(lip.ih ?? 0) || 0;
  facialState.lip.ou = Number(lip.ou ?? 0) || 0;
  facialState.lip.talkPhase = Number(lip.talkPhase ?? 0) || 0;
  updateFacialUi();
}

function applyFacialExpressions(delta) {
  if (!Number.isFinite(delta) || delta < 0) return;
  const manager = getExpressionManager();
  if (!manager || !currentVrm) {
    return;
  }

  const now = performance.now();
  const faceWeight = clampNumber(facialState.face.weight, 0, 1);
  const eyeMode = facialState.eye.mode;
  let blinkValue = facialState.eye.blinkUntil > now ? 1 : 0;
  if (eyeMode === 'open') {
    blinkValue = 0;
  }
  if (eyeMode === 'auto' && facialState.eye.blinkUntil <= now && now >= facialState.eye.nextBlinkAt) {
    facialState.eye.blinkUntil = now + 140;
    facialState.eye.nextBlinkAt = now + 2400 + Math.random() * 2400;
    blinkValue = 1;
  }

  let aa = clampNumber(facialState.lip.aa, 0, 1);
  let ih = clampNumber(facialState.lip.ih, 0, 1);
  let ou = clampNumber(facialState.lip.ou, 0, 1);

  if (facialState.lip.mode === 'talk' && Number.isFinite(facialState.lip.talkPhase)) {
    facialState.lip.talkPhase += delta * 6.5;
    const t = facialState.lip.talkPhase;
    aa = 0.42 + 0.38 * Math.sin(t * 1.7);
    ih = 0.2 + 0.18 * Math.sin(t * 2.3 + 1.2);
    ou = 0.18 + 0.22 * Math.sin(t * 2.0 + 2.1);
  }

  // Audio-driven lip sync: override aa/ih/ou with real-time amplitude from TTS playback
  if (ttsIsPlaying && ttsAnalyser && ttsAnalyserData) {
    ttsAnalyser.getByteTimeDomainData(ttsAnalyserData);
    let sumSq = 0;
    for (let i = 0; i < ttsAnalyserData.length; i++) {
      const v = (ttsAnalyserData[i] - 128) / 128;
      sumSq += v * v;
    }
    const rms = Math.sqrt(sumSq / ttsAnalyserData.length);
    const amplitude = Math.min(1, rms * 12);
    aa = amplitude;
    ih = amplitude * 0.28;
    ou = amplitude * 0.12;
  }

  setExpressionValue('blink', blinkValue);
  setExpressionValue('blinkLeft', blinkValue);
  setExpressionValue('blinkRight', blinkValue);
  const faceMode = facialState.face.mode;
  setExpressionValue('happy', faceMode === 'happy' || faceMode === 'smile' ? faceWeight : 0);
  setExpressionValue('sad', faceMode === 'sad' ? faceWeight : 0);
  setExpressionValue('angry', faceMode === 'angry' ? faceWeight : 0);
  setExpressionValue('surprised', faceMode === 'surprised' ? faceWeight : 0);
  setExpressionValue('relaxed', faceMode === 'relaxed' ? faceWeight : faceMode === 'thinking' ? Math.max(faceWeight, 0.35) : 0);
  setExpressionValue('aa', aa);
  setExpressionValue('ih', ih);
  setExpressionValue('ou', ou);
  setExpressionValue('ee', faceMode === 'smile' ? 0.3 : 0);
  setExpressionValue('oh', faceMode === 'happy' ? 0.25 : faceMode === 'surprised' ? 0.4 : 0);
  updateExpressionManager();
}

function getSceneSnapshot() {
  return {
    version: 2,
    timestamp: new Date().toISOString(),
    model: {
      key: currentModelKey,
      label: currentModelLabel,
      sourceUrl: currentModelSourceUrl,
      settings: { ...currentModelSettings },
      groundCorrection: modelGroundCorrectionEnabled,
    },
    motion: {
      selectedUrl: selectedBodyMotionUrl,
      currentUrl: currentMotionUrl,
      loop: currentMotionLoopEnabled(),
      playbackSpeed: currentPlaybackSpeed,
    },
    camera: {
      preset: currentCameraPresetName,
      position: camera.position.toArray(),
      target: controls.target.toArray(),
      fov: camera.fov,
    },
    stage: {
      preset: currentStagePresetName,
      config: currentStageConfig,
      textureLabel: currentStageTextureLabel,
      textureUrl: currentStageTextureUrl,
    },
    light: {
      intensity: Number(currentStageConfig?.directionalLight?.intensity ?? 0) || 0,
      enabled: Boolean(currentStageConfig?.directionalLight?.enabled),
    },
    profile: {
      modelProfiles,
      selectedModelKey: currentModelKey,
    },
    blendshape: readFacialState(),
    action: {
      autoplay: actionAutoPlayEnabled,
      pollingState: currentActionPollingState,
      source: actionSourceEl?.textContent ?? '',
    },
    extraCharacters: extraCharacters.map((ch) => ({
      label: ch.label,
      posX: ch.posX,
      posZ: ch.posZ,
      motionUrl: ch.motionUrl,
    })),
    story: {
      mode: storyMode,
      clips: storyClips.map((c) => ({
        id: c.id,
        label: c.label,
        motionUrl: c.motionUrl,
        durationSec: c.durationSec,
        cameraPreset: c.cameraPreset,
        speech: c.speech,
        speakerName: c.speakerName,
        transitionType: c.transitionType,
        fadeDurSec: c.fadeDurSec,
        trimStartSec: c.trimStartSec,
        trimEndSec: c.trimEndSec,
      })),
      currentIdx: storyCurrentIdx,
    },
    // キャラクター・衣装
    character: {
      activeCharacterId: getActiveCharacterId(),
      activeCostumeId: (() => {
        const id = getActiveCharacterId();
        return id ? (loadCharacterList().find((c) => c.id === id)?.activeCostumeId ?? null) : null;
      })(),
    },
    // アイテム一覧（位置・回転・スケール含む）
    items: (() => { try { return loadItemList() ?? []; } catch { return []; } })(),
    // ステージモデル
    stageModel: {
      activeId: getActiveStageModelId(),
    },
    // カメラアニメーションキーフレーム
    cameraKeyframes: cameraKeyframes.map((kf) => ({ ...kf })),
  };
}

// ── project management ────────────────────────────────────────────────────────

function getAllProjects() {
  const result = readStoredJson(STORAGE_KEYS.projects, {});
  return (result && typeof result === 'object' && !Array.isArray(result)) ? result : {};
}

function writeAllProjects(obj) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return;
  writeStoredJson(STORAGE_KEYS.projects, obj);
}

function getActiveProjectId() {
  try { return localStorage.getItem(STORAGE_KEYS.activeProjectId) ?? null; } catch { return null; }
}

function setActiveProjectId(id) {
  try {
    if (id) {
      localStorage.setItem(STORAGE_KEYS.activeProjectId, id);
    } else {
      localStorage.removeItem(STORAGE_KEYS.activeProjectId);
    }
  } catch { /* ignore storage errors */ }
}

function createProject(name) {
  name = String(name ?? '').trim().slice(0, 50);
  if (!name) name = `プロジェクト ${new Date().toLocaleDateString('ja', { month: '2-digit', day: '2-digit' })}`;
  const id = `proj_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
  const project = {
    id,
    name: name.trim() || '新規プロジェクト',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    scene: getSceneSnapshot(),
  };
  const all = getAllProjects();
  all[id] = project;
  writeAllProjects(all);
  return project;
}

function saveCurrentSceneToProject(id) {
  if (!id || typeof id !== 'string') return;
  const all = getAllProjects();
  if (!all[id]) return;
  all[id].scene = getSceneSnapshot();
  all[id].updatedAt = new Date().toISOString();
  writeAllProjects(all);
}

function renameProject(id, name) {
  if (!id || !name || typeof name !== 'string') return;
  const all = getAllProjects();
  if (!all[id]) return;
  const trimmed = name.trim().slice(0, 80);
  all[id].name = trimmed || all[id].name;
  all[id].updatedAt = new Date().toISOString();
  writeAllProjects(all);
}

function deleteProjectById(id) {
  if (!id || typeof id !== 'string') return;
  const all = getAllProjects();
  delete all[id];
  writeAllProjects(all);
  if (getActiveProjectId() === id) setActiveProjectId(null);
}

function safeQs(sel, parent = document) {
  if (!sel) return null;
  try { return parent?.querySelector(sel) ?? null; } catch { return null; }
}

function formatDuration(seconds) {
  if (!Number.isFinite(seconds) || seconds < 0) return '0:00';
  if (seconds > 86400) return '99:59';
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
}

function isElementInViewport(el) {
  if (!el) return false;
  try {
    const rect = el.getBoundingClientRect();
    return rect.top < window.innerHeight && rect.bottom > 0 && rect.left < window.innerWidth && rect.right > 0;
  } catch { return false; }
}

function escapeHtml(str) {
  if (str == null) return '';
  if (typeof str === 'number' || typeof str === 'boolean') return String(str);
  if (typeof str === 'object') { try { str = JSON.stringify(str); } catch { str = '[object]'; } }
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/**
 * window.confirm の代替。将来的にネイティブTauriダイアログに切り替え可能な薄いラッパー。
 * 現状はブラウザ標準confirmを使用するが一元管理することで将来のリファクタリングを容易にする。
 */
let _lastConfirmTime = 0;
function confirmDialog(message) {
  if (!message) return false;
  if (typeof message !== 'string') message = String(message);
  // Rate limit to prevent accidental double-confirm
  const now = Date.now();
  if (now - _lastConfirmTime < 200) return false;
  _lastConfirmTime = now;
  return window.confirm(message);
}

function formatProjectDate(isoStr) {
  try {
    if (!isoStr) return '—';
    const d = new Date(isoStr);
    if (isNaN(d.getTime())) return '—';
    return d.toLocaleString('ja-JP', { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  } catch {
    return isoStr ?? '—';
  }
}

function updateProjectIndicator() {
  const id = getActiveProjectId();
  const all = getAllProjects();
  const project = id ? all[id] : null;
  if (projectIndicatorNameEl) {
    projectIndicatorNameEl.textContent = project ? escapeHtml(project.name) : '未選択';
  }
  if (projectOpenBtn) {
    const _ptitle = project ? `プロジェクト: ${String(project.name ?? '').slice(0, 60)}` : 'プロジェクトを開く';
    projectOpenBtn.title = _ptitle;
  }
}

let _projectModalOpenerEl = null;
function openProjectModal() {
  _projectModalOpenerEl = document.activeElement;
  renderProjectList();
  if (projectModalEl) projectModalEl.classList.remove('is-hidden');
}
function closeProjectModal() {
  if (_projectModalOpenerEl && typeof _projectModalOpenerEl.focus === 'function') {
    _projectModalOpenerEl.focus();
  }
  _projectModalOpenerEl = null;
  if (projectModalEl) projectModalEl.classList.add('is-hidden');
  hideProjectNewForm();
}

function showProjectNewForm() {
  if (projectNewForm) projectNewForm.classList.remove('is-hidden');
  if (projectCreateBtn) projectCreateBtn.style.display = 'none';
  if (projectNewNameInput) { projectNewNameInput.value = ''; projectNewNameInput.focus(); }
}

function hideProjectNewForm() {
  if (projectNewForm) projectNewForm.classList.add('is-hidden');
  if (projectCreateBtn) projectCreateBtn.style.display = '';
}

function renderProjectList() {
  const _projListEl = document.getElementById('project-list');
  if (!_projListEl || !projectListEl) return;
  const all = getAllProjects();
  const activeId = getActiveProjectId();
  const projects = Object.values(all).sort((a, b) => (b.updatedAt ?? '').localeCompare(a.updatedAt ?? ''));

  if (projects.length === 0) {
    projectListEl.innerHTML = '<div class="project-empty">プロジェクトがありません。新規作成してください。</div>';
    return;
  }

  projectListEl.innerHTML = projects.map((p) => {
    const isActive = p.id === activeId;
    const date = formatProjectDate(p.updatedAt);
    return `
      <div class="project-item ${isActive ? 'is-active' : ''}" data-id="${escapeHtml(p.id)}">
        <div class="project-item-info">
          <div class="project-item-name">${escapeHtml(p.name)}</div>
          <div class="project-item-date">更新: ${escapeHtml(date)}</div>
        </div>
        <div class="project-item-actions">
          ${isActive
            ? '<span class="proj-active-badge">現在</span>'
            : `<button class="proj-btn proj-primary proj-open-item" data-id="${escapeHtml(p.id)}">開く</button>`
          }
          <button class="proj-btn proj-rename-item" data-id="${escapeHtml(p.id)}">名前変更</button>
          <button class="proj-btn proj-danger proj-delete-item" data-id="${escapeHtml(p.id)}">削除</button>
        </div>
      </div>
    `;
  }).join('');
}

async function switchToProject(id) {
  if (!id || typeof id !== 'string') return;
  const all = getAllProjects();
  const project = all[id];
  if (!project) { setStatus(`プロジェクトが見つかりません: ${id}`, 'warn'); return; }
  setActiveProjectId(id);
  if (project.scene) {
    await loadScenePresetFromObject(project.scene);
  }
  updateProjectIndicator();
  renderProjectList();
}

function startInlineRename(id) {
  const item = projectListEl?.querySelector(`.project-item[data-id="${id}"]`);
  if (!item) return;
  const nameEl = item.querySelector('.project-item-name');
  const actionsEl = item.querySelector('.project-item-actions');
  if (!nameEl) return;
  const currentName = nameEl.textContent;

  const input = document.createElement('input');
  input.className = 'project-rename-input';
  input.value = currentName;
  nameEl.replaceWith(input);
  input.focus();
  input.select();

  const commit = () => {
    const newName = input.value.trim().slice(0, 80);
    if (newName && newName !== currentName) renameProject(id, newName);
    renderProjectList();
    updateProjectIndicator();
  };

  input.addEventListener('blur', commit);
  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') { e.preventDefault(); input.blur(); }
    if (e.key === 'Escape') { input.value = currentName; input.blur(); }
  });
}

// ── end project management ────────────────────────────────────────────────────

// ── Named Scene Slots ────────────────────────────────────────────────────────
const _SCENE_SLOTS_KEY = 'avatar.namedSceneSlots';
const _SCENE_SLOTS_MAX = 8;

function _loadSceneSlots() {
  try {
    const data = JSON.parse(localStorage.getItem(_SCENE_SLOTS_KEY) ?? '[]');
    return Array.isArray(data) ? data : [];
  } catch { return []; }
}
function _saveSceneSlots(arr) { try { localStorage.setItem(_SCENE_SLOTS_KEY, JSON.stringify(arr)); } catch (e) { console.warn('[sceneSlots] save failed:', e); } }

function saveCurrentToSlot(name) {
  if (!name?.trim()) return;
  const trimName = name.trim().slice(0, 40);
  const slots = _loadSceneSlots();
  const idx = slots.findIndex((s) => s.name === trimName);
  const entry = { name: trimName, savedAt: new Date().toISOString(), scene: getSceneSnapshot() };
  if (idx >= 0) slots[idx] = entry;
  else slots.unshift(entry);
  try { _saveSceneSlots(slots.slice(0, _SCENE_SLOTS_MAX)); }
  catch (e) { setStatus(`スロット保存失敗: ${e.message}`, 'error'); return; }
  renderSceneSlotList();
  setStatus(`スロット「${trimName}」を保存しました`);
}

async function loadSceneSlot(name) {
  const slot = _loadSceneSlots().find((s) => s.name === name);
  if (!slot) return;
  try {
    await loadScenePresetFromObject(slot.scene);
    setStatus(`スロット「${name}」を読み込みました`);
  } catch (e) {
    console.error('[loadSceneSlot]', e);
    setStatus(`スロット「${name}」の読み込みに失敗しました: ${e.message}`);
  }
}

function deleteSceneSlot(name) {
  _saveSceneSlots(_loadSceneSlots().filter((s) => s.name !== name));
  renderSceneSlotList();
}

function renderSceneSlotList() {
  const listEl = document.getElementById('scene-slot-list');
  if (!listEl) return;
  const slots = _loadSceneSlots();
  listEl.innerHTML = '';
  if (slots.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'scene-slot-empty';
    empty.textContent = 'スロットは空です';
    listEl.appendChild(empty);
    return;
  }
  for (const slot of slots) {
    const row = document.createElement('div');
    row.className = 'scene-slot-row';
    const nameEl = document.createElement('span');
    nameEl.className = 'scene-slot-name';
    nameEl.textContent = slot.name;
    const _slotDate = slot.savedAt ? new Date(slot.savedAt) : null;
    nameEl.title = _slotDate && !isNaN(_slotDate) ? _slotDate.toLocaleString('ja') : '';
    const loadBtn = document.createElement('button');
    loadBtn.type = 'button';
    loadBtn.className = 'scene-slot-btn';
    loadBtn.textContent = '読込';
    loadBtn.addEventListener('click', () => loadSceneSlot(slot.name));
    const delBtn = document.createElement('button');
    delBtn.type = 'button';
    delBtn.className = 'scene-slot-btn scene-slot-del';
    delBtn.textContent = '削除';
    delBtn.addEventListener('click', () => { if (confirmDialog(`「${slot.name}」を削除しますか？`)) deleteSceneSlot(slot.name); });
    row.append(nameEl, loadBtn, delBtn);
    listEl.appendChild(row);
  }
}

function _initSceneSlots() {
  renderSceneSlotList();
  const saveBtn = document.getElementById('scene-slot-save-btn');
  const nameInput = document.getElementById('scene-slot-name-input');
  const counter = document.getElementById('scene-slot-name-counter');
  if (saveBtn && nameInput) {
    saveBtn.addEventListener('click', () => {
      const name = nameInput.value.trim() || `スロット${_loadSceneSlots().length + 1}`;
      saveCurrentToSlot(name);
      saveBtn.classList.add('btn-did-save');
      setTimeout(() => saveBtn.classList.remove('btn-did-save'), 700);
    });
    nameInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') saveBtn.click(); });
    if (counter) {
      nameInput.addEventListener('input', () => {
        const len = nameInput.value.length;
        const max = parseInt(nameInput.maxLength) || 20;
        counter.textContent = `${len}/${max}`;
        counter.classList.toggle('is-near-limit', len >= max * 0.8);
        counter.classList.toggle('is-at-limit', len >= max);
        counter.style.color = len >= max ? 'var(--danger)' : len >= max * 0.8 ? 'var(--warning)' : '';
      });
    }
  }
}

async function saveScenePreset() {
  const snapshot = getSceneSnapshot();
  const blob = new Blob([`${JSON.stringify(snapshot, null, 2)}\n`], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = 'viewer_three_vrm_scene.json';
  anchor.click();
  setTimeout(() => URL.revokeObjectURL(url), 5000);
  setStoredString(STORAGE_KEYS.scenePreset, JSON.stringify(snapshot));
  setScenePresetDirty(false);
  setActionLog('scene preset saved');
  setStatus('scene preset を保存しました');
}

async function loadScenePresetFromObject(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
    setStatus('シーンプリセットのフォーマットが無効です', 'error'); return;
  }

  const _presetWarn = (label, e) => {
    console.warn(`[scenePreset] ${label} 失敗:`, e);
    setActionLog(`scene preset: ${label} の復元に失敗 (${e.message})`);
  };

  if (payload.stage?.config || payload.stage?.preset) {
    try {
      if (payload.stage.config) {
        applyStageConfig(payload.stage.config);
      } else if (payload.stage.preset) {
        applyStagePreset(payload.stage.preset);
      }
      if (payload.stage.textureUrl) {
        await applyStageTexture(payload.stage.textureUrl, payload.stage.textureLabel ?? 'scene texture');
      }
    } catch (e) { _presetWarn('ステージ', e); }
  }

  if (payload.camera?.preset) {
    applyCameraPreset(payload.camera.preset);
  } else if (payload.camera?.position && payload.camera?.target) {
    applyCameraConfig(payload.camera);
  }

  if (payload.model?.groundCorrection !== undefined) {
    modelGroundCorrectionEnabled = Boolean(payload.model.groundCorrection);
    if (modelGroundCorrectionEl) {
      modelGroundCorrectionEl.checked = modelGroundCorrectionEnabled;
    }
    setStoredString(STORAGE_KEYS.groundCorrection, String(modelGroundCorrectionEnabled));
  }

  const modelSourceUrl = payload.model?.sourceUrl
    || (payload.model?.key === 'default_vrm' ? MODEL_VRM : payload.model?.key === 'default_glb' ? MODEL_GLB : '');
  if (modelSourceUrl) {
    try {
      await loadModel(modelSourceUrl, modelSourceUrl === MODEL_GLB ? MODEL_VRM : null);
    } catch (e) { _presetWarn('モデル', e); }
  }

  if (payload.model?.settings && currentModelKey) {
    currentModelSettings = {
      groundOffset: Number(payload.model.settings.groundOffset ?? 0) || 0,
      scale: Number(payload.model.settings.scale ?? 1) || 1,
      yPosition: Number(payload.model.settings.yPosition ?? 0) || 0,
      cameraHeight: Number(payload.model.settings.cameraHeight ?? 0) || 0,
      rotationY: Number(payload.model.settings.rotationY ?? 0) || 0,
      rightFootFix: Boolean(payload.model.settings.rightFootFix),
      notes: String(payload.model.settings.notes ?? ''),
    };
    persistCurrentModelSettings();
    applyModelSettingsToCurrentModel();
    applyModelProfileToUi(currentModelSettings);
  }

  if (payload.motion?.selectedUrl) {
    selectBodyMotion(payload.motion.selectedUrl, basenameFromUrl(payload.motion.selectedUrl));
  }

  if (payload.motion?.currentUrl) {
    try {
      await loadMotion(payload.motion.currentUrl, {
        autoPlay: false,
        label: basenameFromUrl(payload.motion.currentUrl),
      });
    } catch (e) { _presetWarn('モーション', e); }
  }
  if (payload.motion?.loop !== undefined && selectedBodyMotionUrl) {
    setMotionLoopEnabled(selectedBodyMotionUrl, Boolean(payload.motion.loop));
  }
  if (payload.motion?.playbackSpeed !== undefined) {
    setPlaybackSpeed(payload.motion.playbackSpeed);
  }

  if (payload.blendshape) {
    restoreFacialState(payload.blendshape);
  }

  if (payload.action?.autoplay !== undefined) {
    actionAutoPlayEnabled = Boolean(payload.action.autoplay);
    if (actionAutoplayEl) {
      actionAutoplayEl.checked = actionAutoPlayEnabled;
    }
    setStoredString(STORAGE_KEYS.actionAutoplay, String(actionAutoPlayEnabled));
  }

  if (typeof payload.sceneState === 'string') {
    scenePresetDirty = payload.sceneState !== '保存済み';
  } else {
    scenePresetDirty = false;
  }

  // Restore extra characters (only for server-hosted models to avoid blob URL issues)
  if (Array.isArray(payload.extraCharacters) && payload.extraCharacters.length > 0) {
    const modelUrl = currentModelSourceUrl;
    if (modelUrl && (modelUrl.startsWith('/assets/') || modelUrl.startsWith('http'))) {
      for (const saved of payload.extraCharacters) {
        const id = `char_${nextExtraCharId++}`;
        const ch = {
          id,
          label: saved.label || `キャラ ${nextExtraCharId - 1}`,
          vrm: null, mixer: null, action: null, modelRoot: null,
          motionUrl: '',
          posX: Number(saved.posX) || 0,
          posZ: Number(saved.posZ) || 0,
        };
        extraCharacters.push(ch);
        try {
          await loadModelForExtraChar(ch, modelUrl);
          if (saved.motionUrl) await loadMotionForExtraChar(ch, saved.motionUrl);
        } catch (e) {
          _presetWarn('追加キャラ', e);
          if (ch.action) ch.action.stop();
          if (ch.modelRoot) { scene.remove(ch.modelRoot); disposeObject3D(ch.modelRoot); }
          const idx = extraCharacters.indexOf(ch);
          if (idx >= 0) extraCharacters.splice(idx, 1);
        }
      }
      renderExtraCharacterList();
    }
  }

  // Restore story clips
  if (Array.isArray(payload.story?.clips)) {
    storyClips = payload.story.clips.map((c) => ({
      id: c.id || `sclip_${nextStoryClipId++}`,
      label: c.label || basenameFromUrl(c.motionUrl || ''),
      motionUrl: c.motionUrl || '',
      durationSec: c.durationSec != null ? Number(c.durationSec) : null,
      cameraPreset: c.cameraPreset ?? undefined,
      speech: c.speech ?? '',
      speakerName: c.speakerName ?? '',
      transitionType: c.transitionType ?? 'cut',
      fadeDurSec: c.fadeDurSec != null ? Number(c.fadeDurSec) : 0.28,
      trimStartSec: c.trimStartSec != null ? Number(c.trimStartSec) : 0,
      trimEndSec: c.trimEndSec != null ? Number(c.trimEndSec) : null,
    }));
    nextStoryClipId = Math.max(nextStoryClipId, storyClips.length + 1);
    storyCurrentIdx = -1;
    setStoryMode(Boolean(payload.story.mode));
    renderStoryEditor();
    renderStoryTrack();
  }

  // キャラクター・衣装の復元
  if (payload.character?.activeCharacterId) {
    const charId = payload.character.activeCharacterId;
    const ch = loadCharacterList().find((c) => c.id === charId);
    if (ch) {
      if (payload.character.activeCostumeId) {
        setActiveCostume(charId, payload.character.activeCostumeId);
      }
      await applyCharacterCostume(charId).catch((e) => setStatus(`キャラ復元失敗: ${e.message}`));
    }
  }

  // アイテム一覧の復元
  if (Array.isArray(payload.items)) {
    saveItemList(payload.items);
    await reloadAllItems().catch((e) => setStatus(`アイテム復元失敗: ${e.message}`));
    renderItemPanel();
  }

  // ステージモデルの復元
  if (payload.stageModel !== undefined) {
    const smId = payload.stageModel?.activeId ?? null;
    await applyStageModel(smId).catch((e) => setStatus(`ステージモデル復元失敗: ${e.message}`));
  }

  // カメラアニメーションキーフレームの復元
  if (Array.isArray(payload.cameraKeyframes)) {
    cameraKeyframes = payload.cameraKeyframes.map((kf) => ({ ...kf }));
    renderCameraKeyframePanel();
  }

  setStoredString(STORAGE_KEYS.scenePreset, JSON.stringify(payload));
  updateSceneStateUi();
  updatePlaybackUi();
  updateMotionDetailUi();
  setActionLog('scene preset loaded');
  setStatus('シーンプリセットを復元しました');
}

async function loadScenePresetFromFile(file) {
  if (!file || typeof file.text !== 'function') {
    setStatus('ファイルの読み込みに失敗しました', 'error'); return;
  }
  const text = await file.text();
  let payload;
  try {
    payload = JSON.parse(text);
  } catch {
    throw new Error('JSONの解析に失敗しました。ファイルが壊れているか形式が正しくありません');
  }
  await loadScenePresetFromObject(payload);
}

async function applyStageTexture(url, label = basenameFromUrl(url)) {
  if (!url || typeof url !== 'string') return;
  label = String(label ?? basenameFromUrl(url)).slice(0, 100);
  let texture;
  try {
    texture = await new Promise((resolve, reject) => {
      textureLoader.load(url, resolve, undefined, (e) => reject(new Error(`テクスチャ読み込み失敗: ${url}`)));
    });
  } catch (e) { setStatus(e.message, 'error'); return; }
  texture.colorSpace = THREE.SRGBColorSpace;
  currentStageTexture = texture;
  currentStageTextureUrl = url;
  currentStageTextureLabel = label;
  scene.background = texture;
  currentStageLabel = label;
  currentStagePresetName = 'custom';
  setStoredString(STORAGE_KEYS.stagePreset, currentStagePresetName);
  updateStageUi();
  setScenePresetDirty(true);
}

function clearStageTexture() {
  if (currentStageTexture) {
    try { currentStageTexture.dispose?.(); } catch {}
    currentStageTexture = null;
  }
  currentStageTextureUrl = '';
  currentStageTextureLabel = '';
}

function isStageTextureFile(file) {
  if (!file) return false;
  const name = String(file.name ?? '').toLowerCase();
  return /\.(png|jpe?g|webp)$/i.test(name);
}

async function handleDroppedFile(file) {
  if (!file || typeof file !== 'object') return;
  const name = String(file.name ?? '').toLowerCase();
  if (/\.(vrm|glb)$/i.test(name)) {
    const url = createManagedObjectUrl(file);
    await loadModel(url, name.endsWith('.glb') ? MODEL_VRM : null);
    currentModelLabel = file.name;
    currentModelKey = `custom:${normalizeModelKey(file.name)}`;
    setStoredString(STORAGE_KEYS.selectedModelKey, currentModelKey);
    currentModelSettings = getModelSettingsForKey(currentModelKey);
    applyModelSettingsToCurrentModel();
    updatePlaybackUi();
    renderModelList();
    return;
  }
  if (name.endsWith('.vrma')) {
    const url = createManagedObjectUrl(file);
    selectBodyMotion(url, file.name);
    await loadMotion(url, { autoPlay: false, label: file.name });
    return;
  }
  if (/\.(gltf|glb)$/i.test(name)) {
    const url = createManagedObjectUrl(file);
    await loadStageAsset(url, file.name);
    return;
  }
  if (isStageTextureFile(file)) {
    const url = createManagedObjectUrl(file);
    await applyStageTexture(url, file.name);
    return;
  }
  if (name.endsWith('.json')) {
    try {
      const text = await file.text();
      const obj = JSON.parse(text);
      if (obj && typeof obj === 'object' && (obj.camera || obj.stage || obj.model)) {
        await loadScenePresetFromObject(obj);
        setStatus(`シーンプリセットを読み込みました: ${file.name}`);
        return;
      }
    } catch { /* not a scene preset */ }
  }
  setStatus(`非対応のファイル形式です: ${file.name}`, 'warn');
}

function updateFpsCounter() {
  fpsFrameCount += 1;
  if (document.hidden) return;
  const now = performance.now();
  const elapsed = now - fpsLastStamp;
  if (elapsed < 500) {
    return;
  }
  currentFps = (fpsFrameCount * 1000) / elapsed;
  fpsFrameCount = 0;
  fpsLastStamp = now;
  if (fpsCounterEl) {
    const _renderInfo = renderer?.info?.render ?? {};
    const _triangles = Number(_renderInfo?.triangles ?? 0);
    const _drawCalls = Number(_renderInfo?.calls ?? 0);
    const _memHint = _triangles > 100000 ? ` | ${(_triangles/1000).toFixed(0)}k△` : '';
    const _heapMB = performance?.memory?.usedJSHeapSize ? Math.round(performance.memory.usedJSHeapSize / 1048576) : null;
    const _heapHint = _heapMB != null ? ` | ${_heapMB}MB` : '';
    fpsCounterEl.textContent = `FPS: ${currentFps.toFixed(1)}${_memHint}${_heapHint}`;
    fpsCounterEl.title = `FPS: ${currentFps.toFixed(1)} | ポリゴン: ${_triangles.toLocaleString()} | ドローコール: ${_drawCalls}`;
    // カラーコーディング: 良好(緑) / 普通(黄) / 低下(赤)
    fpsCounterEl.classList.toggle('fps-good', currentFps >= 55);
    fpsCounterEl.classList.toggle('fps-ok',   currentFps >= 25 && currentFps < 55);
    fpsCounterEl.classList.toggle('fps-bad',  currentFps < 25);
    fpsCounterEl.setAttribute('aria-label', `FPS: ${currentFps.toFixed(1)}`);
  }
}

document.addEventListener('fullscreenchange', () => {
  fullscreenActive = !!document.fullscreenElement;
  const btn = document.getElementById('fullscreen-btn');
  if (btn) btn.title = fullscreenActive ? 'フルスクリーン解除 (F)' : 'フルスクリーン (F)';
  const inlineBtn = document.getElementById('fullscreen-toggle-inline');
  if (inlineBtn) inlineBtn.title = fullscreenActive ? 'フルスクリーン解除' : 'フルスクリーン';
});

function toggleFullscreen() {
  if (document.fullscreenElement) {
    document.exitFullscreen().catch((e) => console.warn('[fullscreen]', e));
  } else {
    (document.documentElement.requestFullscreen?.() ?? Promise.reject()).catch((e) => {
      console.warn('[fullscreen]', e);
      setStatus('フルスクリーンに切り替えられませんでした', 'warn');
    });
  }
}

function getCurrentCameraState() {
  if (!camera || !controls) return { position: [0,1.35,2.6], target: [0,0.95,0], fov: CAMERA_FOV };
  return {
    position: [camera.position.x, camera.position.y, camera.position.z],
    target: [controls.target.x, controls.target.y, controls.target.z],
    fov: camera.fov,
  };
}

function resetCameraToPreset() {
  applyCameraPreset(currentCameraPresetName);
  if (camAnimPlaying && controls) { camAnimPlaying = false; controls.enabled = true; }
  setStatus(`カメラをリセット: ${currentCameraPresetName}`);
}

function setActionLog(message) {
  if (!actionLogEl) return;
  if (message == null) return;
  const _logTs = new Date().toLocaleTimeString();
  const _msg = String(message).slice(0, 300);
  const _logLines = actionLogEl.textContent.split('\n').slice(0, 150).join('\n');
  actionLogEl.textContent = `${_logTs} ${_msg}\n${_logLines}`;
}

function formatVec3(vec) {
  return `[${vec.map((value) => (Number(value) || 0).toFixed(3)).join(', ')}]`;
}

function formatQuat(quat) {
  return `[${quat.map((value) => (Number(value) || 0).toFixed(4)).join(', ')}]`;
}

const _avecLeft = new THREE.Vector3();
const _avecRight = new THREE.Vector3();
function angleBetweenVectors(a, b) {
  _avecLeft.fromArray(a).normalize();
  _avecRight.fromArray(b).normalize();
  return THREE.MathUtils.radToDeg(_avecLeft.angleTo(_avecRight));
}

const _sampleQ = new THREE.Quaternion();
const _sampleDir = new THREE.Vector3();
function sampleBoneDebug(bone) {
  if (!bone) {
    return null;
  }
  const localQ = bone.quaternion.clone();
  const worldQ = bone.getWorldQuaternion(_sampleQ);
  const worldDir = _sampleDir.set(0, 1, 0).applyQuaternion(worldQ).normalize().toArray();
  const worldRight = new THREE.Vector3(1, 0, 0).applyQuaternion(worldQ).normalize();
  const worldForward = new THREE.Vector3(0, 0, 1).applyQuaternion(worldQ).normalize();
  return {
    localQ: [localQ.x, localQ.y, localQ.z, localQ.w],
    worldQ: [worldQ.x, worldQ.y, worldQ.z, worldQ.w],
    worldDir: Array.isArray(worldDir) ? worldDir : [worldDir.x, worldDir.y, worldDir.z],
    worldRight: [worldRight.x, worldRight.y, worldRight.z],
    worldForward: [worldForward.x, worldForward.y, worldForward.z],
  };
}

function getBoneDebugSnapshot() {
  const humanoid = currentVrm?.humanoid;
  const rows = BONE_DEBUG_NAMES.map((name) => {
    const bone = humanoid?.getRawBoneNode(name) ?? null;
    return {
      name,
      ...sampleBoneDebug(bone),
    };
  });
  return rows;
}

let _boneDebugLastHash = '';
function updateBoneDebugOverlay(summaryText = '') {
  if (!boneDebugOverlayEl || !boneDebugGridEl) {
    return;
  }
  boneDebugOverlayEl.classList.toggle('is-hidden', !boneDebugVisible);
  if (boneDebugToggleEl) {
    const _boneFrameInfo = currentAction ? ` [${Math.floor(currentAction.time * 30)}f]` : '';
    boneDebugToggleEl.textContent = boneDebugVisible ? `非表示にする${_boneFrameInfo}` : '表示する';
  }
  if (boneDebugSummaryEl && summaryText) {
    boneDebugSummaryEl.textContent = summaryText;
  } else if (boneDebugSummaryEl && !boneDebugSummaryEl.textContent) {
    boneDebugSummaryEl.textContent = '未取得';
  }
  if (!boneDebugVisible) {
    return;
  }
  const rows = getBoneDebugSnapshot();
  // Skip DOM rebuild if data hasn't changed
  const newHash = rows.map(r => r.name + (r.localQ ? r.localQ.x.toFixed(4) : 'x')).join('|');
  if (newHash === _boneDebugLastHash) return;
  _boneDebugLastHash = newHash;
  boneDebugGridEl.innerHTML = '';
  rows.forEach((row) => {
    const rowEl = document.createElement('div');
    rowEl.className = 'debug-bone-row';

    const nameEl = document.createElement('div');
    nameEl.className = 'debug-bone-name';
    nameEl.textContent = String(row.name || '');

    const valuesEl = document.createElement('div');
    valuesEl.className = 'debug-bone-values';
    if (!row.localQ) {
      valuesEl.textContent = 'no bone';
    } else {
      valuesEl.textContent = [
        `localQ ${formatQuat(row.localQ)}`,
        `worldQ ${formatQuat(row.worldQ)}`,
        `worldDirY ${formatVec3(row.worldDir)}`,
      ].join('\n');
    }

    rowEl.append(nameEl, valuesEl);
    boneDebugGridEl.appendChild(rowEl);
  });
}

function logBoneDebugSnapshot(label) {
  const rows = getBoneDebugSnapshot();
  if (!rows.length) {
    setActionLog(`bone debug ${label}: no VRM humanoid`);
    return;
  }

  const lower = rows.find((row) => row.name === 'rightLowerLeg');
  const foot = rows.find((row) => row.name === 'rightFoot');
  const leftLower = rows.find((row) => row.name === 'leftLowerLeg');
  const leftFoot = rows.find((row) => row.name === 'leftFoot');
  const summary = [
    `model=${currentModelLabel}`,
    `motion=${basenameFromUrl(currentMotionUrl || selectedBodyMotionUrl)}`,
    `R/L lower angle=${lower?.worldDir && leftLower?.worldDir ? angleBetweenVectors(leftLower.worldDir, lower.worldDir).toFixed(2) : 'n/a'}deg`,
    `R/L foot angle=${foot?.worldDir && leftFoot?.worldDir ? angleBetweenVectors(leftFoot.worldDir, foot.worldDir).toFixed(2) : 'n/a'}deg`,
  ].join(' | ');
  updateBoneDebugOverlay(summary);

  const lines = rows.map((row) => {
    if (!row.localQ) {
      return `${row.name}: no bone`;
    }
    return `${row.name} localQ=${formatQuat(row.localQ)} worldQ=${formatQuat(row.worldQ)} worldDirY=${formatVec3(row.worldDir)}`;
  });
  const compare = lower && foot && leftLower && leftFoot
    ? `compare right/left lower=${angleBetweenVectors(leftLower.worldDir, lower.worldDir).toFixed(2)}deg foot=${angleBetweenVectors(leftFoot.worldDir, foot.worldDir).toFixed(2)}deg`
    : 'compare n/a';
  const message = `bone debug ${label}: ${summary}\n${lines.join('\n')}\n${compare}`;
  if (import.meta.env?.DEV) console.log(message);
  setActionLog(message);
}

function getViewportSize() {
  const rect = viewportEl?.getBoundingClientRect();
  const width = Math.max(320, Math.floor(rect?.width || window.innerWidth));
  const height = Math.max(200, Math.floor(rect?.height || window.innerHeight));
  return { width, height };
}

function makeCameraFrame(frame, options) {
  const height = Math.max(frame.height ?? frame.size.y, 0.1);
  const widthDepth = Math.max(frame.widthDepth, 0.6);
  const target = new THREE.Vector3(
    frame.center.x,
    frame.min.y + height * options.targetYRatio,
    frame.center.z,
  );
  const horizontal = new THREE.Vector3(options.offset[0], 0, options.offset[2]);
  if (horizontal.lengthSq() === 0) {
    horizontal.z = 1;
  }
  horizontal.normalize().multiplyScalar(Math.max(widthDepth * options.distanceScale, height * 0.72, 0.95));

  return {
    target,
    cameraPosition: target.clone().add(new THREE.Vector3(
      horizontal.x,
      height * options.offset[1],
      horizontal.z,
    )),
    fov: options.fov,
  };
}

function resolveCameraPresetFrame(presetName, frame = currentModelFrame ?? DEFAULT_CAMERA_FRAME) {
  const preset = CAMERA_PRESETS[presetName] ?? CAMERA_PRESETS[DEFAULT_CAMERA_PRESET];
  return preset.resolve(frame);
}

function measureObjectFrame(object3d) {
  const bounds = _sharedBox3.setFromObject(object3d);
  if (!Number.isFinite(bounds.min.y) || !Number.isFinite(bounds.max.y)) {
    return DEFAULT_CAMERA_FRAME;
  }

  const size = bounds.getSize(_sharedVec3A).clone();
  const center = bounds.getCenter(_sharedVec3B).clone();
  return {
    center,
    min: bounds.min.clone(),
    size,
    widthDepth: Math.max(size.x, size.z, 0.6),
    height: Math.max(size.y, 0.1),
  };
}

function normalizeConfigName(value) {
  return String(value ?? '').trim().toLowerCase().replaceAll('-', '_');
}

function resolveCameraPresetName(presetName) {
  const normalizedName = normalizeConfigName(presetName);
  return CAMERA_PRESET_ALIASES[normalizedName] ?? normalizedName;
}

function normalizeStageSection(defaultSection, sectionConfig) {
  if (typeof sectionConfig === 'boolean') {
    return {
      ...defaultSection,
      enabled: sectionConfig,
    };
  }
  if (sectionConfig && typeof sectionConfig === 'object') {
    return {
      ...defaultSection,
      ...sectionConfig,
    };
  }
  return {
    ...defaultSection,
  };
}

function normalizeStageConfig(stageConfig = {}) {
  if (typeof stageConfig === 'string') {
    const normalizedName = normalizeConfigName(stageConfig);
    return STAGE_PRESETS[normalizedName] ?? STAGE_PRESETS[{
      bright: 'studio',
      plain: 'grid_only',
    }[normalizedName]] ?? {};
  }
  if (!stageConfig || typeof stageConfig !== 'object') {
    return {};
  }
  const aliasedStageConfig = {
    ...stageConfig,
  };
  if (stageConfig.background_color && !aliasedStageConfig.background) {
    aliasedStageConfig.background = stageConfig.background_color;
  }
  if (stageConfig.hemisphere_light && !aliasedStageConfig.hemisphereLight) {
    aliasedStageConfig.hemisphereLight = stageConfig.hemisphere_light;
  }
  if (stageConfig.directional_light && !aliasedStageConfig.directionalLight) {
    aliasedStageConfig.directionalLight = stageConfig.directional_light;
  }
  if (stageConfig.lights && typeof stageConfig.lights === 'object') {
    const hemisphere = stageConfig.lights.hemisphereLight ?? stageConfig.lights.hemisphere;
    const directional = stageConfig.lights.directionalLight ?? stageConfig.lights.directional;
    if (hemisphere && !aliasedStageConfig.hemisphereLight) {
      aliasedStageConfig.hemisphereLight = hemisphere;
    }
    if (directional && !aliasedStageConfig.directionalLight) {
      aliasedStageConfig.directionalLight = directional;
    }
  }
  if (stageConfig.shadow && !aliasedStageConfig.shadows) {
    aliasedStageConfig.shadows = stageConfig.shadow;
  }
  if (stageConfig.preset) {
    return {
      ...(
        STAGE_PRESETS[normalizeConfigName(aliasedStageConfig.preset)] ??
        STAGE_PRESETS[{
          bright: 'studio',
          plain: 'grid_only',
        }[normalizeConfigName(aliasedStageConfig.preset)]] ??
        {}
      ),
      ...aliasedStageConfig,
    };
  }
  return aliasedStageConfig;
}

function mergeStageConfig(stageConfig = {}) {
  const normalizedStageConfig = normalizeStageConfig(stageConfig);
  return {
    background: normalizedStageConfig.background ?? DEFAULT_STAGE_CONFIG.background,
    floor: normalizeStageSection(DEFAULT_STAGE_CONFIG.floor, normalizedStageConfig.floor),
    grid: normalizeStageSection(DEFAULT_STAGE_CONFIG.grid, normalizedStageConfig.grid),
    hemisphereLight: normalizeStageSection(
      DEFAULT_STAGE_CONFIG.hemisphereLight,
      normalizedStageConfig.hemisphereLight,
    ),
    directionalLight: normalizeStageSection(
      DEFAULT_STAGE_CONFIG.directionalLight,
      normalizedStageConfig.directionalLight,
    ),
    shadows: normalizeStageSection(DEFAULT_STAGE_CONFIG.shadows, normalizedStageConfig.shadows),
  };
}

function vectorFromArray(value, fallback) {
  if (!Array.isArray(value) || value.length < 3) {
    return fallback ? fallback.clone() : new THREE.Vector3();
  }
  const x = Number(value[0]), y = Number(value[1]), z = Number(value[2]);
  if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(z)) {
    return fallback ? fallback.clone() : new THREE.Vector3();
  }
  return new THREE.Vector3(x, y, z);
}

function enhanceGltfTextures(root) {
  const maxAniso = renderer.capabilities.getMaxAnisotropy();
  root.traverse((obj) => {
    if (!obj.isMesh) return;
    const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
    for (const mat of mats) {
      if (!mat) continue;
      for (const key of ['map', 'normalMap', 'roughnessMap', 'metalnessMap', 'emissiveMap', 'aoMap']) {
        const tex = mat[key];
        if (!tex) continue;
        tex.anisotropy = maxAniso;
        tex.needsUpdate = true;
      }
    }
  });
}

async function applyImageTextureToObject(root, imageFile) {
  const url = URL.createObjectURL(imageFile);
  return new Promise((resolve, reject) => {
    textureLoader.load(url, (tex) => {
      URL.revokeObjectURL(url);
      tex.colorSpace = THREE.SRGBColorSpace;
      tex.anisotropy = renderer.capabilities.getMaxAnisotropy();
      root.traverse((obj) => {
        if (!obj.isMesh) return;
        const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
        for (const mat of mats) {
          if (!mat) continue;
          if (mat.map) mat.map.dispose();
          mat.map = tex;
          mat.needsUpdate = true;
        }
      });
      resolve();
    }, undefined, (err) => { URL.revokeObjectURL(url); reject(err); });
  });
}

const _gltfExporter = new GLTFExporter();

function exportObjectToGlbBuffer(object) {
  return new Promise((resolve, reject) => {
    _gltfExporter.parse(
      object,
      (glb) => resolve(glb),
      (err) => reject(err),
      { binary: true, embedImages: true },
    );
  });
}

function collectMeshNodes(root) {
  if (!root || typeof root.traverse !== 'function') return [];
  const nodes = [];
  root.traverse((obj) => {
    if (obj && (obj.isMesh || obj.isSkinnedMesh)) {
      nodes.push({ uuid: obj.uuid, name: obj.name || '(無名メッシュ)', object: obj });
    }
  });
  return nodes;
}

function disposeMaterial(material) {
  if (!material || typeof material !== 'object') return;
  if (Array.isArray(material)) { material.forEach(disposeMaterial); return; }
  // Dispose texture maps to free GPU memory
  const texMaps = ['map','normalMap','roughnessMap','metalnessMap','emissiveMap','alphaMap',
                   'aoMap','lightMap','bumpMap','displacementMap','envMap','specularMap',
                   'specularColorMap','transmissionMap','thicknessMap','sheenColorMap','sheenRoughnessMap'];
  for (const key of texMaps) { material[key]?.dispose?.(); }
  material.dispose?.();
}

function disposeObject3D(object3d) {
  if (!object3d || typeof object3d.traverse !== 'function') return;
  object3d.traverse((child) => {
    child.geometry?.dispose?.();
    disposeMaterial(child.material);
    // Clear any animation references
    child.morphTargetDictionary = undefined;
    child.morphTargetInfluences = undefined;
  });
}

function replaceStageObject(key, object3d) {
  const previous = stageObjects[key];
  if (previous) {
    if (scene) scene.remove(previous);
    disposeObject3D(previous);
  }
  stageObjects[key] = object3d ?? null;
  if (object3d && scene) {
    scene.add(object3d);
  }
}

function configureDirectionalShadow(light, shadowConfig) {
  if (!light || !shadowConfig || !light.shadow?.camera) return;
  light.shadow.mapSize.set(
    Math.min(shadowConfig.mapSize ?? 2048, 4096),
    Math.min(shadowConfig.mapSize ?? 2048, 4096)
  );
  const cameraSize = shadowConfig.cameraSize;
  light.shadow.camera.left = -cameraSize;
  light.shadow.camera.right = cameraSize;
  light.shadow.camera.top = cameraSize;
  light.shadow.camera.bottom = -cameraSize;
  light.shadow.camera.near = 0.1;
  light.shadow.camera.far = 20;
  light.shadow.camera.updateProjectionMatrix();
}

function applyObjectShadowSettings(object3d) {
  if (!object3d || typeof object3d.traverse !== 'function') return;
  const shadowsEnabled = Boolean(currentStageConfig?.shadows?.enabled);
  object3d.traverse((child) => {
    if (child.isMesh) {
      child.castShadow = shadowsEnabled;
      child.receiveShadow = shadowsEnabled;
    }
  });
}

function applyStageConfig(stageConfig = {}) {
  if (currentStageTexture) {
    currentStageTexture.dispose?.();
    currentStageTexture = null;
    currentStageTextureUrl = '';
    currentStageTextureLabel = '';
  }
  currentStageConfig = mergeStageConfig(stageConfig);
  if (Object.hasOwn(stageConfig, 'preset')) {
    const normalizedPreset = normalizeConfigName(stageConfig.preset);
    currentStagePresetName = STAGE_PRESETS[normalizedPreset] ? normalizedPreset : 'custom';
  } else {
    currentStagePresetName = 'custom';
  }
  try { scene.background = new THREE.Color(currentStageConfig.background); } catch { scene.background = new THREE.Color('#1a1a2e'); }
  renderer.shadowMap.enabled = Boolean(currentStageConfig.shadows.enabled);
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;

  if (currentStageConfig.floor.enabled) {
    const floor = new THREE.Mesh(
      new THREE.CircleGeometry(currentStageConfig.floor.radius, 64),
      new THREE.MeshStandardMaterial({
        color: new THREE.Color(currentStageConfig.floor.color),
        roughness: 1.0,
        metalness: 0.0,
      }),
    );
    floor.rotation.x = -Math.PI / 2;
    floor.position.y = -0.01;
    floor.receiveShadow = renderer.shadowMap.enabled;
    replaceStageObject('floor', floor);
  } else {
    replaceStageObject('floor', null);
  }

  {
    const gc = currentStageConfig.grid;
    const gridKey = JSON.stringify(gc);
    if (gridKey !== _cachedGridKey) {
      _cachedGridKey = gridKey;
      if (gc.enabled) {
        const grid = new THREE.GridHelper(
          gc.size, gc.divisions,
          new THREE.Color(gc.colorCenterLine),
          new THREE.Color(gc.colorGrid),
        );
        grid.position.y = 0.002;
        replaceStageObject('grid', grid);
      } else {
        replaceStageObject('grid', null);
      }
    }
  }

  if (currentStageConfig.hemisphereLight.enabled) {
    const hemisphereLight = new THREE.HemisphereLight(
      new THREE.Color(currentStageConfig.hemisphereLight.skyColor),
      new THREE.Color(currentStageConfig.hemisphereLight.groundColor),
      currentStageConfig.hemisphereLight.intensity,
    );
    replaceStageObject('hemisphereLight', hemisphereLight);
  } else {
    replaceStageObject('hemisphereLight', null);
  }

  if (currentStageConfig.directionalLight.enabled) {
    const directionalLight = new THREE.DirectionalLight(
      new THREE.Color(currentStageConfig.directionalLight.color),
      currentStageConfig.directionalLight.intensity,
    );
    directionalLight.position.copy(vectorFromArray(
      currentStageConfig.directionalLight.position,
      new THREE.Vector3(2, 4, 3),
    ));
    directionalLight.castShadow = renderer.shadowMap.enabled && currentStageConfig.directionalLight.castShadow;
    configureDirectionalShadow(directionalLight, currentStageConfig.shadows);
    replaceStageObject('directionalLight', directionalLight);
  } else {
    replaceStageObject('directionalLight', null);
  }

  if (currentModelRoot) {
    applyObjectShadowSettings(currentModelRoot);
  }
  if (currentStageAssetRoot) {
    applyObjectShadowSettings(currentStageAssetRoot);
  }
  updateStageUi();
  setStoredString(STORAGE_KEYS.stagePreset, currentStagePresetName);
  writeStoredJson(STORAGE_KEYS.stageConfig, currentStageConfig);
  updateSceneStateUi();
}

function applyStagePreset(presetName) {
  if (!presetName) { setStatus('ステージプリセット名が空です', 'warn'); return; }
  const normalizedName = normalizeConfigName(presetName);
  const aliasedName = {
    bright: 'studio',
    plain: 'grid_only',
  }[normalizedName] ?? normalizedName;
  const resolvedName = STAGE_PRESETS[aliasedName] ? aliasedName : 'custom';
  currentStagePresetName = resolvedName;
  setStoredString(STORAGE_KEYS.stagePreset, resolvedName);
  applyStageConfig({
    preset: resolvedName,
    ...(STAGE_PRESETS[resolvedName] ?? {}),
  });
  setScenePresetDirty(true);
}

function updateCameraPresetButtons() {
  cameraPresetButtons.forEach((button) => {
    button.classList.toggle('is-active', button.dataset.cameraPreset === currentCameraPresetName);
  });
}

function basenameFromUrl(url) {
  if (!url) return '';
  if (String(url).startsWith('blob:')) return '(カスタムファイル)';
  const withoutQuery = String(url).split('?')[0].split('#')[0];
  const parts = withoutQuery.split('/');
  const raw = parts[parts.length - 1] || withoutQuery;
  try { return decodeURIComponent(raw); } catch { return raw; }
}

function ensureMotionOption(url, label = basenameFromUrl(url)) {
  if (!bodyMotionSelect || !url) return;
  label = String(label ?? url).slice(0, 100);
  const existing = [...bodyMotionSelect.options].find((option) => option.value === url);
  if (existing) {
    existing.textContent = label;
    return;
  }
  bodyMotionSelect.append(new Option(label, url));
}

// ── Motion edit / add modal ──────────────────────────────────────────────────
function _getMotionModal() { return document.getElementById('motion-modal'); }

function openMotionEditModal(motion) {
  if (!motion?.url) return;
  const modal = _getMotionModal();
  if (!modal) return;
  modal.dataset.mode = 'edit';
  modal.dataset.targetUrl = motion.url;
  const titleEl = document.getElementById('motion-modal-title');
  if (titleEl) titleEl.textContent = 'モーション名を編集';
  const nameEl = document.getElementById('motion-modal-name');
  if (nameEl) nameEl.value = _getMotionDisplayName(motion);
  const urlRow = document.getElementById('motion-modal-url-row');
  if (urlRow) urlRow.style.display = 'none';
  const catRow = document.getElementById('motion-modal-cat-row');
  if (catRow) catRow.style.display = 'none';
  const descRow = document.getElementById('motion-modal-desc-row');
  if (descRow) descRow.style.display = 'none';
  modal.showModal();
}

function openMotionAddModal() {
  const modal = _getMotionModal();
  if (!modal) return;
  modal.dataset.mode = 'add';
  modal.dataset.targetUrl = '';
  const titleEl = document.getElementById('motion-modal-title');
  if (titleEl) titleEl.textContent = 'モーションを追加';
  const nameEl = document.getElementById('motion-modal-name');
  if (nameEl) nameEl.value = '';
  const urlEl = document.getElementById('motion-modal-url');
  if (urlEl) urlEl.value = '';
  const catEl = document.getElementById('motion-modal-cat');
  if (catEl) catEl.value = 'custom';
  const descEl = document.getElementById('motion-modal-desc');
  if (descEl) descEl.value = '';
  const urlRow = document.getElementById('motion-modal-url-row');
  if (urlRow) urlRow.style.display = '';
  const catRow = document.getElementById('motion-modal-cat-row');
  if (catRow) catRow.style.display = '';
  const descRow = document.getElementById('motion-modal-desc-row');
  if (descRow) descRow.style.display = '';
  modal.showModal();
}

// ── Panel section collapse ────────────────────────────────────────────────────
function _initPanelCollapse() {
  const _COLLAPSE_KEY = 'avatar.panelCollapsed';
  let _collapsedRaw; try { _collapsedRaw = JSON.parse(localStorage.getItem(_COLLAPSE_KEY) ?? '[]'); } catch { _collapsedRaw = []; }
  if (!Array.isArray(_collapsedRaw)) _collapsedRaw = [];
  const collapsed = new Set(_collapsedRaw);

  function saveCollapsed() { try { localStorage.setItem(_COLLAPSE_KEY, JSON.stringify([...collapsed])); } catch { /* quota */ } }

  document.querySelectorAll('section.panel-section').forEach((section, i) => {
    const labelEl = section.querySelector('.section-label:not(.section-label-toggle)');
    if (!labelEl) return;
    const key = String(i);
    const toggle = document.createElement('button');
    toggle.type = 'button';
    toggle.className = 'panel-collapse-btn';
    toggle.setAttribute('aria-label', '折りたたむ');

    function setOpen(open) {
      toggle.textContent = open ? '▼' : '▶';
      section.classList.toggle('panel-section-collapsed', !open);
    }
    setOpen(!collapsed.has(key));

    toggle.addEventListener('click', () => {
      const isOpen = !collapsed.has(key);
      if (isOpen) collapsed.add(key); else collapsed.delete(key);
      saveCollapsed();
      setOpen(!isOpen);
    });

    if (labelEl.parentElement === section) {
      labelEl.style.display = 'flex';
      labelEl.style.justifyContent = 'space-between';
      labelEl.style.alignItems = 'center';
      labelEl.appendChild(toggle);
    }
  });
}

// ── Splash / Welcome Screen ───────────────────────────────────────────────────
function _switchPropTab(tabId) {
  if (window._activatePropTab) window._activatePropTab(tabId);
  document.querySelectorAll('#prop-nav-tabs .panel-nav-tab').forEach(t => {
    t.classList.toggle('is-active', t.dataset.propTab === tabId);
  });
}

function _navigateToSection(targetId, panelId) {
  const section = document.getElementById(targetId);
  if (!section) return;

  // Activate the correct LEFT panel tab if section belongs to one
  const navTab = section.dataset.navTab;
  if (navTab) {
    const tabBtn = document.querySelector(`#asset-panel .panel-nav-tab[data-nav-tab="${navTab}"]`);
    if (tabBtn && !tabBtn.classList.contains('is-active')) tabBtn.click();
  }

  // Activate the correct RIGHT panel tab if section belongs to one
  const propTab = section.dataset.propTab;
  if (propTab) _switchPropTab(propTab);

  // Expand the section if it's collapsed
  if (section.classList.contains('panel-section-collapsed')) {
    const btn = section.querySelector('.panel-collapse-btn');
    btn?.click();
  }

  // Give the tab switch a frame to apply display before scrolling
  requestAnimationFrame(() => {
    section.scrollIntoView({ behavior: 'smooth', block: 'start' });
    section.style.transition = 'outline 0s';
    section.style.outline = '2px solid rgba(91,142,245,0.6)';
    section.style.borderRadius = '6px';
    setTimeout(() => { section.style.outline = 'none'; }, 1200);
  });
}

function _initSplash() {
  const _SPLASH_SKIP_KEY = 'avatar.skipSplash';
  const splash = document.getElementById('splash-screen');
  if (!splash) return;

  // Skip if user opted out — mark as acted so project modal doesn't auto-open
  if ((() => { try { return localStorage.getItem(_SPLASH_SKIP_KEY); } catch { return null; } })() === '1') {
    splash.classList.add('is-hidden');
    window._splashActionTaken = true;
    return;
  }

  const skipCheck = document.getElementById('splash-skip-check');

  function closeSplash() {
    if (skipCheck?.checked) { try { localStorage.setItem(_SPLASH_SKIP_KEY, '1'); } catch { /* ignore */ } }
    splash.style.animation = 'splashFadeOut 0.2s ease forwards';
    setTimeout(() => splash.classList.add('is-hidden'), 200);
  }

  // Tile buttons with target section
  splash.querySelectorAll('.splash-tile[data-splash-target]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const targetId   = btn.dataset.splashTarget;
      const panelId    = btn.dataset.splashPanel;
      const clickAfter = btn.dataset.splashClick;
      window._splashActionTaken = true;
      closeSplash();
      setTimeout(() => {
        closeProjectModal();
        _navigateToSection(targetId, panelId);
        if (clickAfter) document.getElementById(clickAfter)?.click();
      }, 600);
    });
  });

  // Tile buttons with custom action
  splash.querySelectorAll('.splash-tile[data-splash-action]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const action = btn.dataset.splashAction;
      window._splashActionTaken = true;
      closeSplash();
      setTimeout(() => {
        closeProjectModal();
      }, 600);
    });
  });

  // "そのまま始める"
  document.getElementById('splash-start-btn')?.addEventListener('click', () => {
    closeSplash();
    // プロジェクトモーダルが後から開く場合はそちらに任せる
  });

  // "API連携"
  document.getElementById('splash-api-btn')?.addEventListener('click', () => {
    window._splashActionTaken = true;
    closeSplash();
    setTimeout(() => {
      closeProjectModal();
      document.getElementById('api-modal')?.classList.remove('is-hidden');
      document.dispatchEvent(new CustomEvent('api-modal-open'));
    }, 600);
  });

  // Click outside card to close
  splash.addEventListener('click', (e) => { if (e.target === splash) closeSplash(); });
}

function _initMotionModal() {
  const modal = _getMotionModal();
  if (!modal) return;
  document.getElementById('motion-modal-cancel')?.addEventListener('click', () => modal.close());
  document.getElementById('motion-modal-save')?.addEventListener('click', () => {
    const name = (document.getElementById('motion-modal-name')?.value.trim() ?? '').slice(0, 80);
    if (!name) { setStatus('表示名を入力してください'); return; }
    if (modal.dataset.mode === 'edit') {
      const url = modal.dataset.targetUrl;
      const names = _loadCustomNames();
      names[url] = name;
      _saveCustomNames(names);
      _rebuildRuntimeMap();
      modal.close();
      renderMotionLibrary();
      updateMotionDetailUi();
    } else {
      const url = document.getElementById('motion-modal-url')?.value.trim() ?? '';
      if (!url) { setStatus('URLを入力してください'); return; }
      const cat = document.getElementById('motion-modal-cat')?.value ?? 'custom';
      const desc = document.getElementById('motion-modal-desc')?.value.trim() ?? '';
      const id = 'custom_' + Date.now();
      const entry = { id, label: name, displayName: name, url, category: cat, description: desc || undefined };
      const arr = _loadCustomMotions();
      if (arr.some((m) => m.url === url)) { setStatus('同じURLのモーションが既に存在します'); return; }
      arr.push(entry);
      _saveCustomMotions(arr);
      _rebuildRuntimeMap();
      modal.close();
      renderMotionLibrary();
    }
  });
  modal.addEventListener('click', (e) => { if (e.target === modal) modal.close(); });
}

function renderMotionLibrary() {
  if (!motionLibraryEl) {
    return;
  }

  const searchTerm = String(motionSearchInput?.value ?? '').replace(/[<>&"']/g, '').trim().toLowerCase().slice(0, 200);
  const groupedMotions = [..._getFullMotionLibrary()].sort((a, b) => {
    const categoryOrder = motionCategoryOrder(a.category) - motionCategoryOrder(b.category);
    if (categoryOrder !== 0) {
      return categoryOrder;
    }
    return (a.displayName ?? '').localeCompare(b.displayName ?? '', 'ja');
  });

  const matchesSearch = (motion) => {
    if (!searchTerm) {
      return true;
    }
    const haystack = [
      motion.displayName,
      motion.label,
      motion.category,
      basenameFromUrl(motion.url ?? ''),
      ...(motion.tags ?? []),
    ].join(' ').toLowerCase();
    return haystack.includes(searchTerm);
  };

  const recent = motionRecentUrls
    .slice(0, 10)
    .map((url) => _getRuntimeEntry(url))
    .filter(Boolean)
    .filter(matchesSearch);

  if (motionRecentEl) {
    motionRecentEl.innerHTML = '';
    recent.forEach((motion) => {
      const button = document.createElement('button');
      button.type = 'button';
      button.className = 'motion-recent-pill';
      button.dataset.motionUrl = motion.url;
      button.textContent = motion.displayName;
      button.title = `${motion.displayName} [${MOTION_CATEGORY_LABELS[motion.category] ?? motion.category ?? 'custom'}]`;
      if (motion.url === selectedBodyMotionUrl) button.classList.add('is-selected');
      motionRecentEl.appendChild(button);
    });
  }

  // Accordion state: set of collapsed category keys (persisted in localStorage)
  const ACCORDION_KEY = 'avatar.motionAccordion.collapsed';
  let collapsedCats;
  try { collapsedCats = new Set(JSON.parse(localStorage.getItem(ACCORDION_KEY) ?? '[]')); }
  catch { collapsedCats = new Set(); localStorage.removeItem(ACCORDION_KEY); }

  function saveAccordion() {
    try { localStorage.setItem(ACCORDION_KEY, JSON.stringify([...collapsedCats])); } catch { /* ignore */ }
  }

  function buildAccordionSection(key, label, motions) {
    if (motions.length === 0) return null;
    const isOpen = !collapsedCats.has(key);
    const section = document.createElement('section');
    section.className = 'motion-category';

    const heading = document.createElement('button');
    heading.type = 'button';
    heading.className = 'motion-category-heading';
    heading.innerHTML = `<span>${escapeHtml(label)}</span><span class="accordion-chevron">${isOpen ? '▼' : '▶'}</span>`;

    const grid = document.createElement('div');
    grid.className = 'motion-card-grid' + (isOpen ? '' : ' is-collapsed');
    motions.forEach((m) => { const c = createMotionCard(m); if (c) grid.appendChild(c); });

    heading.addEventListener('click', () => {
      const open = !collapsedCats.has(key);
      if (open) collapsedCats.add(key); else collapsedCats.delete(key);
      saveAccordion();
      grid.classList.toggle('is-collapsed', !open);
      const chevron = heading.querySelector('.accordion-chevron');
      if (chevron) chevron.textContent = open ? '▶' : '▼';
    });

    section.appendChild(heading);
    section.appendChild(grid);
    return section;
  }

  const _mlFrag = document.createDocumentFragment();
  if (recent.length > 0) {
    const _recentSection = buildAccordionSection('__recent__', '最近使用', recent);
    if (_recentSection) _mlFrag.appendChild(_recentSection);
  }
  const categories = [...new Set(groupedMotions.map((motion) => motion.category))];
  let totalVisible = 0;
  for (const category of categories) {
    if (category === 'debug') continue;
    const motions = groupedMotions
      .filter((m) => m.category === category)
      .filter(matchesSearch);
    totalVisible += motions.length;
    const s = buildAccordionSection(category, MOTION_CATEGORY_LABELS[category] ?? category, motions);
    if (s) _mlFrag.appendChild(s);
  }
  motionLibraryEl.innerHTML = '';
  motionLibraryEl.appendChild(_mlFrag);

  // 空状態とバッジを更新
  const emptyEl = document.getElementById('motion-empty-state');
  if (emptyEl) {
    const showEmpty = totalVisible === 0 && !recent.length;
    emptyEl.style.display = showEmpty ? '' : 'none';
    if (showEmpty) {
      emptyEl.textContent = searchTerm
        ? `「${searchTerm}」に一致するモーションが見つかりません — 別のキーワードを試してください`
        : 'モーションがありません — VRMAファイルをドロップして追加できます';
    }
  }
  // Search result count display
  const searchCountEl = document.getElementById('motion-search-count');
  if (searchCountEl) {
    searchCountEl.textContent = searchTerm ? `${totalVisible}件ヒット` : '';
    searchCountEl.style.display = searchTerm ? '' : 'none';
  }
  const badgeEl = document.getElementById('motion-count-badge');
  if (badgeEl) {
    const total = groupedMotions.filter((m) => m.category !== 'debug').length;
    badgeEl.textContent = total > 0 ? `${total}件` : '';
    badgeEl.title = `${total}個のモーション`;
  }

  // 選択済みカードをビューポートにスクロールする（検索なし＆選択あり時のみ）
  if (!searchTerm && selectedBodyMotionUrl) {
    const selectedCard = motionLibraryEl.querySelector('.motion-card.is-selected');
    if (selectedCard) {
      // 既に表示範囲内であればスクロールしない
      const cardRect = selectedCard.getBoundingClientRect();
      const libRect = motionLibraryEl.getBoundingClientRect();
      if (cardRect.top < libRect.top || cardRect.bottom > libRect.bottom) {
        selectedCard.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
      }
    }
  }
}

function createMotionCard(motion) {
  if (!motion?.url) return null;
  ensureMotionOption(motion.url, motion.displayName ?? basenameFromUrl(motion.url));

  const card = document.createElement('div');
  card.className = 'motion-card';
  card.dataset.motionUrl = motion.url;

  // Thumbnail (captured screenshot or category emoji)
  const thumbEl = document.createElement('div');
  thumbEl.className = 'motion-card-thumb';
  const catIcon = MOTION_CATEGORY_ICONS[motion.category] ?? MOTION_CATEGORY_ICONS.custom;
  const storedThumb = _loadMotionThumbs()[motion.url];
  if (storedThumb) {
    thumbEl.style.backgroundImage = `url("${storedThumb}")`;
  } else {
    thumbEl.textContent = catIcon.icon;
    thumbEl.style.background = catIcon.bg;
  }

  const playBtn = document.createElement('button');
  playBtn.type = 'button';
  playBtn.className = 'motion-card-play';

  const title = document.createElement('div');
  title.className = 'motion-card-title';
  title.textContent = _getMotionDisplayName(motion);

  const descText = _motionRuntimeMap.get(motion.url)?.description ?? motion.description;

  const meta = document.createElement('div');
  meta.className = 'motion-card-meta';
  meta.textContent = basenameFromUrl(motion.url);

  const chipRow = document.createElement('div');
  chipRow.className = 'motion-card-chips';

  const favoriteChip = document.createElement('span');
  favoriteChip.className = 'motion-chip';
  favoriteChip.textContent = isMotionFavorite(motion.url) ? 'favorite' : 'normal';

  const loopChip = document.createElement('span');
  loopChip.className = 'motion-chip';
  loopChip.textContent = getMotionLoopEnabled(motion.url) ? 'loop' : 'once';

  chipRow.append(favoriteChip, loopChip);

  if (descText) {
    const desc = document.createElement('div');
    desc.className = 'motion-card-desc';
    desc.textContent = descText;
    playBtn.append(title, desc, meta, chipRow);
  } else {
    playBtn.append(title, meta, chipRow);
  }
  card.appendChild(thumbEl);

  // Edit button
  const editBtn = document.createElement('button');
  editBtn.type = 'button';
  editBtn.className = 'motion-card-edit-btn';
  editBtn.title = '名前を編集';
  editBtn.setAttribute('aria-label', `${_getMotionDisplayName(motion)} の名前を編集`);
  editBtn.textContent = '✏';
  editBtn.addEventListener('click', (e) => { e.stopPropagation(); openMotionEditModal(motion); });

  card.append(playBtn, editBtn);

  // Delete button for custom motions
  if (_isCustomMotion(motion.url)) {
    card.classList.add('is-custom');
    const delBtn = document.createElement('button');
    delBtn.type = 'button';
    delBtn.className = 'motion-card-del-btn';
    delBtn.title = '削除';
    delBtn.setAttribute('aria-label', `${_getMotionDisplayName(motion)} を削除`);
    delBtn.textContent = '🗑';
    delBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      if (!confirmDialog(`「${_getMotionDisplayName(motion)}」を削除しますか？`)) return;
      const arr = _loadCustomMotions().filter((m) => m.url !== motion.url);
      _saveCustomMotions(arr);
      _rebuildRuntimeMap();
      renderMotionLibrary();
    });
    card.appendChild(delBtn);
  }

  if (selectedBodyMotionUrl === motion.url) card.classList.add('is-selected');
  if (currentMotionUrl === motion.url) card.classList.add('is-playing');
  if (isMotionFavorite(motion.url)) card.classList.add('is-favorite');

  return card;
}

function updateMotionDetailUi() {
  const motionMeta = selectedMotionMeta ?? motionMetaFromUrl(selectedBodyMotionUrl);
  const _displayName = String(motionMeta?.displayName || basenameFromUrl(selectedBodyMotionUrl) || '未選択').slice(0, 80);
  if (motionDisplayNameEl && motionDisplayNameEl.textContent !== _displayName) {
    motionDisplayNameEl.textContent = _displayName;
  }
  const _catLabel = MOTION_CATEGORY_LABELS[motionMeta.category] ?? motionMeta.category ?? 'custom';
  if (motionCategoryEl && motionCategoryEl.textContent !== _catLabel) {
    motionCategoryEl.textContent = _catLabel;
  }
  if (motionPathEl) {
    motionPathEl.textContent = motionMeta.url || '未選択';
  }
  if (motionFavoriteStateEl) {
    motionFavoriteStateEl.textContent = isMotionFavorite(selectedBodyMotionUrl) ? 'あり' : 'なし';
  }
  if (motionLoopStateEl) {
    motionLoopStateEl.textContent = currentMotionLoopEnabled() ? 'あり' : 'なし';
  }
  if (motionSelectedStateEl) {
    if (!currentMotionUrl) {
      motionSelectedStateEl.textContent = '未読み込み';
    } else if (currentMotionUrl === selectedBodyMotionUrl && currentAction?.paused) {
      motionSelectedStateEl.textContent = '読み込み済み / 未再生';
    } else if (currentMotionUrl === selectedBodyMotionUrl) {
      motionSelectedStateEl.textContent = '再生中';
    } else {
      motionSelectedStateEl.textContent = '選択中';
    }
  }
  if (motionFavoriteEl) {
    motionFavoriteEl.textContent = isMotionFavorite(selectedBodyMotionUrl) ? 'お気に入り解除' : 'お気に入り';
  }
  if (motionLoopEl) {
    motionLoopEl.textContent = currentMotionLoopEnabled() ? 'ループON' : 'ループOFF';
  }
  if (motionPreviewEl) {
    motionPreviewEl.textContent = !currentAction ? '(未ロード)' : currentAction.paused ? 'プレビュー再生' : '再生中';
  }
  if (motionTagListEl) {
    const _tagFrag = document.createDocumentFragment();
    (motionMeta.tags ?? []).slice(0, 20).forEach((tag) => {
      const chip = document.createElement('span');
      chip.className = 'motion-chip';
      chip.textContent = String(tag).slice(0, 30);
      _tagFrag.appendChild(chip);
    });
    motionTagListEl.innerHTML = '';
    motionTagListEl.appendChild(_tagFrag);
  }
}

function renderModelList() {
  if (!modelListEl) {
    return;
  }

  const modelEntries = [];

  const currentCustomLabel = currentModelKey.startsWith('custom:') ? currentModelLabel : '';
  if (currentCustomLabel) {
    modelEntries.push({
      key: currentModelKey,
      label: currentCustomLabel,
      description: currentModelKey,
      action: async () => {
        if (currentModelRoot) {
          updatePlaybackUi();
          return;
        }
      },
    });
  }

  const _mlModelFrag = document.createDocumentFragment();
  modelEntries.forEach((entry) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'model-card';
    button.textContent = entry.label;
    button.title = entry.description || entry.label;
    button.setAttribute('aria-pressed', entry.key === currentModelKey ? 'true' : 'false');
    if (entry.key === currentModelKey) {
      button.classList.add('is-active');
    }
    button.addEventListener('click', () => {
      if (currentModelRoot) {
        selectCurrentModelKey(entry.key, currentModelLabel);
      }
    });
    _mlModelFrag.appendChild(button);
  });
  modelListEl.innerHTML = '';
  modelListEl.appendChild(_mlModelFrag);
}

function selectCurrentModelKey(key, label = currentModelLabel) {
  currentModelKey = key || 'custom';
  currentModelLabel = label || currentModelLabel;
  setStoredString(STORAGE_KEYS.selectedModelKey, currentModelKey);
  updatePlaybackUi();
  renderModelList();
}

function applyModelSettingsFromUi() {
  const _safeNum = (el, fallback) => { const v = Number(el?.value); return Number.isFinite(v) ? v : fallback; };
  currentModelSettings = {
    groundOffset: _safeNum(modelGroundOffsetInput, 0),
    scale: Math.max(0.01, _safeNum(modelScaleInput, 1)),
    yPosition: _safeNum(modelYPositionInput, 0),
    cameraHeight: _safeNum(modelCameraHeightInput, 0),
    rotationY: _safeNum(modelRotationYInput, 0),
    rightFootFix: Boolean(modelRightFootFixInput?.checked),
    notes: String(modelNotesInput?.value ?? ''),
  };
  persistCurrentModelSettings();
  applyModelSettingsToCurrentModel();
  setScenePresetDirty(true);
}

function refreshCurrentModelProfileUi() {
  if (!currentModelKey) return;
  const profile = getModelProfileForKey(currentModelKey);
  if (modelProfileStatusEl) {
    modelProfileStatusEl.textContent = modelProfiles[currentModelKey] ? 'JSON/LocalStorage' : '既定値';
  }
  applyModelProfileToUi(profile);
}

function saveCurrentModelProfile() {
  const profile = collectCurrentModelProfile();
  saveModelProfileOverride(currentModelKey, profile);
  currentModelSettings = profile;
  persistCurrentModelSettings();
  applyModelSettingsToCurrentModel();
  refreshCurrentModelProfileUi();
  setActionLog(`model profile saved: ${currentModelKey}`);
  setStatus(`モデルプロファイルを保存: ${currentModelKey}`);
  setScenePresetDirty(true);
}

function loadCurrentModelProfile() {
  const profile = getModelProfileForKey(currentModelKey);
  currentModelSettings = {
    groundOffset: Number(profile.groundOffset ?? 0) || 0,
    scale: Number(profile.scale ?? 1) || 1,
    yPosition: Number(profile.yPosition ?? 0) || 0,
    cameraHeight: Number(profile.cameraHeight ?? 0) || 0,
    rotationY: Number(profile.rotationY ?? 0) || 0,
    rightFootFix: Boolean(profile.rightFootFix),
    notes: String(profile.notes ?? ''),
  };
  persistCurrentModelSettings();
  applyModelProfileToUi(currentModelSettings);
  applyModelSettingsToCurrentModel();
  setActionLog(`model profile loaded: ${currentModelKey}`);
  setStatus(`モデルプロファイルを読込: ${currentModelKey}`);
  setScenePresetDirty(true);
}

async function exportModelProfiles() {
  const merged = {
    ...modelProfiles,
    [currentModelKey]: collectCurrentModelProfile(),
  };
  const blob = new Blob([`${JSON.stringify(merged, null, 2)}\n`], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = 'model_profiles.json';
  anchor.click();
  window.setTimeout(() => URL.revokeObjectURL(url), 5000);
  setActionLog('model profiles exported');
  setStatus('model_profiles.json を出力しました');
}

function updateActionPollingUi(state) {
  if (!state || typeof state !== 'string') return;
  currentActionPollingState = state;
  updateActionStatusUi(actionSourceEl?.textContent ?? '', new Date());
}

function selectBodyMotion(url, label = basenameFromUrl(url)) {
  const resolvedUrl = sanitizeMotionUrl(url);
  selectedBodyMotionUrl = resolvedUrl;
  selectedMotionMeta = motionMetaFromUrl(resolvedUrl);
  pushRecentMotion(resolvedUrl);
  ensureMotionOption(selectedBodyMotionUrl, label);
  if (bodyMotionSelect) {
    bodyMotionSelect.value = selectedBodyMotionUrl;
  }
  updatePlaybackUi();
  updateMotionDetailUi();
  (window.requestIdleCallback ?? ((fn) => setTimeout(fn, 50)))(renderMotionLibrary);
  setStoredString(STORAGE_KEYS.selectedMotionUrl, selectedBodyMotionUrl);
  setScenePresetDirty(true);
  document.title = label ? `${String(label).slice(0, 60)} — AI Avatar` : 'AI Avatar';
}

function updateStageUi() {
  if (stageFileEl) {
    stageFileEl.textContent = currentStageTextureLabel || currentStageLabel;
  }
  if (stagePresetEl) {
    stagePresetEl.textContent = currentStagePresetName ?? 'custom';
  }
  if (stageBackgroundEl) {
    stageBackgroundEl.textContent = currentStageConfig?.background ?? '標準';
  }
  if (stageFloorStateEl) {
    stageFloorStateEl.textContent = currentStageConfig?.floor.enabled ? '有効' : '無効';
  }
  if (stageLightStateEl) {
    const hemi = currentStageConfig?.hemisphereLight.enabled;
    const directional = currentStageConfig?.directionalLight.enabled;
    stageLightStateEl.textContent = hemi || directional ? '有効' : '無効';
  }
  if (stageLightIntensityEl) {
    const intensity = Number(currentStageConfig?.directionalLight?.intensity ?? 0);
    stageLightIntensityEl.textContent = intensity.toFixed(2);
  }
  if (stageBackgroundInput) {
    stageBackgroundInput.value = currentStageConfig?.background ?? DEFAULT_STAGE_CONFIG.background;
  }
  if (stageFloorToggle) {
    stageFloorToggle.checked = Boolean(currentStageConfig?.floor.enabled);
  }
  if (stageGridToggle) {
    stageGridToggle.checked = Boolean(currentStageConfig?.grid.enabled);
  }
  if (stageLightIntensityInput) {
    stageLightIntensityInput.value = String(currentStageConfig?.directionalLight?.intensity ?? DEFAULT_STAGE_CONFIG.directionalLight.intensity);
  }
  updateSceneStateUi();
}

function updateBodyMotionState() {
  if (!bodyMotionStateEl) return;
  if (typeof selectedBodyMotionUrl !== 'string' || !selectedBodyMotionUrl) {
    bodyMotionStateEl.textContent = '未選択';
    return;
  }
  if (currentMotionUrl !== selectedBodyMotionUrl) {
    bodyMotionStateEl.textContent = '選択中';
    return;
  }
  bodyMotionStateEl.textContent = currentAction?.paused ? '読み込み済み' : '再生中';
}

function updatePlaybackUi() {
  // Update document title with current model name
  if (storyMode) {
    document.title = `[Story] ${currentModelLabel || 'VRM Viewer'}`;
  } else if (currentModelLabel && currentModelLabel !== 'default') {
    document.title = `${currentModelLabel} — VRM Viewer`;
  }
  const selectedMotionLabel = bodyMotionSelect?.selectedOptions[0]?.textContent || basenameFromUrl(selectedBodyMotionUrl);
  if (motionFileEl) {
    motionFileEl.textContent = currentMotionUrl
      ? (currentMotionUrl === selectedBodyMotionUrl ? selectedMotionLabel : basenameFromUrl(currentMotionUrl))
      : '未読み込み';
  }
  if (selectedMotionTrackEl) {
    selectedMotionTrackEl.textContent = selectedMotionLabel;
  }
  if (playbackSpeedSlider) {
    playbackSpeedSlider.value = String(currentPlaybackSpeed);
  }
  if (playbackSpeedValueEl) {
    playbackSpeedValueEl.textContent = `${currentPlaybackSpeed.toFixed(2)}x`;
  }
  if (stopMotionBtn) {
    stopMotionBtn.disabled = !currentAction;
  }
  if (resetMotionBtn) {
    resetMotionBtn.disabled = !currentAction;
  }
  if (modelFileEl) {
    modelFileEl.textContent = currentModelLabel;
  }
  if (modelNameEl) {
    modelNameEl.textContent = currentModelLabel;
  }
  if (modelBlendShapeEl) {
    modelBlendShapeEl.textContent = currentVrm?.blendShapeProxy || currentVrm?.expressionManager ? 'あり' : 'なし';
  }
  if (modelSettingsLabelEl) {
    modelSettingsLabelEl.textContent = currentModelKey;
  }
  if (modelGroundOffsetInput) {
    modelGroundOffsetInput.value = String(currentModelSettings.groundOffset ?? 0);
  }
  if (modelScaleInput) {
    modelScaleInput.value = String(currentModelSettings.scale ?? 1);
  }
  if (modelYPositionInput) {
    modelYPositionInput.value = String(currentModelSettings.yPosition ?? 0);
  }
  if (modelGroundCorrectionEl) {
    modelGroundCorrectionEl.checked = modelGroundCorrectionEnabled;
  }
  if (modelCameraHeightInput) {
    modelCameraHeightInput.value = String(currentModelSettings.cameraHeight ?? 0);
  }
  if (modelRotationYInput) {
    modelRotationYInput.value = String(currentModelSettings.rotationY ?? 0);
  }
  if (modelRightFootFixInput) {
    modelRightFootFixInput.checked = Boolean(currentModelSettings.rightFootFix);
  }
  if (modelNotesInput) {
    modelNotesInput.value = String(currentModelSettings.notes ?? '');
  }
  updateBodyMotionState();
  updateMotionDetailUi();
  // Defer heavy DOM rebuilds to next idle frame to avoid blocking caller
  if (typeof requestIdleCallback !== 'undefined') {
    requestIdleCallback(() => { renderMotionLibrary(); renderModelList(); refreshCurrentModelProfileUi(); }, { timeout: 200 });
  } else {
    setTimeout(() => { renderMotionLibrary(); renderModelList(); refreshCurrentModelProfileUi(); }, 0);
  }
}

function updateActionStatusUi(source, updatedAt = new Date()) {
  if (actionSourceEl) {
    actionSourceEl.textContent = String(source || 'なし').slice(0, 100);
  }
  if (actionUpdatedAtEl) {
    try {
      actionUpdatedAtEl.textContent = updatedAt instanceof Date ? updatedAt.toLocaleTimeString() : '未取得';
    } catch { actionUpdatedAtEl.textContent = '未取得'; }
  }
  if (actionPollingStateEl) {
    actionPollingStateEl.textContent = currentActionPollingState;
  }
  if (actionEmotionEl) {
    actionEmotionEl.textContent = currentActionEmotion || 'なし';
  }
  if (actionSpeechEl) {
    actionSpeechEl.textContent = currentActionSpeech || 'なし';
  }
}

function setActionMotionState(message) {
  if (actionMotionStateEl) {
    actionMotionStateEl.textContent = String(message ?? '').slice(0, 80);
  }
}

function clampNumber(value, min, max) {
  if (!Number.isFinite(Number(value))) return Number.isFinite(min) ? min : 0;
  value = Number(value);
  if (!Number.isFinite(min)) min = -Infinity;
  if (!Number.isFinite(max)) max = Infinity;
  return Math.min(Math.max(value, min), max);
}

function setPlaybackSpeed(speed) {
  const raw = Number(speed);
  speed = Number.isFinite(raw) ? Math.max(0.01, Math.min(10, raw)) : 1;
  const sliderMin = Number(playbackSpeedSlider?.min ?? 0.01);
  const sliderMax = Number(playbackSpeedSlider?.max ?? 3);
  currentPlaybackSpeed = clampNumber(speed, sliderMin || 0.01, sliderMax || 10);
  if (currentAction) {
    currentAction.timeScale = currentPlaybackSpeed;
  }
  updatePlaybackUi();
}

function syncCurrentActionLoopMode() {
  if (!currentAction || !selectedBodyMotionUrl) {
    return;
  }
  const loopEnabled = getMotionLoopEnabled(selectedBodyMotionUrl);
  currentAction.setLoop(loopEnabled ? THREE.LoopRepeat : THREE.LoopOnce, loopEnabled ? Infinity : 1);
  currentAction.clampWhenFinished = !loopEnabled;
}

function normalizeMotionFileUrl(motionFile) {
  if (typeof motionFile !== 'string') {
    return '';
  }
  const trimmed = motionFile.trim();
  if (!trimmed) {
    return '';
  }
  if (/^(https?:)?\/\//.test(trimmed) || trimmed.startsWith('blob:') || trimmed.startsWith('data:')) {
    return trimmed;
  }
  const normalizedPath = trimmed.replace(/^(\.\.?\/)+/, '');
  return normalizedPath.startsWith('/') ? normalizedPath : `/${normalizedPath}`;
}

function normalizeMotionName(motionName) {
  return String(motionName ?? '')
    .trim()
    .toLowerCase()
    .replaceAll('-', '_');
}

function resolveActionMotionUrl(actionConfig = {}) {
  const motionFileUrl = normalizeMotionFileUrl(actionConfig.motion_file);
  if (motionFileUrl) {
    return motionFileUrl;
  }

  const motionName = normalizeMotionName(actionConfig.motion);
  if (motionName && MOTION_NAME_TO_URL.has(motionName)) {
    return MOTION_NAME_TO_URL.get(motionName);
  }

  return '';
}

function applyCameraPreset(presetName) {
  if (!presetName || typeof presetName !== 'string') presetName = DEFAULT_CAMERA_PRESET;
  const aliasedName = resolveCameraPresetName(presetName);
  const resolvedName = CAMERA_PRESETS[aliasedName] ? aliasedName : DEFAULT_CAMERA_PRESET;
  currentCameraPresetName = resolvedName;
  setStoredString(STORAGE_KEYS.cameraPreset, resolvedName);
  applyFrame(resolveCameraPresetFrame(resolvedName));
  applyCameraHeightAdjustment();
  updateCameraPresetButtons();
  setScenePresetDirty(true);
}

function applyCameraConfig(cameraConfig) {
  if (!cameraConfig || typeof cameraConfig !== 'object' && typeof cameraConfig !== 'string') {
    return;
  }
  if (typeof cameraConfig === 'string') {
    applyCameraPreset(cameraConfig);
    return;
  }

  if (cameraConfig.preset) {
    applyCameraPreset(cameraConfig.preset);
  }

  if (cameraConfig.position && cameraConfig.target) {
    currentCameraPresetName = cameraConfig.preset ?? 'custom';
    applyFrame({
      cameraPosition: vectorFromArray(cameraConfig.position, camera.position),
      target: vectorFromArray(cameraConfig.target, controls.target),
      fov: Number.isFinite(Number(cameraConfig.fov)) ? Number(cameraConfig.fov) : camera.fov,
    });
    updateCameraPresetButtons();
  }
}

function readActionSpeed(actionConfig) {
  if (!Object.hasOwn(actionConfig, 'speed') && !Object.hasOwn(actionConfig, 'playback_speed')) {
    return null;
  }
  const speed = Number(actionConfig.speed ?? actionConfig.playback_speed);
  return Number.isFinite(speed) ? speed : null;
}

async function applyActionConfig(actionConfig = {}, options = {}) {
  if (!actionConfig || typeof actionConfig !== 'object' || Array.isArray(actionConfig)) return;

  const applied = [];
  currentActionPollingState = options.pollingState ?? '監視中';
  updateActionStatusUi(actionConfig.source, options.updatedAt ?? new Date());
  currentActionEmotion = String(actionConfig.emotion ?? '').trim();
  currentActionSpeech = String(actionConfig.speech ?? '').trim();
  updateActionStatusUi(actionConfig.source, options.updatedAt ?? new Date());
  setActionLog(`action受信 source=${actionConfig.source || 'なし'} emotion=${currentActionEmotion || 'なし'} speech=${currentActionSpeech || 'なし'}`);
  if (Object.hasOwn(actionConfig, 'emotion')) {
    applyEmotionToFacialState(currentActionEmotion);
  }
  if (Object.hasOwn(actionConfig, 'speech')) {
    applySpeechToFacialState(currentActionSpeech);
  }
  updateFacialUi();

  const speed = readActionSpeed(actionConfig);
  if (speed !== null && speed !== lastActionSpeed) {
    setPlaybackSpeed(speed);
    lastActionSpeed = speed;
    applied.push(`再生速度=${currentPlaybackSpeed.toFixed(2)}`);
  }

  if (Object.hasOwn(actionConfig, 'stage')) {
    const nextStageConfig = mergeStageConfig(actionConfig.stage);
    const nextStageSignature = JSON.stringify(nextStageConfig);
    if (nextStageSignature !== lastActionStageSignature) {
      applyStageConfig(actionConfig.stage);
      lastActionStageSignature = JSON.stringify(currentStageConfig);
      applied.push('ステージ');
    }
  }

  if (Object.hasOwn(actionConfig, 'camera')) {
    const nextCameraSignature = JSON.stringify(actionConfig.camera);
    if (nextCameraSignature !== lastActionCameraSignature) {
      applyCameraConfig(actionConfig.camera);
      lastActionCameraSignature = nextCameraSignature;
      applied.push(`カメラ=${currentCameraPresetName}`);
    }
  }

  if (Object.hasOwn(actionConfig, 'motion') || Object.hasOwn(actionConfig, 'motion_file')) {
    const nextMotionUrl = resolveActionMotionUrl(actionConfig);
    if (nextMotionUrl !== lastActionMotionUrl) {
      lastActionMotionUrl = nextMotionUrl;
      if (!nextMotionUrl) {
        if (currentMotionUrl) {
          clearCurrentAnimation();
          applied.push('モーションファイル=なし');
        }
        setActionMotionState('指定なし');
      } else if (nextMotionUrl !== currentMotionUrl && nextMotionUrl !== loadingMotionUrl) {
        const actionMotionLabel = basenameFromUrl(nextMotionUrl);
        selectBodyMotion(nextMotionUrl, actionMotionLabel);
        await loadMotion(nextMotionUrl, {
          autoPlay: actionAutoPlayEnabled,
          label: actionMotionLabel,
        });
        setActionMotionState(actionAutoPlayEnabled ? 'actionから再生中' : 'actionから読み込み済み / 未再生');
        applied.push(`モーションファイル=${nextMotionUrl}`);
      } else {
        selectBodyMotion(nextMotionUrl, basenameFromUrl(nextMotionUrl));
        setActionMotionState(currentAction?.paused ? 'actionから読み込み済み / 未再生' : 'actionから再生中');
      }
    }
  }

  // render_style: レンダリングスタイルを変更
  if (Object.hasOwn(actionConfig, 'render_style')) {
    const rs = String(actionConfig.render_style ?? '').trim();
    if (rs && rs !== activeRenderStyle) {
      applyRenderStyle(rs);
      applied.push(`スタイル=${rs}`);
    }
  }

  // lipsync: 口パクモードを直接指定 ('talk' | 'neutral' | 'aa' | 'ih' | 'ou')
  if (Object.hasOwn(actionConfig, 'lipsync')) {
    const ls = String(actionConfig.lipsync ?? 'neutral').trim();
    setLipMode(ls);
    if (ls !== 'neutral') applied.push(`口パク=${ls}`);
  }

  // tts: テキストを読み上げ (変化した場合のみ)
  if (Object.hasOwn(actionConfig, 'tts')) {
    const ttsText = String(actionConfig.tts ?? '').trim();
    if (ttsText && ttsText !== (window._lastActionTts ?? '')) {
      window._lastActionTts = ttsText;
      speakText(ttsText, actionConfig.speaker ?? '');
      applied.push(`TTS=${ttsText.slice(0, 20)}`);
    } else if (!ttsText) {
      window._lastActionTts = '';
    }
  }

  if (applied.length > 0) {
    setStatus(`action.json反映: ${applied.join(', ')}`);
  }
}

async function fetchActionConfig() {
  if (!ACTION_JSON_URL) return null;
  if (typeof navigator !== 'undefined' && navigator.onLine === false) return null;
  const response = await fetch(`${ACTION_JSON_URL}?t=${Date.now()}`, {
    cache: 'no-store',
  });
  if (!response.ok) {
    throw new Error(`action.json取得失敗: ${response.status}`);
  }
  let payload;
  try {
    payload = await response.json();
  } catch (e) {
    throw new Error(`action.jsonのパースに失敗: ${e.message}`);
  }
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
    throw new Error('action.jsonのルートはObjectである必要があります');
  }
  return payload;
}

async function pollActionConfig() {
  if (!ACTION_JSON_URL) return;
  if (actionPollInFlight) {
    return;
  }

  actionPollInFlight = true;
  currentActionPollingState = '取得中';
  updateActionStatusUi(actionSourceEl?.textContent ?? '', new Date());
  try {
    const actionConfig = await fetchActionConfig();
    await applyActionConfig(actionConfig, { updatedAt: new Date() });
    currentActionPollingState = '監視中';
  } catch (error) {
    console.error(error);
    currentActionPollingState = 'エラー';
    setActionLog(`action.json監視エラー: ${error.message}`);
    setStatus(`action.json監視エラー: ${error.message}`);
  } finally {
    actionPollInFlight = false;
    updateActionStatusUi(actionSourceEl?.textContent ?? '', new Date());
  }
}

// Ensure love system functions are available
const _loveSystemReady = typeof getRelationship === 'function' && typeof recordTalk === 'function';

function startActionPolling() {
  if (actionPollTimer) {
    window.clearTimeout(actionPollTimer);
    window.clearInterval(actionPollTimer);
    actionPollTimer = null;
  }
  pollActionConfig();
  actionPollTimer = window.setInterval(pollActionConfig, ACTION_POLL_INTERVAL_MS);
}

// ステータスメッセージ表示（エラー・警告は自動タイムアウトせず残る）
let _statusClearTimer = null;
// Ensure status element is accessible
if (statusEl) {
  statusEl.setAttribute('role', 'status');
  statusEl.setAttribute('aria-live', 'polite');
  statusEl.setAttribute('aria-atomic', 'true');
}
function setStatus(message, type = '') {
  if (!message && !type) return;
  if (typeof message !== 'string') message = String(message ?? '');
  if (statusEl) {
    statusEl.classList.remove('status-success', 'status-warn', 'status-error');
    if (type) statusEl.classList.add(`status-${type}`);
  }
  if (message.length > 200) message = message.slice(0, 197) + '…';
  if (!statusEl) return;
  statusEl.textContent = message;
  statusEl.title = message; // Full message on hover for truncated text
  // カラーコーディング
  const isError = type === 'error' || message.startsWith('❌') || message.includes('エラー') || message.startsWith('VRMA読み込み失敗');
  const isWarn  = type === 'warn'  || message.startsWith('⚠');
  const isOk    = type === 'success' || message.startsWith('✅');
  if (isError) statusEl.classList.add('status-error');
  else if (isWarn) statusEl.classList.add('status-warn');
  else if (isOk) statusEl.classList.add('status-success');

  // 通常メッセージは8秒後にクリア、エラーは残す、警告は20秒後クリア
  clearTimeout(_statusClearTimer);
  if (!isError) {
    const delay = isWarn ? 20000 : STATUS_SUCCESS_CLEAR_MS;
    _statusClearTimer = setTimeout(() => {
      if (!statusEl.classList.contains('status-error')) {
        statusEl.classList.remove('status-success', 'status-warn');
        statusEl.textContent = '';
      }
    }, delay);
  }

  logEl.textContent = `${message}\n${logEl.textContent}`.slice(0, 5000);
  setActionLog(message);
}

function clearCurrentAnimation() {
  if (currentAction) {
    currentAction.stop();
    currentAction = null;
  }
  if (currentMixer) {
    currentMixer.stopAllAction();
    if (currentVrm?.scene) {
      try { currentMixer.uncacheRoot(currentVrm.scene); } catch {}
    }
    currentMixer = null;
  }
  _tlCachedTime = -1; _tlCachedDuration = -1; _tlCachedFrame = -1;
  currentMotionUrl = '';
  clearMotionProp();
  updatePlaybackUi();
}

function clearCurrentModel() {
  clearCurrentAnimation();
  // VRM リソースを明示的に解放
  if (currentVrm) {
    try { VRMUtils.deepDispose(currentVrm.scene); } catch {}
  }
  // 古いモデルのblobURLを即座に解放
  if (currentModelSourceUrl?.startsWith('blob:') && objectUrls.has(currentModelSourceUrl)) {
    URL.revokeObjectURL(currentModelSourceUrl);
    objectUrls.delete(currentModelSourceUrl);
  }
  // Reset renderer info for accurate polygon counts
  renderer?.info?.reset?.();
  if (currentModelRoot) {
    scene.remove(currentModelRoot);
    currentModelRoot = null;
  }
  currentVrm = null;
  currentModelFrame = null;
  currentGroundOffset = 0;
  _boneDebugLastHash = ''; // reset bone debug cache
  currentModelBasePosition = new THREE.Vector3(0, 0, 0);
  currentModelBaseScale = 1;
  currentModelSourceUrl = '';
  lastActionMotionUrl = null;
  // 前モデルの表情状態を引き継がないようリップ・フェースをニュートラルに戻す
  facialState.lip.mode = 'neutral';
  facialState.lip.aa = 0;
  facialState.lip.ih = 0;
  facialState.lip.ou = 0;
  facialState.lip.talkPhase = 0;
  facialState.face.mode = 'neutral';
  facialState.face.weight = 0;
  // モデル未読み込み時はカメラプリセットボタンを無効化
  cameraPresetButtons.forEach((btn) => { btn.disabled = true; });
}

function applyFrame(frame) {
  if (!frame || !camera || !controls) return;
  if (!frame.cameraPosition || !frame.target) return;
  if (Array.isArray(frame.cameraPosition) || typeof frame.cameraPosition.x !== 'number') return;
  currentFrame = {
    baseTarget: frame.target.clone(),
    baseCameraPosition: frame.cameraPosition.clone(),
    target: frame.target.clone(),
    cameraPosition: frame.cameraPosition.clone(),
    fov: frame.fov ?? camera.fov,
  };
  camera.fov = currentFrame.fov;
  camera.updateProjectionMatrix();
  camera.position.copy(currentFrame.cameraPosition);
  controls.target.copy(currentFrame.target);
  camera.lookAt(currentFrame.target);
  controls.update();
}

function applyCameraHeightAdjustment() {
  if (!currentModelSettings) return;
  const cameraHeight = Number(currentModelSettings.cameraHeight ?? 0) || 0;
  if (!cameraHeight || !currentFrame) {
    if (currentFrame?.baseTarget && currentFrame?.baseCameraPosition) {
      currentFrame.target = currentFrame.baseTarget.clone();
      currentFrame.cameraPosition = currentFrame.baseCameraPosition.clone();
      camera.position.copy(currentFrame.cameraPosition);
      controls.target.copy(currentFrame.target);
      camera.lookAt(currentFrame.target);
      controls.update();
    }
    return;
  }
  currentFrame.target = currentFrame.baseTarget.clone();
  currentFrame.cameraPosition = currentFrame.baseCameraPosition.clone();
  currentFrame.target.y += cameraHeight;
  currentFrame.cameraPosition.y += cameraHeight;
  camera.position.copy(currentFrame.cameraPosition);
  controls.target.copy(currentFrame.target);
  camera.lookAt(currentFrame.target);
  controls.update();
}

function getLowestWorldY(object3d) {
  if (!object3d || typeof object3d.traverse !== 'function') return 0;
  const bounds = _sharedBox3.setFromObject(object3d);
  if (bounds.isEmpty() || !Number.isFinite(bounds.min.y)) {
    return 0;
  }
  return bounds.min.y;
}

function updateGroundOffset(vrm = currentVrm) {
  if (!vrm?.scene || !modelGroundCorrectionEnabled) {
    return;
  }

  const lowestY = getLowestWorldY(vrm.scene);
  const offset = -lowestY;
  vrm.scene.position.y += offset;
  currentGroundOffset += offset;
}


const _lcEuler = new THREE.Euler();
const _lcQuat  = new THREE.Quaternion();
function applyLiveBoneCorrections() {
  if (!currentVrm?.humanoid || !currentVrm.scene || !currentMotionUrl) return;
  if (!correctionDraft || typeof correctionDraft !== 'object' || !currentMixer) return;
  for (const boneName of CORRECTION_BONE_NAMES) {
    const corr = correctionDraft[boneName];
    if (!corr) continue;
    const { x = 0, y = 0, z = 0 } = corr;
    if (Math.abs(x) < 0.01 && Math.abs(y) < 0.01 && Math.abs(z) < 0.01) continue;
    const node = currentVrm.humanoid.getRawBoneNode(boneName);
    if (!node) continue;
    _lcEuler.set(x * Math.PI / 180, y * Math.PI / 180, z * Math.PI / 180, 'XYZ');
    _lcQuat.setFromEuler(_lcEuler);
    node.quaternion.multiply(_lcQuat);
  }
}

function loadGltf(loader, url, onProgress, signal) {
  if (!loader) return Promise.reject(new Error('GLTFLoaderが未初期化です'));
  if (!url || typeof url !== 'string') return Promise.reject(new Error('URLが指定されていません'));
  if (url.length > 4096) return Promise.reject(new Error('URLが長すぎます'));
  return new Promise((resolve, reject) => {
    if (signal?.aborted) { reject(new DOMException('Aborted', 'AbortError')); return; }
    signal?.addEventListener('abort', () => reject(new DOMException('Aborted', 'AbortError')), { once: true });
    loader.load(url, resolve, onProgress ?? undefined, reject);
  });
}

function createManagedObjectUrl(file) {
  if (!file) return null;
  if (file.size > 0 && file.size > 500 * 1024 * 1024) {
    setStatus(`ファイルが大きすぎます: ${(file.size / 1024 / 1024).toFixed(0)}MB`, 'warn');
  }
  const url = URL.createObjectURL(file);
  objectUrls.add(url);
  return url;
}

function clearStageAsset() {
  if (!currentStageAssetRoot || !scene) return;
  try { scene.remove(currentStageAssetRoot); } catch {}
  try { disposeObject3D(currentStageAssetRoot); } catch {}
  currentStageAssetRoot = null;
  currentStageLabel = '標準ステージ';
  // Force garbage collection hint
  if (renderer) renderer.info.reset?.();
  updateStageUi();
}

// ── Motion-linked prop (chair, table, etc.) ──────────────────────────────────

const propGltfCache = new Map(); // url → GLTF (shared source, clone on use)
const PROP_CACHE_MAX = 5;
function _addToPropCache(url, gltf) {
  if (propGltfCache.size >= PROP_CACHE_MAX) {
    const firstKey = propGltfCache.keys().next().value;
    propGltfCache.delete(firstKey);
  }
  propGltfCache.set(url, gltf);
}

function clearMotionProp() {
  if (!currentPropRoot) return;
  if (scene) scene.remove(currentPropRoot);
  disposeObject3D(currentPropRoot);
  currentPropRoot = null;
  // Remove blob URL if it was a custom prop
  if (currentPropBlobUrl) {
    try { URL.revokeObjectURL(currentPropBlobUrl); } catch {}
    currentPropBlobUrl = null;
  }
}
let currentPropBlobUrl = null;

async function loadMotionProp(propDef) {
  clearMotionProp();
  const url = `/assets/props/${propDef.model}`;
  let gltf = propGltfCache.get(url);
  if (!gltf) {
    gltf = await loadGltf(propLoader, url);
    // LRU制限: 最大5エントリ — 古いものをDISPOSEして削除
    _addToPropCache(url, gltf);
  }
  const root = gltf.scene.clone(true);
  const [px = 0, py = 0, pz = 0] = propDef.position ?? [];
  const [rx = 0, ry = 0, rz = 0] = propDef.rotation ?? [];
  const [sx = 1, sy = 1, sz = 1] = propDef.scale ?? [1, 1, 1];
  root.position.set(px, py, pz);
  root.rotation.set(
    THREE.MathUtils.degToRad(rx),
    THREE.MathUtils.degToRad(ry),
    THREE.MathUtils.degToRad(rz),
  );
  root.scale.set(sx, sy, sz);
  root.traverse((obj) => {
    if (obj.isMesh) { obj.castShadow = true; obj.receiveShadow = true; }
  });
  scene.add(root);
  currentPropRoot = root;
}

async function loadStageAsset(url, label = basenameFromUrl(url)) {
  if (!url) { setStatus('ステージURLが指定されていません', 'warn'); return; }
  clearStageAsset();
  setStatus(`ステージ読み込み中: ${label}`);
  const gltf = await loadGltf(stageLoader, url, (e) => {
    if (e.lengthComputable && e.total > 0) {
      const pct = Math.round((e.loaded / e.total) * 100);
      setStatus(`ステージ読み込み中: ${label} (${pct}%)`);
    }
  });
  currentStageAssetRoot = gltf.scene;
  currentStageAssetRoot.position.set(0, 0, 0);
  applyObjectShadowSettings(currentStageAssetRoot);
  scene.add(currentStageAssetRoot);
  currentStageLabel = label;
  currentStagePresetName = 'custom';
  setStoredString(STORAGE_KEYS.stagePreset, currentStagePresetName);
  updateStageUi();
  setScenePresetDirty(true);
  setStatus(`ステージ読み込み完了: ${label}`);
}

function fixVrmMeshes(vrmScene) {
  if (!vrmScene || typeof vrmScene.traverse !== 'function') return;
  vrmScene.traverse((obj) => {
    if (!obj.isMesh) return;
    // スキンドメッシュのフラスタムカリングを無効化 (バウンディングボックスが不正確)
    obj.frustumCulled = false;

    const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
    for (const mat of mats) {
      if (!mat) continue;
      // 透過マテリアル (BLEND モード) の深度バッファ書き込みを無効化して
      // 半透明部位 (髪・衣服) がボディを隠さないようにする
      const isBlend = mat.transparent || mat.alphaMode === 'BLEND';
      if (isBlend) {
        mat.depthWrite = false;
        if (!obj.renderOrder || obj.renderOrder === 0) obj.renderOrder = 1;
      }
    }
  });
}

function normalizeRawGlbModel(root, sourceUrl) {
  // マテリアル品質向上
  enhanceGltfTextures(root);

  // 透過マテリアルのフラスタムカリング・深度書き込み修正
  root.traverse((obj) => {
    if (!obj.isMesh) return;
    obj.frustumCulled = false;
    const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
    for (const mat of mats) {
      if (!mat) continue;
      if (mat.transparent || mat.alphaMode === 'BLEND') {
        mat.depthWrite = false;
        if (obj.renderOrder === 0) obj.renderOrder = 1;
      }
    }
  });

  // バウンディングボックスで中央化・自動スケール
  const box = new THREE.Box3().setFromObject(root);
  const size = box.getSize(new THREE.Vector3());
  const center = box.getCenter(new THREE.Vector3());
  const maxDim = Math.max(size.x, size.y, size.z, 0.001);
  if (!Number.isFinite(maxDim) || maxDim <= 0) { console.warn('[normalizeRawGlbModel] bad bbox'); return; }
  const targetScale = Math.min(10, 1.6 / maxDim);

  root.position.x -= center.x * targetScale;
  root.position.z -= center.z * targetScale;
  root.position.y -= box.min.y * targetScale; // 足元を床に合わせる
  root.scale.setScalar(targetScale);

  scene.add(root);
  currentModelRoot = root;
  _updateOutlineSelection();
  currentModelBasePosition = root.position.clone();
  currentModelBaseScale = targetScale;
  currentModelSourceUrl = sourceUrl;
  currentModelLabel = basenameFromUrl(sourceUrl);
  currentModelKey = sourceUrl === MODEL_GLB
    ? 'default_glb'
    : sourceUrl === MODEL_VRM
      ? 'default_vrm'
      : `custom:${normalizeModelKey(currentModelLabel || sourceUrl)}`;
  setStoredString(STORAGE_KEYS.selectedModelKey, currentModelKey);
  applyObjectShadowSettings(root);
  currentModelSettings = getModelSettingsForKey(currentModelKey);
  applyModelSettingsToCurrentModel();
  currentModelFrame = measureObjectFrame(root);
  applyCameraPreset(currentCameraPresetName);
  updatePlaybackUi();
  document.getElementById('viewport-empty')?.classList.add('is-hidden');
  setStatus(`GLBモデル読み込み完了: ${currentModelLabel}`);
  setScenePresetDirty(true);
  logBoneDebugSnapshot(`model load ${currentModelLabel}`);
  if (typeof loveShowOverlay === 'function') loveShowOverlay();
}

function normalizeLoadedModel(gltf, sourceUrl) {
  if (!gltf || !gltf.userData) return null;
  const vrm = gltf.userData.vrm ?? null;
  if (!vrm) {
    return null;
  }

  VRMUtils.removeUnnecessaryJoints(vrm.scene);
  fixVrmMeshes(vrm.scene);

  const box = new THREE.Box3().setFromObject(vrm.scene);
  const size = box.getSize(new THREE.Vector3());
  const center = box.getCenter(new THREE.Vector3());
  const maxDim = Math.max(size.x, size.y, size.z) || 1;
  if (!Number.isFinite(maxDim) || maxDim <= 0) {
    console.warn('[normalizeLoadedModel] invalid bounding box');
    return null;
  }

  vrm.scene.position.x -= center.x;
  vrm.scene.position.y -= center.y;
  vrm.scene.position.z -= center.z;
  currentModelBaseScale = 1.6 / maxDim;
  vrm.scene.scale.setScalar(currentModelBaseScale);
  vrm.scene.position.y += 0.05;
  currentModelBasePosition = vrm.scene.position.clone();

  scene.add(vrm.scene);
  currentVrm = vrm;
  currentModelRoot = vrm.scene;
  _updateOutlineSelection();
  currentModelSourceUrl = sourceUrl;
  updateGroundOffset(vrm);
  applyObjectShadowSettings(vrm.scene);
  // VRMメタデータがあればモデル名として使用（VRM1.0: meta.name / VRM0.x: meta.title）
  const vrmMetaName = vrm.meta?.name || vrm.meta?.title || '';
  currentModelLabel = vrmMetaName || basenameFromUrl(sourceUrl);
  currentModelKey = sourceUrl === MODEL_GLB
    ? 'default_glb'
    : sourceUrl === MODEL_VRM
      ? 'default_vrm'
      : `custom:${normalizeModelKey(currentModelLabel || sourceUrl)}`;
  setStoredString(STORAGE_KEYS.selectedModelKey, currentModelKey);
  currentModelSettings = getModelSettingsForKey(currentModelKey);
  applyModelSettingsToCurrentModel();
  currentModelFrame = measureObjectFrame(vrm.scene);
  applyCameraPreset(currentCameraPresetName);
  updatePlaybackUi();
  // モデル読み込み後はカメラプリセットボタンを有効化
  cameraPresetButtons.forEach((btn) => { btn.disabled = false; });
  setStatus(`VRMモデル読み込み完了: ${currentModelLabel}`);
  document.title = `${currentModelLabel} — AI Avatar`;
  logBoneDebugSnapshot(`model load ${currentModelLabel}`);
  // こいカツ: モデルロード時にオーバーレイを表示
  loveShowOverlay();
  return vrm;
}

function applyModelSettingsToCurrentModel() {
  if (!currentModelRoot) {
    return;
  }
  if (!currentModelSettings || typeof currentModelSettings !== 'object') return;
  const rawScale = Number(currentModelSettings.scale ?? 1);
  const scale = (Number.isFinite(rawScale) && rawScale > 0) ? Math.max(0.001, Math.min(100, rawScale)) : 1;
  const groundOffset = Number(currentModelSettings.groundOffset ?? 0) || 0;
  const yPosition = Number(currentModelSettings.yPosition ?? 0) || 0;
  const rotationY = Number(currentModelSettings.rotationY ?? 0) || 0;
  currentModelRoot.position.copy(currentModelBasePosition);
  if (modelGroundCorrectionEnabled) {
    currentModelRoot.position.y += currentGroundOffset;
  }
  currentModelRoot.position.y += groundOffset + yPosition;
  currentModelRoot.scale.setScalar(currentModelBaseScale * scale * (charamakeBodyParams.heightScale ?? 1));
  currentModelRoot.rotation.y = THREE.MathUtils.degToRad(rotationY);
  if (currentVrm?.scene === currentModelRoot) {
    currentVrm.scene.updateMatrixWorld(true);
  }
  currentModelFrame = measureObjectFrame(currentModelRoot);
  applyCameraPreset(currentCameraPresetName);
  updatePlaybackUi();
}

async function loadModel(url, fallbackUrl = null) {
  clearCurrentModel();
  currentModelSourceUrl = url;
  setStatus(`モデル読み込み中: ${basenameFromUrl(url)}`);

  const _modelBase = basenameFromUrl(url);
  let gltf;
  try {
    gltf = await loadGltf(gltfLoader, url, (e) => {
      if (e.lengthComputable && e.total > 0 && e.loaded <= e.total) {
        const pct = Math.round((e.loaded / e.total) * 100);
        setStatus(`モデル読み込み中: ${_modelBase} (${pct}%)`);
      }
    });
  } catch (e) {
    setStatus(`モデル読み込み失敗: ${_modelBase} — ${e.message}`, 'error');
    throw e;
  }
  const vrm = normalizeLoadedModel(gltf, url);

  if (vrm) {
    document.getElementById('viewport-empty')?.classList.add('is-hidden');
    setScenePresetDirty(true);
    return vrm;
  }

  if (fallbackUrl) {
    setStatus(`VRM拡張が見つからないため標準VRMへ切り替えます: ${basenameFromUrl(fallbackUrl)}`);
    setActionLog(`model fallback: ${basenameFromUrl(url)} -> ${basenameFromUrl(fallbackUrl)}`);
    return loadModel(fallbackUrl, null);
  }

  normalizeRawGlbModel(gltf.scene, url);
  return null;
}

// ---- motion bone correction (manual, per-URL, stored in localStorage) ----

const CORRECTION_BONE_NAMES = ['hips', 'leftUpperLeg', 'rightUpperLeg', 'leftLowerLeg', 'rightLowerLeg', 'leftFoot', 'rightFoot', 'leftToes', 'rightToes'];

// CMU mocap ベースのウォークモーションはリターゲット後に足首ピッチがずれる。
// ユーザーが補正を保存していない場合のデフォルト補正値 (°)。
const MOTION_DEFAULT_CORRECTIONS = {
  '/assets/motions_vrma/walk/walk.vrma': {
    leftFoot: { x: -8, y: 0, z: 0 },
    rightFoot: { x: -8, y: 0, z: 0 },
  },
  '/assets/motions_vrma/debug/walk_bad_foot.vrma': {
    leftFoot: { x: -8, y: 0, z: 0 },
    rightFoot: { x: -8, y: 0, z: 0 },
  },
};
const CORRECTION_BONE_LABELS = {
  hips: '腰', leftUpperLeg: '左脚', rightUpperLeg: '右脚', leftFoot: '左足首', rightFoot: '右足首',
};

let selectedCorrectionBone = 'hips';
let correctionDraft = {};

const correctionRaycaster = new THREE.Raycaster();
let correctionPointerDownPos = null;

function getAllMotionCorrections() {
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEYS.motionCorrections) || '{}');
  } catch { return {}; }
}

function getMotionCorrections(url) {
  return getAllMotionCorrections()[url] ?? {};
}

function saveMotionCorrections(url, corrections) {
  const all = getAllMotionCorrections();
  all[url] = corrections;
  try { localStorage.setItem(STORAGE_KEYS.motionCorrections, JSON.stringify(all)); } catch { /* ignore */ }
}

function clearMotionCorrections(url) {
  const all = getAllMotionCorrections();
  delete all[url];
  try { localStorage.setItem(STORAGE_KEYS.motionCorrections, JSON.stringify(all)); } catch { /* ignore */ }
}

function applyBoneCorrection(track, xDeg, yDeg, zDeg) {
  if (!track?.values?.length || track.values.length % 4 !== 0) return;
  if (!Number.isFinite(xDeg) || !Number.isFinite(yDeg) || !Number.isFinite(zDeg)) return;
  const _bcEuler = new THREE.Euler(xDeg * Math.PI / 180, yDeg * Math.PI / 180, zDeg * Math.PI / 180, 'XYZ');
  const q = new THREE.Quaternion().setFromEuler(_bcEuler);
  const ax = q.x, ay = q.y, az = q.z, aw = q.w;
  const count = track.values.length / 4;
  for (let i = 0; i < count; i++) {
    const bx = track.values[i * 4];
    const by = track.values[i * 4 + 1];
    const bz = track.values[i * 4 + 2];
    const bw = track.values[i * 4 + 3];
    track.values[i * 4]     = aw * bx + ax * bw + ay * bz - az * by;
    track.values[i * 4 + 1] = aw * by - ax * bz + ay * bw + az * bx;
    track.values[i * 4 + 2] = aw * bz + ax * by - ay * bx + az * bw;
    track.values[i * 4 + 3] = aw * bw - ax * bx - ay * by - az * bz;
  }
}

function selectCorrectionBone(boneName) {
  if (!boneName || typeof boneName !== 'string') return;
  selectedCorrectionBone = boneName;
  // タブのアクティブ状態を更新
  for (const tab of document.querySelectorAll('.correction-tab')) {
    tab.classList.toggle('is-active', tab.dataset.bone === boneName);
  }
  // スライダーと数値入力を現在のdraft値で更新
  const boneCorr = correctionDraft[boneName] ?? { x: 0, y: 0, z: 0 };
  for (const axis of ['x', 'y', 'z']) {
    const val = boneCorr[axis] ?? 0;
    const slider = document.querySelector(`.correction-slider[data-axis="${axis}"]`);
    const num = document.querySelector(`.correction-num[data-axis="${axis}"]`);
    if (slider) slider.value = val;
    if (num) num.value = val;
  }
}

function updateCorrectionUi() {
  const url = currentMotionUrl || '';
  const nameEl = document.querySelector('#correction-motion-name');
  if (nameEl) nameEl.textContent = url ? basenameFromUrl(url).slice(0, 80) : '未選択';
  if (url) {
    const userCorr = getMotionCorrections(url);
    const hasUser = Object.keys(userCorr).length > 0;
    const defaults = !hasUser ? (MOTION_DEFAULT_CORRECTIONS[url] ?? {}) : {};
    correctionDraft = JSON.parse(JSON.stringify({ ...defaults, ...userCorr }));
  } else {
    correctionDraft = {};
  }
  selectCorrectionBone(selectedCorrectionBone);
}

function showCorrectionPopup(clientX, clientY) {
  const popup = document.querySelector('#correction-popup');
  if (!popup) return;
  const saved = readStoredJson(STORAGE_KEYS.correctionPopupPos, null);
  if (saved?.x != null && saved?.y != null) {
    const vw = window.innerWidth, vh = window.innerHeight;
    const pw = popup.offsetWidth || 290, ph = popup.offsetHeight || 240;
    popup.style.left = `${Math.max(0, Math.min(saved.x, vw - pw))}px`;
    popup.style.top = `${Math.max(0, Math.min(saved.y, vh - ph))}px`;
  } else {
    const W = 290, H = 240;
    const vw = window.innerWidth, vh = window.innerHeight;
    let px = clientX + 18;
    let py = clientY - 30;
    if (px + W > vw - 10) px = clientX - W - 18;
    if (py + H > vh - 10) py = vh - H - 10;
    if (py < 10) py = 10;
    popup.style.left = `${Math.max(10, px)}px`;
    popup.style.top = `${py}px`;
  }
  popup.style.right = 'auto';
  popup.style.bottom = 'auto';
  popup.classList.remove('is-hidden');
}

function hideCorrectionPopup() {
  document.querySelector('#correction-popup')?.classList.add('is-hidden');
}

function pickBoneFromCanvas(e) {
  // drag threshold guard
  if (correctionPointerDownPos) {
    const dx = e.clientX - correctionPointerDownPos.x;
    const dy = e.clientY - correctionPointerDownPos.y;
    if (Math.sqrt(dx * dx + dy * dy) > 5) return;
  }
  const rect = canvas.getBoundingClientRect();
  const nx = ((e.clientX - rect.left) / rect.width) * 2 - 1;
  const ny = -((e.clientY - rect.top) / rect.height) * 2 + 1;
  const ndc = new THREE.Vector2(nx, ny);

  // 1. Hotspot priority (always active)
  const hotspotMeshes = hotspots.map(h => h.mesh).filter(Boolean);
  if (hotspotMeshes.length > 0) {
    stageRaycaster.setFromCamera(ndc, camera);
    const hsHits = stageRaycaster.intersectObjects(hotspotMeshes, false);
    if (hsHits.length > 0) {
      const hs = hotspots.find(h => h.mesh === hsHits[0].object);
      if (hs) { activateHotspot(hs).catch((e) => setStatus(`ホットスポット失敗: ${e.message}`)); return; }
    }
  }

  // 2. Floor click → walk-to (only when move mode is on)
  if (stageInteractMoveEnabled && currentModelRoot) {
    stageRaycaster.setFromCamera(ndc, camera);
    const floorHits = stageRaycaster.intersectObject(floorRayPlane, false);
    if (floorHits.length > 0) {
      const pt = floorHits[0].point;
      startMoveTo(pt.x, pt.z);
      return;
    }
  }

  // 3. Bone picking → correction popup (requires VRM)
  if (!currentVrm) return;
  correctionRaycaster.setFromCamera(ndc, camera);
  const meshes = [];
  currentVrm.scene.traverse(obj => { if (obj.isSkinnedMesh || obj.isMesh) meshes.push(obj); });
  const hits = correctionRaycaster.intersectObjects(meshes, false);
  if (hits.length === 0) return;
  const point = hits[0].point;
  let nearest = null;
  let nearestDist = Infinity;
  for (const boneName of CORRECTION_BONE_NAMES) {
    const node = currentVrm.humanoid?.getNormalizedBoneNode(boneName);
    if (!node) continue;
    const bonePos = new THREE.Vector3();
    node.getWorldPosition(bonePos);
    const dist = bonePos.distanceTo(point);
    if (dist < nearestDist) { nearestDist = dist; nearest = boneName; }
  }
  if (nearest) {
    selectCorrectionBone(nearest);
    showCorrectionPopup(e.clientX, e.clientY);
  }
}

// ---- end motion bone correction ----

function sanitizeClipTracks(clip, vrm, url) {
  if (!clip || !Array.isArray(clip.tracks)) return;
  // CMU mocap など、hips の Y 回転が forward (-Z) からずれている VRMA を補正する。
  // 最初の非レストポーズフレームの Y 成分を測定し、そのバイアスを全フレームから除去。
  const hipsNodeName = vrm?.humanoid?.getNormalizedBoneNode('hips')?.name;
  const leftUpperLegName = vrm?.humanoid?.getNormalizedBoneNode('leftUpperLeg')?.name;
  const rightUpperLegName = vrm?.humanoid?.getNormalizedBoneNode('rightUpperLeg')?.name;
  if (hipsNodeName) {
    const hipsQuatTrack = clip.tracks.find((t) => t.name === `${hipsNodeName}.quaternion`);
    if (hipsQuatTrack && hipsQuatTrack.values.length >= 8) {
      let biasY = 0, biasW = 1;
      for (let i = 0; i < hipsQuatTrack.values.length / 4; i++) {
        const bx = hipsQuatTrack.values[i * 4];
        const by = hipsQuatTrack.values[i * 4 + 1];
        const bz = hipsQuatTrack.values[i * 4 + 2];
        if (Math.sqrt(bx * bx + by * by + bz * bz) > 0.05) {
          biasY = by;
          biasW = hipsQuatTrack.values[i * 4 + 3];
          break;
        }
      }
      if (Math.abs(biasY) > 0.1) {
        // Y-twist の共役で補正: (0, -biasY, 0, biasW) normalized
        const mag = Math.sqrt(biasY * biasY + biasW * biasW);
        const ay = -biasY / mag;
        const aw = biasW / mag;
        const count = hipsQuatTrack.values.length / 4;
        for (let i = 0; i < count; i++) {
          const bx = hipsQuatTrack.values[i * 4];
          const by = hipsQuatTrack.values[i * 4 + 1];
          const bz = hipsQuatTrack.values[i * 4 + 2];
          const bw = hipsQuatTrack.values[i * 4 + 3];
          if (Math.sqrt(bx * bx + by * by + bz * bz) < 0.01) continue; // rest pose はスキップ
          // (0, ay, 0, aw) * (bx, by, bz, bw)
          hipsQuatTrack.values[i * 4]     = aw * bx + ay * bz;
          hipsQuatTrack.values[i * 4 + 1] = aw * by + ay * bw;
          hipsQuatTrack.values[i * 4 + 2] = aw * bz - ay * bx;
          hipsQuatTrack.values[i * 4 + 3] = aw * bw - ay * by;
        }
      }
    }
  }

  const validTracks = [];
  for (const track of clip.tracks) {
    if (!track || typeof track.name !== 'string' || !track.times?.length || !track.values?.length) continue;
    if (track.name.endsWith('.position')) {
      let hasInvalid = false;
      for (let i = 0; i < track.values.length; i++) {
        if (!isFinite(track.values[i])) {
          hasInvalid = true;
          break;
        }
      }
      if (hasInvalid) {
        // VRMA の restHipsPosition.y=0 によるゼロ除算 → NaN/Infinity
        // → このトラックを除外してin-place再生にフォールバック
        console.warn(`[loadMotion] 無効なpositionトラックをスキップ (NaN/Inf): ${track.name}`);
        continue;
      }
      // ルートモーション(X/Z)を除去してin-place化。Y(上下)は保持。
      const count = track.values.length / 3;
      for (let i = 0; i < count; i++) {
        track.values[i * 3] = 0;
        track.values[i * 3 + 2] = 0;
      }
    }
    // quaternionトラックのNaN/Inf検証（不正クォータニオンは単位クォータニオンに置換）
    if (track.name.endsWith('.quaternion') && track.values?.length) {
      const count = Math.floor(track.values.length / 4);
      for (let i = 0; i < count; i++) {
        const base = i * 4;
        const x = track.values[base], y = track.values[base+1], z = track.values[base+2], w = track.values[base+3];
        if (!isFinite(x) || !isFinite(y) || !isFinite(z) || !isFinite(w)) {
          track.values[base] = 0; track.values[base+1] = 0; track.values[base+2] = 0; track.values[base+3] = 1;
        }
      }
    }
    validTracks.push(track);
  }
  clip.tracks = validTracks;

  // 補正はトラックに焼き込まず、毎フレームのapplyLiveBoneCorrections()で適用する
}

async function loadMotion(url, options = {}) {
  const { autoPlay = false, label: _rawLabel } = options;
  const _resolvedRaw = _rawLabel ?? basenameFromUrl(url);
  const label = String(_resolvedRaw).replace(/[<>&"]/g, '').slice(0, 80) || basenameFromUrl(url) || url.slice(-40);
  if (motionLibraryEl) motionLibraryEl.setAttribute('data-loading', '1');
  if (!currentVrm) {
    if (motionLibraryEl) motionLibraryEl.removeAttribute('data-loading');
    setStatus('VRMモデルが未読み込みのためVRMAを適用できません', 'warn');
    return;
  }

  const myGen = ++_motionLoadGen;
  loadingMotionUrl = url;
  clearCurrentAnimation();
  setStatus(`VRMA読み込み中: ${label}`);

  try {
    const gltf = await loadGltf(vrmaLoader, url, (e) => {
      if (e.lengthComputable && e.total > 0 && myGen === _motionLoadGen) {
        const pct = Math.round((e.loaded / e.total) * 100);
        setStatus(`VRMA読み込み中: ${label} (${pct}%)`);
      }
    });
    if (myGen !== _motionLoadGen) return; // 新しいロードが開始されたためキャンセル
    const vrmAnimation = gltf.userData.vrmAnimation ?? gltf.userData.vrmAnimations?.[0];

    if (!vrmAnimation) {
      throw new Error(`VRMAアニメーションが見つかりません: ${label}`);
    }

    const clip = createVRMAnimationClip(vrmAnimation, currentVrm);
    if (!clip) throw new Error(`アニメーションクリップの作成に失敗しました: ${label}`);
    if (clip.tracks) sanitizeClipTracks(clip, currentVrm, url);
    const mixer = new THREE.AnimationMixer(currentVrm.scene);
    const action = mixer.clipAction(clip);
    action.reset();
    const loopEnabled = getMotionLoopEnabled(url);
    action.setLoop(loopEnabled ? THREE.LoopRepeat : THREE.LoopOnce, loopEnabled ? Infinity : 1);
    action.clampWhenFinished = !loopEnabled;
    action.timeScale = currentPlaybackSpeed;
    action.paused = !autoPlay;
    action.play();

    currentMixer = mixer;
    currentAction = action;
    currentMotionUrl = url;
    _tlCachedTime = -1; _tlCachedDuration = -1; _tlCachedFrame = -1; // reset dirty cache
    pushRecentMotion(url);
    selectBodyMotion(url, label);
    if (!_loadMotionThumbs()[url]) captureMotionThumb(url);
    updatePlaybackUi();
    updateCorrectionUi();
    setScenePresetDirty(true);
    { const entry = MOTION_URL_TO_ENTRY.get(url);
      if (entry?.prop) loadMotionProp(entry.prop).catch((e) => setStatus(`プロップ読み込み失敗: ${e.message}`));
      else clearMotionProp(); }
    if (motionLibraryEl) motionLibraryEl.removeAttribute('data-loading');
    setStatus(`${autoPlay ? '再生中' : 'VRMA読み込み完了'}: ${label}`);
    logBoneDebugSnapshot(`motion load ${label}`);
    if (url === MOTION_VRMA || basenameFromUrl(url).toLowerCase().includes('walk')) {
      setTimeout(() => {
        if (currentMotionUrl === url) {
          logBoneDebugSnapshot(`motion sample ${label} +1s`);
        }
      }, 1000);
    }
    return null;
  } catch (error) {
    console.error(error);
    setActionLog(`VRMA読み込み失敗: ${label} (${error.message})`);
    setStatus(`VRMA読み込み失敗: ${label}`);
    // 失敗時にmixer/actionが中途半端な状態で残らないよう確実にクリア
    if (currentMixer && !currentAction) {
      currentMixer.stopAllAction();
      currentMixer = null;
    }
    if (motionLibraryEl) motionLibraryEl.removeAttribute('data-loading');
    throw error;
  } finally {
    loadingMotionUrl = '';
    if (motionLibraryEl) motionLibraryEl.removeAttribute('data-loading');
  }
}

async function loadDefaultScene() {
  // 標準モデルは自動ロードしない。カスタムモデルのみ復元する。
  try {
    const preferredModelKey = getStoredString(STORAGE_KEYS.selectedModelKey, '');
    if (!preferredModelKey || typeof preferredModelKey !== 'string' || !preferredModelKey.startsWith('custom:')) return;
    if (!selectedBodyMotionUrl || typeof selectedBodyMotionUrl !== 'string') return;
    await loadMotion(selectedBodyMotionUrl, { autoPlay: false });
  } catch (error) {
    console.error(error);
    setActionLog(`default scene load failed: ${error.message}`);
    setStatus(`デフォルトシーン読み込み失敗: ${error.message}`, 'error');
  }
}

async function playSelectedBodyMotion() {
  charMoving = false;
  charMoveTarget = null;
  if (!selectedBodyMotionUrl || selectedBodyMotionUrl.length > 2048) {
    setStatus('再生するbody motionを選択してください');
    return;
  }
  if (!currentVrm) {
    setStatus('VRMモデルが未読み込みです。先にモデルを読み込んでください', 'warn');
    return;
  }

  if (!currentAction || currentMotionUrl !== selectedBodyMotionUrl) {
    await loadMotion(selectedBodyMotionUrl, {
      autoPlay: true,
      label: basenameFromUrl(selectedBodyMotionUrl),
    });
    return;
  }

  syncCurrentActionLoopMode();
  currentAction.paused = false;
  currentAction.play();
  updatePlaybackUi();
  setStatus(`再生中: ${basenameFromUrl(currentMotionUrl)}`);
}

function stopPlayback() {
  if (!currentAction) return;
  currentAction.paused = true;
  updatePlaybackUi();
  updateTimelineUi();
  const label = currentMotionUrl ? basenameFromUrl(currentMotionUrl) : (currentAction?.getClip()?.name ?? 'アニメーション');
  setStatus(`⏸ 停止: ${label}`);
  // Also stop camera anim if running
  if (camAnimPlaying && controls) { camAnimPlaying = false; controls.enabled = true; }
}

function resetPlayback() {
  if (!currentAction) return;
  const _resetLabel = basenameFromUrl(currentMotionUrl) || 'アニメーション';
  currentAction.stop();
  currentAction.reset();
  currentAction.paused = true;
  if (currentMixer) currentMixer.update(0);
  if (currentVrm) currentVrm.update(0);
  _tlCachedTime = -1;
  updatePlaybackUi();
  updateTimelineUi();
  setStatus(`⏮ 先頭に戻りました: ${_resetLabel}`);
}

function getClipFps(clip) {
  if (!clip?.tracks?.length) return 30;
  if (!Number.isFinite(clip.duration) || clip.duration <= 0) return 30;
  let bestFps = 0;
  for (const track of clip.tracks) {
    if (!track?.times || track.times.length < 2) continue;
    for (let i = 1; i < track.times.length && i < 20; i++) {
      const dt = track.times[i] - track.times[i - 1];
      if (dt > 0.001 && dt < 1) {
        const fps = 1 / dt;
        if (fps > bestFps) bestFps = fps;
        break;
      }
    }
  }
  return bestFps > 0 ? Math.min(120, Math.round(bestFps)) : 30;
}

function seekToTime(t) {
  if (!currentAction || !currentMixer) return;
  if (!Number.isFinite(t)) return;
  const clip = currentAction.getClip();
  if (!clip) return;
  const clamped = Math.max(0, Math.min(clip.duration, t));
  const wasPaused = currentAction.paused;
  // Re-enable if action was stopped at end due to clampWhenFinished
  if (!currentAction.isRunning() && !currentAction.paused) {
    currentAction.reset();
    currentAction.paused = true;
  }
  currentAction.time = clamped;
  currentAction.paused = false;
  currentMixer.update(0);
  if (currentVrm) currentVrm.update(0);
  currentAction.paused = wasPaused;
  // Force expression update after seek
  if (currentVrm?.expressionManager) {
    try { currentVrm.expressionManager.update(); } catch {}
  }
  updateTimelineUi();
}

function stepFrame(direction) {
  if (!currentAction) return;
  const clip = currentAction.getClip();
  if (!clip) return;
  const fps = getClipFps(clip);
  const next = Math.max(0, Math.min(clip.duration, currentAction.time + direction / fps));
  if (!currentAction.paused) {
    currentAction.paused = true;
    updatePlaybackUi();
  }
  seekToTime(next);
  const curFrame = Math.floor(next * fps);
  const totalFrames = Math.floor(clip.duration * fps);
  setStatus(`フレーム: ${curFrame} / ${totalFrames} (${next.toFixed(3)}s)`);
}

function updateTimelineUi() {
  if (!currentAction) {
    if (_tlCachedTime !== -1) {
      _tlCachedTime = -1; _tlCachedDuration = -1; _tlCachedFrame = -1;
      if (tlScrubber) { tlScrubber.value = '0'; tlScrubber.disabled = true; }
      if (tlCurrentTimeEl) tlCurrentTimeEl.textContent = '0.000';
      if (tlDurationEl) tlDurationEl.textContent = '0.000';
      if (tlFrameNumEl) tlFrameNumEl.textContent = '0';
      if (tlFrameTotalEl) tlFrameTotalEl.textContent = '0';
    }
    return;
  }
  const clip = currentAction.getClip();
  const duration = clip.duration;
  const current = Math.max(0, Math.min(duration, currentAction.time));
  const fps = getClipFps(clip);
  const frame = Math.floor(current * fps);
  // Skip DOM updates when nothing changed (60fps optimization)
  if (Math.abs(current - _tlCachedTime) < 0.001 && duration === _tlCachedDuration && frame === _tlCachedFrame) return;
  _tlCachedTime = current;
  _tlCachedDuration = duration;
  _tlCachedFrame = frame;
  if (tlScrubber && !isScrubbing) {
    tlScrubber.disabled = false;
    tlScrubber.value = duration > 0 ? String(Math.round((current / duration) * 1000)) : '0';
  }
  if (tlCurrentTimeEl) tlCurrentTimeEl.textContent = current.toFixed(3);
  if (tlDurationEl) tlDurationEl.textContent = duration.toFixed(3);
  if (tlFrameNumEl) tlFrameNumEl.textContent = String(frame);
  if (tlFrameTotalEl) tlFrameTotalEl.textContent = String(Math.floor(duration * fps));
}

function bindLayerActionButtons() {
  faceActionButtons.forEach((button) => {
    button.addEventListener('click', () => {
      setFaceMode(button.dataset.faceAction);
      setActionLog(`face layer: ${button.dataset.faceAction}`);
    });
  });

  eyeActionButtons.forEach((button) => {
    button.addEventListener('click', () => {
      setEyeMode(button.dataset.eyeAction);
      setActionLog(`eye layer: ${button.dataset.eyeAction}`);
    });
  });

  lipActionButtons.forEach((button) => {
    button.addEventListener('click', () => {
      setLipMode(button.dataset.lipAction);
      setActionLog(`lip layer: ${button.dataset.lipAction}`);
    });
  });
}

function bindBoneDebugControls() {
  boneDebugToggleEl?.addEventListener('click', () => {
    boneDebugVisible = !boneDebugVisible;
    updateBoneDebugOverlay(boneDebugSummaryEl?.textContent ?? '');
    setStatus(`bone debug: ${boneDebugVisible ? '表示' : '非表示'}`);
  });
}

async function handleSceneFileSelection() {
  const file = sceneFileInput?.files?.[0];
  if (!file) {
    return;
  }
  try {
    await loadScenePresetFromFile(file);
  } catch (error) {
    console.error(error);
    setActionLog(`scene preset load failed: ${error.message}`);
    setStatus(`scene preset 読込失敗: ${error.message}`);
  } finally {
    if (sceneFileInput) {
      sceneFileInput.value = '';
    }
  }
}

function handleDropFiles(fileList) {
  if (!fileList) return;
  const files = [...fileList];
  if (files.length === 0) return;

  const supported = files.find((file) => /\.(vrm|vrma|glb|gltf|png|jpg|jpeg|webp|json)$/i.test(file.name));
  if (!supported) {
    const exts = [...new Set(files.map(f => {
      const parts = f.name.split('.');
      return parts.length > 1 ? '.' + parts.pop().toLowerCase() : f.name;
    }))].slice(0, 5).join(' / ');
    setStatus(`非対応ファイル形式: ${exts}`, 'warn');
    return;
  }
  // サポートファイルが複数ある場合は最初の1件のみ処理（パフォーマンス上の理由）
  handleDroppedFile(supported).catch((error) => {
    console.error(error);
    setStatus(`ドラッグ&ドロップ失敗: ${error.message}`, 'error');
    setActionLog(`drag-drop error: ${error.message}`);
  });
}

let _dragAbortController = null;
function bindDragAndDrop() {
  // 以前のリスナーがあればクリーンアップ
  _dragAbortController?.abort();
  _dragAbortController = new AbortController();
  const { signal } = _dragAbortController;

  const prevent = (event) => {
    event.preventDefault();
    if (event.dataTransfer) event.dataTransfer.dropEffect = 'copy';
  };

  // ドラッグ中のビジュアルフィードバック
  let _dragCounter = 0;
  window.addEventListener('dragenter', (e) => {
    if (!e.dataTransfer?.types?.includes('Files')) return;
    _dragCounter++;
    viewportEl?.classList.add('is-drag-over');
  }, { signal });
  window.addEventListener('dragleave', () => {
    _dragCounter = Math.max(0, _dragCounter - 1);
    if (_dragCounter === 0) viewportEl?.classList.remove('is-drag-over');
  }, { signal });

  viewportEl?.addEventListener('dragover', prevent, { signal });
  viewportEl?.addEventListener('drop', (event) => {
    prevent(event);
    _dragCounter = 0;
    viewportEl?.classList.remove('is-drag-over');
    handleDropFiles(event.dataTransfer?.files ?? []);
  }, { signal });
  window.addEventListener('dragover', prevent, { signal });
  window.addEventListener('drop', (event) => {
    prevent(event);
    _dragCounter = 0;
    viewportEl?.classList.remove('is-drag-over');
    handleDropFiles(event.dataTransfer?.files ?? []);
  }, { signal });
}

