function startRecordingWithCountdown() {
  let count = 3;
  setStatus(`録画開始まで ${count}…`);
  showStageMessage(`🔴 ${count}`, 900);
  const tick = () => {
    count--;
    if (count > 0) {
      setStatus(`録画開始まで ${count}…`);
      showStageMessage(`🔴 ${count}`, 900);
      setTimeout(tick, 1000);
    } else {
      showStageMessage('● REC', 2000);
      setStatus('◉ 録画中');
      startRecording();
    }
  };
  setTimeout(tick, 1000);
}

