// Browser TTS voice list
(function initBrowserTts() {
  const pitchEl = document.getElementById('tts-browser-pitch');
  const pitchValEl = document.getElementById('tts-browser-pitch-value');
  pitchEl?.addEventListener('input', () => { if (pitchValEl) pitchValEl.textContent = (Number(pitchEl.value) || 0).toFixed(2); });
  const voiceSelect = document.getElementById('tts-browser-voice');
  function populateVoices() {
    if (!voiceSelect) return;
    const voices = window.speechSynthesis?.getVoices() ?? [];
    const jaVoices = voices.filter((v) => v.lang.startsWith('ja'));
    voiceSelect.innerHTML = '<option value="">システムデフォルト</option>';
    jaVoices.forEach((v) => {
      const opt = new Option(`${v.name} (${v.lang})`, v.name);
      voiceSelect.appendChild(opt);
    });
    if (jaVoices.length === 0) {
      voices.forEach((v) => {
        const opt = new Option(`${v.name} (${v.lang})`, v.name);
        voiceSelect.appendChild(opt);
      });
    }
  }
  if (window.speechSynthesis) {
    populateVoices();
    window.speechSynthesis.addEventListener('voiceschanged', populateVoices);
  }
})();

