// ── セリフウィンドウ デザインカスタマイズ ─────────────────────────────────────
{
  const LS_DW_STYLE = 'avatar.dialogueWindowStyle';

  function hexToRgba(hex, alpha) {
    const h = String(hex ?? '#000000');
    const r = parseInt(h.slice(1, 3), 16) || 0;
    const g = parseInt(h.slice(3, 5), 16) || 0;
    const b = parseInt(h.slice(5, 7), 16) || 0;
    return `rgba(${r},${g},${b},${alpha})`;
  }

  function applyDialogueWindowStyle(s) {
    if (!dialogueWindowEl) return;
    const bgColor = hexToRgba(s.bgColor, s.bgOpacity);
    dialogueWindowEl.style.setProperty('--dw-bg-color', bgColor);
    dialogueWindowEl.style.setProperty('--dw-text-color', s.textColor);
    dialogueWindowEl.style.setProperty('--dw-speaker-color', s.speakerColor);
    dialogueWindowEl.style.setProperty('--dw-font-size', `${s.fontSize}px`);
    dialogueWindowEl.classList.remove('dw-pos-bottom', 'dw-pos-top', 'dw-pos-center');
    dialogueWindowEl.classList.add(`dw-pos-${s.position}`);
  }

  function loadDwStyle() {
    try {
      const raw = localStorage.getItem(LS_DW_STYLE);
      if (raw) return JSON.parse(raw);
    } catch { /* ignore */ }
    return { position: 'bottom', fontSize: 14, bgColor: '#0a0e1a', bgOpacity: 0.82, textColor: '#f1f5f9', speakerColor: '#93c5fd' };
  }

  function saveDwStyle(s) {
    localStorage.setItem(LS_DW_STYLE, JSON.stringify(s));
  }

  const dwStyle = loadDwStyle();

  // 初期値を UI に反映
  const dwPositionEl = document.querySelector('#dw-position');
  const dwFontSizeEl = document.querySelector('#dw-font-size');
  const dwFontSizeValueEl = document.querySelector('#dw-font-size-value');
  const dwBgColorEl = document.querySelector('#dw-bg-color');
  const dwBgOpacityEl = document.querySelector('#dw-bg-opacity');
  const dwBgOpacityValueEl = document.querySelector('#dw-bg-opacity-value');
  const dwTextColorEl = document.querySelector('#dw-text-color');
  const dwSpeakerColorEl = document.querySelector('#dw-speaker-color');

  if (dwPositionEl) dwPositionEl.value = dwStyle.position;
  if (dwFontSizeEl) { dwFontSizeEl.value = dwStyle.fontSize; if (dwFontSizeValueEl) dwFontSizeValueEl.textContent = `${dwStyle.fontSize}px`; }
  if (dwBgColorEl) dwBgColorEl.value = dwStyle.bgColor;
  if (dwBgOpacityEl) { dwBgOpacityEl.value = dwStyle.bgOpacity; if (dwBgOpacityValueEl) dwBgOpacityValueEl.textContent = `${Math.round(dwStyle.bgOpacity * 100)}%`; }
  if (dwTextColorEl) dwTextColorEl.value = dwStyle.textColor;
  if (dwSpeakerColorEl) dwSpeakerColorEl.value = dwStyle.speakerColor;

  applyDialogueWindowStyle(dwStyle);

  function onDwChange() {
    dwStyle.position = dwPositionEl?.value ?? 'bottom';
    dwStyle.fontSize = Number(dwFontSizeEl?.value ?? 14);
    dwStyle.bgColor = dwBgColorEl?.value ?? '#0a0e1a';
    dwStyle.bgOpacity = Number(dwBgOpacityEl?.value ?? 0.82);
    dwStyle.textColor = dwTextColorEl?.value ?? '#f1f5f9';
    dwStyle.speakerColor = dwSpeakerColorEl?.value ?? '#93c5fd';
    if (dwFontSizeValueEl) dwFontSizeValueEl.textContent = `${dwStyle.fontSize}px`;
    if (dwBgOpacityValueEl) dwBgOpacityValueEl.textContent = `${Math.round(dwStyle.bgOpacity * 100)}%`;
    applyDialogueWindowStyle(dwStyle);
    saveDwStyle(dwStyle);
  }

  [dwPositionEl, dwFontSizeEl, dwBgColorEl, dwBgOpacityEl, dwTextColorEl, dwSpeakerColorEl]
    .forEach((el) => el?.addEventListener('input', onDwChange));
}

