storyClipListEl?.addEventListener('click', (e) => {
  const removeBtn = e.target.closest('[data-remove]');
  const moveBtn = e.target.closest('[data-move]');
  if (removeBtn) { removeStoryClip(removeBtn.dataset.remove); return; }
  if (moveBtn) {
    const id = moveBtn.closest('.story-clip-item')?.dataset.clipId;
    if (id) moveStoryClip(id, parseInt(moveBtn.dataset.move, 10));
    return;
  }
  const clipItem = e.target.closest('.story-clip-item');
  if (clipItem && storyMode) {
    const idx = parseInt(clipItem.dataset.clipIdx ?? '-1', 10);
    if (idx >= 0) playStoryClip(idx).catch((e) => setStatus(`ストーリー再生失敗: ${e.message}`));
  }
});

storyClipListEl?.addEventListener('change', (e) => {
  const durInput = e.target.closest('.story-clip-dur-input');
  if (durInput) {
    const id = durInput.closest('.story-clip-item')?.dataset.clipId;
    const val = parseFloat(durInput.value);
    if (id) setStoryClipDuration(id, Number.isFinite(val) && val > 0 ? val : null);
    return;
  }
  const camSel = e.target.closest('.story-clip-cam-select');
  if (camSel) {
    const id = camSel.dataset.clipCam;
    const clip = storyClips.find((c) => c.id === id);
    if (clip) { clip.cameraPreset = camSel.value || undefined; }
    return;
  }
  // Transition type
  const transSel = e.target.closest('.story-clip-trans-select');
  if (transSel) {
    const id = transSel.dataset.clipId;
    const clip = storyClips.find((c) => c.id === id);
    if (clip) {
      clip.transitionType = transSel.value;
      if (transSel.value === 'fade') clip.fadeDurSec = 0.28;
      else if (transSel.value === 'slowfade') clip.fadeDurSec = 1.0;
      const fadeDurInput = transSel.closest('.story-clip-anim-row')?.querySelector('.story-clip-fadedur-input');
      if (fadeDurInput) fadeDurInput.disabled = transSel.value !== 'fadecustom';
      renderStoryTrack();
    }
    return;
  }
  // Fade duration (custom)
  const fadeDurInput = e.target.closest('.story-clip-fadedur-input');
  if (fadeDurInput) {
    const id = fadeDurInput.closest('.story-clip-item')?.dataset.clipId;
    const clip = storyClips.find((c) => c.id === id);
    const val = parseFloat(fadeDurInput.value);
    if (clip && Number.isFinite(val) && val > 0) clip.fadeDurSec = val;
    return;
  }
  // Trim start
  const trimStart = e.target.closest('.story-clip-trim-start');
  if (trimStart) {
    const id = trimStart.closest('.story-clip-item')?.dataset.clipId;
    const clip = storyClips.find((c) => c.id === id);
    const val = parseFloat(trimStart.value);
    if (clip) {
      const safeVal = Number.isFinite(val) && val >= 0 ? val : 0;
      if (clip.trimEndSec !== null && safeVal >= clip.trimEndSec) {
        trimStart.style.borderColor = '#e66';
        setTimeout(() => { trimStart.style.borderColor = ''; }, 1500);
        setStatus('トリム開始は終了より前の時刻を指定してください', 'warn');
      } else {
        trimStart.style.borderColor = '';
        clip.trimStartSec = safeVal;
        renderStoryTrack();
      }
    }
    return;
  }
  // Trim end
  const trimEnd = e.target.closest('.story-clip-trim-end');
  if (trimEnd) {
    const id = trimEnd.closest('.story-clip-item')?.dataset.clipId;
    const clip = storyClips.find((c) => c.id === id);
    const rawVal = trimEnd.value.trim();
    const val = rawVal === '' ? null : parseFloat(rawVal);
    if (clip) {
      if (val !== null && (!Number.isFinite(val) || val <= clip.trimStartSec)) {
        trimEnd.style.borderColor = '#e66';
        setTimeout(() => { trimEnd.style.borderColor = ''; }, 1500);
        if (Number.isFinite(val)) setStatus('トリム終了は開始より後の時刻を指定してください', 'warn');
        else { clip.trimEndSec = null; renderStoryTrack(); }
      } else {
        trimEnd.style.borderColor = '';
        clip.trimEndSec = val;
        renderStoryTrack();
      }
    }
    return;
  }
});

