document.addEventListener('keydown', async (e) => {
  const tag = document.activeElement?.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;

  // Ctrl+S: シーン保存
  if ((e.ctrlKey || e.metaKey) && e.key === 's') {
    e.preventDefault();
    sceneSaveBtn?.click();
    return;
  }

  // 左右矢印キー / J/K: フレームステップ（一時停止中のみ）
  if (e.key === 'ArrowLeft' || e.key === 'ArrowRight' || e.key === 'j' || e.key === 'k') {
    if (currentAction && currentAction.paused) {
      e.preventDefault();
      const dir = (e.key === 'ArrowLeft' || e.key === 'j') ? -1 : 1;
      stepFrame(dir);
    }
    return;
  }

  // M key: toggle audio mute
  if ((e.key === 'm' || e.key === 'M') && !e.ctrlKey && !e.metaKey) {
    e.preventDefault();
    const bgmVolumeEl = document.getElementById('bgm-volume');
    if (bgmVolumeEl) {
      bgmVolumeEl.value = bgmVolumeEl.value === '0' ? '70' : '0';
      bgmVolumeEl.dispatchEvent(new Event('input'));
      setStatus(bgmVolumeEl.value === '0' ? '🔇 ミュート' : '🔊 ミュート解除');
    }
    return;
  }

  // 0 key: reset to start
  if (e.key === '0' && !e.ctrlKey && !e.metaKey) {
    if (currentAction) { e.preventDefault(); resetPlayback(); }
    return;
  }

  if (e.key === ' ' || e.code === 'Space') {
    e.preventDefault();
    if (currentAction && !currentAction.paused) {
      stopPlayback();
    } else {
      try { await playSelectedBodyMotion(); } catch (err) { setStatus(`再生失敗: ${err.message}`); }
    }
  } else if (e.key === 'f' || e.key === 'F') {
    toggleFullscreen();
  } else if ((e.key === 's' || e.key === 'S') && e.shiftKey) {
    triggerScreenshotFlash();
    takeScreenshot();
    setStatus('スクリーンショットを保存しました');
  } else if (e.key === 'r' || e.key === 'R') {
    resetCameraToPreset();
  } else if (e.key === 'm' || e.key === 'M') {
    stopTts();
  } else if (e.key === 't' || e.key === 'T') {
    // T: TTS読み上げ（テキストエリアの内容を即時再生）
    const text = ttsTextEl?.value?.trim();
    if (text) { speakText(text, ''); setStatus('TTS: 読み上げ開始'); }
    else { setStatus('T キー: テキストエリアにセリフを入力してください'); }
  } else if (e.key === 'd' || e.key === 'D') {
    // D: ダイアログウィンドウ表示/非表示トグル
    if (dialogueWindowEl) {
      const hidden = dialogueWindowEl.classList.toggle('is-hidden');
      setStatus(hidden ? 'ダイアログ: 非表示' : 'ダイアログ: 表示');
    }
  } else if (e.key === 'l' || e.key === 'L') {
    // L: 現在モーションのループトグル
    if (selectedBodyMotionUrl) {
      const next = !getMotionLoopEnabled(selectedBodyMotionUrl);
      setMotionLoopEnabled(selectedBodyMotionUrl, next);
      updateMotionDetailUi();
      if (currentMotionUrl === selectedBodyMotionUrl && currentAction) syncCurrentActionLoopMode();
      setStatus(`ループ: ${next ? 'ON' : 'OFF'}`);
    }
  } else if (e.key === 'c' || e.key === 'C') {
    // C: カメラプリセットを順番に切り替え
    if (cameraPresetButtons.length > 0) {
      const activeIdx = cameraPresetButtons.findIndex(b => b.classList.contains('is-active'));
      const nextBtn = cameraPresetButtons[(activeIdx + 1) % cameraPresetButtons.length];
      if (nextBtn?.dataset.cameraPreset) {
        applyCameraPreset(nextBtn.dataset.cameraPreset);
        setStatus(`カメラ: ${nextBtn.textContent.trim()}`);
      }
    }
  } else if (e.key === 'h' || e.key === 'H') {
    // H: サイドパネル表示/非表示トグル
    const panel = document.getElementById('asset-panel');
    if (panel) { panel.classList.toggle('is-hidden'); }
  } else if (e.key === 'b' || e.key === 'B') {
    // B: ボーンデバッグオーバーレイトグル
    const dbg = document.getElementById('debug-overlay');
    const dbgBtn = document.querySelector('#bone-debug-toggle');
    if (dbgBtn) dbgBtn.click();
    else if (dbg) dbg.classList.toggle('is-hidden');
  } else if (e.key === '?') {
    const helpModal = document.getElementById('shortcut-help-modal');
    if (helpModal) {
      helpModal.classList.toggle('is-hidden');
      document.getElementById('shortcut-help-close')?.focus();
    }
  }
});

// ---- 補正ポップアップ: ドラッグ移動 & 最小化 ----
{
  const popup = document.querySelector('#correction-popup');
  const header = document.querySelector('#correction-popup-header');
  const minimizeBtn = document.querySelector('#correction-popup-minimize');

  let dragOffsetX = 0;
  let dragOffsetY = 0;
  let isDraggingPopup = false;

  header?.addEventListener('pointerdown', (e) => {
    if (e.target.closest('button')) return; // ボタンクリックはドラッグしない
    isDraggingPopup = true;
    const rect = popup.getBoundingClientRect();
    dragOffsetX = e.clientX - rect.left;
    dragOffsetY = e.clientY - rect.top;
    header.setPointerCapture(e.pointerId);
    e.preventDefault();
  });

  header?.addEventListener('pointermove', (e) => {
    if (!isDraggingPopup) return;
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const pw = popup.offsetWidth;
    const ph = popup.offsetHeight;
    let nx = e.clientX - dragOffsetX;
    let ny = e.clientY - dragOffsetY;
    nx = Math.max(0, Math.min(nx, vw - pw));
    ny = Math.max(0, Math.min(ny, vh - ph));
    popup.style.left = `${nx}px`;
    popup.style.top = `${ny}px`;
    popup.style.right = 'auto';
    popup.style.bottom = 'auto';
  });

  const saveCorrectionPopupPos = () => {
    if (!popup) return;
    writeStoredJson(STORAGE_KEYS.correctionPopupPos, { x: parseInt(popup.style.left, 10) || 0, y: parseInt(popup.style.top, 10) || 0 });
  };
  header?.addEventListener('pointerup', () => { isDraggingPopup = false; saveCorrectionPopupPos(); });
  header?.addEventListener('pointercancel', () => { isDraggingPopup = false; });

  minimizeBtn?.addEventListener('click', () => {
    const minimized = popup.classList.toggle('is-minimized');
    minimizeBtn.textContent = minimized ? '□' : '─';
    minimizeBtn.title = minimized ? '展開' : '最小化';
    minimizeBtn.setAttribute('aria-label', minimized ? '展開' : '最小化');
    minimizeBtn.setAttribute('aria-expanded', minimized ? 'false' : 'true');
  });
}

// ---- タイムライン スクラバー & ステップコントロール ----
tlScrubber?.addEventListener('pointerdown', () => { isScrubbing = true; });
tlScrubber?.addEventListener('pointerup', () => { isScrubbing = false; });
tlScrubber?.addEventListener('pointercancel', () => { isScrubbing = false; });
