window.addEventListener('pointerup', () => { if (isScrubbing) isScrubbing = false; });
// スクラバーホバー・ドラッグでタイムコードツールチップ
{
  let _scrubTooltip = null;
  function getScrubTooltip() {
    if (!_scrubTooltip) {
      _scrubTooltip = document.createElement('div');
      _scrubTooltip.id = 'tl-scrubber-tooltip';
      _scrubTooltip.style.display = 'none';
      document.body.appendChild(_scrubTooltip);
    }
    return _scrubTooltip;
  }
  function updateScrubberTooltip(timeSec, totalSec) {
    if (!tlScrubber) return;
    const tip = getScrubTooltip();
    const fmt = (s) => `${String(Math.floor(s / 60)).padStart(2,'0')}:${(s % 60).toFixed(2).padStart(5,'0')}`;
    tip.textContent = `${fmt(timeSec)} / ${fmt(totalSec)}`;
    const rect = tlScrubber.getBoundingClientRect();
    const ratio = totalSec > 0 ? timeSec / totalSec : 0;
    tip.style.left = `${rect.left + rect.width * ratio}px`;
    tip.style.top = `${rect.top - 30}px`;
    tip.style.display = 'block';
  }

  tlScrubber?.addEventListener('input', () => {
    if (!currentAction) return;
    const clip = currentAction.getClip();
    if (!clip) return;
    const t = Math.min(clip.duration, (Number(tlScrubber.value) / 1000) * clip.duration);
    seekToTime(t);
    updateScrubberTooltip(t, clip.duration);
  });
  tlScrubber?.addEventListener('mousemove', (e) => {
    if (!currentAction) return;
    const clip = currentAction.getClip();
    if (!clip) return;
    const rect = tlScrubber.getBoundingClientRect();
    const ratio = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    updateScrubberTooltip(ratio * clip.duration, clip.duration);
  });
  tlScrubber?.addEventListener('mouseleave', () => {
    if (_scrubTooltip) _scrubTooltip.style.display = 'none';
  });
}

