// ── アイテムパネル ────────────────────────────────────────────────────────────

function renderItemPanel() {
  const container = document.querySelector('#avitem-list');
  if (!container) return;
  const allList = loadItemList() ?? [];
  const list = _itemCategoryFilter
    ? allList.filter((i) => i.category === _itemCategoryFilter)
    : allList;

  if (allList.length === 0) {
    container.innerHTML = '<div class="avitem-empty">アイテムがありません</div>';
    return;
  }
  if (list.length === 0) {
    container.innerHTML = '<div class="avitem-empty">このカテゴリにアイテムがありません</div>';
    return;
  }

  const equipped = loadEquippedParts();

  container.innerHTML = '';
  list.forEach((item) => {
    const obj = placedItems.get(item.id);
    const isEquipped = item.category && equipped[item.category] === item.id;
    const card = document.createElement('div');
    card.className = 'avitem-card' + (isEquipped ? ' is-equipped' : '');
    card.dataset.itemId = item.id;

    card.innerHTML = `
      <div class="avitem-header">
        <button type="button" class="avitem-vis-btn" title="表示/非表示">${item.visible !== false ? '👁' : '🙈'}</button>
        <span class="avitem-name">${escapeHtml(item.name)}</span>
        ${item.category ? `<span class="avitem-cat-badge">${escapeHtml(item.category)}</span>` : ''}
        <button type="button" class="avitem-del-btn" title="削除">🗑</button>
      </div>
      ${item.category ? `<button type="button" class="avitem-equip-btn${isEquipped ? ' is-equipped' : ''}">${isEquipped ? '✓ 装着中' : '装着'}</button>` : ''}
      <div class="avitem-transforms">
        <div class="avitem-transform-row">
          <span class="avitem-axis-label">X</span>
          <input type="number" step="0.1" value="${item.position?.[0] ?? 0}" class="avitem-num avitem-px" />
          <span class="avitem-axis-label">Y</span>
          <input type="number" step="0.1" value="${item.position?.[1] ?? 0}" class="avitem-num avitem-py" />
          <span class="avitem-axis-label">Z</span>
          <input type="number" step="0.1" value="${item.position?.[2] ?? 0}" class="avitem-num avitem-pz" />
        </div>
        <div class="avitem-transform-row">
          <span class="avitem-axis-label">回Y</span>
          <input type="number" step="1" value="${item.rotation?.[1] ?? 0}" class="avitem-num avitem-ry" />
          <span class="avitem-axis-label" style="margin-left:4px">倍率</span>
          <input type="number" step="0.1" value="${item.scale?.[0] ?? 1}" min="0.01" class="avitem-num avitem-sc" style="flex:0 0 40px" />
        </div>
      </div>
      <div class="avitem-tex-row">
        <label class="avitem-tex-label">テクスチャ</label>
        <input type="file" accept="image/*" class="avitem-tex-file is-hidden" />
        <button type="button" class="avitem-tex-btn">画像を適用</button>
        <span class="avitem-tex-status"></span>
      </div>
      <button type="button" class="avitem-parts-btn">パーツに分けて保存</button>
    `;

    // 表示/非表示
    card.querySelector('.avitem-vis-btn')?.addEventListener('click', () => {
      const newVisible = !(item.visible !== false);
      updateItemTransform(item.id, { visible: newVisible });
      if (obj) obj.visible = newVisible;
      renderItemPanel();
    });

    // 削除
    card.querySelector('.avitem-del-btn')?.addEventListener('click', async () => {
      // 装着中なら外す
      const eq = loadEquippedParts();
      if (item.category && eq[item.category] === item.id) unequipPart(item.category);
      removePlacedItem(item.id);
      deleteItem(item.id);
      await deleteItemFile(item.id).catch(() => {});
      renderItemPanel();
      renderOutfitPanel();
    });

    // 装着ボタン
    if (item.category) {
      card.querySelector('.avitem-equip-btn')?.addEventListener('click', async () => {
        // シーンに未読み込みなら読み込む
        if (!placedItems.has(item.id)) {
          await loadPlacedItem(item).catch((e) => setStatus(`アイテム読み込み失敗: ${e.message}`));
        }
        toggleEquipItem(item.id);
      });
    }

    // トランスフォーム変更
    const applyTransform = () => {
      const px = Number(card.querySelector('.avitem-px')?.value) || 0;
      const py = Number(card.querySelector('.avitem-py')?.value) || 0;
      const pz = Number(card.querySelector('.avitem-pz')?.value) || 0;
      const ry = Number(card.querySelector('.avitem-ry')?.value) || 0;
      const sc = Math.max(0.01, Number(card.querySelector('.avitem-sc')?.value) || 1);
      updateItemTransform(item.id, { position: [px, py, pz], rotation: [0, ry, 0], scale: [sc, sc, sc] });
      if (obj) {
        obj.position.set(px, py, pz);
        obj.rotation.set(0, THREE.MathUtils.degToRad(ry), 0);
        obj.scale.set(sc, sc, sc);
      }
    };
    card.querySelectorAll('.avitem-num').forEach((input) => input.addEventListener('change', applyTransform));

    // テクスチャ画像適用
    const texFileInput = card.querySelector('.avitem-tex-file');
    const texBtn = card.querySelector('.avitem-tex-btn');
    const texStatus = card.querySelector('.avitem-tex-status');
    texBtn?.addEventListener('click', () => texFileInput?.click());
    texFileInput?.addEventListener('change', async () => {
      const file = texFileInput.files?.[0];
      if (!file || !obj) return;
      if (texBtn) texBtn.disabled = true;
      if (texStatus) texStatus.textContent = '適用中...';
      try {
        await applyImageTextureToObject(obj, file);
        if (texStatus) texStatus.textContent = '✅';
      } catch (e) {
        if (texStatus) texStatus.textContent = '❌';
        setStatus(`テクスチャ適用失敗: ${e.message}`);
      } finally {
        if (texBtn) texBtn.disabled = false;
      }
    });

    // パーツ分解ボタン
    card.querySelector('.avitem-parts-btn')?.addEventListener('click', () => {
      if (!obj) return;
      openPartsExtractDialog(obj, item.name);
    });

    container.appendChild(card);
  });
}

// アイテム追加フォーム
{
  const addBtn = document.querySelector('#avitem-add-btn');
  const form = document.querySelector('#avitem-add-form');
  const cancelBtn = document.querySelector('#avitem-add-cancel');
  const okBtn = document.querySelector('#avitem-add-ok');
  const nameInput = document.querySelector('#avitem-name-input');
  const fileInput = document.querySelector('#avitem-file-input');
  const fileDisplay = document.querySelector('#avitem-file-display');
  const statusEl2 = document.querySelector('#avitem-add-status');

  addBtn?.addEventListener('click', () => {
    form?.classList.toggle('is-hidden');
  });
  cancelBtn?.addEventListener('click', () => {
    form?.classList.add('is-hidden');
    if (nameInput) nameInput.value = '';
    if (fileInput) fileInput.value = '';
    if (fileDisplay) fileDisplay.textContent = 'GLBファイルを選択...';
    if (statusEl2) statusEl2.textContent = '';
  });
  fileInput?.addEventListener('change', () => {
    const f = fileInput.files?.[0];
    if (f && !_validateFileUpload(f, { exts: ['glb', 'gltf'], maxMB: 100 })) {
      fileInput.value = '';
      if (fileDisplay) fileDisplay.textContent = 'GLBファイルを選択...';
      return;
    }
    if (fileDisplay) fileDisplay.textContent = f ? f.name : 'GLBファイルを選択...';
  });
  okBtn?.addEventListener('click', async () => {
    const name = nameInput?.value?.trim() || '新しいアイテム';
    const file = fileInput?.files?.[0];
    if (!file) { if (statusEl2) statusEl2.textContent = 'GLBファイルを選択してください'; return; }
    if (okBtn) okBtn.disabled = true;
    if (statusEl2) statusEl2.textContent = '追加中...';
    try {
      const buf = await file.arrayBuffer();
      const item = createItem(name);
      await storeItemFile(item.id, buf);
      await loadPlacedItem(item).catch((e) => { if (statusEl2) statusEl2.textContent = `読み込み失敗: ${e.message}`; });
      renderItemPanel();
      if (nameInput) nameInput.value = '';
      if (fileInput) fileInput.value = '';
      if (fileDisplay) fileDisplay.textContent = 'GLBファイルを選択...';
      if (statusEl2) statusEl2.textContent = '追加しました';
      setTimeout(() => { if (statusEl2) statusEl2.textContent = ''; }, 2000);
      form?.classList.add('is-hidden');
    } catch (e) {
      if (statusEl2) statusEl2.textContent = `エラー: ${e.message}`;
    } finally {
      if (okBtn) okBtn.disabled = false;
    }
  });
}

