// ── ステージモデル ────────────────────────────────────────────────────────────

function clearStageModel() {
  if (!stageModelRoot) return;
  if (scene) scene.remove(stageModelRoot);
  disposeObject3D(stageModelRoot);
  stageModelRoot = null;
}

async function applyStageModel(id) {
  clearStageModel();
  setActiveStageModelId(id ?? null);
  renderStageModelPanel();
  if (!id) return;
  const blobUrl = await createStageModelBlobUrl(id);
  if (!blobUrl) { setStatus('ステージモデルのファイルが見つかりません'); return; }
  let gltf;
  try {
    gltf = await loadGltf(stageModelLoader, blobUrl);
  } catch (e) {
    URL.revokeObjectURL(blobUrl);
    setStatus(`ステージモデル読み込み失敗: ${e.message}`, 'error'); return;
  }
  URL.revokeObjectURL(blobUrl);
  stageModelRoot = gltf.scene;
  stageModelRoot.traverse((obj) => { if (obj.isMesh) { obj.castShadow = true; obj.receiveShadow = true; } });
  if (scene) scene.add(stageModelRoot);
  setStatus('ステージモデルを読み込みました');
}

function renderStageModelPanel() {
  const container = document.querySelector('#avsmdl-list');
  if (!container) return;
  try {
  const list = loadStageModelList();
  const activeId = getActiveStageModelId();

  container.innerHTML = '';

  const noneBtn = document.createElement('button');
  noneBtn.type = 'button';
  noneBtn.className = `avsmdl-none-btn${!activeId ? ' is-active' : ''}`;
  noneBtn.textContent = 'なし';
  noneBtn.addEventListener('click', () => applyStageModel(null));
  container.appendChild(noneBtn);

  list.forEach((sm) => {
    const isActive = sm.id === activeId;
    const card = document.createElement('div');
    card.className = `avsmdl-card${isActive ? ' is-active' : ''}`;
    card.innerHTML = `
      <button type="button" class="avsmdl-select-btn">
        ${isActive ? '<span class="avsmdl-active-dot">●</span>' : ''}
        <span class="avsmdl-name">${escapeHtml(sm.name)}</span>
      </button>
      <button type="button" class="avsmdl-del-btn" title="削除">🗑</button>
    `;
    card.querySelector('.avsmdl-select-btn')?.addEventListener('click', () => {
      if (sm.id === getActiveStageModelId()) return;
      applyStageModel(sm.id).catch((e) => setStatus(`ステージモデルエラー: ${e.message}`));
    });
    card.querySelector('.avsmdl-del-btn')?.addEventListener('click', async () => {
      if (!confirmDialog(`「${sm.name}」を削除しますか？`)) return;
      if (getActiveStageModelId() === sm.id) { clearStageModel(); setActiveStageModelId(null); }
      deleteStageModel(sm.id);
      await deleteStageModelFile(sm.id).catch(() => {});
      renderStageModelPanel();
    });
    container.appendChild(card);
  });
  } catch (e) { console.warn('[renderStageModelPanel]', e); }
}

