// ── カメラアニメーション ──────────────────────────────────────────────────────

function addCameraKeyframe() {
  if (!camera || !controls) { setStatus('カメラが初期化されていません', 'warn'); return; }
  if (cameraKeyframes.length >= 50) { setStatus('キーフレームは最大50件です', 'warn'); return; }
  const kf = {
    id: 'ckf_' + Date.now().toString(36),
    name: `KF ${cameraKeyframes.length + 1} (${camera.position.x.toFixed(1)},${camera.position.y.toFixed(1)},${camera.position.z.toFixed(1)})`,
    position: camera.position.toArray(),
    target: controls.target.toArray(),
    fov: Math.round(camera.fov * 100) / 100,
    durationSec: 2,
  };
  cameraKeyframes.push(kf);
  renderCameraKeyframePanel();
  try { localStorage.setItem('avatar.cameraKeyframes', JSON.stringify(cameraKeyframes)); } catch {}
  setStatus(`カメラKF追加 (${cameraKeyframes.length}件)`);
}

function removeCameraKeyframe(id) {
  if (!id) return;
  const removed = cameraKeyframes.find((kf) => kf.id === id);
  cameraKeyframes = cameraKeyframes.filter((kf) => kf.id !== id);
  camAnimKfIdx = Math.max(0, Math.min(camAnimKfIdx, cameraKeyframes.length - 1));
  renderCameraKeyframePanel();
  try { localStorage.setItem('avatar.cameraKeyframes', JSON.stringify(cameraKeyframes)); } catch {}
  if (removed) setStatus(`カメラKF削除: ${removed.name} (残り${cameraKeyframes.length}件)`);
}

function jumpToCameraKeyframe(id) {
  const kf = cameraKeyframes.find((k) => k.id === id);
  if (!kf) return;
  if (!kf.position || !kf.target || kf.position.some(isNaN) || kf.target.some(isNaN)) {
    setStatus('無効なキーフレームです。再登録してください', 'warn'); return;
  }
  camAnimPlaying = false;
  if (controls) controls.enabled = true;
  camTransFrom = { pos: camera.position.clone(), target: controls.target.clone(), fov: camera.fov };
  camTransTo = { pos: new THREE.Vector3(...kf.position), target: new THREE.Vector3(...kf.target), fov: kf.fov ?? camera.fov };
  camTransProgress = 0;
  setStatus(`カメラ移動: ${kf.name}`);
}

function startCameraAnimation() {
  if (cameraKeyframes.length < 2) { setStatus('キーフレームが2つ以上必要です', 'warn'); return; }
  const invalid = cameraKeyframes.find(kf => !kf.position || !kf.target || kf.position.some(isNaN) || kf.target.some(isNaN));
  if (invalid) { setStatus('無効なカメラKFがあります。再登録してください', 'error'); return; }
  camAnimPlaying = true;
  camAnimKfIdx = 0;
  camAnimKfProgress = 0;
  if (controls) controls.enabled = false;
  const playBtn = document.querySelector('#cam-anim-play-btn');
  const stopBtn = document.querySelector('#cam-anim-stop-btn');
  if (playBtn) playBtn.disabled = true;
  if (stopBtn) stopBtn.disabled = false;
  setStatus(`カメラアニメーション開始 (${cameraKeyframes.length}KF)`);
}

function stopCameraAnimation() {
  camAnimPlaying = false;
  camAnimKfProgress = 0;
  if (controls) controls.enabled = true;
  const playBtn = document.querySelector('#cam-anim-play-btn');
  const stopBtn = document.querySelector('#cam-anim-stop-btn');
  if (playBtn) playBtn.disabled = false;
  if (stopBtn) stopBtn.disabled = true;
  setStatus('カメラアニメーション停止');
}

function renderCameraKeyframePanel() {
  const container = document.querySelector('#cam-anim-kf-list');
  if (!container) return;
  if (cameraKeyframes.length === 0) {
    container.innerHTML = '<div class="cam-anim-empty">キーフレームがありません</div>';
    return;
  }
  container.innerHTML = '';
  cameraKeyframes.forEach((kf, i) => {
    if (!kf || !kf.id) return;
    const row = document.createElement('div');
    row.className = 'cam-anim-kf-row';
    const kfName = String(kf.name ?? `KF ${i + 1}`).slice(0, 60);
    row.innerHTML = `
      <button type="button" class="cam-anim-kf-jump" title="このキーフレームへ移動">${i + 1}</button>
      <span class="cam-anim-kf-name" title="${escapeHtml(kfName)}">${escapeHtml(kfName.slice(0, 25))}</span>
      <label class="cam-anim-kf-dur-label">
        <input type="number" class="cam-anim-kf-dur" value="${kf.durationSec}" min="0.1" max="60" step="0.1" />
        <span>s</span>
      </label>
      <button type="button" class="cam-anim-kf-del" title="削除">✕</button>
    `;
    row.querySelector('.cam-anim-kf-jump')?.addEventListener('click', () => jumpToCameraKeyframe(kf.id));
    row.querySelector('.cam-anim-kf-dur')?.addEventListener('change', (e) => {
      kf.durationSec = Math.max(0.1, Math.min(3600, Number(e.target.value) || 2));
      try { localStorage.setItem('avatar.cameraKeyframes', JSON.stringify(cameraKeyframes)); } catch {}
    });
    row.querySelector('.cam-anim-kf-del')?.addEventListener('click', () => removeCameraKeyframe(kf.id));
    container.appendChild(row);
  });
}

// カメラアニメーション UI wire-up
{
  const addKfBtn = document.querySelector('#cam-anim-add-kf');
  const playBtn = document.querySelector('#cam-anim-play-btn');
  const stopBtn = document.querySelector('#cam-anim-stop-btn');
  addKfBtn?.addEventListener('click', addCameraKeyframe);
  playBtn?.addEventListener('click', startCameraAnimation);
  stopBtn?.addEventListener('click', stopCameraAnimation);
  renderCameraKeyframePanel();
}

// ── BGM・SE管理 ───────────────────────────────────────────────────────────────

function detectAudioMime(filename) {
  if (!filename) return 'audio/mpeg';
  const ext = (String(filename).split('.').pop() ?? '').toLowerCase().trim();
  const map = { mp3: 'audio/mpeg', ogg: 'audio/ogg', wav: 'audio/wav', m4a: 'audio/mp4', aac: 'audio/aac', flac: 'audio/flac', opus: 'audio/ogg; codecs=opus', webm: 'audio/webm' };
  return map[ext] ?? 'audio/mpeg';
}

function stopBgm(skipRender = false) {
  if (bgmAudio) {
    try { bgmAudio.pause(); } catch {}
    try { bgmAudio.src = ''; } catch {}
    bgmAudio = null;
  }
  bgmActiveId = null;
  if (!skipRender) renderBgmPanel();
}

async function playBgm(id) {
  if (!id) return;
  const list = loadBgmList();
  const meta = list.find((b) => b.id === id);
  if (!meta || typeof meta !== 'object') return;
  if (bgmActiveId === id && bgmAudio && !bgmAudio.paused) { stopBgm(); return; }
  stopBgm();
  const url = await createBgmBlobUrl(id, meta.mimeType);
  if (!url) { setStatus('BGMファイルが見つかりません'); return; }
  bgmAudio = new Audio(url);
  bgmAudio.loop = Boolean(meta.loop);
  bgmAudio.volume = Math.max(0, Math.min(1, Number.isFinite(+meta.volume) ? +meta.volume : 0.8));
  bgmAudio.addEventListener('error', (e) => {
    setStatus(`BGM読み込みエラー: ${e.target?.error?.message ?? 'unknown'}`, 'warn');
    bgmActiveId = null; bgmAudio = null; renderBgmPanel();
  });
  bgmAudio.addEventListener('ended', () => { if (!meta.loop) { bgmActiveId = null; bgmAudio = null; renderBgmPanel(); } });
  bgmAudio.play().catch((e) => setStatus(`BGM再生エラー: ${e.message}`, 'warn'));
  bgmActiveId = id;
  renderBgmPanel();
}

function renderBgmPanel() {
  const container = document.querySelector('#bgm-list');
  if (!container) return;
  const list = loadBgmList() ?? [];
  if (list.length === 0) {
    container.innerHTML = '<div class="avitem-empty">BGMがありません</div>';
    return;
  }
  const _bgmFrag = document.createDocumentFragment();
  list.forEach((bgm) => {
    const isPlaying = bgmActiveId === bgm.id && bgmAudio && !bgmAudio.paused;
    const card = document.createElement('div');
    card.className = 'bgm-card';
    card.innerHTML = `
      <button type="button" class="bgm-play-btn${isPlaying ? ' is-playing' : ''}" title="${isPlaying ? '停止' : '再生'}">
        ${isPlaying ? '■' : '▶'}
      </button>
      <span class="bgm-name">${escapeHtml(bgm.name)}</span>
      <label class="bgm-vol-label" title="音量">
        <input type="range" class="bgm-vol" min="0" max="1" step="0.05" value="${bgm.volume}" />
      </label>
      <button type="button" class="bgm-del-btn" title="削除">🗑</button>
    `;
    card.querySelector('.bgm-play-btn')?.addEventListener('click', () => playBgm(bgm.id));
    card.querySelector('.bgm-vol')?.addEventListener('input', (e) => {
      const vol = Math.max(0, Math.min(1, Number(e.target.value) || 0));
      updateBgm(bgm.id, { volume: vol });
      if (bgmActiveId === bgm.id && bgmAudio) bgmAudio.volume = vol;
    });
    card.querySelector('.bgm-del-btn')?.addEventListener('click', async () => {
      if (!confirmDialog(`「${bgm.name}」を削除しますか？`)) return;
      if (bgmActiveId === bgm.id) stopBgm();
      deleteBgm(bgm.id);
      await deleteBgmFile(bgm.id).catch(() => {});
      renderBgmPanel();
      setStatus(`BGM削除: ${bgm.name}`);
    });
    _bgmFrag.appendChild(card);
  });
  container.innerHTML = '';
  container.appendChild(_bgmFrag);
}

async function playSe(id) {
  const list = loadSeList();
  const meta = list.find((s) => s.id === id);
  if (!meta) return;
  const url = await createSeBlobUrl(id, meta.mimeType);
  if (!url) { setStatus('SEファイルが見つかりません'); return; }
  const audio = new Audio(url);
  audio.volume = Math.max(0, Math.min(1, Number.isFinite(Number(meta.volume)) ? Number(meta.volume) : 0.8));
  const _seRevoke = () => { try { URL.revokeObjectURL(url); } catch {} };
  audio.addEventListener('ended', _seRevoke, { once: true });
  audio.addEventListener('error', _seRevoke, { once: true });
  audio.play().catch((e) => { setStatus(`SE再生エラー: ${e.message}`, 'error'); _seRevoke(); });
}

function renderSePanel() {
  const container = document.querySelector('#se-list');
  if (!container) return;
  const list = loadSeList();
  if (list.length === 0) {
    container.innerHTML = '<div class="avitem-empty">効果音がありません</div>';
    return;
  }
  const _seFrag = document.createDocumentFragment();
  list.forEach((se) => {
    const card = document.createElement('div');
    card.className = 'bgm-card';
    card.innerHTML = `
      <button type="button" class="bgm-play-btn" title="再生">▶</button>
      <span class="bgm-name">${escapeHtml(se.name)}</span>
      <label class="bgm-vol-label" title="音量">
        <input type="range" class="bgm-vol" min="0" max="1" step="0.05" value="${se.volume}" />
      </label>
      <button type="button" class="bgm-del-btn" title="削除">🗑</button>
    `;
    card.querySelector('.bgm-play-btn')?.addEventListener('click', () => playSe(se.id));
    card.querySelector('.bgm-vol')?.addEventListener('input', (e) => {
      updateSe(se.id, { volume: Math.max(0, Math.min(1, Number(e.target.value) || 0)) });
    });
    card.querySelector('.bgm-del-btn')?.addEventListener('click', async () => {
      if (!confirmDialog(`「${se.name}」を削除しますか？`)) return;
      deleteSe(se.id);
      await deleteSeFile(se.id).catch(() => {});
      renderSePanel();
      setStatus(`SE削除: ${se.name}`);
    });
    _seFrag.appendChild(card);
  });
  container.innerHTML = '';
  container.appendChild(_seFrag);
}

// BGM追加フォーム
{
  const addBtn = document.querySelector('#bgm-add-btn');
  const form = document.querySelector('#bgm-add-form');
  const cancelBtn = document.querySelector('#bgm-add-cancel');
  const okBtn = document.querySelector('#bgm-add-ok');
  const nameInput = document.querySelector('#bgm-name-input');
  const fileInput = document.querySelector('#bgm-file-input');
  const fileDisplay = document.querySelector('#bgm-file-display');
  const statusElBgm = document.querySelector('#bgm-add-status');

  addBtn?.addEventListener('click', () => form?.classList.toggle('is-hidden'));
  cancelBtn?.addEventListener('click', () => {
    form?.classList.add('is-hidden');
    if (nameInput) nameInput.value = '';
    if (fileInput) fileInput.value = '';
    if (fileDisplay) fileDisplay.textContent = '音声ファイルを選択...';
    if (statusElBgm) statusElBgm.textContent = '';
  });
  fileInput?.addEventListener('change', () => {
    const f = fileInput.files?.[0];
    if (fileDisplay) fileDisplay.textContent = f ? f.name : '音声ファイルを選択...';
  });
  okBtn?.addEventListener('click', async () => {
    const name = nameInput?.value?.trim() || '新しいBGM';
    const file = fileInput?.files?.[0];
    if (!file) { if (statusElBgm) statusElBgm.textContent = '音声ファイルを選択してください'; return; }
    if (okBtn) okBtn.disabled = true;
    if (statusElBgm) statusElBgm.textContent = '追加中...';
    try {
      const mimeType = detectAudioMime(file.name);
      const buf = await file.arrayBuffer();
      const bgm = createBgm(name, mimeType);
      await storeBgmFile(bgm.id, buf);
      if (nameInput) nameInput.value = '';
      if (fileInput) fileInput.value = '';
      if (fileDisplay) fileDisplay.textContent = '音声ファイルを選択...';
      if (statusElBgm) statusElBgm.textContent = '追加しました';
      setTimeout(() => { if (statusElBgm) statusElBgm.textContent = ''; }, 2000);
      form?.classList.add('is-hidden');
      renderBgmPanel();
      _switchPropTab('sound');
    } catch (e) {
      if (statusElBgm) statusElBgm.textContent = `エラー: ${e.message}`;
    } finally {
      if (okBtn) okBtn.disabled = false;
    }
  });

  renderBgmPanel();
}

