// ── キャラメイク: 体型ボーンスケール適用 (animate ループから毎フレーム呼ばれる) ─────
function applyCharaMakeBodyParams() {
  if (!currentVrm?.humanoid || !currentVrm.scene) return;
  const p = charamakeBodyParams ?? {};
  const h = currentVrm.humanoid;
  const _clampScale = (v, min = 0.1, max = 3.0) => Math.max(min, Math.min(max, Number(v) || 1));

  const headNode = h.getRawBoneNode('head');
  if (headNode) {
    const hs = _clampScale(p.headScale ?? 1);
    const fw = _clampScale(p.faceWidth ?? 1);
    headNode.scale.set(hs * fw, hs, hs * fw);
  }
  const jawNode = h.getRawBoneNode('jaw');
  if (jawNode) jawNode.scale.y = _clampScale(p.jawScale ?? 1, 0.5, 2.0);

  const chestNode = h.getRawBoneNode('upperChest') ?? h.getRawBoneNode('chest');
  if (chestNode) {
    const cw = p.chestWidth ?? 1;
    chestNode.scale.x = cw;
    chestNode.scale.z = Math.pow(cw, 0.6); // 奥行きは控えめに
  }

  const hipsNode = h.getRawBoneNode('hips');
  if (hipsNode) {
    const hw = p.hipWidth ?? 1;
    hipsNode.scale.x = hw;
    hipsNode.scale.z = Math.pow(hw, 0.6);
  }

  const spineNode = h.getRawBoneNode('spine');
  if (spineNode) spineNode.scale.y = p.upperBodyScale ?? 1;

  for (const b of ['leftUpperLeg', 'rightUpperLeg', 'leftLowerLeg', 'rightLowerLeg']) {
    const node = h.getRawBoneNode(b);
    if (node) node.scale.y = p.legLength ?? 1;
  }
  for (const b of ['leftUpperArm', 'rightUpperArm', 'leftLowerArm', 'rightLowerArm']) {
    const node = h.getRawBoneNode(b);
    if (node) node.scale.y = p.armLength ?? 1;
  }
}

// ── キャラメイク: マテリアルカラーユーティリティ ──────────────────────────────
function getMaterialColor(mat) {
  if (!mat) return '#ffffff';
  try {
    const lf = mat.uniforms?.litFactor?.value;
    if (lf) {
      const r = Number(lf.x ?? lf.r ?? 1);
      const g = Number(lf.y ?? lf.g ?? 1);
      const b = Number(lf.z ?? lf.b ?? 1);
      return '#' + new THREE.Color(
        Number.isFinite(r) ? r : 1,
        Number.isFinite(g) ? g : 1,
        Number.isFinite(b) ? b : 1
      ).getHexString();
    }
    if (mat.color?.isColor) return '#' + mat.color.getHexString();
  } catch { /* ignore */ }
  return '#ffffff';
}

function setMaterialColor(mat, hex) {
  if (!mat || !hex) return false;
  let c;
  try { c = new THREE.Color(hex); } catch { return false; }
  const lf = mat.uniforms?.litFactor?.value;
  if (lf) {
    if (typeof lf.x === 'number') { lf.x = c.r; lf.y = c.g; lf.z = c.b; }
    else { lf.r = c.r; lf.g = c.g; lf.b = c.b; }
    if (mat.uniforms.shadeColorFactor?.value) {
      const sf = mat.uniforms.shadeColorFactor.value;
      if (typeof sf.x === 'number') { sf.x = c.r * 0.7; sf.y = c.g * 0.7; sf.z = c.b * 0.7; }
      else { sf.r = c.r * 0.7; sf.g = c.g * 0.7; sf.b = c.b * 0.7; }
    }
    mat.needsUpdate = true;
    return true;
  }
  if (mat.color?.isColor) { mat.color.copy(c); mat.needsUpdate = true; return true; }
  return false;
}

function scanVrmMaterials() {
  if (!currentVrm?.scene) return [];
  const seen = new Map(); // name → {name, mat, hex}
  currentVrm.scene.traverse((obj) => {
    if (!obj.isMesh && !obj.isSkinnedMesh) return;
    const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
    for (const mat of mats) {
      if (!mat || seen.has(mat.uuid)) continue;
      seen.set(mat.uuid, { name: mat.name || '(unnamed)', mat, hex: getMaterialColor(mat) });
    }
  });
  return [...seen.values()].sort((a, b) => a.name.localeCompare(b.name));
}

function applyCharaMakeColors(costumeId) {
  if (!costumeId || !currentVrm?.scene) return;
  const overrides = loadColorOverrides(costumeId);
  if (!overrides || Object.keys(overrides).length === 0) return;
  currentVrm.scene.traverse((obj) => {
    if (!obj.isMesh && !obj.isSkinnedMesh) return;
    const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
    for (const mat of mats) {
      if (!mat || !overrides[mat.uuid]) continue;
      setMaterialColor(mat, overrides[mat.uuid]);
    }
  });
}

