        add(new THREE.ConeGeometry(0.092, 0.21, 32), Mc(0xcc1111), hX, brimY + 0.105, hZ);
        add(new THREE.CylinderGeometry(0.097, 0.097, 0.027, 40), wm, hX, brimY, hZ);
