    const EYE_LINER_KW  = ['eyelash', 'lash', 'liner', 'eyeline', '睫毛', 'cilium'];
    bindDetailColor('cm-eye-shadow-color', 'cm-eye-shadow-hex', (hex) => applyColorToMats(filterActiveMats(EYE_SHADOW_KW), hex));
    bindDetailColor('cm-eye-liner-color',  'cm-eye-liner-hex',  (hex) => applyColorToMats(filterActiveMats(EYE_LINER_KW), hex));
    bindDetailColor('cm-face-lip-color',   'cm-face-lip-hex',   (hex) => applyColorToMats(filterActiveMats(LIP_KEYWORDS), hex));
