  // ── アクセサリーパネル ───────────────────────────────────────────────────────
  function _pvUpdateAccPosition() {
    ACCESSORY_SLOT_KEYS.forEach((k) => {
      const v = _pvAccessoryVrmMap[k];
      if (v) v.scene.position.set(_pvAccOffsetX, _pvAccOffsetY, _pvAccOffsetZ);
    });
  }

  async function _pvApplyAccessorySlot(slotKey, vrmUrl) {
    if (!_pvScene) return;
    const loadingEl = document.getElementById('cm-accessory-loading');
    if (loadingEl) loadingEl.classList.remove('is-hidden');
    _pvShowLoading('アクセサリー読込中...');
    if (_pvAccessoryVrmMap[slotKey]) {
      _pvScene.remove(_pvAccessoryVrmMap[slotKey].scene);
      if (_pvAccessoryVrmMap[slotKey].humanoid) {
        VRMUtils.deepDispose(_pvAccessoryVrmMap[slotKey].scene);
      } else {
        disposeObject3D(_pvAccessoryVrmMap[slotKey].scene);
      }
      _pvAccessoryVrmMap[slotKey] = null;
    }
    if (vrmUrl) {
      if (vrmUrl.startsWith('procedural:')) {
        const genKey = vrmUrl.replace('procedural:', '');
        const accObj = _pvGenProceduralAcc(genKey);
        _pvScene.add(accObj.scene);
        _pvAccessoryVrmMap[slotKey] = accObj;
        if (loadingEl) loadingEl.classList.add('is-hidden');
        return;
      }
      try {
        const loader = new GLTFLoader();
        loader.register((parser) => new VRMLoaderPlugin(parser));
        const gltf = await loader.loadAsync(vrmUrl);
        const vrm  = gltf.userData.vrm;
        if (!vrm) throw new Error('VRMデータが見つかりません');
        if (vrm.meta?.metaVersion === '0') VRMUtils.rotateVRM0(vrm);
        _pvScene.add(vrm.scene);
        // 頭ボーン位置で自動アライン（最初のスロットロード時のみ）
        const firstLoad = ACCESSORY_SLOT_KEYS.every((k) => _pvAccessoryVrmMap[k] === null);
        if (firstLoad) {
          try {
            const baseHead = _pvVrm?.humanoid?.humanBones?.head?.node;
            const accHead  = vrm?.humanoid?.humanBones?.head?.node;
            if (baseHead && accHead) {
              const bPos = new THREE.Vector3();
              const hPos = new THREE.Vector3();
              _pvVrm.scene.updateWorldMatrix(true, true);
              vrm.scene.updateWorldMatrix(true, true);
              baseHead.getWorldPosition(bPos);
              accHead.getWorldPosition(hPos);
              _pvAccOffsetY = Math.max(-0.25, Math.min(0.25, bPos.y - hPos.y));
            } else { _pvAccOffsetY = 0; }
          } catch (_) { _pvAccOffsetY = 0; }
          _pvAccOffsetX = 0; _pvAccOffsetZ = 0;
          ['x','y','z'].forEach((axis) => {
            const v  = axis === 'x' ? _pvAccOffsetX : axis === 'y' ? _pvAccOffsetY : _pvAccOffsetZ;
            const sl = document.getElementById(`cm-acc-offset-${axis}`);
            const vl = document.getElementById(`cm-acc-offset-${axis}-val`);
            if (sl) sl.value = v;
            if (vl) vl.textContent = v.toFixed(3);
          });
        }
        _pvAccessoryVrmMap[slotKey] = vrm;
        vrm.scene.position.set(_pvAccOffsetX, _pvAccOffsetY, _pvAccOffsetZ);
      } catch (e) {
        console.warn('[charamake accessory] VRM load failed:', e);
        setStatus(`アクセサリーVRM読み込み失敗: ${e.message}`);
      }
    }
    if (loadingEl) loadingEl.classList.add('is-hidden');
    _pvHideLoading();
  }

  function _findAccStyleById(id) {
    for (const cat of _pvAccessoryStyleDefs) {
      const s = cat.styles.find((x) => x.id === id);
      if (s) return s;
    }
    return null;
  }

  function _renderAccessoryGrid() {
    const grid = document.getElementById('cm-accessory-grid');
    if (!grid) return;
    grid.innerHTML = '';

    // スロットタブ
    const tabBar = document.createElement('div');
    tabBar.className = 'cm-hair-section-tabs';
    ACCESSORY_SLOT_KEYS.forEach((k) => {
      const styleId   = _pvAccActiveStyleMap[k];
      const styleName = styleId ? (_findAccStyleById(styleId)?.name ?? '') : 'なし';
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'cm-hair-section-tab' + (k === _pvActiveAccSlotKey ? ' is-active' : '');
      btn.dataset.slotKey = k;
      btn.innerHTML = `<span class="cm-section-tab-part">${ACCESSORY_SLOT_LABELS[k]}</span><span class="cm-section-tab-style">${escapeHtml(styleName)}</span>`;
      btn.addEventListener('click', () => {
        _pvActiveAccSlotKey = k;
        _renderAccessoryGrid();
      });
      tabBar.appendChild(btn);
    });
    grid.appendChild(tabBar);

    // ＋追加ボタン行
    const addRow = document.createElement('div');
    addRow.className = 'cm-hair-style-addrow';
    const accAddBtn = document.createElement('button');
    accAddBtn.type = 'button';
    accAddBtn.className = 'cm-hair-style-addbtn';
    accAddBtn.id = 'cm-acc-style-add-btn';
    accAddBtn.textContent = '＋ アイテム追加';
    accAddBtn.addEventListener('click', () => _showAccStyleAddForm());
    addRow.appendChild(accAddBtn);
    grid.appendChild(addRow);

    for (const catDef of _pvAccessoryStyleDefs) {
      if (catDef.styles.length === 0) continue;
      const catLabel = document.createElement('div');
      catLabel.className = 'cm-style-category-label';
      catLabel.textContent = catDef.cat;
      grid.appendChild(catLabel);

      const row = document.createElement('div');
      row.className = 'cm-style-grid';
      for (const style of catDef.styles) {
        const slot      = _pvActiveAccSlotKey;
        const isActive  = _pvAccActiveStyleMap[slot] === style.id;
        const card = document.createElement('div');
        card.className = 'cm-hair-card' + (isActive ? ' is-active' : '');
        card.dataset.styleId = style.id;
        card.innerHTML = `<span class="cm-hair-card-icon">${escapeHtml(style.icon ?? '◆')}</span><span class="cm-hair-card-name">${escapeHtml(style.name)}</span><button type="button" class="cm-hair-card-del" title="削除">✕</button>`;
        card.addEventListener('click', async (e) => {
          if (e.target.closest('.cm-hair-card-del')) return;
          try {
            if (isActive) {
              _pvAccActiveStyleMap[slot] = null;
              await _pvApplyAccessorySlot(slot, null);
            } else {
              _pvAccActiveStyleMap[slot] = style.id;
              await _pvApplyAccessorySlot(slot, style.vrm);
            }
            _renderAccessoryGrid();
          } catch (e) {
            setStatus(`アクセサリー適用失敗: ${e.message}`);
          }
        });
        row.appendChild(card);
      }
      grid.appendChild(row);
    }

    if (_pvAccessoryStyleDefs.every((c) => c.styles.length === 0)) {
      const empty = document.createElement('div');
      empty.className = 'cm-style-category-label';
      empty.style.color = '#475569';
      empty.style.marginTop = '12px';
      empty.textContent = '「＋ アイテム追加」でVRMを追加してください';
      grid.appendChild(empty);
    }

    // 削除ボタン
    grid.querySelectorAll('.cm-hair-card-del').forEach((btn) => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        const card = btn.closest('.cm-hair-card');
        if (!card) return;
        const styleId = card.dataset.styleId;
        const styleName = _findAccStyleById(styleId)?.name ?? styleId;
        if (!confirmDialog(`「${styleName}」を削除しますか？`)) return;
        for (const cat of _pvAccessoryStyleDefs) {
          cat.styles = cat.styles.filter((s) => s.id !== styleId);
        }
        const cleanups = [];
        ACCESSORY_SLOT_KEYS.forEach((k) => {
          if (_pvAccActiveStyleMap[k] === styleId) {
            _pvAccActiveStyleMap[k] = null;
            cleanups.push(_pvApplyAccessorySlot(k, null));
          }
        });
        try {
          await Promise.all(cleanups);
        } catch (e) {
          setStatus(`アクセサリー削除失敗: ${e.message}`);
        }
        _renderAccessoryGrid();
      });
    });

  }

  function _showAccStyleAddForm() {
    const grid = document.getElementById('cm-accessory-grid');
    const existing = document.getElementById('cm-acc-addform');
    if (existing) { existing.remove(); return; }
    const form = document.createElement('div');
    form.id = 'cm-acc-addform';
    form.className = 'cm-hair-addform';
    form.innerHTML = `
      <input type="text" id="cm-acc-addform-name" class="cm-hair-addform-input" placeholder="アイテム名" />
      <select id="cm-acc-addform-vrm" class="cm-hair-addform-select">
        ${_HAIR_VRMS.map((v) => `<option value="${v.vrm ?? ''}">${v.label}</option>`).join('')}
      </select>
      <select id="cm-acc-addform-cat" class="cm-hair-addform-select">
        ${_pvAccessoryStyleDefs.map((c) => `<option value="${escapeHtml(c.cat)}">${escapeHtml(c.cat)}</option>`).join('')}
        <option value="__new">＋ 新しいカテゴリ</option>
      </select>
      <div class="cm-hair-addform-btns">
        <button type="button" class="cm-hair-addform-btn-ok" id="cm-acc-addform-ok">追加</button>
        <button type="button" class="cm-hair-addform-btn-cancel" id="cm-acc-addform-cancel">キャンセル</button>
      </div>`;
    const addRow = grid.querySelector('.cm-hair-style-addrow');
    addRow ? addRow.after(form) : grid.prepend(form);

    document.getElementById('cm-acc-addform-cancel')?.addEventListener('click', () => form.remove());
    document.getElementById('cm-acc-addform-ok')?.addEventListener('click', () => {
      const name = document.getElementById('cm-acc-addform-name')?.value.trim();
      const vrmVal = document.getElementById('cm-acc-addform-vrm')?.value;
      let catName = document.getElementById('cm-acc-addform-cat')?.value;
      if (!name) return;
      const vrmPath = vrmVal || null;
      const newStyle = { id: 'acc_' + Date.now(), name, icon: '◆', vrm: vrmPath };
      if (catName === '__new') {
        const nc = (window.prompt('新しいカテゴリ名:') || 'カスタム').trim();
        _pvAccessoryStyleDefs.push({ cat: nc, styles: [newStyle] });
      } else {
        const cat = _pvAccessoryStyleDefs.find((c) => c.cat === catName);
        if (cat) cat.styles.push(newStyle);
        else _pvAccessoryStyleDefs.push({ cat: catName, styles: [newStyle] });
      }
      form.remove();
      _renderAccessoryGrid();
    });
  }

  let _accPanelInit = false;
  function renderAccessoryPanel() {
    _renderAccessoryGrid();
    if (_accPanelInit) return;
    _accPanelInit = true;

    ['x','y','z'].forEach((axis) => {
      const sl = document.getElementById(`cm-acc-offset-${axis}`);
      const vl = document.getElementById(`cm-acc-offset-${axis}-val`);
      if (!sl) return;
      sl.addEventListener('input', () => {
        const val = parseFloat(sl.value);
        if (axis === 'x') _pvAccOffsetX = val;
        else if (axis === 'y') _pvAccOffsetY = val;
        else _pvAccOffsetZ = val;
        if (vl) vl.textContent = val.toFixed(3);
        _pvUpdateAccPosition();
      });
    });
  }

  // ── 衣装パネル ─────────────────────────────────────────────────────────────

  // 全身コスチュームにリターゲットするボーン名一覧
  const _RETARGET_BONES = [
    'hips','spine','chest','upperChest','neck','head',
    'leftShoulder','leftUpperArm','leftLowerArm','leftHand',
    'rightShoulder','rightUpperArm','rightLowerArm','rightHand',
    'leftUpperLeg','leftLowerLeg','leftFoot','leftToes',
    'rightUpperLeg','rightLowerLeg','rightFoot','rightToes',
  ];

  function _pvRetargetFullCloth() {
    const fullVrm = _pvClothVrmMap['full'];
    if (!fullVrm || !_pvVrm) return;
    _RETARGET_BONES.forEach((name) => {
      const src = _pvVrm.humanoid?.getNormalizedBoneNode?.(name);
      const dst = fullVrm.humanoid?.getNormalizedBoneNode?.(name);
      if (src && dst) dst.quaternion.copy(src.quaternion);
    });
    // ヒップ位置を同期してルートずれを防ぐ
    const srcHips = _pvVrm.humanoid?.humanBones?.hips?.node;
    const dstHips = fullVrm.humanoid?.humanBones?.hips?.node;
    if (srcHips && dstHips) {
      const sp = new THREE.Vector3(); srcHips.getWorldPosition(sp);
      const dp = new THREE.Vector3(); dstHips.getWorldPosition(dp);
      fullVrm.scene.position.y += sp.y - dp.y;
    }
  }

  async function _pvApplyClothSlot(slotKey, vrmUrl) {
    if (!_pvScene) return;
    const loadingEl = document.getElementById('cm-outfit-loading');
    if (loadingEl) loadingEl.classList.remove('is-hidden');
    _pvShowLoading('衣装読込中...');
    if (_pvClothVrmMap[slotKey]) {
      const _old = _pvClothVrmMap[slotKey];
      if (_old._isProcedural) {
        _old.dispose?.();
        _pvScene?.remove(_old.scene);
        // プロシージャル衣装はベースVRMを非表示にしていないので復元不要
      } else {
        _pvScene.remove(_old.scene);
        VRMUtils.deepDispose(_old.scene);
      }
      _pvClothVrmMap[slotKey] = null;
      if (slotKey === 'full') _pvCostumeHeadMeshes = [];
    }
    // ── ビルトイン（プロシージャル）衣装 ──
    if (vrmUrl?.startsWith('builtin:')) {
      // meshy-current はベースVRM不要。他のビルトインはベースVRMが必要
      const needsBaseVrm = !vrmUrl.startsWith('builtin:meshy');
      if (_pvVrm || !needsBaseVrm) {
        let clothObj = _pvBuildBuiltinCostume(vrmUrl, _pvVrm);
        // 非同期ビルダー（KKキャラ等）の場合は await
        if (clothObj && typeof clothObj.then === 'function') {
          clothObj = await clothObj;
        }
        if (clothObj) {
          _pvScene.add(clothObj.scene);
          _pvClothVrmMap[slotKey] = clothObj;
          // KKキャラは _hidesBaseVrm=true なのでベースVRMを非表示に
          if (slotKey === 'full' && _pvVrm) {
            _pvVrm.scene.visible = !clothObj._hidesBaseVrm;
          }
          if (slotKey === 'full') { _pvCostumeHeadMeshes = []; }
        }
      }
      if (loadingEl) loadingEl.classList.add('is-hidden');
      _pvHideLoading();
      return;
    }
    if (vrmUrl) {
      try {
        const loader = new GLTFLoader();
        loader.register((parser) => new VRMLoaderPlugin(parser));
        const gltf = await loader.loadAsync(vrmUrl);
        const vrm  = gltf.userData.vrm;
        if (!vrm) throw new Error('VRMデータが見つかりません');
        if (vrm?.meta?.metaVersion === '0') VRMUtils.rotateVRM0(vrm);

        if (slotKey === 'full') {
          // 全身スロット: ベースキャラを非表示にしてコスチュームを表示
          if (_pvVrm) {
            // スケールをベースVRMに合わせる（足底〜頭の高さ基準）
            const bFoot = _pvVrm.humanoid?.humanBones?.leftFoot?.node ?? _pvVrm.humanoid?.humanBones?.hips?.node;
            const bHead = _pvVrm.humanoid?.humanBones?.head?.node;
            const cFoot = vrm.humanoid?.humanBones?.leftFoot?.node ?? vrm.humanoid?.humanBones?.hips?.node;
            const cHead = vrm.humanoid?.humanBones?.head?.node;
            if (bFoot && bHead && cFoot && cHead) {
              _pvVrm.scene.updateWorldMatrix(true, true);
              vrm.scene.updateWorldMatrix(true, true);
              const bf = new THREE.Vector3(); bFoot.getWorldPosition(bf);
              const bh = new THREE.Vector3(); bHead.getWorldPosition(bh);
              const cf = new THREE.Vector3(); cFoot.getWorldPosition(cf);
              const ch = new THREE.Vector3(); cHead.getWorldPosition(ch);
              const baseH = bh.y - bf.y;
              const clothH = ch.y - cf.y;
              if (clothH > 0.01) vrm.scene.scale.setScalar(baseH / clothH);
              vrm.scene.updateWorldMatrix(true, true);
              // 足元を揃える
              cFoot.getWorldPosition(cf);
              bf.y = 0; cf.y = 0; // 水平方向は無視
              const bfWorld = new THREE.Vector3(); bFoot.getWorldPosition(bfWorld);
              const cfWorld = new THREE.Vector3(); cFoot.getWorldPosition(cfWorld);
              vrm.scene.position.y += bfWorld.y - cfWorld.y;
            }
            _pvVrm.scene.visible = false;
          }
        } else {
          // 部分スロット: ベースキャラは表示したままスケール合わせ
          const baseHips = _pvVrm?.humanoid?.humanBones?.hips?.node;
          const clothHips = vrm?.humanoid?.humanBones?.hips?.node;
          if (baseHips && clothHips) {
            _pvVrm.scene.updateWorldMatrix(true, true);
            vrm.scene.updateWorldMatrix(true, true);
            const bHipsPos = new THREE.Vector3(); baseHips.getWorldPosition(bHipsPos);
            const cHipsPos = new THREE.Vector3(); clothHips.getWorldPosition(cHipsPos);
            const baseHead = _pvVrm?.humanoid?.humanBones?.head?.node;
            const clothHead = vrm?.humanoid?.humanBones?.head?.node;
            if (baseHead && clothHead) {
              const bHp = new THREE.Vector3(); baseHead.getWorldPosition(bHp);
              const cHp = new THREE.Vector3(); clothHead.getWorldPosition(cHp);
              const bH = bHp.y - bHipsPos.y; const cH = cHp.y - cHipsPos.y;
              if (cH > 0.01) vrm.scene.scale.setScalar(bH / cH);
              vrm.scene.updateWorldMatrix(true, true);
              clothHips.getWorldPosition(cHipsPos);
            }
            vrm.scene.position.y = bHipsPos.y - cHipsPos.y;
          }
        }

        _pvScene.add(vrm.scene);
        _pvClothVrmMap[slotKey] = vrm;
        // 全身コスチューム: 頭部/髪メッシュ優先度を即時評価
        if (slotKey === 'full') {
          _pvCostumeHeadMeshes = [];
          _pvUpdateCostumeHeadVisibility();
        }
      } catch (e) {
        console.warn('[charamake outfit] VRM load failed:', e);
        setStatus('衣装VRMの読み込みに失敗しました: ' + (e?.message ?? e));
        if (slotKey === 'full' && _pvVrm) _pvVrm.scene.visible = true;
      }
    } else if (slotKey === 'full') {
      // 全身コスチュームを解除 → ベースキャラを再表示
      _pvCostumeHeadMeshes = [];
      if (_pvVrm) _pvVrm.scene.visible = true;
    }
    if (loadingEl) loadingEl.classList.add('is-hidden');
    _pvHideLoading();
  }

  function _findClothStyleById(id) {
    for (const cat of _pvClothStyleDefs) {
      const s = cat.styles.find((x) => x.id === id);
      if (s) return s;
    }
    return null;
  }

  function _renderClothGrid() {
    const grid = document.getElementById('cm-outfit-grid');
    if (!grid) return;
    grid.innerHTML = '';

    // スロットタブ
    const tabBar = document.createElement('div');
    tabBar.className = 'cm-hair-section-tabs';
    CLOTH_SLOT_KEYS.forEach((k) => {
      const styleId   = _pvClothActiveStyleMap[k];
      const styleName = styleId ? (_findClothStyleById(styleId)?.name ?? '') : 'なし';
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'cm-hair-section-tab' + (k === _pvActiveClothSlotKey ? ' is-active' : '');
      btn.dataset.slotKey = k;
      btn.innerHTML = `<span class="cm-section-tab-part">${CLOTH_SLOT_ICONS[k]} ${CLOTH_SLOT_LABELS[k]}</span><span class="cm-section-tab-style">${escapeHtml(styleName)}</span>`;
      btn.addEventListener('click', () => {
        _pvActiveClothSlotKey = k;
        _renderClothGrid();
      });
      tabBar.appendChild(btn);
    });
    grid.appendChild(tabBar);

    // ＋追加ボタン行
    const addRow = document.createElement('div');
    addRow.className = 'cm-hair-style-addrow';
    const clothAddBtn = document.createElement('button');
    clothAddBtn.type = 'button';
    clothAddBtn.className = 'cm-hair-style-addbtn';
    clothAddBtn.id = 'cm-cloth-style-add-btn';
    clothAddBtn.textContent = '＋ VRMを追加';
    clothAddBtn.addEventListener('click', () => _showClothStyleAddForm());
    addRow.appendChild(clothAddBtn);
    const netAddBtn = document.createElement('button');
    netAddBtn.type = 'button';
    netAddBtn.className = 'cm-hair-style-addbtn';
    netAddBtn.id = 'cm-cloth-net-add-btn';
    netAddBtn.textContent = '🌐 ネットから追加';
    netAddBtn.addEventListener('click', () => _showClothNetCatalog());
    addRow.appendChild(netAddBtn);
    grid.appendChild(addRow);

    // 現在のスロットに対応するカテゴリのみ表示
    const slotDefs = _pvClothStyleDefs.filter((c) => c.slot === _pvActiveClothSlotKey);
    // + カスタム追加分（slot記載のないもの）
    const customDefs = _pvClothStyleDefs.filter((c) => !c.slot);

    for (const catDef of [...slotDefs, ...customDefs]) {
      if (catDef.styles.length === 0) continue;
      const catLabel = document.createElement('div');
      catLabel.className = 'cm-style-category-label';
      catLabel.textContent = catDef.cat;
      grid.appendChild(catLabel);

      const row = document.createElement('div');
      row.className = 'cm-style-grid';
      row.style.cssText = 'grid-template-columns:repeat(auto-fill,minmax(80px,1fr));gap:5px;padding:0 0 4px;';

      for (const style of catDef.styles) {
        const slot     = _pvActiveClothSlotKey;
        const isActive = _pvClothActiveStyleMap[slot] === style.id;
        const hasVrm   = !!style.vrm;
        const card = document.createElement('div');
        card.className = 'cm-hair-card cm-cloth-card' + (isActive ? ' is-active' : '') + (!hasVrm ? ' cm-cloth-card--no-vrm' : '');
        card.dataset.styleId = style.id;
        card.innerHTML = `
          <button type="button" class="cm-hair-card-main">
            <span class="cm-hair-card-icon">${escapeHtml(style.icon ?? '👗')}</span>
            <span class="cm-hair-card-label">${escapeHtml(style.name)}</span>
            ${!hasVrm ? '<span class="cm-cloth-no-vrm-badge">未設定</span>' : ''}
          </button>
          <div class="cm-hair-card-actions">
            <button type="button" class="cm-cloth-card-link" title="${hasVrm ? 'VRM変更' : 'VRM追加'}">📎</button>
            <button type="button" class="cm-hair-card-edit" title="名前を変更">✏</button>
            <button type="button" class="cm-hair-card-del"  title="削除">×</button>
          </div>`;

        card.querySelector('.cm-hair-card-main')?.addEventListener('click', async () => {
          if (!hasVrm) {
            setStatus('📎 ボタンからVRMファイルを関連付けてください');
            return;
          }
          try {
            if (isActive) {
              _pvClothActiveStyleMap[slot] = null;
              await _pvApplyClothSlot(slot, null);
            } else {
              _pvClothActiveStyleMap[slot] = style.id;
              await _pvApplyClothSlot(slot, style.vrm);
            }
            _renderClothGrid();
          } catch (err) {
            setStatus(`衣装適用失敗: ${err.message}`);
          }
        });

        card.querySelector('.cm-cloth-card-link')?.addEventListener('click', (e) => {
          e.stopPropagation();
          _showClothVrmLinkForm(style.id, catDef);
        });

        card.querySelector('.cm-hair-card-edit')?.addEventListener('click', (e) => {
          e.stopPropagation();
          const newName = window.prompt('新しい名前:', style.name);
          if (newName?.trim()) { style.name = newName.trim(); _renderClothGrid(); }
        });

        card.querySelector('.cm-hair-card-del')?.addEventListener('click', async (e) => {
          e.stopPropagation();
          if (!confirmDialog(`「${style.name}」を削除しますか？`)) return;
          catDef.styles = catDef.styles.filter((s) => s.id !== style.id);
          const cleanups = [];
          CLOTH_SLOT_KEYS.forEach((k) => {
            if (_pvClothActiveStyleMap[k] === style.id) {
              _pvClothActiveStyleMap[k] = null;
              cleanups.push(_pvApplyClothSlot(k, null));
            }
          });
          try {
            await Promise.all(cleanups);
          } catch (e) {
            setStatus(`衣装削除失敗: ${e.message}`);
          }
          _renderClothGrid();
        });

        row.appendChild(card);
      }
      grid.appendChild(row);
    }
  }

  function _showClothVrmLinkForm(styleId, catDef) {
    const style = catDef.styles.find((s) => s.id === styleId);
    if (!style) return;
    const grid = document.getElementById('cm-outfit-grid');
    const existing = document.getElementById('cm-cloth-linkform');
    if (existing) { existing.remove(); if (existing.dataset.forId === styleId) return; }

    const form = document.createElement('div');
    form.id = 'cm-cloth-linkform';
    form.dataset.forId = styleId;
    form.className = 'cm-hair-addform';
    form.innerHTML = `
      <div style="margin-bottom:6px;font-size:0.85rem;color:#94a3b8">「${escapeHtml(style.name)}」にVRMを関連付け</div>
      <label class="cm-hair-addform-filelabel">
        <span id="cm-cloth-linkform-fname">${style.vrm ? style.vrm.split('/').pop() : 'VRMファイルを選択...'}</span>
        <input type="file" id="cm-cloth-linkform-file" accept=".vrm,.glb,model/gltf-binary" style="display:none" />
      </label>
      <div style="display:flex;gap:6px;margin-top:6px">
        <input type="url" id="cm-cloth-linkform-url" class="cm-hair-addform-input" style="flex:1" placeholder="またはVRM URLを入力..." />
        <button type="button" class="cm-hair-addform-btn-ok" id="cm-cloth-linkform-url-fetch" style="flex-shrink:0">取得</button>
      </div>
      <div id="cm-cloth-linkform-status" style="font-size:11px;min-height:14px;margin-top:4px;color:#6a9ec8"></div>
      <div class="cm-hair-addform-btns">
        <button type="button" class="cm-hair-addform-btn-ok" id="cm-cloth-linkform-ok">適用</button>
        <button type="button" class="cm-hair-addform-btn-cancel" id="cm-cloth-linkform-cancel">キャンセル</button>
      </div>`;
    const addRow = grid.querySelector('.cm-hair-style-addrow');
    addRow ? addRow.after(form) : grid.prepend(form);

    let _selectedVrmBlob = null;
    const _linkStatusEl = document.getElementById('cm-cloth-linkform-status');
    document.getElementById('cm-cloth-linkform-file')?.addEventListener('change', (e) => {
      const file = e.target.files?.[0];
      if (!file) return;
      if (_selectedVrmBlob?.startsWith('blob:')) URL.revokeObjectURL(_selectedVrmBlob);
      _selectedVrmBlob = URL.createObjectURL(file);
      const fname = document.getElementById('cm-cloth-linkform-fname');
      if (fname) fname.textContent = file.name;
    });
    document.getElementById('cm-cloth-linkform-url-fetch')?.addEventListener('click', async () => {
      const urlEl = document.getElementById('cm-cloth-linkform-url');
      const url = urlEl?.value?.trim();
      if (!url) return;
      const fetchBtn = document.getElementById('cm-cloth-linkform-url-fetch');
      if (fetchBtn) { fetchBtn.disabled = true; fetchBtn.textContent = '取得中…'; }
      if (_linkStatusEl) { _linkStatusEl.textContent = 'ダウンロード中...'; _linkStatusEl.style.color = '#6a9ec8'; }
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const buf = await res.arrayBuffer();
        if (_selectedVrmBlob?.startsWith('blob:')) URL.revokeObjectURL(_selectedVrmBlob);
        _selectedVrmBlob = URL.createObjectURL(new Blob([buf], { type: 'model/gltf-binary' }));
        const fname = document.getElementById('cm-cloth-linkform-fname');
        const dispName = url.split('/').pop().replace(/\.(vrm|glb)$/i, '');
        if (fname) fname.textContent = dispName || url;
        if (_linkStatusEl) { _linkStatusEl.textContent = '取得完了 ✓'; _linkStatusEl.style.color = '#5bc96d'; }
      } catch (err) {
        if (_linkStatusEl) { _linkStatusEl.textContent = `エラー: ${err.message}`; _linkStatusEl.style.color = '#e05555'; }
      } finally {
        if (fetchBtn) { fetchBtn.disabled = false; fetchBtn.textContent = '取得'; }
      }
    });
    document.getElementById('cm-cloth-linkform-cancel')?.addEventListener('click', () => {
      if (_selectedVrmBlob?.startsWith('blob:')) URL.revokeObjectURL(_selectedVrmBlob);
      form.remove();
    });
    document.getElementById('cm-cloth-linkform-ok')?.addEventListener('click', async () => {
      if (!_selectedVrmBlob) { form.remove(); return; }
      style.vrm = _selectedVrmBlob;
      // 選択中だったらすぐ再適用
      if (_pvClothActiveStyleMap[_pvActiveClothSlotKey] === styleId) {
        try {
          await _pvApplyClothSlot(_pvActiveClothSlotKey, style.vrm);
        } catch (e) {
          setStatus(`衣装適用失敗: ${e.message}`);
        }
      }
      form.remove();
      _renderClothGrid();
    });
  }

  function _showClothStyleAddForm() {
    const grid = document.getElementById('cm-outfit-grid');
    const existing = document.getElementById('cm-cloth-addform');
    if (existing) { existing.remove(); return; }
    const slotCats = _pvClothStyleDefs.filter((c) => c.slot === _pvActiveClothSlotKey);
    const form = document.createElement('div');
    form.id = 'cm-cloth-addform';
    form.className = 'cm-hair-addform';
    form.innerHTML = `
      <input type="text" id="cm-cloth-addform-name" class="cm-hair-addform-input" placeholder="衣装名（例: デニムワンピ）" />
      <label class="cm-hair-addform-filelabel">
        <span id="cm-cloth-addform-fname">VRMファイルを選択...</span>
        <input type="file" id="cm-cloth-addform-file" accept=".vrm,.glb,model/gltf-binary" style="display:none" />
      </label>
      <div class="cm-hair-addform-btns">
        <button type="button" class="cm-hair-addform-btn-ok" id="cm-cloth-addform-ok">追加</button>
        <button type="button" class="cm-hair-addform-btn-cancel" id="cm-cloth-addform-cancel">キャンセル</button>
      </div>`;
    const addRow = grid.querySelector('.cm-hair-style-addrow');
    addRow ? addRow.after(form) : grid.prepend(form);

    let _selectedVrmBlob = null;
    document.getElementById('cm-cloth-addform-file')?.addEventListener('change', (e) => {
      const file = e.target.files?.[0];
      if (!file) return;
      if (_selectedVrmBlob?.startsWith('blob:')) URL.revokeObjectURL(_selectedVrmBlob);
      _selectedVrmBlob = URL.createObjectURL(file);
      const fname = document.getElementById('cm-cloth-addform-fname');
      if (fname) fname.textContent = file.name;
    });
    document.getElementById('cm-cloth-addform-cancel')?.addEventListener('click', () => {
      if (_selectedVrmBlob?.startsWith('blob:')) URL.revokeObjectURL(_selectedVrmBlob);
      form.remove();
    });
    document.getElementById('cm-cloth-addform-ok')?.addEventListener('click', () => {
      const name = document.getElementById('cm-cloth-addform-name')?.value.trim();
      if (!name) return;
      const newStyle = { id: 'cs_custom_' + Date.now(), name, icon: CLOTH_SLOT_ICONS[_pvActiveClothSlotKey] ?? '👗', vrm: _selectedVrmBlob };
      if (slotCats.length > 0) {
        slotCats[0].styles.push(newStyle);
      } else {
        _pvClothStyleDefs.push({ cat: CLOTH_SLOT_LABELS[_pvActiveClothSlotKey], slot: _pvActiveClothSlotKey, styles: [newStyle] });
      }
      form.remove();
      _renderClothGrid();
    });
  }

