// 汎用文字数カウンター初期化
function _initCharCounter(inputId, counterId, maxLen) {
  const input = document.getElementById(inputId);
  const counter = document.getElementById(counterId);
  if (!input || !counter) return;
  const max = maxLen || parseInt(input.maxLength) || 100;
  const update = () => {
    const len = input.value.length;
    counter.textContent = `${len} / ${max}文字`;
    counter.classList.toggle('is-near-limit', len >= max * 0.8);
    counter.classList.toggle('is-at-limit', len >= max);
  };
  input.addEventListener('input', update);
  update();
}

