// ステージ背景色: カラーピッカー ↔ hex入力テキスト の双方向同期
(function () {
  const input = document.getElementById('stage-background-input');
  const hex = document.getElementById('stage-bg-hex');
  if (!input || !hex) return;
  // カラーピッカー → hex入力
  input.addEventListener('input', () => { hex.value = input.value; });
  // hex入力 → カラーピッカー（有効な6桁hex形式のみ適用）
  hex.addEventListener('input', () => {
    const v = hex.value.trim();
    if (/^#[0-9a-fA-F]{6}$/.test(v)) {
      input.value = v;
      input.dispatchEvent(new Event('input', { bubbles: true }));
    }
  });
  hex.value = input.value;
})();

