// LLM接続テストボタン
(function () {
  const btn = document.getElementById('llm-test-conn-btn');
  if (!btn) return;
  btn.addEventListener('click', async () => {
    const url = document.getElementById('llm-base-url')?.value?.trim();
    if (!url) return;
    btn.textContent = '確認中…';
    btn.disabled = true;
    btn.classList.remove('ok', 'fail');
    try {
      const resp = await fetch(`${url}/api/tags`, { signal: AbortSignal.timeout(4000) });
      if (resp.ok) {
        btn.textContent = '✓ OK';
        btn.classList.add('ok');
      } else {
        throw new Error(`HTTP ${resp.status}`);
      }
    } catch {
      btn.textContent = '✗ 失敗';
      btn.classList.add('fail');
    } finally {
      btn.disabled = false;
      setTimeout(() => { btn.textContent = '確認'; btn.classList.remove('ok', 'fail'); }, 3000);
    }
  });
})();

// VOICEVOX話者プレビューボタン
(function () {
  const btn = document.getElementById('tts-vv-preview');
  if (!btn) return;
  btn.addEventListener('click', async () => {
    const host    = document.getElementById('tts-vv-host')?.value ?? 'http://localhost:50021';
    const speaker = document.getElementById('tts-vv-speaker')?.value ?? '1';
    const text    = 'こんにちは、テスト再生です';
    btn.disabled  = true;
    btn.textContent = '…';
    try {
      const qRes  = await fetch(`${host}/audio_query?text=${encodeURIComponent(text)}&speaker=${speaker}`, { method: 'POST', signal: AbortSignal.timeout(5000) });
      const query = await qRes.json();
      const synRes = await fetch(`${host}/synthesis?speaker=${speaker}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(query),
        signal: AbortSignal.timeout(8000),
      });
      const blob   = await synRes.blob();
      const url    = URL.createObjectURL(blob);
      const audio  = new Audio(url);
      audio.onended = () => URL.revokeObjectURL(url);
      await audio.play();
    } catch (e) {
      console.warn('[VV preview]', e);
    } finally {
      btn.disabled    = false;
      btn.textContent = '▶';
    }
  });
})();

