// モーションドロップゾーンのDrag & Drop
(function () {
  const hint = document.getElementById('motion-drop-hint');
  const fileInput = document.getElementById('motion-file-input');
  if (!hint || !fileInput) return;
  const viewport = document.getElementById('viewport') || document.body;
  viewport.addEventListener('dragover', (e) => {
    if ([...e.dataTransfer.items].some((i) => i.kind === 'file')) {
      hint.classList.add('is-drag-over');
    }
  });
  viewport.addEventListener('dragleave', () => hint.classList.remove('is-drag-over'));
  viewport.addEventListener('drop', (e) => {
    hint.classList.remove('is-drag-over');
    const file = [...e.dataTransfer.files].find((f) => f.name.endsWith('.vrma'));
    if (file && fileInput) {
      const dt = new DataTransfer();
      dt.items.add(file);
      fileInput.files = dt.files;
      fileInput.dispatchEvent(new Event('change', { bubbles: true }));
    }
  });
})();

