// [Feature 1] 個別ブレンドシェイプスライダー (VRMViewer参考実装)
// ═══════════════════════════════════════════════════════════════════
let _bsManualMode = false;
const _bsOverrides = {};

function _populateBlendShapeSliders() {
  const container = document.getElementById('bs-sliders-container');
  if (!container) return;

  const manager = getExpressionManager();
  if (!manager) {
    container.innerHTML = '<span class="help-text">VRMモデルを読み込むと表示されます</span>';
    return;
  }

  const exprMap = manager.expressionMap ?? {};
  const names = Object.keys(exprMap);
  if (names.length === 0) {
    container.innerHTML = '<span class="help-text">このモデルにはブレンドシェイプがありません</span>';
    return;
  }

  container.innerHTML = '';
  for (const name of names) {
    const row = document.createElement('div');
    row.className = 'bs-slider-row';

    const label = document.createElement('span');
    label.className = 'bs-slider-label';
    label.textContent = name;
    label.title = name;

    const slider = document.createElement('input');
    slider.type = 'range';
    slider.min = '0';
    slider.max = '1';
    slider.step = '0.01';
    slider.value = '0';
    slider.className = 'bs-slider-range';
    slider.dataset.bsName = name;
    slider.setAttribute('aria-label', `${name} ブレンドシェイプ`);

    const valDisplay = document.createElement('span');
    valDisplay.className = 'bs-slider-val';
    valDisplay.textContent = '0.00';

    slider.addEventListener('input', () => {
      const v = parseFloat(slider.value);
      valDisplay.textContent = v.toFixed(2);
      _bsOverrides[name] = v;
      if (_bsManualMode) {
        setExpressionValue(name, v);
        updateExpressionManager();
      }
    });

    row.appendChild(label);
    row.appendChild(slider);
    row.appendChild(valDisplay);
    container.appendChild(row);
  }
}

// 手動モードON/OFFトグル
document.getElementById('bs-manual-mode')?.addEventListener('change', (e) => {
  _bsManualMode = e.target.checked;
  if (_bsManualMode) {
    // 現在のスライダー値を一括適用
    const container = document.getElementById('bs-sliders-container');
    container?.querySelectorAll('.bs-slider-range').forEach((s) => {
      setExpressionValue(s.dataset.bsName, parseFloat(s.value));
    });
    updateExpressionManager();
  }
});

// 全リセット
document.getElementById('bs-reset-all-btn')?.addEventListener('click', () => {
  const container = document.getElementById('bs-sliders-container');
  container?.querySelectorAll('.bs-slider-range').forEach((s) => {
    s.value = '0';
    const row = s.closest('.bs-slider-row');
    row?.querySelector('.bs-slider-val')?.setText?.call(row.querySelector('.bs-slider-val'), '0.00');
    if (row?.querySelector('.bs-slider-val')) row.querySelector('.bs-slider-val').textContent = '0.00';
    _bsOverrides[s.dataset.bsName] = 0;
    if (_bsManualMode) setExpressionValue(s.dataset.bsName, 0);
  });
  if (_bsManualMode) updateExpressionManager();
});

// モデルロード後にスライダーを再生成（applyModelSettingsToCurrentModel の後に呼ばれる）
const _origApplyModelSettings = applyModelSettingsToCurrentModel;
// eslint-disable-next-line no-global-assign
(function _patchApplyModelSettings() {
  if (typeof applyModelSettingsToCurrentModel !== 'function') {
    console.debug('[patch] applyModelSettingsToCurrentModel not found, skipping patch');
    return;
  }
  const orig = applyModelSettingsToCurrentModel;
  window.__bsPatchDone = window.__bsPatchDone || false;
  if (window.__bsPatchDone) return;
  window.__bsPatchDone = true;
  // normalizeLoadedModel の後に差し込む（MutationObserver で #model-name 変化を監視）
  const modelNameEl = document.getElementById('model-name');
  if (modelNameEl) {
    new MutationObserver(() => {
      setTimeout(_populateBlendShapeSliders, 200);
    }).observe(modelNameEl, { childList: true, characterData: true, subtree: true });
  }
})();
// 初回呼び出し
_populateBlendShapeSliders();

