function _getPoseBoneNode(boneName) {
  if (!currentVrm?.humanoid) return null;
  return currentVrm.humanoid.getRawBoneNode(boneName) ?? null;
}

function _applyPoseRotation(boneName, x, y, z) {
  const node = _getPoseBoneNode(boneName);
  if (!node) return;
  if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(z)) return;
  const PI2 = Math.PI * 2;
  x = ((x % PI2) + PI2) % PI2;
  y = ((y % PI2) + PI2) % PI2;
  z = ((z % PI2) + PI2) % PI2;
  const baseRot = _poseOverrides[boneName]?.base ?? node.rotation.clone();
  if (!_poseOverrides[boneName]) {
    _poseOverrides[boneName] = { base: baseRot, x: 0, y: 0, z: 0 };
  }
  _poseOverrides[boneName].x = x;
  _poseOverrides[boneName].y = y;
  _poseOverrides[boneName].z = z;
  node.rotation.set(
    THREE.MathUtils.degToRad(x),
    THREE.MathUtils.degToRad(y),
    THREE.MathUtils.degToRad(z),
  );
  node.updateMatrixWorld(true);
}

function _poseReadCurrentValues(boneName) {
  if (!boneName) return { x: 0, y: 0, z: 0 };
  const node = _getPoseBoneNode(boneName);
  if (!node) return { x: 0, y: 0, z: 0 };
  const saved = _poseOverrides[boneName];
  if (saved) return { x: saved.x, y: saved.y, z: saved.z };
  return {
    x: THREE.MathUtils.radToDeg(node.rotation.x),
    y: THREE.MathUtils.radToDeg(node.rotation.y),
    z: THREE.MathUtils.radToDeg(node.rotation.z),
  };
}

function _poseUpdateSliders(boneName) {
  if (!boneName || typeof boneName !== 'string') return;
  const vals = _poseReadCurrentValues(boneName);
  for (const axis of ['x', 'y', 'z']) {
    const slider = document.getElementById(`pose-slider-${axis}`);
    const num = document.getElementById(`pose-num-${axis}`);
    if (slider) slider.value = (Number.isFinite(vals[axis]) ? vals[axis] : 0).toFixed(1);
    if (num) num.value = (Number.isFinite(vals[axis]) ? vals[axis] : 0).toFixed(1);
  }
  // active state
  document.querySelectorAll('.pose-bone-btn').forEach((b) => {
    b.classList.toggle('is-active', b.dataset.boneName === boneName);
  });
}

function _poseRenderBoneList(cat) {
  if (!cat || typeof cat !== 'string') return;
  const listEl = document.getElementById('pose-bone-list');
  if (!listEl) return;
  listEl.innerHTML = '';
  const bones = POSE_BONE_CATEGORIES[cat] ?? [];
  const humanoid = currentVrm?.humanoid;
  for (const boneName of bones) {
    const node = humanoid?.getRawBoneNode(boneName);
    if (!node) continue;
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'pose-bone-btn';
    btn.textContent = POSE_BONE_LABELS[boneName] ?? boneName;
    btn.dataset.boneName = boneName;
    if (_poseOverrides[boneName]) btn.classList.add('is-modified');
    btn.addEventListener('click', () => {
      _poseCurrentBone = boneName;
      _poseUpdateSliders(boneName);
    });
    listEl.appendChild(btn);
  }
  if (listEl.children.length === 0) {
    listEl.innerHTML = '<span class="help-text" style="font-size:10px">このモデルにはボーンがありません</span>';
  }
}

// カテゴリボタン
document.querySelectorAll('.pose-cat-btn').forEach((btn) => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.pose-cat-btn').forEach((b) => b.classList.remove('is-active'));
    btn.classList.add('is-active');
    _poseCurrentCat = btn.dataset.cat;
    _poseRenderBoneList(_poseCurrentCat);
  });
});

// XYZスライダー同期
for (const axis of ['x', 'y', 'z']) {
  const slider = document.getElementById(`pose-slider-${axis}`);
  const num = document.getElementById(`pose-num-${axis}`);
  const sync = (v) => {
    if (slider) slider.value = v;
    if (num) num.value = parseFloat(v).toFixed(1);
    const vals = {
      x: parseFloat(document.getElementById('pose-slider-x')?.value ?? 0),
      y: parseFloat(document.getElementById('pose-slider-y')?.value ?? 0),
      z: parseFloat(document.getElementById('pose-slider-z')?.value ?? 0),
    };
    _applyPoseRotation(_poseCurrentBone, vals.x, vals.y, vals.z);
    // modified badge
    document.querySelectorAll('.pose-bone-btn').forEach((b) => {
      if (b.dataset.boneName === _poseCurrentBone) {
        b.classList.toggle('is-modified', _poseOverrides[_poseCurrentBone] !== undefined);
      }
    });
  };
  slider?.addEventListener('input', () => sync(slider.value));
  num?.addEventListener('input', () => sync(num.value));
  num?.addEventListener('change', () => sync(num.value));
}

// 選択ボーンリセット
document.getElementById('pose-reset-bone-btn')?.addEventListener('click', () => {
  delete _poseOverrides[_poseCurrentBone];
  const node = _getPoseBoneNode(_poseCurrentBone);
  if (node) node.rotation.set(0, 0, 0);
  _poseUpdateSliders(_poseCurrentBone);
  document.querySelectorAll('.pose-bone-btn').forEach((b) => {
    if (b.dataset.boneName === _poseCurrentBone) b.classList.remove('is-modified');
  });
});

// 全ボーンリセット
document.getElementById('pose-reset-all-btn')?.addEventListener('click', () => {
  Object.keys(_poseOverrides).forEach((boneName) => {
    const node = _getPoseBoneNode(boneName);
    if (node) node.rotation.set(0, 0, 0);
  });
  Object.keys(_poseOverrides).forEach((k) => delete _poseOverrides[k]);
  _poseUpdateSliders(_poseCurrentBone);
  document.querySelectorAll('.pose-bone-btn').forEach((b) => b.classList.remove('is-modified'));
});

// ポーズ保存 (JSON)
document.getElementById('pose-save-btn')?.addEventListener('click', () => {
  const poseData = {};
  Object.keys(_poseOverrides).forEach((boneName) => {
    const o = _poseOverrides[boneName];
    if (o) poseData[boneName] = { x: o.x, y: o.y, z: o.z };
  });
  const json = JSON.stringify({ version: 1, pose: poseData }, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `pose_${Date.now()}.json`;
  a.click();
  URL.revokeObjectURL(url);
});

// ポーズ読込 (JSON)
document.getElementById('pose-load-btn')?.addEventListener('click', () => {
  document.getElementById('pose-load-input')?.click();
});
document.getElementById('pose-load-input')?.addEventListener('change', (e) => {
  const file = e.target.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (ev) => {
    try {
      const data = JSON.parse(ev.target.result);
      const pose = data.pose ?? data;
      Object.keys(pose).forEach((boneName) => {
        const { x = 0, y = 0, z = 0 } = pose[boneName];
        _applyPoseRotation(boneName, x, y, z);
      });
      _poseRenderBoneList(_poseCurrentCat);
      _poseUpdateSliders(_poseCurrentBone);
    } catch (err) {
      console.warn('[PoseLoad]', err);
    }
  };
  reader.readAsText(file);
  e.target.value = '';
});

// panel open → ボーンリストを再描画
document.getElementById('pose-editor-panel')?.addEventListener('toggle', (e) => {
  if (e.newState === 'open' || e.target?.open) {
    _poseRenderBoneList(_poseCurrentCat);
    _poseUpdateSliders(_poseCurrentBone);
  }
});

// モデル切替後にポーズリストを再描画
{
  const modelNameEl = document.getElementById('model-name');
  if (modelNameEl) {
    new MutationObserver(() => {
      Object.keys(_poseOverrides).forEach((k) => delete _poseOverrides[k]);
      _poseRenderBoneList(_poseCurrentCat);
    }).observe(modelNameEl, { childList: true, characterData: true, subtree: true });
  }
}

// ═══════════════════════════════════════════════════════════════════
// [Feature 3] VRMエクスポート (CharacterStudio参考実装)
// ═══════════════════════════════════════════════════════════════════
(function () {
  const exportBtn = document.getElementById('vrm-export-btn');
  const statusEl = document.getElementById('vrm-export-status');

  function _setExportStatus(msg, type = '') {
    if (!statusEl) return;
    statusEl.textContent = String(msg ?? '').slice(0, 200);
    statusEl.classList.remove('is-hidden', 'is-error', 'is-success', 'is-warn');
    if (type && typeof type === 'string') statusEl.classList.add(type);
  }

  exportBtn?.addEventListener('click', async () => {
    if (!currentVrm?.scene) {
      _setExportStatus('モデルが読み込まれていません', 'is-error');
      return;
    }
    // ヒューマノイドアーマチュア検証（hipsボーンが必須）
    const hipsNode = currentVrm.humanoid?.getRawBoneNode('hips');
    if (!hipsNode) {
      _setExportStatus('エラー: ヒューマノイドアーマチュアが不完全です（hipsボーンが見つかりません）', 'is-error');
      return;
    }

    exportBtn.disabled = true;
    _setExportStatus('エクスポート準備中…');

    try {
      // エクスポート対象: VRM本体 + 衣装パーツ（チェック時）
      const includeOutfits = document.getElementById('vrm-export-with-outfits')?.checked ?? true;
      let exportTarget = currentVrm.scene;

      if (includeOutfits) {
        // 全パーツを含む一時グループを作成
        const group = new THREE.Group();
        group.add(currentVrm.scene.clone());
        // scene内の衣装オブジェクト(cloth slot等)を探して追加
        scene.traverse((obj) => {
          if (obj !== currentVrm.scene && obj.userData?.isClothSlot) {
            group.add(obj.clone());
          }
        });
        exportTarget = group.children.length > 1 ? group : currentVrm.scene;
      }

      _setExportStatus('GLTFシリアライズ中…');
      const buffer = await exportObjectToGlbBuffer(exportTarget);

      // .glb → .vrm として配布 (VRMはGLBのスーパーセット)
      const blob = new Blob([buffer], { type: 'model/gltf-binary' });
      const url = URL.createObjectURL(blob);
      const basename = currentModelLabel?.replace(/\.[^.]+$/, '') || 'export';
      const a = document.createElement('a');
      a.href = url;
      a.download = `${sanitizeFilename(basename)}_export.vrm`;
      a.click();
      URL.revokeObjectURL(url);

      _setExportStatus(`✓ エクスポート完了: ${basename}_export.vrm`, 'is-success');
      setTimeout(() => statusEl?.classList.add('is-hidden'), 4000);
    } catch (err) {
      console.error('[VRMExport]', err);
      _setExportStatus(`エラー: ${err.message ?? err}`, 'is-error');
    } finally {
      exportBtn.disabled = false;
    }
  });
})();

// ── 自動保存 (30秒ごと、アクティブプロジェクトがある場合のみ) ────────────────
(function _initAutoSave() {
  const AUTO_SAVE_INTERVAL_MS = 30_000;
  let _autoSaveTimer = null;

  function _doAutoSave() {
    const activeId = getActiveProjectId();
    if (!activeId) return;
    if (!scenePresetDirty) return;
    try {
      saveCurrentSceneToProject(activeId);
      setScenePresetDirty(false);
      console.debug('[AutoSave] 自動保存完了:', new Date().toLocaleTimeString());
    } catch (err) {
      console.warn('[AutoSave] 自動保存失敗:', err);
    }
  }

  // ページが表示状態に戻ったときも保存（バックグラウンド中の変更を確実に保存）
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible' && typeof _doAutoSave === 'function') _doAutoSave();
  });

  _autoSaveTimer = setInterval(_doAutoSave, AUTO_SAVE_INTERVAL_MS);
})();

/* ════════════════════════════════════════════════════════════════
   [166-200] JS拡張パック — 次の35件
   ════════════════════════════════════════════════════════════════ */

// ── [166] Ctrl+R → 録画トグル ──────────────────────────────────
document.addEventListener('keydown', (e) => {
  if ((e.ctrlKey || e.metaKey) && e.key === 'r') {
    const el = document.activeElement;
    if (!el) return;
    const tag = el.tagName;
    if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || el.isContentEditable) return;
    e.preventDefault();
    if (typeof recIsRecording !== 'undefined' && recIsRecording) stopRecording();
    else if (typeof startRecordingWithCountdown === 'function') startRecordingWithCountdown();
  }
});

// ── [167] ステータスバー クリックでコピー / 履歴ポップアップ ──
{
  const _statusHistory = [];
  const MAX_HISTORY = 20;

  const origSetStatus = window._origSetStatus ?? setStatus;
  function patchedSetStatus(message, type = '') {
    const ts = new Date().toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    _statusHistory.unshift({ ts, message: String(message ?? '').slice(0, 300), type: String(type ?? '') });
    if (_statusHistory.length > MAX_HISTORY) _statusHistory.pop();
    return origSetStatus(message, type);
  }
  // setStatus はこのスコープより上で定義済みなので直接上書きしない
  // 代わりにsetActionLog呼び出しをhookする形で履歴だけ収集する

  let _historyPopup = null;
  let _historyVisible = false;

  function showStatusHistory() {
    if (!Array.isArray(_statusHistory)) return;
    if (!_historyPopup) {
      _historyPopup = document.createElement('div');
      _historyPopup.id = 'status-history-popup';
      document.body.appendChild(_historyPopup);
    }
    _historyPopup.innerHTML = _statusHistory
      .slice(0, 15)
      .map(({ ts, message, type }) => {
        const cls = type === 'error' || message.includes('エラー') ? 'is-error'
                  : type === 'success' || message.startsWith('✅') ? 'is-success' : '';
        return `<div class="status-history-item"><span class="status-history-ts">${ts}</span><span class="status-history-msg ${cls}">${message}</span></div>`;
      })
      .join('');
    _historyPopup.style.display = 'block';
    _historyVisible = true;
  }

  function hideStatusHistory() {
    if (_historyPopup) _historyPopup.style.display = 'none';
    _historyVisible = false;
  }

  statusEl?.addEventListener('click', () => {
    if (_historyVisible) { hideStatusHistory(); return; }
    // テキストをクリップボードにコピー
    const text = statusEl.textContent?.trim();
    if (text) navigator.clipboard?.writeText(text).catch(() => {});
    if (_statusHistory.length > 0) showStatusHistory();
  });

  // 外クリックで閉じる
  document.addEventListener('click', (e) => {
    if (_historyVisible && !statusEl?.contains(e.target) && !_historyPopup?.contains(e.target)) {
      hideStatusHistory();
    }
  });

  // setStatusをラップして履歴収集
  const _origSetStatusFn = setStatus;
  window.setStatus = function(message, type = '') {
    const ts = new Date().toLocaleTimeString('ja-JP', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    _statusHistory.unshift({ ts, message, type });
    if (_statusHistory.length > MAX_HISTORY) _statusHistory.pop();
    return _origSetStatusFn(message, type);
  };
}

// ── [168] 自動保存インジケーターフラッシュ ─────────────────────
{
  function showAutosaveIndicator() {
    let el = document.getElementById('autosave-indicator');
    if (!el) {
      try {
        el = document.createElement('div');
        el.id = 'autosave-indicator';
        el.setAttribute('aria-live', 'polite');
        el.textContent = '✓ 保存済み';
        document.body.appendChild(el);
      } catch { return; }
    }
    try { el.classList.add('is-visible'); } catch { return; }
    clearTimeout(el._timer);
    el._timer = setTimeout(() => { try { el.classList.remove('is-visible'); } catch {} }, 1800);
  }

  // Ctrl+S 保存時にインジケーターを表示
  document.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 's') {
      setTimeout(showAutosaveIndicator, 200);
    }
  });
  sceneSaveBtn?.addEventListener('click', () => setTimeout(showAutosaveIndicator, 200));
}

// ── [169] ドラッグオーバー キャンバスに is-drag-over クラス ──
// (viewportEl に追加済みだがキャンバス自体にも追加する)
{
  const cvs = canvas ?? document.getElementById('three-canvas');
  if (cvs) {
    window.addEventListener('dragenter', (e) => {
      if (e.dataTransfer?.types?.includes('Files')) cvs.classList.add('is-drag-over');
    });
    window.addEventListener('dragleave', (e) => {
      if (!e.relatedTarget || e.relatedTarget === document.documentElement) {
        cvs.classList.remove('is-drag-over');
      }
    });
    window.addEventListener('drop', () => cvs.classList.remove('is-drag-over'));
  }
}

// ── [170] Ctrl+V キャンバスにフォーカス時 VRM URL ペースト ───
document.addEventListener('paste', async (e) => {
  const tag = document.activeElement?.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA') return;
  const text = e.clipboardData?.getData('text/plain')?.trim() ?? '';
  if (!text) return;
  if (/^https?:\/\/.+\.(vrm|glb)(\?|$)/i.test(text)) {
    e.preventDefault();
    setStatus(`URL貼付: ${text.slice(0, 60)}`);
    try { await loadModelFromUrl(text); }
    catch (err) { setStatus(`URL読込失敗: ${err.message}`, 'error'); }
  }
});

// ── [171] LLM メッセージ コピーボタン動的追加 ────────────────
{
  const chatHistory = document.querySelector('#llm-chat-history');
  if (chatHistory) {
    const observer = new MutationObserver((mutations) => {
      mutations.forEach((m) => {
        m.addedNodes.forEach((node) => {
          if (node.nodeType !== 1) return;
          const bubble = node.querySelector?.('.llm-msg-bubble') ?? (node.classList?.contains('llm-msg-bubble') ? node : null);
          if (!bubble) return;
          if (bubble.querySelector('.llm-msg-copy')) return;
          const btn = document.createElement('button');
          btn.className = 'llm-msg-copy';
          btn.textContent = '⎘';
          btn.title = 'コピー';
          btn.addEventListener('click', async (e) => {
            e.stopPropagation();
            const text = bubble.textContent?.replace(btn.textContent, '').trim() ?? '';
            try {
              await navigator.clipboard.writeText(text);
              btn.textContent = '✓';
              btn.classList.add('is-copied');
              setTimeout(() => { btn.textContent = '⎘'; btn.classList.remove('is-copied'); }, 1500);
            } catch {}
          });
          bubble.style.position = 'relative';
          bubble.appendChild(btn);
        });
      });
    });
    observer.observe(chatHistory, { childList: true, subtree: true });
  }
}

// ── [172] パネルスクロール位置 保存/復元 ───────────────────────
{
  const SCROLL_KEYS = {
    'asset-panel-body': 'panel_scroll_asset',
    'prop-panel-body': 'panel_scroll_prop',
  };
  Object.entries(SCROLL_KEYS).forEach(([id, key]) => {
    const el = document.getElementById(id);
    if (!el) return;
    const saved = sessionStorage.getItem(key);
    if (saved) el.scrollTop = Number(saved);
    el.addEventListener('scroll', () => {
      sessionStorage.setItem(key, String(el.scrollTop));
    }, { passive: true });
  });
}

// ── [173] details 開閉状態を localStorage に保存 ────────────────
{
  document.querySelectorAll('details[id]').forEach((det) => {
    const key = `details_open_${det.id}`;
    const saved = localStorage.getItem(key);
    if (saved === 'true') det.open = true;
    else if (saved === 'false') det.open = false;
    det.addEventListener('toggle', () => {
      localStorage.setItem(key, String(det.open));
    });
  });
}

// ── [174] ツールチップ システム (title属性をhoverで表示) ────────
{
  let _tip = null;
  let _tipTimer = null;

  function getTip() {
    if (!_tip) {
      try {
        _tip = document.createElement('div');
        _tip.className = 'tip tip-hidden';
        _tip.setAttribute('role', 'tooltip');
        _tip.setAttribute('aria-hidden', 'true');
        document.body.appendChild(_tip);
      } catch { return null; }
    }
    return _tip;
  }

  document.addEventListener('mouseover', (e) => {
    const target = e.target.closest('[title]');
    if (!target) return;
    const text = target.getAttribute('title');
    if (!text || text.length < 2) return;
    clearTimeout(_tipTimer);
    _tipTimer = setTimeout(() => {
      const tip = getTip();
      if (!tip) return;
      tip.textContent = String(text ?? '').slice(0, 200);
      tip.classList.remove('tip-hidden');
      // position
      const rect = target.getBoundingClientRect();
      tip.style.left = `${Math.min(rect.left + rect.width / 2, window.innerWidth - 270)}px`;
      tip.style.top = `${rect.top - 6}px`;
      tip.style.transform = 'translate(-50%, -100%)';
    }, 600);
  });

  document.addEventListener('mouseout', (e) => {
    const target = e.target.closest('[title]');
    if (!target) return;
    clearTimeout(_tipTimer);
    if (_tip) _tip.classList.add('tip-hidden');
  });

  document.addEventListener('click', () => {
    clearTimeout(_tipTimer);
    if (_tip) _tip.classList.add('tip-hidden');
  });
}

// ── [175] 数値入力 マウスホイールスクロールで値変更 ────────────
document.addEventListener('wheel', (e) => {
  const el = e.target;
  if (el.tagName !== 'INPUT' || el.type !== 'number') return;
  if (document.activeElement !== el) return;
  e.preventDefault();
  const step = Number(el.step) || 1;
  const dir = e.deltaY < 0 ? 1 : -1;
  const cur = Number(el.value) || 0;
  const min = el.min !== '' ? Number(el.min) : -Infinity;
  const max = el.max !== '' ? Number(el.max) : Infinity;
  el.value = String(Math.min(max, Math.max(min, cur + step * dir)));
  el.dispatchEvent(new Event('input', { bubbles: true }));
  el.dispatchEvent(new Event('change', { bubbles: true }));
}, { passive: false });

// ── [176] textarea 自動リサイズ (行数に応じて高さ変更) ─────────
document.addEventListener('input', (e) => {
  const el = e.target;
  if (el.tagName !== 'TEXTAREA' || el.dataset.noAutoresize) return;
  el.style.height = 'auto';
  const minH = parseInt(getComputedStyle(el).minHeight) || 0;
  el.style.height = `${Math.max(minH, el.scrollHeight)}px`;
}, { passive: true });

// ── [177] モーションカード コンテキストメニュー ──────────────
{
  let _ctxMenu = null;

  function getCtxMenu() {
    if (!_ctxMenu) {
      _ctxMenu = document.createElement('div');
      _ctxMenu.id = 'ctx-menu';
      _ctxMenu.style.display = 'none';
      document.body.appendChild(_ctxMenu);
    }
    return _ctxMenu;
  }

  function showCtxMenu(x, y, items) {
    if (!Array.isArray(items) || items.length === 0) return;
    const menu = getCtxMenu();
    if (!menu) return;
    menu.innerHTML = items.filter(Boolean).map(item =>
      item.divider
        ? `<div class="ctx-divider"></div>`
        : `<div class="ctx-item${item.danger ? ' is-danger' : ''}" data-action="${escapeHtml(String(item.action ?? ''))}">
             <span class="ctx-item-icon" aria-hidden="true">${String(item.icon ?? '')}</span>${escapeHtml(String(item.label ?? ''))}
           </div>`
    ).join('');
    const safeX = Math.max(4, Math.min(x, window.innerWidth - 180));
    const safeY = Math.max(4, Math.min(y, window.innerHeight - 10));
    menu.style.left = `${safeX}px`;
    menu.style.top = `${safeY}px`;
    menu.style.display = 'block';
    return menu;
  }

  function hideCtxMenu() { if (_ctxMenu) { try { _ctxMenu.style.display = 'none'; } catch {} } }

  document.addEventListener('click', (e) => { if (!_ctxMenu?.contains(e.target)) hideCtxMenu(); });
  document.addEventListener('keydown', (e) => { if (e.key === 'Escape') hideCtxMenu(); });

  motionLibraryEl?.addEventListener('contextmenu', async (e) => {
    const card = e.target.closest('[data-motion-url]');
    if (!card) return;
    e.preventDefault();
    const url = card.dataset.motionUrl;
    const isFav = isMotionFavorite(url);
    const isLoop = getMotionLoopEnabled(url);

    const menu = showCtxMenu(e.clientX, e.clientY, [
      { action: 'play',  icon: '▶', label: '再生' },
      { action: 'select', icon: '☑', label: '選択' },
      { divider: true },
      { action: 'fav',   icon: isFav ? '★' : '☆', label: isFav ? 'お気に入り解除' : 'お気に入り追加' },
      { action: 'loop',  icon: '🔁', label: isLoop ? 'ループ OFF' : 'ループ ON' },
      { divider: true },
      { action: 'copy-url', icon: '⎘', label: 'URLをコピー' },
    ]);

    menu.addEventListener('click', async (ev) => {
      const item = ev.target.closest('.ctx-item');
      if (!item) return;
      hideCtxMenu();
      const action = item.dataset.action;
      if (action === 'play') {
        selectBodyMotion(url);
        try { await playSelectedBodyMotion(); } catch {}
      } else if (action === 'select') {
        selectBodyMotion(url);
      } else if (action === 'fav') {
        setMotionFavorite(url, !isFav);
        updateMotionDetailUi();
        renderMotionLibrary();
      } else if (action === 'loop') {
        setMotionLoopEnabled(url, !isLoop);
        updateMotionDetailUi();
        renderMotionLibrary();
        if (currentMotionUrl === url && currentAction) syncCurrentActionLoopMode();
      } else if (action === 'copy-url') {
        await navigator.clipboard.writeText(url).catch(() => {});
        setStatus('URLをコピーしました');
      }
    }, { once: true });
  });
}

