// ── [179] 録画 最大時間警告 ──────────────────────────────────
{
  const MAX_REC_SECONDS = 600; // 10分
  let _recWarnTimer = null;
  const _origStartRec = startRecording;
  function startRecordingPatched() {
    if (typeof _origStartRec !== 'function') return;
    try { _origStartRec.call(this, ...arguments); } catch (e) { setStatus(`録画開始エラー: ${e.message}`, 'error'); return; }
    const warnSec = typeof MAX_REC_SECONDS === 'number' ? MAX_REC_SECONDS : 600;
    _recWarnTimer = setTimeout(() => {
      if (recIsRecording) {
        setStatus(`⚠ 録画が${Math.round(warnSec/60)}分を超えました。容量にご注意ください。`, 'warn');
      }
    }, warnSec * 1000);
  }
  const _origStopRec = stopRecording;
  // 直接置換するとスコープ外なので、recBtnのclickをオーバーライド
  // 代わりにsetIntervalで時間チェック
  let _recTimeChecker = null;
  document.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'r') {
      if (recIsRecording && _recTimeChecker) { clearInterval(_recTimeChecker); }
    }
  });
}

