// ── [187] FPS スパークライン (簡易 10秒バッファ) ─────────────────
{
  const FPS_BUFFER_SIZE = 60;
  const _fpsBuf = [];
  const _origFpsUpdate = window._fpsUpdateHook;

  // fpsCounterEl への書き込みをオブザーブして値を取得
  if (fpsCounterEl) {
    const fpsMo = new MutationObserver(() => {
      const text = fpsCounterEl.textContent;
      const val = parseFloat(text.replace('FPS:', '').trim());
      if (!isNaN(val)) {
        _fpsBuf.push(val);
        if (_fpsBuf.length > FPS_BUFFER_SIZE) _fpsBuf.shift();
      }
    });
    fpsMo.observe(fpsCounterEl, { characterData: true, subtree: true, childList: true });
  }

  // FPS平均をtitle属性で表示
  if (fpsCounterEl) {
    fpsCounterEl.style.cursor = 'default';
    fpsCounterEl.addEventListener('mouseenter', () => {
      if (_fpsBuf.length === 0) return;
      const avg = (_fpsBuf.reduce((a, b) => a + b, 0) / _fpsBuf.length).toFixed(1);
      const min = Math.min(..._fpsBuf).toFixed(1);
      const max = Math.max(..._fpsBuf).toFixed(1);
      fpsCounterEl.title = `平均: ${avg} / 最小: ${min} / 最大: ${max}`;
    });
  }
}

