// ── [190] range スライダー --range-fill CSS カスタムプロパティ更新 ─
{
  function updateRangeFill(slider) {
    if (!slider) return;
    const min = Number(slider.min ?? 0);
    const max = Number(slider.max ?? 100);
    const val = Number(slider.value ?? 0);
    if (!Number.isFinite(min) || !Number.isFinite(max) || !Number.isFinite(val)) return;
    const range = max - min;
    const pct = range > 0 ? ((val - min) / range) * 100 : 0;
    slider.style.setProperty('--range-fill', `${Math.max(0, Math.min(100, pct)).toFixed(2)}%`);
  }

  document.querySelectorAll('input[type="range"]').forEach(updateRangeFill);

  document.addEventListener('input', (e) => {
    if (e.target.type === 'range') updateRangeFill(e.target);
  }, { passive: true });

  // MutationObserverで後から追加されるスライダーにも対応 (ガード付き)
  const _rangeMo = new MutationObserver((mutations) => {
    mutations.forEach((m) => {
      m.addedNodes.forEach((n) => {
        if (n.nodeType !== 1) return;
        n.querySelectorAll?.('input[type="range"]').forEach(updateRangeFill);
        if (n.tagName === 'INPUT' && n.type === 'range') updateRangeFill(n);
      });
    });
  });
  _rangeMo.observe(document.body, { childList: true, subtree: true });
}

