// ── [196] フォーカストラップ: モーダル表示中のTab循環 ───────────
{
  function trapFocus(modalEl) {
    if (!modalEl || typeof modalEl.addEventListener !== 'function') return;
    const FOCUSABLE = 'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])';
    modalEl.addEventListener('keydown', (e) => {
      if (e.key !== 'Tab') return;
      const focusable = [...modalEl.querySelectorAll(FOCUSABLE)].filter(el => !el.disabled && el.offsetParent !== null);
      if (focusable.length === 0) return;
      const first = focusable[0];
      const last = focusable[focusable.length - 1];
      if (e.shiftKey) {
        if (document.activeElement === first) { e.preventDefault(); last.focus(); }
      } else {
        if (document.activeElement === last) { e.preventDefault(); first.focus(); }
      }
    });
  }

  // プロジェクトモーダル
  const projModal = document.getElementById('project-modal-dialog') ?? document.querySelector('.project-modal-dialog');
  if (projModal) trapFocus(projModal);
}

