// ── [251] Undo/Redo スタック（ブレンドシェイプ値）────────────────
{
  const BS_UNDO_MAX = 40;
  let _bsUndoStack = [];
  let _bsRedoStack = [];

  function _captureBsState() {
    const vrm = window.currentVrm ?? currentVrm;
    if (!vrm) return null;
    const state = {};
    try {
      const em = vrm.expressionManager;
      if (!em || typeof em.getValue !== 'function') return null;
      const names = em.expressionMap ? Object.keys(em.expressionMap) : (em.expressionNames ?? []);
      for (const n of names) {
        if (typeof n === 'string' && n.length > 0) {
          const v = em.getValue(n);
          if (Number.isFinite(v)) state[n] = v;
        }
      }
    } catch { return null; }
    return Object.keys(state).length > 0 ? state : null;
  }

  window.bsPushUndo = function() {
    if (!window.currentVrm) return;
    const s = _captureBsState();
    if (!s || Object.keys(s).length === 0) return;
    _bsUndoStack.push(s);
    if (_bsUndoStack.length > BS_UNDO_MAX) _bsUndoStack.shift();
    _bsRedoStack = [];
  };

  window.bsUndo = function() {
    if (_bsUndoStack.length === 0) { setStatus('元に戻す: 履歴がありません', 'warn'); return; }
    const cur = _captureBsState();
    if (cur) _bsRedoStack.push(cur);
    const prev = _bsUndoStack.pop();
    if (!prev) return;
    _applyBsState(prev);
    setStatus(`ブレンドシェイプ: 元に戻した (残り${_bsUndoStack.length})`);
  };

  window.bsRedo = function() {
    if (_bsRedoStack.length === 0) { setStatus('やり直し: 履歴がありません', 'warn'); return; }
    const cur = _captureBsState();
    if (cur) _bsUndoStack.push(cur);
    const next = _bsRedoStack.pop();
    if (!next) return;
    _applyBsState(next);
    setStatus(`ブレンドシェイプ: やり直した (残り${_bsRedoStack.length})`);
  };

  function _applyBsState(state) {
    if (!window.currentVrm || !state || typeof state !== 'object') return;
    try {
      const em = window.currentVrm.expressionManager;
      if (!em || typeof em.setValue !== 'function') return;
      for (const [n, v] of Object.entries(state)) {
        if (typeof n === 'string') em.setValue(n, clampNumber(Number(v) || 0, 0, 1));
      }
      if (typeof updateBlendShapeUI === 'function') updateBlendShapeUI();
    } catch (e) { console.warn('[BS] applyBsState error:', e); }
  }

  document.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && !e.shiftKey && e.key === 'z') { e.preventDefault(); window.bsUndo(); }
    if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'Z') { e.preventDefault(); window.bsRedo(); }
  });
}

// ── [252] モーション再生キュー（連続再生）──────────────────────
{
  window._motionQueue = [];
  window._motionQueuePlaying = false;

  window.enqueueMotion = function(url) {
    if (!url || typeof url !== 'string') { console.warn('[motionQueue] invalid url'); return; }
    if (window._motionQueue.length >= 50) { setStatus('モーションキューが満杯です (最大50件)', 'warn'); return; }
    window._motionQueue.push(url.slice(0, 2048));
    if (!window._motionQueuePlaying) _playNextInQueue();
  };

  window.clearMotionQueue = function() {
    const count = Array.isArray(window._motionQueue) ? window._motionQueue.length : 0;
    window._motionQueue = [];
    window._motionQueuePlaying = false;
    if (count > 0) setStatus(`モーションキュー: ${count}件クリア`, 'success');
  };

  function _playNextInQueue() {
    if (window._motionQueue.length === 0) {
      window._motionQueuePlaying = false;
      setStatus('モーションキュー: 完了', 'success');
      return;
    }
    window._motionQueuePlaying = true;
    const url = window._motionQueue.shift();
    if (!url || typeof url !== 'string') { _playNextInQueue(); return; }
    if (typeof loadMotion === 'function') {
      loadMotion(url);
      setStatus(`キュー再生: ${url.split('/').pop()}`);
    }
  }

  // モーション終了イベントを監視してキューを進める
  document.addEventListener('motionEnded', () => {
    if (window._motionQueuePlaying && window._motionQueue.length > 0) {
      setTimeout(_playNextInQueue, 200);
    }
  });
}

// ── [253] VRMメタ情報をパネルに表示 ────────────────────────────
{
  window.renderVrmMeta = function(vrm) {
    const container = document.getElementById('vrm-meta-container') ?? document.querySelector('[data-section="vrm-meta"]');
    if (!container) return;
    const meta = vrm?.meta;
    if (!meta) { container.innerHTML = '<p style="color:var(--text-lo);font-size:11px">メタ情報なし</p>'; return; }
    const fields = [
      ['名前', meta.name],
      ['作者', meta.authors?.join(', ') ?? meta.author],
      ['バージョン', meta.version],
      ['ライセンス', meta.licenseName ?? meta.licenseUrl],
      ['連絡先', meta.contactInformation],
      ['参照', meta.references?.join(', ')],
    ];
    const rows = fields
      .filter(([, v]) => v)
      .map(([k, v]) => `<tr><td>${k}</td><td>${v}</td></tr>`)
      .join('');
    container.innerHTML = `<table class="vrm-meta-table">${rows}</table>`;
  };
}

// ── [254] ブレンドシェイプ プリセット 保存/読込 ────────────────
{
  const BS_PRESETS_KEY = 'vrmApp_bsPresets';

  window.saveBsPreset = function(name) {
    const state = _captureBsState?.() ?? null;
    if (!state) { setStatus('プリセット保存: VRMなし', 'warn'); return; }
    const presets = JSON.parse(localStorage.getItem(BS_PRESETS_KEY) ?? '{}');
    presets[name] = state;
    localStorage.setItem(BS_PRESETS_KEY, JSON.stringify(presets));
    setStatus(`表情プリセット保存: ${name}`, 'success');
    if (typeof renderBsPresets === 'function') renderBsPresets();
  };

  window.loadBsPreset = function(name) {
    const presets = JSON.parse(localStorage.getItem(BS_PRESETS_KEY) ?? '{}');
    const state = presets[name];
    if (!state) { setStatus(`プリセット未存在: ${name}`, 'warn'); return; }
    if (typeof window.bsPushUndo === 'function') window.bsPushUndo();
    if (typeof _applyBsState === 'function') _applyBsState(state);
    setStatus(`表情プリセット適用: ${name}`, 'success');
  };

  window.deleteBsPreset = function(name) {
    const presets = JSON.parse(localStorage.getItem(BS_PRESETS_KEY) ?? '{}');
    delete presets[name];
    localStorage.setItem(BS_PRESETS_KEY, JSON.stringify(presets));
    setStatus(`プリセット削除: ${name}`);
    if (typeof renderBsPresets === 'function') renderBsPresets();
  };

  window.getBsPresets = function() {
    return JSON.parse(localStorage.getItem(BS_PRESETS_KEY) ?? '{}');
  };
}

// ── [255] カメラ スムーズ補間アニメーション ────────────────────
{
  window.animateCameraTo = function(targetPos, targetTarget, durationMs = 600) {
    const cam = window.camera;
    const ctrl = window.orbitControls ?? window.controls;
    if (!cam || !ctrl) return;

    const startPos = cam.position.clone();
    const startTarget = ctrl.target.clone();
    const endPos = targetPos.clone ? targetPos.clone() : new THREE.Vector3(...targetPos);
    const endTgt = targetTarget.clone ? targetTarget.clone() : new THREE.Vector3(...targetTarget);

    const startTime = performance.now();

    function easeInOut(t) { return t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t; }

    function step(now) {
      const t = Math.min((now - startTime) / durationMs, 1);
      const e = easeInOut(t);
      cam.position.lerpVectors(startPos, endPos, e);
      ctrl.target.lerpVectors(startTarget, endTgt, e);
      ctrl.update();
      if (t < 1) requestAnimationFrame(step);
    }
    requestAnimationFrame(step);
  };
}

// ── [256] キーボードショートカット一覧ダイアログ ─────────────────
{
  const SHORTCUTS = [
    ['Space', '再生 / 一時停止'],
    ['←  →', '1フレーム移動'],
    ['Shift+← →', '10フレーム移動'],
    ['S', 'スクリーンショット'],
    ['R', '録画 開始/停止 (Ctrl+R)'],
    ['T', 'TTS 読み上げ'],
    ['D', 'ダイアログ 表示/非表示'],
    ['L', 'ループ ON/OFF'],
    ['C', 'カメラプリセット 次へ'],
    ['H', 'パネル 表示/非表示'],
    ['B', 'ボーンデバッグ'],
    ['Escape', '選択解除 / モーダル閉じる'],
    ['Ctrl+Z', 'ブレンドシェイプ 元に戻す'],
    ['Ctrl+Shift+Z', 'ブレンドシェイプ やり直し'],
    ['Ctrl+V', 'VRM URL 貼り付けロード'],
    ['1-9', '表情プリセット (数字キー)'],
  ];

  window.showShortcutsDialog = function() {
    let dlg = document.getElementById('shortcuts-dialog');
    if (!dlg) {
      dlg = document.createElement('div');
      dlg.id = 'shortcuts-dialog';
      dlg.style.cssText = `
        position:fixed;inset:0;z-index:var(--z-modal);
        display:flex;align-items:center;justify-content:center;
        background:rgba(0,0,0,0.7);backdrop-filter:blur(4px)`;
      dlg.innerHTML = `
        <div style="background:var(--bg-panel);border:1px solid var(--border-mid);
          border-radius:10px;padding:20px;max-width:420px;width:90%;
          box-shadow:0 20px 60px rgba(0,0,0,0.8)">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
            <span style="font-size:13px;font-weight:600;color:var(--text-hi)">キーボードショートカット</span>
            <button id="shortcuts-close" style="background:none;border:none;color:var(--text-mid);font-size:18px;cursor:pointer;line-height:1">×</button>
          </div>
          <table class="shortcut-table">
            ${SHORTCUTS.map(([k, d]) =>
              `<tr>
                <td><span class="shortcut-key">${k}</span></td>
                <td style="color:var(--text-mid);font-size:11px;padding-left:8px">${d}</td>
              </tr>`
            ).join('')}
          </table>
        </div>`;
      document.body.appendChild(dlg);
      document.getElementById('shortcuts-close').addEventListener('click', () => dlg.remove());
      dlg.addEventListener('click', (e) => { if (e.target === dlg) dlg.remove(); });
    } else {
      dlg.remove();
    }
  };

  document.addEventListener('keydown', (e) => {
    if (e.key === '?' && !e.ctrlKey && !e.metaKey) {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
      e.preventDefault();
      window.showShortcutsDialog();
    }
  });
}

// ── [257] モーションお気に入り localStorage 永続化 ─────────────
{
  const FAV_KEY = 'vrmApp_motionFavorites';

  window.getMotionFavorites = function() {
    try { return new Set(JSON.parse(localStorage.getItem(FAV_KEY) ?? '[]')); }
    catch { return new Set(); }
  };

  window.toggleMotionFavorite = function(motionId) {
    const favs = window.getMotionFavorites();
    const added = !favs.has(motionId);
    if (added) favs.add(motionId); else favs.delete(motionId);
    localStorage.setItem(FAV_KEY, JSON.stringify([...favs]));
    setStatus(added ? `★ お気に入り追加: ${motionId}` : `☆ お気に入り解除: ${motionId}`);
    if (typeof renderMotionLibrary === 'function') renderMotionLibrary();
    return added;
  };

  window.isMotionFavorite = function(motionId) {
    return window.getMotionFavorites().has(motionId);
  };
}

// ── [258] スクリーンショット バースト撮影 ──────────────────────
{
  window.burstScreenshot = async function(count = 3, intervalMs = 500) {
    if (typeof triggerScreenshotFlash !== 'function' || typeof takeScreenshot !== 'function') return;
    setStatus(`バースト撮影: ${count}枚`);
    for (let i = 0; i < count; i++) {
      triggerScreenshotFlash();
      await takeScreenshot();
      if (i < count - 1) await new Promise(r => setTimeout(r, intervalMs));
    }
    setStatus(`バースト撮影完了: ${count}枚`, 'success');
  };
}

// ── [259] パネル幅 ドラッグリサイズ ────────────────────────────
{
  const panel = document.getElementById('asset-panel');
  if (panel) {
    const handle = document.createElement('div');
    handle.className = 'panel-resize-handle';
    panel.style.position = 'relative';
    panel.appendChild(handle);

    let _dragging = false;
    let _startX = 0;
    let _startW = 0;

    handle.addEventListener('mousedown', (e) => {
      _dragging = true;
      _startX = e.clientX;
      _startW = panel.offsetWidth;
      handle.classList.add('is-dragging');
      document.body.style.userSelect = 'none';
      e.preventDefault();
    });

    document.addEventListener('mousemove', (e) => {
      if (!_dragging) return;
      const delta = e.clientX - _startX;
      const newW = Math.max(200, Math.min(600, _startW - delta));
      panel.style.width = newW + 'px';
      document.documentElement.style.setProperty('--panel-width', newW + 'px');
    });

    document.addEventListener('mouseup', () => {
      if (!_dragging) return;
      _dragging = false;
      handle.classList.remove('is-dragging');
      document.body.style.userSelect = '';
      localStorage.setItem('vrmApp_panelWidth', panel.offsetWidth);
    });

    const savedW = localStorage.getItem('vrmApp_panelWidth');
    if (savedW) {
      panel.style.width = savedW + 'px';
      document.documentElement.style.setProperty('--panel-width', savedW + 'px');
    }
  }
}

// ── [260] ポーズスナップショット 保存/復元 ──────────────────────
{
  const POSE_KEY = 'vrmApp_poseSnapshots';
  let _poseSnaps = JSON.parse(localStorage.getItem(POSE_KEY) ?? '{}');

  window.savePoseSnapshot = function(name) {
    if (!window.currentVrm) { setStatus('ポーズ保存: VRMなし', 'warn'); return; }
    try {
      const bones = {};
      window.currentVrm.humanoid?.humanBones && Object.entries(window.currentVrm.humanoid.humanBones).forEach(([boneName, bone]) => {
        const node = bone?.node;
        if (node) bones[boneName] = {
          rx: node.rotation.x, ry: node.rotation.y, rz: node.rotation.z, rw: node.rotation.w
        };
      });
      _poseSnaps[name] = { bones, ts: Date.now() };
      localStorage.setItem(POSE_KEY, JSON.stringify(_poseSnaps));
      setStatus(`ポーズ保存: ${name}`, 'success');
    } catch (err) { setStatus('ポーズ保存エラー', 'error'); }
  };

  window.loadPoseSnapshot = function(name) {
    const snap = _poseSnaps[name];
    if (!snap || !window.currentVrm) { setStatus('ポーズ復元: 失敗', 'warn'); return; }
    try {
      Object.entries(snap.bones).forEach(([boneName, rot]) => {
        const bone = window.currentVrm.humanoid?.humanBones?.[boneName]?.node;
        if (bone) bone.rotation.set(rot.rx, rot.ry, rot.rz, rot.rw);
      });
      setStatus(`ポーズ復元: ${name}`, 'success');
    } catch { setStatus('ポーズ復元エラー', 'error'); }
  };

  window.getPoseSnapshots = () => _poseSnaps;
  window.deletePoseSnapshot = function(name) {
    delete _poseSnaps[name];
    localStorage.setItem(POSE_KEY, JSON.stringify(_poseSnaps));
    setStatus(`ポーズ削除: ${name}`);
  };
}

