// ── [263] カメラ位置 Export/Import JSON ────────────────────────
{
  window.exportCameraState = function() {
    const cam = window.camera;
    const ctrl = window.orbitControls ?? window.controls;
    if (!cam) return null;
    const state = {
      position: cam.position.toArray(),
      target: ctrl?.target?.toArray() ?? [0, 1, 0],
      fov: cam.fov,
      zoom: cam.zoom,
    };
    const json = JSON.stringify(state, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `camera_${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(a.href);
    setStatus('カメラ設定をエクスポート', 'success');
    return state;
  };

  window.importCameraState = function(json) {
    try {
      const state = typeof json === 'string' ? JSON.parse(json) : json;
      const cam = window.camera;
      const ctrl = window.orbitControls ?? window.controls;
      if (!cam) return;
      if (state.position) cam.position.fromArray(state.position);
      if (state.target && ctrl) ctrl.target.fromArray(state.target);
      if (state.fov) { cam.fov = state.fov; cam.updateProjectionMatrix(); }
      if (state.zoom) cam.zoom = state.zoom;
      ctrl?.update();
      setStatus('カメラ設定をインポート', 'success');
    } catch { setStatus('カメラJSONパースエラー', 'error'); }
  };
}

// ── [264] ブレンドシェイプ ランダム表情 ───────────────────────
{
  window.randomFace = function(intensity = 0.5) {
    if (!window.currentVrm) return;
    if (typeof window.bsPushUndo === 'function') window.bsPushUndo();
    try {
      const em = window.currentVrm.expressionManager;
      if (!em) return;
      const SKIP = ['blink', 'blinkLeft', 'blinkRight', 'lookUp', 'lookDown', 'lookLeft', 'lookRight'];
      const names = em.expressionMap ? Object.keys(em.expressionMap).filter(n => !SKIP.includes(n)) : [];
      names.forEach(n => em.setValue(n, 0));
      const pick = names[Math.floor(Math.random() * names.length)];
      if (pick) em.setValue(pick, intensity + Math.random() * (1 - intensity));
      if (typeof updateBlendShapeUI === 'function') updateBlendShapeUI();
      setStatus(`ランダム表情: ${pick ?? '?'}`);
    } catch {}
  };
}

// ── [265] 環境光 色温度スライダー対応 ──────────────────────────
{
  const kelvinSlider = document.querySelector('#light-kelvin, [data-id="light-kelvin"]');
  if (kelvinSlider) {
    function kelvinToRgb(k) {
      if (!Number.isFinite(k) || k <= 0) k = 6500;
      k = Math.max(1000, Math.min(40000, k)) / 100;
      let r, g, b;
      r = k <= 66 ? 255 : 329.698727446 * Math.pow(k - 60, -0.1332047592);
      g = k <= 66 ? 99.4708025861 * Math.log(k) - 161.1195681661 : 288.1221695283 * Math.pow(k - 60, -0.0755148492);
      b = k >= 66 ? 255 : (k <= 19 ? 0 : 138.5177312231 * Math.log(k - 10) - 305.0447927307);
      return [Math.min(255, Math.max(0, r)), Math.min(255, Math.max(0, g)), Math.min(255, Math.max(0, b))];
    }
    kelvinSlider.addEventListener('input', () => {
      const [r, g, b] = kelvinToRgb(Number(kelvinSlider.value));
      const ambientLight = window.ambientLight ?? window.scene?.getObjectByName?.('ambientLight');
      if (ambientLight?.color) ambientLight.color.setRGB(r / 255, g / 255, b / 255);
      setStatus(`色温度: ${kelvinSlider.value}K`);
    });
  }
}

