// ── [272] モーションカード ソート（名前/カテゴリ/お気に入り）──
{
  const SORT_KEY = 'vrmApp_motionSort';
  window._motionSortMode = localStorage.getItem(SORT_KEY) ?? 'default';

  window.setMotionSort = function(mode) {
    window._motionSortMode = mode;
    localStorage.setItem(SORT_KEY, mode);
    if (typeof renderMotionLibrary === 'function') renderMotionLibrary();
    setStatus(`モーション並び替え: ${mode}`);
  };

  window.getMotionSortComparator = function() {
    switch (window._motionSortMode) {
      case 'name': return (a, b) => (a.displayName ?? a.label).localeCompare(b.displayName ?? b.label, 'ja');
      case 'category': return (a, b) => (a.category ?? '').localeCompare(b.category ?? '');
      case 'favorite': return (a, b) => {
        const af = window.isMotionFavorite?.(a.id) ? 0 : 1;
        const bf = window.isMotionFavorite?.(b.id) ? 0 : 1;
        return af - bf;
      };
      default: return null;
    }
  };
}

// ── [273] タイムライン マーカー追加/削除 ──────────────────────
{
  const MARKER_KEY = 'vrmApp_timelineMarkers';
  window._timelineMarkers = JSON.parse(localStorage.getItem(MARKER_KEY) ?? '[]');

  window.addTimelineMarker = function(time, label = '') {
    window._timelineMarkers.push({ time, label, id: Date.now() });
    window._timelineMarkers.sort((a, b) => a.time - b.time);
    localStorage.setItem(MARKER_KEY, JSON.stringify(window._timelineMarkers));
    if (typeof renderTimelineMarkers === 'function') renderTimelineMarkers();
    setStatus(`マーカー追加: ${label || time.toFixed(2)}s`);
  };

  window.removeTimelineMarker = function(id) {
    window._timelineMarkers = window._timelineMarkers.filter(m => m.id !== id);
    localStorage.setItem(MARKER_KEY, JSON.stringify(window._timelineMarkers));
    if (typeof renderTimelineMarkers === 'function') renderTimelineMarkers();
    setStatus('マーカー削除');
  };

  window.clearTimelineMarkers = function() {
    window._timelineMarkers = [];
    localStorage.removeItem(MARKER_KEY);
    if (typeof renderTimelineMarkers === 'function') renderTimelineMarkers();
    setStatus('マーカー全消去');
  };

  window.jumpToNearestMarker = function(direction = 1) {
    const cur = window._currentTime ?? 0;
    const markers = window._timelineMarkers;
    if (!markers.length) return;
    const sorted = direction > 0
      ? markers.filter(m => m.time > cur + 0.01)
      : [...markers].reverse().filter(m => m.time < cur - 0.01);
    if (sorted.length) {
      const target = sorted[0].time;
      if (typeof seekTo === 'function') seekTo(target);
      setStatus(`マーカーへジャンプ: ${target.toFixed(2)}s`);
    }
  };
}

