// ── [295] 数字キー1-9で表情プリセット切替 ──────────────────────
{
  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey || e.metaKey || e.altKey || e.shiftKey) return;
    if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
    const num = parseInt(e.key);
    if (isNaN(num) || num < 1 || num > 9) return;
    const presets = window.getBsPresets ? Object.keys(window.getBsPresets()) : [];
    const name = presets[num - 1];
    if (name) {
      window.loadBsPreset?.(name);
    } else {
      const BUILT_IN = { 1: 'happy', 2: 'angry', 3: 'sad', 4: 'relaxed', 5: 'surprised', 6: 'neutral' };
      const expr = BUILT_IN[num];
      if (expr && window.currentVrm?.expressionManager) {
        if (typeof window.bsPushUndo === 'function') window.bsPushUndo();
        const em = window.currentVrm.expressionManager;
        const names = em.expressionMap ? Object.keys(em.expressionMap) : [];
        names.forEach(n => em.setValue(n, 0));
        em.setValue(expr, 1.0);
        if (typeof updateBlendShapeUI === 'function') updateBlendShapeUI();
        setStatus(`表情: ${expr}`);
      }
    }
  });
}

// ── [296] ミニチュア プレビューサムネイル 更新 ────────────────
{
  window.updateMiniPreview = function() {
    const canvas = document.querySelector('#three-canvas, canvas');
    const preview = document.querySelector('#mini-preview, [data-id="mini-preview"]');
    if (!canvas || !preview) return;
    try {
      const temp = document.createElement('canvas');
      temp.width = 128; temp.height = 128;
      const ctx = temp.getContext('2d');
      ctx.drawImage(canvas, 0, 0, 128, 128);
      preview.src = temp.toDataURL('image/jpeg', 0.7);
    } catch {}
  };
  setInterval(() => {
    if (typeof window.updateMiniPreview === 'function') window.updateMiniPreview();
  }, 3000);
}

// ── [297] パーティクルエフェクト トグル ─────────────────────────
{
  let _particlesEnabled = localStorage.getItem('vrmApp_particles') !== 'false';
  window.toggleParticles = function() {
    _particlesEnabled = !_particlesEnabled;
    localStorage.setItem('vrmApp_particles', _particlesEnabled);
    const particleSystem = window.particleSystem ?? window._particles;
    if (particleSystem) particleSystem.visible = _particlesEnabled;
    setStatus(`パーティクル: ${_particlesEnabled ? 'ON' : 'OFF'}`);
  };
  const particleBtn = document.querySelector('#particle-toggle, [data-action="toggle-particles"]');
  if (particleBtn) particleBtn.addEventListener('click', window.toggleParticles);
}

// ── [298] モーションカード ドラッグ並び替え ────────────────────
{
  let _dragSrc = null;
  document.addEventListener('dragstart', (e) => {
    const card = e.target.closest('.motion-card[draggable]');
    if (!card) return;
    _dragSrc = card;
    card.style.opacity = '0.5';
    e.dataTransfer.effectAllowed = 'move';
  });
  document.addEventListener('dragend', (e) => {
    const card = e.target.closest('.motion-card[draggable]');
    if (card) card.style.opacity = '';
    _dragSrc = null;
  });
  document.addEventListener('dragover', (e) => {
    const card = e.target.closest('.motion-card[draggable]');
    if (!card || card === _dragSrc) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    const rect = card.getBoundingClientRect();
    const after = e.clientY > rect.top + rect.height / 2;
    card.parentNode.insertBefore(_dragSrc, after ? card.nextSibling : card);
  });
  document.addEventListener('drop', (e) => {
    e.preventDefault();
  });
}

// ── [299] 起動アニメーション ロゴフェードイン ──────────────────
{
  const splash = document.getElementById('splash-screen') ?? document.querySelector('.splash');
  if (splash) {
    splash.style.transition = 'opacity 0.6s ease';
    const hide = () => {
      splash.style.opacity = '0';
      setTimeout(() => { splash.style.display = 'none'; }, 650);
    };
    if (document.readyState === 'complete') setTimeout(hide, 800);
    else window.addEventListener('load', () => setTimeout(hide, 800));
  }
}

// ── [300] パフォーマンスレポート ダウンロード ──────────────────
{
  window.downloadPerfReport = function() {
    const report = {
      timestamp: new Date().toISOString(),
      userAgent: navigator.userAgent,
      screen: { w: screen.width, h: screen.height, dpr: devicePixelRatio },
      fps: {
        current: window._lastFps ?? 0,
        history: window._fpsHistory ?? [],
      },
      memory: performance.memory ? {
        used: Math.round(performance.memory.usedJSHeapSize / 1024 / 1024),
        total: Math.round(performance.memory.totalJSHeapSize / 1024 / 1024),
        limit: Math.round(performance.memory.jsHeapSizeLimit / 1024 / 1024),
      } : null,
      vrm: {
        loaded: !!window.currentVrm,
        name: window.currentVrm?.meta?.name ?? null,
      },
      motion: {
        current: window.currentMotionUrl ?? null,
        speed: window.currentPlaybackSpeed ?? 1,
      },
    };
    const blob = new Blob([JSON.stringify(report, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `perf_report_${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(a.href);
    setStatus('パフォーマンスレポートをダウンロード', 'success');
  };
}

// ════════════════════════════════════════════════════════════════
// IMPROVEMENTS [301] – [400]
// ════════════════════════════════════════════════════════════════

// ── [301] キャンバス クリックリップル エフェクト ─────────────────
{
  const canvas = document.querySelector('#three-canvas, canvas');
  if (canvas) {
    canvas.addEventListener('click', (e) => {
      const r = document.createElement('div');
      r.className = 'canvas-ripple';
      r.style.left = e.clientX + 'px';
      r.style.top = e.clientY + 'px';
      document.body.appendChild(r);
      r.addEventListener('animationend', () => r.remove());
    });
  }
}

// ── [302] スピードフラッシュバッジ 表示ユーティリティ ──────────
{
  let _sfTimer = null;
  function showSpeedFlashBadge(speed) {
    if (!Number.isFinite(speed)) speed = 1;
    let badge = document.getElementById('speed-flash-badge');
    if (!badge) {
      badge = document.createElement('div');
      badge.id = 'speed-flash-badge';
      badge.setAttribute('aria-live', 'polite');
      document.body.appendChild(badge);
    }
    badge.textContent = `×${(+speed).toFixed(speed % 1 === 0 ? 0 : 2)}`;
    badge.classList.add('is-visible');
    clearTimeout(_sfTimer);
    _sfTimer = setTimeout(() => { try { badge.classList.remove('is-visible'); } catch {} }, 900);
  }
  window.showSpeedFlashBadge = showSpeedFlashBadge;

  // Shift+スクロールの速度変更と連動
  const _origSetStatus302 = window.setStatus;
  document.addEventListener('wheel', (e) => {
    if (!e.shiftKey) return;
    const speedEl = document.querySelector('#motion-speed, [data-id="motion-speed"]');
    if (speedEl) {
      requestAnimationFrame(() => showSpeedFlashBadge(speedEl.value));
    }
  }, { passive: true });
}

// ── [303] モーション一括ツールバー 表示/非表示 ──────────────────
{
  function updateBulkToolbar() {
    const bar = document.getElementById('motion-bulk-toolbar');
    if (!bar) return;
    const count = (window._checkedMotions instanceof Set) ? window._checkedMotions.size : 0;
    bar.classList.toggle('is-active', count > 0);
    bar.setAttribute('aria-hidden', String(count === 0));
    const countEl = bar.querySelector('.bulk-count');
    if (countEl) countEl.textContent = count > 0 ? `${count}件選択` : '';
  }
  window._updateBulkToolbar = updateBulkToolbar;

  document.getElementById('motion-bulk-toolbar')?.addEventListener('click', (e) => {
    const action = e.target.closest('[data-bulk-action]')?.dataset?.bulkAction;
    if (!action) return;
    if (action === 'play') window.playCheckedMotions?.();
    else if (action === 'clear') { window.clearMotionChecks?.(); updateBulkToolbar(); }
    else if (action === 'fav') {
      (window._checkedMotions instanceof Set) && window._checkedMotions.forEach(id => window.toggleMotionFavorite?.(id));
      window.clearMotionChecks?.(); updateBulkToolbar();
    }
  });
}

// ── [304] パネル検索 入力イベント接続 ───────────────────────────
{
  const searchInput = document.getElementById('panel-search-input');
  if (searchInput) {
    let _searchTimer = null;
    searchInput.addEventListener('input', () => {
      clearTimeout(_searchTimer);
      _searchTimer = setTimeout(() => {
        const q = String(searchInput.value ?? '').replace(/[<>&"']/g, '').trim().slice(0, 200);
        if (q.length >= 1) window.panelSearch?.(q);
        else if (!q && typeof window.clearPanelSearch === 'function') window.clearPanelSearch();
      }, 400);
    });
    searchInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') window.panelSearch?.(searchInput.value);
      if (e.key === 'Escape') { searchInput.value = ''; searchInput.blur(); }
    });
  }
}

// ── [305] モーション再生速度 プリセットボタン 自動生成 ─────────
{
  const SPEED_PRESETS = [0.25, 0.5, 1.0, 1.5, 2.0];
  const wrap = document.querySelector('.speed-presets');
  const speedSel = document.querySelector('#motion-speed, [data-id="motion-speed"]');
  if (wrap && speedSel) {
    SPEED_PRESETS.forEach(spd => {
      const btn = document.createElement('button');
      btn.className = 'speed-preset-btn';
      btn.textContent = `×${spd}`;
      btn.dataset.speed = spd;
      btn.addEventListener('click', () => {
        speedSel.value = spd;
        speedSel.dispatchEvent(new Event('change'));
        wrap.querySelectorAll('.speed-preset-btn').forEach(b => b.classList.remove('is-active'));
        btn.classList.add('is-active');
        window.showSpeedFlashBadge?.(spd);
      });
      wrap.appendChild(btn);
    });
    speedSel.addEventListener('change', () => {
      const cur = parseFloat(speedSel.value);
      if (!Number.isFinite(cur)) return;
      wrap.querySelectorAll('.speed-preset-btn').forEach(b => {
        const bSpeed = parseFloat(b.dataset?.speed ?? '0');
        b.classList.toggle('is-active', Number.isFinite(bSpeed) && Math.abs(bSpeed - cur) < 0.01);
      });
    });
  }
}

// ── [306] FPS上限 requestAnimationFrame スロットリング ─────────
{
  let _lastRafTime = 0;
  const _origRaf = (window.requestAnimationFrame ?? window.webkitRequestAnimationFrame ?? setTimeout).bind(window);
  window.requestAnimationFrameThrottled = function(callback) {
    if (typeof callback !== 'function') return;
    const cap = window.getFpsCap?.() ?? 0;
    if (!Number.isFinite(cap) || cap <= 0) return _origRaf(callback);
    const minInterval = 1000 / Math.max(1, Math.min(240, Math.round(cap)));
    return _origRaf((now) => {
      if (now - _lastRafTime >= minInterval) {
        _lastRafTime = now;
        callback(now);
      }
    });
  };
}

// ── [307] ゲームパッド インジケーター DOM 更新 ────────────────
{
  function updateGamepadIndicator(connected) {
    let el = document.getElementById('gamepad-indicator');
    if (!el) return;
    el.classList.toggle('is-connected', Boolean(connected));
    const gpName = window._gamepad?.id?.substring(0, 40) ?? '';
    el.title = connected ? `接続中: ${gpName || 'ゲームパッド'}` : '未接続';
    el.setAttribute('aria-label', el.title);
  }
  window.addEventListener('gamepadconnected', () => updateGamepadIndicator(true));
  window.addEventListener('gamepaddisconnected', () => updateGamepadIndicator(false));
}

// ── [308] フルスクリーン ボタン状態同期 ──────────────────────
{
  const fsBtn = document.getElementById('fullscreen-btn');
  if (fsBtn) {
    const update = () => {
      const isFs = !!document.fullscreenElement;
      fsBtn.classList.toggle('is-fullscreen', isFs);
      fsBtn.title = isFs ? 'フルスクリーン解除 (F11)' : 'フルスクリーン (F11)';
    };
    document.addEventListener('fullscreenchange', update);
    fsBtn.addEventListener('click', window.toggleFullscreen);
  }
}

// ── [309] ポーズスナップ グリッド 描画 ──────────────────────
{
  window.renderPoseSnapGrid = function() {
    const grid = document.getElementById('pose-snap-grid');
    if (!grid) return;
    const snaps = window.getPoseSnapshots?.() ?? {};
    const names = Object.keys(snaps);
    if (names.length === 0) {
      grid.innerHTML = '<div class="pose-snap-empty">ポーズ未保存</div>';
      return;
    }
    grid.innerHTML = names.map((name, i) => `
      <div class="pose-snap-card" data-pose="${name}">
        <div class="pose-snap-thumb">🧍</div>
        <div class="pose-snap-label" title="${name}">${name}</div>
        <button class="pose-snap-delete" data-delete="${name}" title="削除">✕</button>
      </div>`).join('');

    grid.addEventListener('click', (e) => {
      const card = e.target.closest('.pose-snap-card');
      const del = e.target.closest('[data-delete]');
      if (del) {
        e.stopPropagation();
        if (confirm(`ポーズ「${del.dataset.delete}」を削除しますか？`)) {
          window.deletePoseSnapshot?.(del.dataset.delete);
          window.renderPoseSnapGrid();
        }
      } else if (card) {
        window.loadPoseSnapshot?.(card.dataset.pose);
      }
    });
  };
}

// ── [310] 表情プリセット グリッド 描画 ──────────────────────
{
  const EXPR_EMOJIS = {
    happy: '😊', angry: '😠', sad: '😢', relaxed: '😌',
    surprised: '😲', neutral: '😐', blink: '😑', blinkLeft: '😉',
  };

  window.renderBsPresets = function() {
    const grid = document.querySelector('#bs-preset-grid, .bs-preset-grid');
    if (!grid) return;
    const presets = window.getBsPresets?.() ?? {};
    const names = Object.keys(presets);
    if (names.length === 0) {
      grid.innerHTML = '<div style="color:var(--text-lo);font-size:11px;text-align:center;padding:10px">プリセット未保存</div>';
      return;
    }
    grid.innerHTML = names.map((name, i) => `
      <div class="expr-preset-btn" data-preset="${name}" style="position:relative">
        ${i < 9 ? `<span class="expr-key-hint">${i + 1}</span>` : ''}
        <span class="expr-emoji">${EXPR_EMOJIS[name] ?? '🎭'}</span>
        <span>${name}</span>
        <div class="expr-preset-actions">
          <button class="expr-preset-load-btn" data-load="${name}">適用</button>
          <button class="expr-preset-del-btn" data-delete="${name}">削除</button>
        </div>
      </div>`).join('');

    grid.addEventListener('click', (e) => {
      const loadBtn = e.target.closest('[data-load]');
      const delBtn = e.target.closest('[data-delete]');
      if (loadBtn) { e.stopPropagation(); window.loadBsPreset?.(loadBtn.dataset.load); }
      else if (delBtn) { e.stopPropagation(); window.deleteBsPresetConfirm?.(delBtn.dataset.delete); }
    });
  };
  window.renderBsPresets();
}

// ── [311] カメラ IO ボタン 接続 ────────────────────────────
{
  document.querySelectorAll('.camera-io-btn[data-action]').forEach(btn => {
    btn.addEventListener('click', () => {
      const action = btn.dataset.action;
      if (action === 'export-camera') window.exportCameraState?.();
      else if (action === 'import-camera') {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.json';
        input.onchange = (e) => {
          const file = e.target.files[0];
          if (!file) return;
          file.text().then(text => window.importCameraState?.(text));
        };
        input.click();
      }
    });
  });
}

// ── [312] ブレンドシェイプ プリセット保存 UI 接続 ─────────────
{
  const saveBtn = document.querySelector('#bs-preset-save, [data-action="bs-preset-save"]');
  const nameInput = document.querySelector('#bs-preset-name, .bs-preset-name-input');
  if (saveBtn && nameInput) {
    saveBtn.addEventListener('click', () => {
      const name = nameInput.value.trim();
      if (!name) { setStatus('プリセット名を入力', 'warn'); return; }
      window.saveBsPreset?.(name);
      nameInput.value = '';
    });
    nameInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') saveBtn.click();
    });
  }
}

// ── [313] ドロップゾーン VRM ファイル受付強化 ──────────────────
{
  const dropZones = document.querySelectorAll('.drop-zone');
  dropZones.forEach(zone => {
    zone.addEventListener('dragenter', (e) => { e.preventDefault(); zone.classList.add('is-over'); });
    zone.addEventListener('dragleave', () => zone.classList.remove('is-over'));
    zone.addEventListener('dragover', (e) => e.preventDefault());
    zone.addEventListener('drop', (e) => {
      e.preventDefault();
      zone.classList.remove('is-over');
      const file = e.dataTransfer.files[0];
      if (!file) return;
      if (file.name.endsWith('.vrm')) {
        const url = URL.createObjectURL(file);
        if (typeof loadVrm === 'function') loadVrm(url);
        setStatus(`VRMファイル読込: ${file.name}`);
      } else {
        setStatus('VRMファイルをドロップしてください', 'warn');
      }
    });
  });
}

// ── [314] タイムライン マーカーUI 描画 ──────────────────────
{
  window.renderTimelineMarkers = function() {
    const container = document.querySelector('#timeline-markers, .timeline-markers-layer');
    if (!container) return;
    const markers = window._timelineMarkers ?? [];
    const duration = window.currentClipDuration ?? window.currentAction?.getClip()?.duration ?? 0;
    if (duration <= 0) return;
    container.innerHTML = '';
    markers.forEach(m => {
      const el = document.createElement('div');
      el.className = 'timeline-marker';
      el.style.left = `${(m.time / duration) * 100}%`;
      el.dataset.label = m.label || `${m.time.toFixed(2)}s`;
      el.title = `${m.label || ''} (${m.time.toFixed(2)}s) — クリックで削除`;
      el.addEventListener('click', () => {
        if (confirm(`マーカー「${m.label || m.time.toFixed(2)}s」を削除しますか？`)) {
          window.removeTimelineMarker?.(m.id);
        }
      });
      container.appendChild(el);
    });
  };
}

// ── [315] VRMロード時メタ表示 + 進捗バー 自動接続 ──────────────
{
  const origVrmLoaded = window.onVrmLoaded;
  window.onVrmLoaded = function(vrm) {
    window.renderVrmMeta?.(vrm);
    window.updateVrmLoadProgress?.(100, '完了');
    setTimeout(() => {
      document.getElementById('vrm-load-progress-wrap')?.classList.remove('is-active');
    }, 800);
    if (typeof origVrmLoaded === 'function') origVrmLoaded.call(this, vrm);
  };
}

// ── [316] お気に入りモーション カード ★ボタン 自動付与 ─────────
{
  const origRenderML = window.renderMotionLibrary;
  if (origRenderML) {
    window.renderMotionLibrary = function(...args) {
      const result = origRenderML.apply(this, args);
      requestAnimationFrame(() => {
        document.querySelectorAll('.motion-card:not([data-fav-wired])').forEach(card => {
          card.dataset.favWired = '1';
          const motionId = card.dataset.motionId ?? card.dataset.id;
          if (!motionId) return;
          const favBtn = card.querySelector('.motion-fav-btn') ?? document.createElement('button');
          if (!card.querySelector('.motion-fav-btn')) {
            favBtn.className = 'motion-fav-btn';
            favBtn.title = 'お気に入り';
            card.appendChild(favBtn);
          }
          const isFav = window.isMotionFavorite?.(motionId);
          favBtn.textContent = isFav ? '★' : '☆';
          favBtn.classList.toggle('is-fav', !!isFav);
          favBtn.onclick = (e) => {
            e.stopPropagation();
            const added = window.toggleMotionFavorite?.(motionId);
            favBtn.textContent = added ? '★' : '☆';
            favBtn.classList.toggle('is-fav', !!added);
          };
        });
      });
      return result;
    };
  }
}

// ── [317] ポーズスナップ 保存ボタン UI 接続 ──────────────────
{
  const snapSaveBtn = document.querySelector('#pose-snap-save, [data-action="pose-snap-save"]');
  const snapNameInput = document.querySelector('#pose-snap-name, [data-id="pose-snap-name"]');
  if (snapSaveBtn) {
    snapSaveBtn.addEventListener('click', () => {
      const name = snapNameInput?.value?.trim() || `ポーズ${Date.now() % 10000}`;
      window.savePoseSnapshot?.(name);
      if (snapNameInput) snapNameInput.value = '';
      window.renderPoseSnapGrid?.();
    });
  }
}

// ── [318] タイムライン マーカー 追加 キーボード ────────────────
{
  document.addEventListener('keydown', (e) => {
    if (e.key === 'm' || e.key === 'M') {
      if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
      if (e.ctrlKey || e.metaKey) return;
      const time = window._currentTime ?? window.currentAction?.time ?? 0;
      window.addTimelineMarker?.(time, `M${(window._timelineMarkers?.length ?? 0) + 1}`);
    }
    if ((e.key === ',' || e.key === '<') && !e.ctrlKey) {
      if (document.activeElement?.tagName === 'INPUT') return;
      window.jumpToNearestMarker?.(-1);
    }
    if ((e.key === '.' || e.key === '>') && !e.ctrlKey) {
      if (document.activeElement?.tagName === 'INPUT') return;
      window.jumpToNearestMarker?.(1);
    }
  });
}

