// ── [325] VRM読込エラー 表示ユーティリティ ──────────────────
{
  window.showVrmError = function(message) {
    const container = document.querySelector('#vrm-error-container, [data-id="vrm-error"]');
    if (!container) {
      setStatus(`VRMエラー: ${message}`, 'error');
      return;
    }
    container.innerHTML = `
      <div class="vrm-error-card">
        <div class="vrm-error-icon">⚠</div>
        <div class="vrm-error-body">
          <div class="vrm-error-title">VRM読込エラー</div>
          <div class="vrm-error-msg">${message}</div>
        </div>
      </div>`;
    container.style.display = 'block';
    setTimeout(() => { container.style.display = ''; }, 8000);
  };
}

// ── [326] スクリーンショット 解像度スケール ─────────────────
{
  const SCALE_KEY = 'vrmApp_screenshotScale';
  window.getScreenshotScale = function() {
    return parseFloat(localStorage.getItem(SCALE_KEY) ?? '1');
  };
  window.setScreenshotScale = function(scale) {
    localStorage.setItem(SCALE_KEY, scale);
    setStatus(`スクリーンショット解像度: ×${scale}`);
  };
  const scaleSelect = document.querySelector('#screenshot-scale, [data-id="screenshot-scale"]');
  if (scaleSelect) {
    scaleSelect.value = window.getScreenshotScale();
    scaleSelect.addEventListener('change', () => window.setScreenshotScale(parseFloat(scaleSelect.value)));
  }
}

// ── [327] キャンバス 右クリック コンテキストメニュー拡張 ──────
{
  const canvas = document.querySelector('#three-canvas, canvas');
  if (canvas) {
    canvas.addEventListener('contextmenu', (e) => {
      e.preventDefault();
      const ITEMS = [
        { label: '📷 スクリーンショット', action: () => typeof takeScreenshot === 'function' && takeScreenshot() },
        { label: '📷× バースト撮影(3枚)', action: () => window.burstScreenshot?.(3, 400) },
        { label: '🎲 ランダム表情', action: () => window.randomFace?.() },
        { label: '📌 カメラ位置をコピー', action: () => window.exportCameraState?.() },
        { label: '⌨ ショートカット一覧', action: () => window.showShortcutsDialog?.() },
      ];
      let menu = document.getElementById('canvas-ctx-menu');
      if (menu) menu.remove();
      menu = document.createElement('div');
      menu.id = 'canvas-ctx-menu';
      menu.style.cssText = `position:fixed;left:${e.clientX}px;top:${e.clientY}px;
        z-index:var(--z-top);background:rgba(4,12,30,0.98);
        border:1px solid var(--border-mid);border-radius:7px;
        padding:4px;min-width:180px;box-shadow:0 8px 24px rgba(0,0,0,0.6)`;
      ITEMS.forEach(item => {
        const el = document.createElement('div');
        el.style.cssText = `padding:6px 10px;font-size:11px;color:var(--text-mid);
          cursor:pointer;border-radius:4px;transition:background 0.1s`;
        el.textContent = item.label;
        el.addEventListener('mouseenter', () => { el.style.background = 'rgba(0,160,255,0.12)'; el.style.color = 'var(--text-hi)'; });
        el.addEventListener('mouseleave', () => { el.style.background = ''; el.style.color = 'var(--text-mid)'; });
        el.addEventListener('click', () => { item.action(); menu.remove(); });
        menu.appendChild(el);
      });
      document.body.appendChild(menu);
      const closeMenu = (e2) => { if (!menu.contains(e2.target)) { menu.remove(); document.removeEventListener('click', closeMenu); } };
      setTimeout(() => document.addEventListener('click', closeMenu), 10);
    });
  }
}

// ── [328] パネル 折りたたみ ボタン 接続 ────────────────────
{
  const colBtn = document.getElementById('panel-collapse-btn');
  const panel = document.getElementById('asset-panel');
  if (colBtn && panel) {
    let _collapsed = false;
    const _expandedW = localStorage.getItem('vrmApp_panelWidth') ?? '300px';
    colBtn.addEventListener('click', () => {
      _collapsed = !_collapsed;
      panel.classList.add('no-transition');
      if (_collapsed) {
        panel.dataset.expandedW = panel.offsetWidth + 'px';
        panel.style.width = '0px';
        panel.style.overflow = 'hidden';
        colBtn.textContent = '▶';
        colBtn.title = 'パネルを開く';
      } else {
        panel.style.width = panel.dataset.expandedW ?? _expandedW;
        panel.style.overflow = '';
        colBtn.textContent = '◀';
        colBtn.title = 'パネルを閉じる';
      }
      requestAnimationFrame(() => panel.classList.remove('no-transition'));
    });
  }
}

// ── [329] VRM メタ ライセンスバッジ 表示 ─────────────────────
{
  window.getLicenseBadge = function(licenseUrl) {
    if (!licenseUrl) return '';
    if (licenseUrl.includes('CC0')) return '<span style="color:var(--success);font-size:10px">CC0</span>';
    if (licenseUrl.includes('CC_BY')) return '<span style="color:var(--accent);font-size:10px">CC BY</span>';
    if (licenseUrl.includes('CC_BY_NC')) return '<span style="color:var(--warning);font-size:10px">CC BY-NC</span>';
    if (licenseUrl.includes('Redistribution_Prohibited')) return '<span style="color:var(--danger);font-size:10px">再配布禁止</span>';
    return `<span style="color:var(--text-lo);font-size:10px">ライセンス</span>`;
  };
}

// ── [330] ロードVRM 進捗バー開始 ────────────────────────────
{
  const origLoad = window.loadVrm ?? window.loadModel;
  if (origLoad) {
    const key = window.loadVrm ? 'loadVrm' : 'loadModel';
    window[key] = function(...args) {
      const wrap = document.getElementById('vrm-load-progress-wrap');
      if (wrap) {
        wrap.classList.add('is-active');
        window.updateVrmLoadProgress?.(0, '読込開始...');
        let pct = 0;
        const ticker = setInterval(() => {
          pct = Math.min(pct + 5, 90);
          window.updateVrmLoadProgress?.(pct);
        }, 150);
        const cleanup = () => { clearInterval(ticker); };
        setTimeout(cleanup, 20000);
      }
      return origLoad.apply(this, args);
    };
  }
}

// ── [331] ブレンドシェイプ 値変更時 Undoプッシュ ────────────
{
  const bsContainer = document.querySelector('#blend-shape-container, .bs-container, [data-section="blend-shapes"]');
  if (bsContainer) {
    let _bsDebounce = null;
    bsContainer.addEventListener('input', (e) => {
      if (!e.target.matches('input[type="range"]')) return;
      clearTimeout(_bsDebounce);
      _bsDebounce = setTimeout(() => window.bsPushUndo?.(), 800);
    });
  }
}

// ── [332] 背景グリッド トグルボタン 接続 ──────────────────
{
  const gridBtn = document.querySelector('#bg-grid-toggle, [data-action="bg-grid"]');
  const overlay = document.getElementById('bg-grid-overlay');
  if (!overlay) {
    const div = document.createElement('div');
    div.id = 'bg-grid-overlay';
    document.body.insertBefore(div, document.body.firstChild);
  }
  if (gridBtn) {
    const BG_GRID_KEY = 'vrmApp_bgGrid';
    let _gridOn = localStorage.getItem(BG_GRID_KEY) === 'true';
    const apply = () => {
      document.getElementById('bg-grid-overlay')?.classList.toggle('is-visible', _gridOn);
      gridBtn.classList.toggle('is-active', _gridOn);
    };
    apply();
    gridBtn.addEventListener('click', () => {
      _gridOn = !_gridOn;
      localStorage.setItem(BG_GRID_KEY, _gridOn);
      apply();
      setStatus(`背景グリッド: ${_gridOn ? 'ON' : 'OFF'}`);
    });
  }
}

// ── [333] アニメーション速度 マウスホイールノブ ─────────────
{
  const speedEl = document.querySelector('#motion-speed, [data-id="motion-speed"]');
  const speedKnob = document.querySelector('.speed-knob-wrap');
  if (speedEl && speedKnob) {
    speedKnob.addEventListener('wheel', (e) => {
      e.preventDefault();
      const SPEEDS = [0.1, 0.25, 0.5, 0.75, 1.0, 1.25, 1.5, 2.0, 3.0];
      const cur = parseFloat(speedEl.value) || 1.0;
      const idx = SPEEDS.findIndex(s => Math.abs(s - cur) < 0.01);
      const next = e.deltaY < 0
        ? SPEEDS[Math.min(SPEEDS.length - 1, idx + 1)]
        : SPEEDS[Math.max(0, idx - 1)];
      speedEl.value = next;
      speedEl.dispatchEvent(new Event('change'));
      window.showSpeedFlashBadge?.(next);
    }, { passive: false });
  }
}

// ── [334] LLMメッセージ 自動スクロール ──────────────────────
{
  const llmLog = document.querySelector('#llm-messages, .llm-messages, #chat-log');
  if (llmLog) {
    const scroll334 = new MutationObserver(() => {
      llmLog.scrollTo({ top: llmLog.scrollHeight, behavior: 'smooth' });
    });
    scroll334.observe(llmLog, { childList: true, subtree: true });
  }
}

// ── [335] キャンバスHUD 情報更新ループ ──────────────────────
{
  const hudTR = document.querySelector('#canvas-hud .hud-corner.tr');
  if (hudTR) {
    setInterval(() => {
      const cam = window.camera;
      if (!cam) return;
      const p = cam.position;
      hudTR.innerHTML = `FOV:${cam.fov?.toFixed(0)}° | X${p.x.toFixed(1)} Y${p.y.toFixed(1)} Z${p.z.toFixed(1)}`;
    }, 500);
  }
}

// ── [336] タグフィルターバー 自動生成 ─────────────────────
{
  window.renderTagFilterBar = function() {
    const bar = document.getElementById('tag-filter-bar');
    if (!bar) return;
    const tags = window.MOTION_TAGS ?? [];
    bar.innerHTML = tags.map(tag =>
      `<div class="tag-filter-chip${window._activeTagFilters?.has(tag) ? ' is-active' : ''}" data-tag="${tag}">${tag}</div>`
    ).join('') + '<button id="tag-filter-clear" title="フィルタークリア">✕</button>';
    bar.querySelectorAll('.tag-filter-chip').forEach(chip => {
      chip.addEventListener('click', () => window.toggleTagFilter?.(chip.dataset.tag));
    });
    bar.querySelector('#tag-filter-clear')?.addEventListener('click', () => window.clearTagFilters?.());
  };
  window.renderTagFilterBar();
}

// ── [337] モーション検索 ハイライト処理 ─────────────────────
{
  window.highlightSearchTerm = function(text, query) {
    if (!query) return text;
    const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    return text.replace(new RegExp(`(${escaped})`, 'gi'), '<mark>$1</mark>');
  };
}

