// ── [384] ジャンプリスト（最近使ったVRM）──────────────────
{
  const RECENT_KEY = 'vrmApp_recentVrms';
  window.addRecentVrm = function(url, name) {
    if (!url || typeof url !== 'string') return;
    try {
      const list = JSON.parse(localStorage.getItem(RECENT_KEY) ?? '[]');
      const safeList = Array.isArray(list) ? list : [];
      const existing = safeList.findIndex(v => v.url === url);
      if (existing >= 0) safeList.splice(existing, 1);
      const safeName = String(name ?? url.split('/').pop() ?? 'VRM').slice(0, 80);
      safeList.unshift({ url: url.slice(0, 2048), name: safeName, ts: Date.now() });
      localStorage.setItem(RECENT_KEY, JSON.stringify(safeList.slice(0, 10)));
    } catch { /* quota or parse error */ }
  };
  window.getRecentVrms = function() {
    try {
      const data = JSON.parse(localStorage.getItem(RECENT_KEY) ?? '[]');
      return Array.isArray(data) ? data.filter(v => v?.url && typeof v.url === 'string') : [];
    } catch { return []; }
  };
}

