// ── [386] FPS グラフ キャンバス描画 ─────────────────────────
{
  const sparkCanvas = document.querySelector('#fps-sparkline, canvas[data-fps-spark]');
  if (sparkCanvas && sparkCanvas.tagName === 'CANVAS') {
    const ctx386 = sparkCanvas.getContext('2d');
    function drawFpsSpark() {
      const hist = window._fpsHistory ?? [];
      const w = sparkCanvas.width, h = sparkCanvas.height;
      ctx386.clearRect(0, 0, w, h);
      if (hist.length < 2) return;
      const max = Math.max(60, ...hist);
      ctx386.strokeStyle = 'rgba(0,212,255,0.6)';
      ctx386.lineWidth = 1.5;
      ctx386.beginPath();
      hist.forEach((v, i) => {
        const x = (i / (hist.length - 1)) * w;
        const y = h - (v / max) * h;
        i === 0 ? ctx386.moveTo(x, y) : ctx386.lineTo(x, y);
      });
      ctx386.stroke();
    }
    setInterval(drawFpsSpark, 500);
  }
}

