// ── [441] LLM履歴 インポート JSON ───────────────────────────
{
  window.importLLMHistory = function(file) {
    if (!file || !(file instanceof File)) { setStatus('ファイルが必要です', 'warn'); return; }
    if (file.size > 5 * 1024 * 1024) { setStatus('LLM履歴ファイルが大きすぎます (最大5MB)', 'warn'); return; }
    const reader = new FileReader();
    reader.onload = function(e) {
      try {
        const data = JSON.parse(e.target.result);
        if (!Array.isArray(data)) throw new Error('配列形式が必要です');
        if (typeof llmHistory !== 'undefined') llmHistory.splice(0, Infinity, ...data.slice(0, 200));
        setStatus(`LLM履歴インポート: ${data.length}件`, 'success');
      } catch (err) { setStatus('LLM履歴インポートエラー: ' + (err?.message ?? '不明'), 'error'); }
    };
    reader.onerror = function() { setStatus('LLM履歴ファイル読込エラー', 'error'); };
    reader.readAsText(file);
  };
  document.querySelector('#llm-import-btn, [data-id="llm-import"]')?.addEventListener('click', function() {
    const inp = document.createElement('input');
    inp.type = 'file'; inp.accept = '.json';
    inp.onchange = function() { if (inp.files?.[0]) window.importLLMHistory(inp.files[0]); };
    inp.click();
  });
}

