// ── [445] LLM ストリーミング トークン表示 ─────────────────────
{
  window.streamLLMToken = function(token, bubbleEl) {
    if (!bubbleEl || !token || typeof token !== 'string') return;
    try {
      const textEl = bubbleEl.querySelector('.llm-msg-bubble-text');
      const target = textEl ?? bubbleEl;
      const maxLen = 8000;
      if ((target.textContent?.length ?? 0) < maxLen) target.textContent += token;
      bubbleEl.parentElement?.scrollIntoView?.({ block: 'end' });
    } catch {}
  };
}

// ── [446] TTS キュー 複数発話 ───────────────────────────────
{
  if (!Array.isArray(window._ttsQueue)) window._ttsQueue = [];
  window.enqueueTTS = function(text, speakerName) {
    if (!text || typeof text !== 'string') return;
    if (window._ttsQueue.length >= 30) { setStatus('TTSキューが満杯です', 'warn'); return; }
    window._ttsQueue.push({ text: text.slice(0, 2000), speakerName: String(speakerName ?? '').slice(0, 60) });
    if (window._ttsQueue.length === 1) window._drainTTSQueue?.();
  };
  window._drainTTSQueue = function() {
    if (!Array.isArray(window._ttsQueue) || !window._ttsQueue.length) return;
    const item = window._ttsQueue[0];
    if (!item || !item.text) { window._ttsQueue.shift(); window._drainTTSQueue?.(); return; }
    if (typeof speakText === 'function') { try { speakText(item.text, item.speakerName); } catch {} }
    const delay = Math.min(Math.max(500, item.text.length * 80), 30000);
    setTimeout(function() {
      window._ttsQueue.shift();
      window._drainTTSQueue?.();
    }, delay);
  };
}

// ── [447] TTS 発音辞書 カスタム追加 ──────────────────────────
{
  window._ttsDict = (function() {
    try {
      const raw = localStorage.getItem('vrmApp_ttsDict');
      if (!raw) return {};
      const data = JSON.parse(raw);
      return (data && typeof data === 'object' && !Array.isArray(data)) ? data : {};
    } catch { return {}; }
  })();
  window.addTTSDictEntry = function(word, reading) {
    if (!word || typeof word !== 'string') { setStatus('単語が必要です', 'warn'); return; }
    if (!reading || typeof reading !== 'string') { setStatus('読みが必要です', 'warn'); return; }
    if (Object.keys(window._ttsDict ?? {}).length >= 500) { setStatus('発音辞書が満杯です (最大500件)', 'warn'); return; }
    window._ttsDict[word.slice(0, 100)] = reading.slice(0, 200);
    try { localStorage.setItem('vrmApp_ttsDict', JSON.stringify(window._ttsDict)); } catch { /* ignore */ }
    const safeWord = escapeHtml(word.slice(0, 20)); const safeReading = escapeHtml(reading.slice(0, 30));
    setStatus(`発音辞書: "${safeWord}" → "${safeReading}"`);
  };
  window.applyTTSDict = function(text) {
    if (!text || typeof text !== 'string') return text ?? '';
    let out = text;
    for (const [word, reading] of Object.entries(window._ttsDict ?? {})) {
      if (!word || typeof word !== 'string') continue;
      try { out = out.replaceAll(word, String(reading ?? '')); } catch {}
    }
    return out;
  };
}

// ── [448] TTS ピッチ/速度 プリセット保存 ────────────────────
{
  window.saveTTSPreset = function(name) {
    if (!name || typeof name !== 'string') { setStatus('プリセット名が必要です', 'warn'); return; }
    const presets = (function() { try { const d = JSON.parse(localStorage.getItem('vrmApp_ttsPresets') ?? '{}'); return (d && typeof d === 'object' && !Array.isArray(d)) ? d : {}; } catch { return {}; } })();
    const pitch = parseFloat(document.querySelector('#tts-pitch-slider, [data-id="tts-pitch"]')?.value ?? 1);
    const rate  = parseFloat(document.querySelector('#tts-speed-slider, [data-id="tts-speed"]')?.value ?? 1);
    presets[name.slice(0, 60)] = {
      pitch: Number.isFinite(pitch) ? pitch : 1,
      rate:  Number.isFinite(rate)  ? rate  : 1,
    };
    try { localStorage.setItem('vrmApp_ttsPresets', JSON.stringify(presets)); } catch { /* ignore */ }
    setStatus(`TTSプリセット保存: "${name.slice(0, 30)}"`, 'success');
  };
  window.loadTTSPreset = function(name) {
    if (!name || typeof name !== 'string') { setStatus('プリセット名が必要です', 'warn'); return; }
    const presets = (function() { try { const d = JSON.parse(localStorage.getItem('vrmApp_ttsPresets') ?? '{}'); return (d && typeof d === 'object' && !Array.isArray(d)) ? d : {}; } catch { return {}; } })();
    const p = presets[name];
    if (!p || typeof p !== 'object') { setStatus(`TTSプリセット "${name.slice(0,20)}" が見つかりません`, 'warn'); return; }
    const pitchSl = document.querySelector('#tts-pitch-slider, [data-id="tts-pitch"]');
    const rateSl  = document.querySelector('#tts-speed-slider, [data-id="tts-speed"]');
    if (pitchSl && Number.isFinite(p.pitch)) { pitchSl.value = p.pitch; pitchSl.dispatchEvent(new Event('input')); }
    if (rateSl  && Number.isFinite(p.rate))  { rateSl.value  = p.rate;  rateSl.dispatchEvent(new Event('input')); }
    setStatus(`TTSプリセット読込: "${name.slice(0,30)}"`, 'success');
  };
}

// ── [449] VOICEVOX スタイルID セレクト 自動ロード ───────────
{
  window.loadVoicevoxStyles = async function(speakerId) {
    if (speakerId === undefined || speakerId === null) { setStatus('スピーカーIDが必要です', 'warn'); return; }
    let url;
    try { url = localStorage.getItem('avatar.tts.vv.url') ?? 'http://127.0.0.1:50021'; } catch { url = 'http://127.0.0.1:50021'; }
    try {
      const res  = await fetch(url + '/speakers', { signal: AbortSignal.timeout(2000) });
      const list = await res.json();
      const speaker = list.find(function(s) { return String(s.speaker_uuid ?? '') === String(speakerId); }) ?? list[0];
      if (!speaker) return;
      const sel = document.querySelector('#tts-vv-style-select, [data-id="vv-style"]');
      if (!sel) return;
      sel.innerHTML = (speaker.styles ?? []).slice(0, 50).map(function(st) {
        if (!st || typeof st.id === 'undefined') return '';
        const safeId = String(st.id).replace(/[<>&"]/g, '');
        const safeName = escapeHtml(String(st.name ?? '').slice(0, 40));
        return '<option value="' + safeId + '">' + safeName + '</option>';
      }).join('');
    } catch { /* offline */ }
  };
}

// ── [450] 音声認識（Web Speech API）────────────────────────
{
  let _recog = null;
  window.startVoiceInput = function(onResult) {
    if (!('webkitSpeechRecognition' in window || 'SpeechRecognition' in window)) {
      setStatus('音声認識: このブラウザは未対応', 'warn'); return;
    }
    const SR = window.SpeechRecognition ?? window.webkitSpeechRecognition;
    _recog = new SR();
    _recog.lang = 'ja-JP'; _recog.interimResults = true;
    _recog.onerror = function(e) { setStatus('音声認識エラー: ' + (e.error ?? '不明'), 'warn'); };
    _recog.onresult = function(e) {
      if (!e.results?.length) return;
      try {
        const transcript = Array.from(e.results).map(function(r) { return r[0]?.transcript ?? ''; }).join('');
        onResult?.(transcript, Boolean(e.results[e.results.length-1]?.isFinal));
      } catch {}
    };
    _recog.start();
  };
  window.stopVoiceInput = function() { _recog?.stop(); _recog = null; };
  const btn = document.querySelector('#voice-input-btn, [data-id="voice-input"]');
  btn?.addEventListener('click', function() {
    if (_recog) { window.stopVoiceInput(); btn.setAttribute('aria-pressed', 'false'); btn.textContent = '🎤'; return; }
    btn.setAttribute('aria-pressed', 'true');
    btn.textContent = '⏹';
    window.startVoiceInput(function(text, final) {
      const inp = document.querySelector('#llm-input, [data-id="llm-input"]');
      if (inp) inp.value = text.slice(0, 5000);
      if (final) { btn.textContent = '🎤'; btn.setAttribute('aria-pressed', 'false'); window.stopVoiceInput(); }
    });
  });
}

