// ── [466] 衣装プリセット 1-9キー クイック切替 ───────────────
{
  document.addEventListener('keydown', function(e) {
    if (e.ctrlKey || e.altKey || e.metaKey || e.shiftKey) return;
    const tag = e.target?.tagName ?? '';
    if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || e.target?.isContentEditable) return;
    if (e.key >= '1' && e.key <= '9') {
      const idx = parseInt(e.key, 10) - 1;
      if (typeof getActiveCostumeList === 'function') {
        const list = getActiveCostumeList?.() ?? [];
        if (Array.isArray(list) && list[idx]) {
          if (typeof setActiveCostume === 'function') setActiveCostume(list[idx].id);
          setStatus('衣装: ' + escapeHtml(String(list[idx].name ?? (idx + 1)).slice(0, 30)));
        }
      }
    }
  });
}

// ── [467] キャラシーンカード ドラッグ並び替え ─────────────────
{
  window.enableSceneCardDrag = function() {
    const container = document.querySelector('#char-scene-list, .char-scene-list');
    if (!container) return;
    let dragSrc = null;
    container.querySelectorAll('.char-scene-card').forEach(function(card) {
      card.draggable = true;
      card.setAttribute('role', 'listitem');
      card.addEventListener('dragstart', function() { dragSrc = card; card.classList.add('is-dragging'); card.setAttribute('aria-grabbed', 'true'); });
      card.addEventListener('dragend',   function() { dragSrc = null; card.classList.remove('is-dragging'); card.setAttribute('aria-grabbed', 'false'); });
      card.addEventListener('dragover',  function(e) { e.preventDefault(); card.classList.add('drag-over'); });
      card.addEventListener('dragleave', function() { card.classList.remove('drag-over'); });
      card.addEventListener('drop',      function(e) {
        e.preventDefault(); card.classList.remove('drag-over');
        if (dragSrc && dragSrc !== card) { try { container.insertBefore(dragSrc, card); } catch {} }
      });
    });
  };
  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    setTimeout(window.enableSceneCardDrag, 100);
  } else {
    document.addEventListener('DOMContentLoaded', window.enableSceneCardDrag);
  }
}

// ── [468] カメラパス 記録 ────────────────────────────────────
{
  window._camPathRecording = false;
  window._camPath = window._camPath ?? [];
  window.startCamPathRecord = function() {
    if (window._camPathRecording) window.stopCamPathRecord?.();
    window._camPath = [];
    window._camPathRecording = true;
    setStatus('カメラパス: 記録開始 (移動してください)');
  };
  window.stopCamPathRecord = function() {
    window._camPathRecording = false;
    const count = Array.isArray(window._camPath) ? window._camPath.length : 0;
    setStatus(`カメラパス: ${count}フレーム記録${count === 0 ? ' (パスなし)' : ' — 再生可能'}`);
  };
  window._recordCamFrame = function() {
    if (!window._camPathRecording) return;
    const cam = camera ?? window._camera;
    if (!cam) return;
    if (!Array.isArray(window._camPath)) window._camPath = [];
    if (window._camPath.length >= 3600) { window.stopCamPathRecord?.(); return; }
    window._camPath.push({
      px: cam.position.x,  py: cam.position.y,  pz: cam.position.z,
      qx: cam.quaternion.x, qy: cam.quaternion.y, qz: cam.quaternion.z, qw: cam.quaternion.w,
      t: performance.now(),
    });
  };
}

// ── [469] カメラパス 再生 ────────────────────────────────────
{
  window.playCamPath = function(loop) {
    loop = Boolean(loop ?? false);
    const path = Array.isArray(window._camPath) ? window._camPath : [];
    if (path.length < 2) { setStatus('カメラパスが不足しています (2フレーム以上必要)', 'warn'); return; }
    const cam = camera ?? window._camera;
    if (!cam) { setStatus('カメラが未初期化です', 'warn'); return; }
    const startT = performance.now();
    const dur = path[path.length - 1].t - path[0].t;
    if (!Number.isFinite(dur) || dur <= 0) { setStatus('カメラパスの時間が無効です', 'warn'); return; }
    setStatus(`カメラパス再生${loop ? '(ループ)' : ''}: ${path.length}フレーム / ${(dur / 1000).toFixed(1)}s`);
    function tick(now) {
      const elapsed = loop ? (now - startT) % dur : Math.min(now - startT, dur);
      const tOffset = path[0].t;
      const nextIdx = path.findIndex(function(f) { return (f.t - tOffset) >= elapsed; });
      const frame = path[Math.max(0, nextIdx - 1)] ?? path[0];
      if (!frame) return;
      try { cam.position.set(frame.px, frame.py, frame.pz); } catch {}
      try { cam.quaternion.set(frame.qx, frame.qy, frame.qz, frame.qw); } catch {}
      if (loop || now - startT < dur) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  };
}

// ── [470] カメラ 360° パノラマスナップ ───────────────────────
{
  window.panoramaSnap = async function(steps) {
    steps = Math.max(2, Math.min(36, parseInt(steps ?? 8, 10)));
    if (!Number.isFinite(steps)) steps = 8;
    const cam = window._camera ?? window.camera;
    if (!cam) { setStatus('カメラが初期化されていません', 'warn'); return []; }
    const origY = Number.isFinite(cam.rotation.y) ? cam.rotation.y : 0;
    const frames = [];
    for (let i = 0; i < steps; i++) {
      cam.rotation.y = origY + (Math.PI * 2 * i / steps);
      await new Promise(function(r) { setTimeout(r, 100); });
      const canvas = renderer?.domElement ?? document.querySelector('canvas');
      if (canvas) {
        try { frames.push(canvas.toDataURL('image/jpeg', 0.85)); } catch {}
      }
    }
    try { cam.rotation.y = origY; } catch {}
    setStatus(`パノラマ: ${frames.length}枚撮影`);
    return frames;
  };
}

// ── [471] スクリーンショット 連番ファイル名 ─────────────────
{
  let _ssSeq = 0;
  window.screenshotSeq = function() {
    _ssSeq++;
    const canvas = renderer?.domElement ?? document.querySelector('canvas');
    if (!canvas) { setStatus('キャンバスが見つかりません', 'warn'); return; }
    try {
      const a = document.createElement('a');
      const pad = String(_ssSeq).padStart(4, '0');
      a.download = 'screenshot_' + pad + '.png';
      a.href = canvas.toDataURL('image/png');
      a.click();
      setStatus('スクリーンショット: screenshot_' + pad + '.png');
    } catch (e) { setStatus(`スクリーンショットエラー: ${e.message}`, 'error'); }
  };
  document.addEventListener('keydown', function(e) {
    if (e.key === 'F2') { e.preventDefault(); window.screenshotSeq(); }
  });
}

// ── [472] スクリーンショット 透過PNG ────────────────────────
{
  window.screenshotTransparent = function() {
    const canvas = renderer?.domElement ?? document.querySelector('canvas');
    if (!canvas) { setStatus('キャンバスが見つかりません', 'error'); return; }
    try {
      const a = document.createElement('a');
      a.download = 'avatar_transparent_' + Date.now() + '.png';
      a.href = canvas.toDataURL('image/png');
      a.click();
      setStatus('透過PNG: ダウンロード', 'success');
    } catch (e) { setStatus(`透過PNG保存エラー: ${e.message}`, 'error'); }
  };
}

// ── [473] 録画 ビットレート選択 ─────────────────────────────
{
  window.getRecordingBitrate = function() {
    const sel = document.querySelector('#recording-bitrate-select, [data-id="rec-bitrate"]');
    const v = parseInt(sel?.value ?? '4000000', 10);
    return Number.isFinite(v) && v > 0 ? v : 4000000;
  };
  const selBR = document.querySelector('#recording-bitrate-select, [data-id="rec-bitrate"]');
  selBR?.addEventListener('change', function() {
    const v = parseInt(selBR.value, 10);
    if (Number.isFinite(v) && v > 0) {
      try { localStorage.setItem('vrmApp_recBitrate', String(v)); } catch { /* ignore */ }
    }
  });
  const savedBR = (function() { try { return localStorage.getItem('vrmApp_recBitrate'); } catch { return null; } })();
  if (savedBR && selBR && /^\d+$/.test(savedBR)) selBR.value = savedBR;
}

// ── [474] 録画 フレームレート固定モード ──────────────────────
{
  window._recordingFPS = 30;
  window.setRecordingFPS = function(fps) {
    const v = parseInt(fps, 10);
    window._recordingFPS = Number.isFinite(v) && v > 0 ? Math.min(v, 120) : 30;
    try { localStorage.setItem('vrmApp_recFPS', String(window._recordingFPS)); } catch { /* ignore */ }
    setStatus('録画FPS: ' + window._recordingFPS);
  };
  const selFPS = document.querySelector('#recording-fps-select, [data-id="rec-fps"]');
  selFPS?.addEventListener('change', function() { window.setRecordingFPS(selFPS.value); });
  const savedFPS = localStorage.getItem('vrmApp_recFPS');
  if (savedFPS) {
    const fps = parseInt(savedFPS, 10);
    if (Number.isFinite(fps) && fps > 0 && fps <= 120) {
      window._recordingFPS = fps;
      if (selFPS) selFPS.value = String(fps);
    }
  }
}

