// ── [479] ストーリークリップ 自動再生 ────────────────────────
{
  window.autoPlayStoryClips = function(clips, interval) {
    if (!Array.isArray(clips) || clips.length === 0) { setStatus('クリップがありません', 'warn'); return; }
    interval = Math.max(500, Number.isFinite(interval) ? interval : 3000);
    let idx = 0;
    function next() {
      if (!Number.isFinite(idx) || idx >= clips.length || idx < 0) { setStatus('ストーリー再生: 完了', 'success'); return; }
      const clip = clips[idx++];
      if (!clip || typeof clip !== 'object') { next(); return; }
      if (clip.motion  && typeof playMotion === 'function') { try { playMotion(clip.motion); } catch {} }
      if (clip.dialogue && clip.dialogue.text) {
        const dText = String(clip.dialogue.text ?? '').slice(0, 2000);
        const dSpeaker = String(clip.dialogue.speaker ?? '').slice(0, 60);
        window.showDialogueWindow?.(dText, dSpeaker);
      }
      if (clip.camera  && typeof window.applyCameraPreset === 'function') window.applyCameraPreset(clip.camera);
      const dur = Number.isFinite(clip.duration) ? clip.duration : interval;
      setTimeout(next, Math.max(100, dur));
    }
    next();
  };
}

// ── [480] ホットスポット ツールチップ 改良 ──────────────────
{
  window.enhanceHotspotTooltips = function() {
    document.querySelectorAll('[data-hotspot-tip]').forEach(function(el) {
      if (el._tipInit) return; el._tipInit = true;
      const tipText = String(el.dataset.hotspotTip ?? '').slice(0, 120);
      if (!tipText) return;
      const tip = document.createElement('div');
      tip.className = 'hotspot-tooltip';
      tip.textContent = tipText;
      tip.setAttribute('aria-hidden', 'true');
      el.style.position = 'relative';
      el.appendChild(tip);
      el.addEventListener('mouseenter', function() { tip.style.opacity = '1'; });
      el.addEventListener('mouseleave', function() { tip.style.opacity = '0'; });
    });
  };
  try {
    new MutationObserver(function() { window.enhanceHotspotTooltips?.(); })
      .observe(document.body, { childList: true, subtree: true });
  } catch { /* ignore */ }
}

// ── [481] Three.js レンダラー統計 表示 ──────────────────────
{
  window.getRendererStats = function() {
    const r = renderer ?? window._renderer;
    const info = r?.info;
    if (!info) return null;
    return {
      drawCalls:  Number(info.render?.calls     ?? 0),
      triangles:  Number(info.render?.triangles ?? 0),
      textures:   Number(info.memory?.textures  ?? 0),
      geometries: Number(info.memory?.geometries ?? 0),
    };
  };
  window.showRendererStats = function() {
    const s = window.getRendererStats();
    if (!s) { setStatus('レンダラー情報なし', 'warn'); return; }
    setStatus(`描画: ${s.drawCalls}calls / ${s.triangles.toLocaleString()}tri / ${s.textures}tex / ${s.geometries}geo`);
  };
}

// ── [482] バウンディングボックス 表示 ────────────────────────
{
  let _bbHelper = null;
  window.toggleBoundingBox = function(on) {
    const sc = scene ?? window._scene;
    if (!sc) return;
    if (_bbHelper) {
      try { sc.remove(_bbHelper); } catch {}
      try { _bbHelper.geometry?.dispose(); } catch {}
      _bbHelper = null;
    }
    const root = currentModelRoot ?? window.currentModelRoot;
    if (on !== false && root && typeof THREE !== 'undefined') {
      try {
        _bbHelper = new THREE.BoxHelper(root, 0x00ffaa);
        sc.add(_bbHelper);
      } catch (e) { console.warn('[bbox]', e); }
    }
    setStatus('バウンディングボックス: ' + (on !== false ? 'ON' : 'OFF'));
  };
  document.querySelector('#bbox-toggle-btn, [data-id="bbox-toggle"]')
    ?.addEventListener('click', function() { window.toggleBoundingBox(!_bbHelper); });
}

// ── [483] ポリゴン数 表示 ────────────────────────────────────
{
  window.getPolyCount = function() {
    const root = currentModelRoot ?? window.currentModelRoot;
    if (!root || typeof root.traverse !== 'function') return 0;
    let count = 0;
    root.traverse(function(obj) {
      if (!obj.isMesh || !obj.geometry) return;
      count += obj.geometry.index
        ? obj.geometry.index.count / 3
        : (obj.geometry.attributes?.position?.count ?? 0) / 3;
    });
    return Math.max(0, Math.round(count));
  };
  window.showPolyCount = function() {
    setStatus('ポリゴン数: ' + window.getPolyCount().toLocaleString() + ' tri');
  };
}

// ── [484] テクスチャ一覧 デバッグ表示 ────────────────────────
{
  window.listTextures = function() {
    const root = currentModelRoot ?? window.currentModelRoot;
    const textures = [];
    root?.traverse(function(obj) {
      if (!obj.isMesh) return;
      const mats = Array.isArray(obj.material) ? obj.material : [obj.material];
      mats.forEach(function(m) {
        ['map','normalMap','roughnessMap','metalnessMap','emissiveMap'].forEach(function(k) {
          if (m?.[k]) textures.push({ key: k, name: m[k].name ?? k });
        });
      });
    });
    console.table(textures);
    const texMsg = `テクスチャ: ${textures.length}件${textures.length > 0 ? ` (${textures.map(t => t.key).join(', ').slice(0, 60)})` : ''}`;
    setStatus(texMsg);
    return textures;
  };
}

// ── [485] WebGLエラー ログ ───────────────────────────────────
{
  window.checkShaderErrors = function() {
    const r = renderer ?? window._renderer;
    const gl = r?.getContext?.() ?? null;
    if (!gl) { setStatus('WebGLコンテキストなし', 'warn'); return; }
    try {
      const err = gl.getError();
      if (err === gl.NO_ERROR) setStatus('WebGLエラー: なし', 'success');
      else setStatus(`WebGLエラー: 0x${err.toString(16)} (${err})`, 'error');
    } catch (e) { setStatus('WebGLエラー取得失敗: ' + e.message, 'warn'); }
  };
}

// ── [486] フレームタイム グラフ 更新 ─────────────────────────
{
  window._frameTimes = [];
  window.recordFrameTime = function(dt) {
    if (!Number.isFinite(dt) || dt < 0 || dt > 1000) return;
    window._frameTimes.push(dt);
    if (window._frameTimes.length > 120) window._frameTimes.shift();
  };
  window.renderFrameTimeGraph = function() {
    const canvas = document.getElementById('anim-speed-sparkline');
    if (!canvas || !window._frameTimes.length) return;
    if (typeof canvas.getContext !== 'function') return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const W = canvas.width || canvas.clientWidth || 200;
    const H = canvas.height || canvas.clientHeight || 32;
    ctx.clearRect(0, 0, W, H);
    const times = window._frameTimes.filter(Number.isFinite);
    if (times.length === 0) return;
    const max = Math.max(...times, 33);
    ctx.strokeStyle = '#00d4ff88'; ctx.lineWidth = 1.5; ctx.beginPath();
    window._frameTimes.forEach(function(t, i) {
      const x = i / window._frameTimes.length * W;
      const y = H - (t / max * H);
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.stroke();
  };
  setInterval(window.renderFrameTimeGraph, 250);
}

// ── [487] メモリ使用量バー 更新 ─────────────────────────────
{
  window.updateMemoryBar = function() {
    const mem = performance?.memory;
    if (!mem || !Number.isFinite(mem.jsHeapSizeLimit) || mem.jsHeapSizeLimit <= 0) return;
    const pct = Math.max(0, Math.min(100, mem.usedJSHeapSize / mem.jsHeapSizeLimit * 100));
    const bar = document.getElementById('memory-usage-bar');
    if (bar) {
      bar.style.width = pct.toFixed(1) + '%';
      bar.style.background = pct > 80 ? 'var(--danger, #ff3358)' : pct > 60 ? 'var(--warning, #ffc020)' : 'var(--accent, #00e4ff)';
      const usedMB = (mem.usedJSHeapSize / 1048576).toFixed(0);
      const totalMB = (mem.jsHeapSizeLimit / 1048576).toFixed(0);
      bar.title = `JS Heap: ${usedMB}MB / ${totalMB}MB`;
    }
  };
  setInterval(window.updateMemoryBar, 3000);
}

// ── [488] GPUテクスチャメモリ 推定 ──────────────────────────
{
  window.estimateGPUMemory = function() {
    const r = renderer ?? window._renderer;
    const texCount = Number(r?.info?.memory?.textures ?? 0);
    const mb = (texCount * 4 * 512 * 512 / 1048576).toFixed(1);
    setStatus(`GPU テクスチャメモリ推定: ~${mb} MB (${texCount}テクスチャ)`);
    return parseFloat(mb);
  };
}

// ── [489] ドローコール カウント ─────────────────────────────
{
  window.showDrawCalls = function() {
    const r = renderer ?? window._renderer;
    const calls = Number(r?.info?.render?.calls     ?? 0);
    const tris  = Number(r?.info?.render?.triangles ?? 0);
    setStatus(`ドローコール: ${calls} / 三角形: ${tris.toLocaleString()}`);
  };
}

// ── [490] シャドウキャスター数 バッジ ───────────────────────
{
  window.countShadowCasters = function() {
    const sc = scene ?? window._scene;
    let n = 0;
    sc?.traverse(function(obj) { if (obj.castShadow) n++; });
    return n;
  };
  setInterval(function() {
    const badge = document.getElementById('shadow-casters-badge');
    if (badge) {
      const count = window.countShadowCasters();
      badge.textContent = `影: ${count}`;
      badge.title = `シャドウキャスター: ${count}個`;
    }
  }, 3000);
}

// ── [491] UI 言語切替 スタブ（日本語/English）──────────────
{
  const I18N = {
    ja: { motion: 'モーション', camera: 'カメラ', scene: 'シーン', export: 'エクスポート' },
    en: { motion: 'Motion', camera: 'Camera', scene: 'Scene', export: 'Export' },
  };
  window.setUILanguage = function(lang) {
    if (!lang || typeof lang !== 'string') lang = 'ja';
    const dict = I18N[lang] ?? I18N.ja;
    document.documentElement.lang = lang;
    Object.entries(dict).forEach(function([key, val]) {
      document.querySelectorAll('[data-i18n="' + CSS.escape(key) + '"]').forEach(function(el) { el.textContent = String(val ?? ''); });
    });
    try { localStorage.setItem('vrmApp_lang', lang); } catch { /* ignore */ }
    setStatus('言語: ' + (lang === 'ja' ? '日本語' : 'English'));
  };
  try {
    const savedLang = localStorage.getItem('vrmApp_lang');
    if (savedLang && /^[a-z]{2}(-[A-Z]{2})?$/.test(savedLang)) window.setUILanguage(savedLang);
  } catch { /* ignore */ }
}

// ── [492] ハイコントラスト モード ────────────────────────────
{
  window.setHighContrast = function(on) {
    document.documentElement.classList.toggle('high-contrast', on);
    if (on) {
      document.documentElement.style.setProperty('--text-hi',  '#ffffff');
      document.documentElement.style.setProperty('--text-mid', '#cccccc');
      document.documentElement.style.setProperty('--bg-base',  '#000000');
      document.documentElement.style.setProperty('--bg-panel', '#111111');
    } else {
      ['--text-hi','--text-mid','--bg-base','--bg-panel'].forEach(function(v) {
        document.documentElement.style.removeProperty(v);
      });
    }
    try { localStorage.setItem('vrmApp_highContrast', String(Boolean(on))); } catch { /* ignore */ }
    setStatus('ハイコントラスト: ' + (on ? 'ON' : 'OFF'));
  };
  try { if (localStorage.getItem('vrmApp_highContrast') === 'true') window.setHighContrast(true); } catch {}
}

// ── [493] リデュースモーション モード ────────────────────────
{
  window.setReduceMotion = function(on) {
    document.documentElement.classList.toggle('reduce-motion', on);
    let st = document.getElementById('reduce-motion-style');
    if (on && !st) {
      st = document.createElement('style');
      st.id = 'reduce-motion-style';
      st.textContent = '.reduce-motion *,.reduce-motion *::before,.reduce-motion *::after{animation-duration:0.01ms!important;transition-duration:0.01ms!important}';
      document.head.appendChild(st);
    } else if (!on && st) { st.remove(); }
    try { localStorage.setItem('vrmApp_reduceMotion', String(Boolean(on))); } catch { /* ignore */ }
  };
  try {
    if (window.matchMedia('(prefers-reduced-motion: reduce)').matches
     || localStorage.getItem('vrmApp_reduceMotion') === 'true') window.setReduceMotion(true);
  } catch { /* ignore matchMedia error */ }
}

// ── [494] キーボードナビゲーション タブ順序 ──────────────────
{
  window.fixPanelTabOrder = function() {
    let idx = 1;
    document.querySelectorAll('.panel-nav-tab, .section-inline-btn, button:not([tabindex="-1"])').forEach(function(el) {
      if (!el.hasAttribute('tabindex') && !el.disabled) el.tabIndex = idx++;
    });
  };
  document.addEventListener('DOMContentLoaded', window.fixPanelTabOrder);
}

// ── [495] ゲームパッド スティック → カメラ制御 ──────────────
{
  let _gpCamActive = false;
  window.startGamepadCam = function() {
    if (_gpCamActive) return; _gpCamActive = true;
    function poll() {
      if (!_gpCamActive) return;
      if (typeof requestAnimationFrame !== 'function') { _gpCamActive = false; return; }
      requestAnimationFrame(poll);
      const gp = navigator.getGamepads?.()[0];
      if (!gp || !window._controls) return;
      const axes = gp.axes ?? [];
      const ax0 = Number(axes[2] ?? axes[0] ?? 0);
      const ax1 = Number(axes[3] ?? axes[1] ?? 0);
      const dz = 0.12;
      const ctrl = controls ?? window._controls;
      if (!ctrl) return;
      if (Number.isFinite(ax0) && Math.abs(ax0) > dz) ctrl.rotateLeft?.(-ax0 * 0.025);
      if (Number.isFinite(ax1) && Math.abs(ax1) > dz) ctrl.rotateUp?.(-ax1 * 0.025);
      ctrl.update?.();
    }
    poll();
  };
  window.addEventListener('gamepadconnected', function(e) {
    const gpId = String(e.gamepad?.id ?? '').substring(0, 50) || '不明';
    setStatus(`ゲームパッド: ${gpId} 接続`);
    document.getElementById('gamepad-indicator')?.classList.add('is-active');
    window.startGamepadCam();
  });
  window.addEventListener('gamepaddisconnected', function() {
    _gpCamActive = false;
    document.getElementById('gamepad-indicator')?.classList.remove('is-active');
    setStatus('ゲームパッド: 切断');
  });
}

// ── [496] ゲームパッド ボタン → モーション割当 ──────────────
{
  window._gpMotionMap = (function() {
    try {
      const raw = localStorage.getItem('vrmApp_gpMotionMap');
      const data = raw ? JSON.parse(raw) : {};
      return (data && typeof data === 'object' && !Array.isArray(data)) ? data : {};
    } catch { return {}; }
  })();
  window.assignGamepadButton = function(btnIdx, motionUrl) {
    const idx = parseInt(btnIdx, 10);
    if (!Number.isFinite(idx) || idx < 0 || idx > 31) { setStatus('無効なボタン番号', 'warn'); return; }
    if (!motionUrl || typeof motionUrl !== 'string') { setStatus('無効なモーションURL', 'warn'); return; }
    if (!(window._gpMotionMap instanceof Object)) window._gpMotionMap = {};
    window._gpMotionMap[idx] = motionUrl.slice(0, 2048);
    try { localStorage.setItem('vrmApp_gpMotionMap', JSON.stringify(window._gpMotionMap)); } catch { /* ignore */ }
    setStatus(`ゲームパッドボタン ${idx}: ${motionUrl.split('/').pop().slice(0, 40)}`);
  };
  setInterval(function() {
    const gp = navigator.getGamepads?.()[0]; if (!gp) return;
    (gp.buttons ?? []).forEach(function(btn, i) {
      if (btn?.pressed && window._gpMotionMap?.[i] && typeof playMotion === 'function') {
        try { playMotion(window._gpMotionMap[i]); } catch {}
      }
    });
  }, 100);
}

// ── [497] タッチジェスチャー ピンチ → FOV ───────────────────
{
  let _lastPinchDist = null;
  document.addEventListener('touchstart', function(e) {
    if (e.touches?.length === 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      const dist = Math.hypot(dx, dy);
      _lastPinchDist = Number.isFinite(dist) ? dist : null;
    }
  }, { passive: true });
  document.addEventListener('touchmove', function(e) {
    if (e.touches.length !== 2 || !_lastPinchDist) return;
    const dx2 = e.touches[0].clientX - e.touches[1].clientX;
    const dy2 = e.touches[0].clientY - e.touches[1].clientY;
    const dist = Math.hypot(dx2, dy2);
    if (!Number.isFinite(dist) || dist <= 0) return;
    const delta = (_lastPinchDist - dist) * 0.2;
    _lastPinchDist = dist;
    const cam = camera ?? window._camera;
    if (cam && Number.isFinite(delta)) {
      cam.fov = Math.max(20, Math.min(90, cam.fov + delta));
      cam.updateProjectionMatrix?.();
    }
  }, { passive: true });
  document.addEventListener('touchend', function() { _lastPinchDist = null; }, { passive: true });
}

// ── [498] タッチジェスチャー スワイプ → モーション送り ──────
{
  let _swipeStartX = null;
  document.addEventListener('touchstart', function(e) {
    if (e.touches.length === 1) _swipeStartX = e.touches[0].clientX;
  }, { passive: true });
  document.addEventListener('touchend', function(e) {
    if (_swipeStartX === null || !e.changedTouches?.length) return;
    const dx = e.changedTouches[0].clientX - _swipeStartX;
    _swipeStartX = null;
    if (!Number.isFinite(dx) || Math.abs(dx) < 80) return;
    if (typeof window.navigateMotion === 'function') window.navigateMotion(dx > 0 ? -1 : 1);
  }, { passive: true });
}

// ── [499] アップデートチェック スタブ ───────────────────────
{
  window.checkForUpdates = function() {
    setStatus('アップデートチェック: オフラインモード（手動で確認してください）', 'warn');
    console.info('[Update] Running version:', window.__vtvVersion ?? '不明');
  };
  document.querySelector('#check-update-btn, [data-id="check-update"]')
    ?.addEventListener('click', window.checkForUpdates);
}

// ── [500] 起動時 チュートリアルヒント ────────────────────────
{
  const TIPS = Object.freeze([
    'Hキー: パネルを隠してフルキャンバス表示',
    'Spaceキー: モーション再生/一時停止',
    'Fキー: カメラをアバターにフォーカス',
    'Ctrl+Z: ブレンドシェイプ Undo',
    'Mキー: タイムラインにマーカーを追加',
    'SillyTavernカードをキャラタブにドロップ: キャラ情報を読込',
    'F6キー: 一人称モード切替',
    'F2キー: 連番スクリーンショット',
    'Alt+←→: 前/次のモーション',
    '天候ボタン: 雨・雪・桜吹雪エフェクト',
  ]);
  window.showStartupTip = function() {
    try { if (sessionStorage.getItem('vrmApp_tipsShown')) return; } catch { return; }
    try { sessionStorage.setItem('vrmApp_tipsShown', '1'); } catch {}
    if (!TIPS || TIPS.length === 0) return;
    const tip = TIPS[Math.floor(Math.random() * TIPS.length)];
    setTimeout(function() { if (typeof setStatus === 'function') setStatus('💡 ' + tip); }, 2500);
  };
  document.addEventListener('DOMContentLoaded', window.showStartupTip);
  console.info(`[VRM Studio] v${window.__vtvVersion ?? '?'} — 改善 [1]–[500] 読込完了`);
}

// ═══════════════════════════════════════════════════════════════════════════════
// POSE KEYFRAME RECORDER — MMD / Blender style keyframe animation authoring
// ═══════════════════════════════════════════════════════════════════════════════
let poseKeyframes = [];   // [{id, time, label, bones:{humanBoneName:[x,y,z,w]}}]
// Restore KF data from session storage
try {
  const _kfStored = sessionStorage.getItem('kfPoseData');
  if (_kfStored) {
    const _parsed = JSON.parse(_kfStored);
    if (Array.isArray(_parsed)) {
      poseKeyframes = _parsed.filter(kf => kf?.id && typeof kf.time === 'number' && kf.bones);
    }
  }
} catch { poseKeyframes = []; }
let kfInterp = 'smooth';  // 'smooth' | 'linear' | 'step'
let kfInterval = 1.0;     // seconds between auto-placed keyframes
let kfCurrentKfIdx = -1;

const kfRecordBtn   = document.querySelector('#kf-record-btn');
const kfPlayBtn     = document.querySelector('#kf-play-btn');
const kfStopBtn     = document.querySelector('#kf-stop-btn');
const kfClearBtn    = document.querySelector('#kf-clear-btn');
const kfInterpSel   = document.querySelector('#kf-interp-select');
const kfIntervalInp = document.querySelector('#kf-interval-input');
const kfListEl      = document.querySelector('#kf-list');
const kfTimelineEl  = document.querySelector('#kf-timeline');

function recordPoseKeyframe() {
  if (!currentVrm) { setStatus('VRMモデルが未読み込みです', 'warn'); return; }
  if (poseKeyframes.length >= 100) { setStatus('ポーズキーフレームは最大100件です', 'warn'); return; }
  const bones = {};
  try {
    const humanBones = currentVrm.humanoid?.normalizedHumanBones;
    if (humanBones) {
      for (const [boneName, boneRef] of Object.entries(humanBones)) {
        const node = boneRef?.node;
        if (node) {
          const q = node.quaternion;
          bones[boneName] = [
            parseFloat(q.x.toFixed(6)),
            parseFloat(q.y.toFixed(6)),
            parseFloat(q.z.toFixed(6)),
            parseFloat(q.w.toFixed(6)),
          ];
        }
      }
    }
  } catch (e) { console.warn('[KF] bone capture error', e); }

  const kfIntervalVal = Number.isFinite(kfInterval) && kfInterval > 0 ? kfInterval : 1.0;
  const t = poseKeyframes.length > 0
    ? (poseKeyframes[poseKeyframes.length - 1].time ?? 0) + kfIntervalVal
    : 0;
  // Also capture facial expressions if available
  const expressions = {};
  try {
    const em = currentVrm?.expressionManager;
    if (em) {
      const names = em.expressionNames ?? (em.expressionMap ? Object.keys(em.expressionMap) : []);
      for (const name of names) {
        if (typeof name !== 'string') continue;
        const v = em.getValue(name);
        if (Number.isFinite(v) && v > 0.001) expressions[name] = parseFloat(v.toFixed(4));
      }
    }
  } catch (eErr) { console.warn('[KF] expression capture error', eErr); }
  const idx = poseKeyframes.length + 1;
  const kfId = `kf_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
  poseKeyframes.push({ id: kfId, time: Number.isFinite(t) ? t : 0, label: `KF${idx}`, bones, expressions });
  renderKfList();
  renderKfTimeline();
  // Auto-save to session storage (restore on reload)
  try { sessionStorage.setItem('kfPoseData', JSON.stringify(poseKeyframes.slice(0, 100))); } catch { /* ignore */ }
  // Auto-scroll to bottom of list
  if (kfListEl) requestAnimationFrame(() => { try { kfListEl.scrollTop = kfListEl.scrollHeight; } catch {} });
  setStatus(`キーフレーム ${idx} 記録 (t=${t.toFixed(2)}s, ${Object.keys(bones).length}ボーン${Object.keys(expressions).length > 0 ? '+' + Object.keys(expressions).length + '表情' : ''})`);
  // Visual flash on record button + update count
  if (kfRecordBtn) {
    try { kfRecordBtn.classList.add('kf-record-flash'); } catch {}
    setTimeout(() => { try { kfRecordBtn.classList.remove('kf-record-flash'); } catch {} }, 300);
    kfRecordBtn.title = `ポーズ記録 (現在${poseKeyframes.length}KF)`;
  }
}

function renderKfList() {
  if (!kfListEl) return;
  // Update KF count badge if present
  const kfCountEl = document.querySelector('#kf-count-badge');
  if (kfCountEl) {
    const count = Array.isArray(poseKeyframes) ? poseKeyframes.length : 0;
    kfCountEl.textContent = count > 0 ? `${count}KF` : '';
    kfCountEl.setAttribute('aria-label', count > 0 ? `${count}キーフレーム` : '');
  }
  if (poseKeyframes.length === 0) {
    kfListEl.innerHTML = '<div class="kf-empty">ポーズを設定して「ポーズ記録」を押してください</div>';
    return;
  }
  const kfHtml = poseKeyframes.map((kf, i) => {
    if (!kf?.id) return '';
    const boneCount = Object.keys(kf.bones ?? {}).length;
    const exprCount = Object.keys(kf.expressions ?? {}).length;
    const exprSuffix = exprCount > 0 ? `+${exprCount}E` : '';
    const safeName = escapeHtml(String(kf.label ?? `KF${i+1}`).slice(0, 40));
    const safeTime = Number.isFinite(kf.time) ? kf.time.toFixed(3) : '0.000';
    return `<div class="kf-item${kfCurrentKfIdx === i ? ' is-active' : ''}" data-kf-id="${kf.id}">
      <span class="kf-idx">${i + 1}</span>
      <input class="kf-label-input" type="text" value="${safeName}" data-kf-id="${kf.id}" title="キーフレーム名" maxlength="40" />
      <input class="kf-time-input" type="number" step="0.05" min="0" value="${safeTime}" data-kf-id="${kf.id}" title="時刻（秒）" />
      <span class="kf-bones-count" title="${boneCount}ボーン${exprCount > 0 ? ' + ' + exprCount + '表情' : ''}">${boneCount}B${exprSuffix}</span>
      <button class="kf-btn kf-apply-btn" data-kf-apply="${kf.id}" title="このポーズをビューポートに適用">適用</button>
      <button class="kf-btn kf-del-btn"   data-kf-del="${kf.id}"   title="このキーフレームを削除">✕</button>
    </div>`;
  }).join('');
  kfListEl.innerHTML = kfHtml;
}

function renderKfTimeline() {
  if (!kfTimelineEl) return;
  if (!Array.isArray(poseKeyframes) || poseKeyframes.length === 0) { kfTimelineEl.innerHTML = ''; return; }
  // Ensure sorted by time
  const sortedKfs = [...poseKeyframes].filter(kf => kf?.id && Number.isFinite(kf.time)).sort((a, b) => a.time - b.time);
  if (sortedKfs.length === 0) { kfTimelineEl.innerHTML = ''; return; }
  const lastTime = sortedKfs[sortedKfs.length - 1].time;
  const kfIntervalSafe = Number.isFinite(kfInterval) && kfInterval > 0 ? kfInterval : 0.5;
  const totalTime = Math.max(0.5, lastTime + kfIntervalSafe * 0.5);
  const dots = sortedKfs.map((kf, i) => {
    const origIdx = poseKeyframes.indexOf(kf);
    if (origIdx < 0) return '';
    const pct = Math.max(0, Math.min(100, (kf.time / totalTime * 100)));
    const safePct = pct.toFixed(1);
    const safeName = escapeHtml(String(kf.label ?? `KF${i+1}`));
    const safeTime = Number.isFinite(kf.time) ? kf.time.toFixed(2) : '?';
    return `<div class="kf-dot${kfCurrentKfIdx === origIdx ? ' is-active' : ''}" style="left:${safePct}%" title="${safeName} (${safeTime}s)" data-kf-idx="${origIdx}"></div>`;
  }).join('');
  // Ruler ticks every second
  let rulerTicks = '';
  const tickMax = Math.min(Math.ceil(totalTime), 300);
  for (let s = 0; s <= tickMax; s++) {
    const pct = (s / totalTime * 100).toFixed(1);
    if (parseFloat(pct) > 100) break;
    rulerTicks += `<span class="kf-ruler-tick" style="left:${pct}%">${s}s</span>`;
  }
  // Playhead
  let playheadHtml = '';
  if (currentAction && currentMotionUrl === '' && kfCurrentKfIdx >= 0 && kfCurrentKfIdx < poseKeyframes.length) {
    const currentKf = poseKeyframes[kfCurrentKfIdx];
    if (currentKf && Number.isFinite(currentKf.time)) {
      const playheadPct = Math.max(0, Math.min(100, currentKf.time / totalTime * 100)).toFixed(1);
      playheadHtml = `<div class="kf-playhead" style="left:${playheadPct}%" aria-hidden="true"></div>`;
    }
  }
  kfTimelineEl.innerHTML =
    `<div class="kf-ruler">${rulerTicks}</div>` +
    `<div class="kf-dots-row">${dots}${playheadHtml}</div>`;
  // Make dots clickable
  kfTimelineEl.querySelectorAll('.kf-dot[data-kf-idx]').forEach((dotEl) => {
    dotEl.style.cursor = 'pointer';
    dotEl.addEventListener('click', () => {
      const idx = parseInt(dotEl.dataset.kfIdx, 10);
      if (poseKeyframes[idx]) applyKfPose(poseKeyframes[idx]);
    });
  });
}

function buildAnimationTracksFromKeyframes() {
  if (!Array.isArray(poseKeyframes) || poseKeyframes.length < 2 || !currentVrm) {
    if (poseKeyframes.length < 2 && poseKeyframes.length > 0) setStatus('KFが2つ以上必要です', 'warn');
    return [];
  }
  const boneNames = new Set();
  for (const kf of poseKeyframes) for (const n of Object.keys(kf.bones)) boneNames.add(n);

  const THREE_INTERP = kfInterp === 'smooth' ? THREE.InterpolateSmooth
    : kfInterp === 'step' ? THREE.InterpolateDiscrete
    : THREE.InterpolateLinear;

  const tracks = [];
  const humanBones = currentVrm.humanoid?.normalizedHumanBones ?? {};
  const sortedKfs = [...poseKeyframes].sort((a, b) => a.time - b.time);
  for (const boneName of boneNames) {
    const node = humanBones[boneName]?.node;
    if (!node) continue;
    const times  = [];
    const values = [];
    for (const kf of sortedKfs) {
      if (!Number.isFinite(kf.time)) continue;
      if (times.length > 0 && Math.abs(kf.time - times[times.length - 1]) < 0.0001) continue;
      const q = kf.bones[boneName] ?? [0, 0, 0, 1];
      times.push(kf.time);
      values.push(
        Number.isFinite(q[0]) ? q[0] : 0,
        Number.isFinite(q[1]) ? q[1] : 0,
        Number.isFinite(q[2]) ? q[2] : 0,
        Number.isFinite(q[3]) ? q[3] : 1
      );
    }
    try {
      if (times.length >= 2 && values.length === times.length * 4) {
        tracks.push(new THREE.QuaternionKeyframeTrack(`${node.name}.quaternion`, times, values, THREE_INTERP));
      }
    } catch (e) { console.warn('[KF] track error', boneName, e); }
  }
  return tracks;
}

async function playPoseKeyframes() {
  if (!currentVrm) { setStatus('VRMモデルが未読み込みです'); return; }
  if (poseKeyframes.length === 0) { setStatus('キーフレームがありません'); return; }
  // Sort KF by time before building tracks
  poseKeyframes.sort((a, b) => a.time - b.time);
  const tracks = buildAnimationTracksFromKeyframes();
  if (tracks.length === 0) { setStatus('再生可能なボーンデータがありません'); return; }
  const kfIntervalFinal = Number.isFinite(kfInterval) && kfInterval > 0 ? kfInterval : 0.5;
  const lastKf = poseKeyframes[poseKeyframes.length - 1];
  const totalDuration = (Number.isFinite(lastKf.time) ? lastKf.time : 0) + kfIntervalFinal * 0.5;
  if (!Number.isFinite(totalDuration) || totalDuration <= 0) {
    setStatus('KFシーケンス時間が無効です', 'error'); return;
  }
  const clip = new THREE.AnimationClip('kf_sequence', totalDuration, tracks);
  clearCurrentAnimation();
  if (!currentVrm.scene || typeof currentVrm.scene.traverse !== 'function') {
    setStatus('VRMシーンが無効です', 'error'); return;
  }
  const mixer = new THREE.AnimationMixer(currentVrm.scene);
  const action = mixer.clipAction(clip);
  const kfLoopEl = document.querySelector('#kf-loop-check');
  const shouldLoop = kfLoopEl?.checked ?? false;
  action.setLoop(shouldLoop ? THREE.LoopRepeat : THREE.LoopOnce, shouldLoop ? Infinity : 1);
  action.clampWhenFinished = !shouldLoop;
  action.timeScale = currentPlaybackSpeed;
  action.play();
  currentMixer = mixer;
  currentAction = action;
  currentMotionUrl = '';
  updatePlaybackUi();
  updateTimelineUi();
  const boneCount = new Set(poseKeyframes.flatMap(kf => Object.keys(kf.bones ?? {}))).size;
  setStatus(`KFシーケンス再生中 (${poseKeyframes.length}KF / ${totalDuration.toFixed(2)}s / ${boneCount}ボーン / 補間:${kfInterp})`);
}

function applyKfPose(kf) {
  if (!currentVrm || !kf) return;
  const humanBones = currentVrm.humanoid?.normalizedHumanBones;
  if (!humanBones) return;
  for (const [boneName, q] of Object.entries(kf.bones)) {
    const node = humanBones[boneName]?.node;
    if (node && q) {
      node.quaternion.set(
        Number.isFinite(q[0]) ? q[0] : 0,
        Number.isFinite(q[1]) ? q[1] : 0,
        Number.isFinite(q[2]) ? q[2] : 0,
        Number.isFinite(q[3]) ? q[3] : 1
      );
      node.quaternion.normalize();
    }
  }
  currentVrm.humanoid?.update?.();
  // Apply expressions if captured
  if (kf.expressions && typeof kf.expressions === 'object' && currentVrm?.expressionManager) {
    try {
      const em = currentVrm.expressionManager;
      for (const [name, val] of Object.entries(kf.expressions)) {
        if (typeof name === 'string' && Number.isFinite(val)) {
          em.setValue(name, clampNumber(val, 0, 1));
        }
      }
      currentVrm.expressionManager.update();
    } catch (eErr) { console.warn('[KF] expression apply error', eErr); }
  }
  kfCurrentKfIdx = poseKeyframes.indexOf(kf);
  renderKfList();
  renderKfTimeline();
  const kfT = Number.isFinite(kf.time) ? kf.time.toFixed(2) : '?';
  setStatus(`ポーズ適用: ${kf.label ?? 'KF'} (t=${kfT}s, ${Object.keys(kf.bones ?? {}).length}ボーン)`);
}

// ── KF event bindings ─────────────────────────────────────────────────────────
kfRecordBtn?.addEventListener('click', recordPoseKeyframe);
if (kfRecordBtn) kfRecordBtn.title = `ポーズ記録 (現在${Array.isArray(poseKeyframes) ? poseKeyframes.length : 0}KF) — R キー`;

kfPlayBtn?.addEventListener('click', () => {
  const kfLoopEl2 = document.querySelector('#kf-loop-check');
  const lastKfTime = poseKeyframes.length > 0 ? (poseKeyframes[poseKeyframes.length - 1]?.time ?? 0) : 0;
  const totalSec = (Number.isFinite(lastKfTime) ? lastKfTime + kfInterval * 0.5 : 0).toFixed(2);
  if (kfPlayBtn) kfPlayBtn.title = `KFシーケンス再生 (${poseKeyframes.length}KF / ~${totalSec}s)${kfLoopEl2?.checked ? ' [ループ]' : ''}`;
  playPoseKeyframes().catch((e) => { console.error('[KF] play error', e); setStatus(`KF再生失敗: ${e?.message ?? '不明'}`, 'error'); });
});

kfStopBtn?.addEventListener('click', () => {
  kfCurrentKfIdx = -1;
  if (currentAction) {
    try {
      currentAction.paused = true;
      currentAction.time = 0;
      if (currentMixer) currentMixer.update(0);
      updatePlaybackUi();
    } catch (e) { console.warn('[KF] stop error', e); }
  }
  renderKfList();
  renderKfTimeline();
  setStatus('キーフレーム再生停止 — 先頭に戻りました');
});

kfClearBtn?.addEventListener('click', async () => {
  if (!Array.isArray(poseKeyframes) || poseKeyframes.length === 0) { setStatus('クリアするキーフレームがありません'); return; }
  const _confirmed = typeof confirmDialog === 'function'
    ? await confirmDialog(`全キーフレーム (${poseKeyframes.length}件) を削除しますか？`)
    : confirm(`全キーフレーム (${poseKeyframes.length}件) を削除しますか？`);
  if (!_confirmed) return;
  poseKeyframes = [];
  kfCurrentKfIdx = -1;
  _kfRecordBusy = false;
  try { sessionStorage.removeItem('kfPoseData'); } catch { /* ignore */ }
  renderKfList();
  renderKfTimeline();
  if (kfTimelineEl) kfTimelineEl.innerHTML = '';
  setStatus('キーフレームをクリアしました');
});

kfInterpSel?.addEventListener('change', () => {
  const valid = ['smooth', 'linear', 'step'];
  kfInterp = valid.includes(kfInterpSel.value) ? kfInterpSel.value : 'linear';
  const labels = { smooth: 'スムーズ補間', linear: 'リニア補間', step: 'ステップ補間' };
  setStatus(`補間モード変更: ${labels[kfInterp]}`);
});
// KF keyboard shortcut: R = record, P = play, S = stop when KF editor is open
document.addEventListener('keydown', (e) => {
  const kfComposer = document.getElementById('kf-composer-details');
  if (!kfComposer || !kfComposer.open) return;
  const tag = document.activeElement?.tagName ?? '';
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT' || document.activeElement?.isContentEditable) return;
  if (e.key === 'r' || e.key === 'R') { e.preventDefault(); if (typeof recordPoseKeyframe === 'function') recordPoseKeyframe(); return; }
  if (e.key === 'p' || e.key === 'P') {
    e.preventDefault();
    if (typeof playPoseKeyframes === 'function') {
      playPoseKeyframes().catch((err) => { console.error('[KF] keydown play error', err); setStatus(`KF再生失敗: ${err?.message ?? '不明'}`, 'error'); });
    }
    return;
  }
  if (e.key === 'Escape') { kfStopBtn?.click(); return; }
});
// Initialize interp selector from stored value
if (kfInterpSel && ['smooth', 'linear', 'step'].includes(kfInterp)) kfInterpSel.value = kfInterp;
if (kfIntervalInp && Number.isFinite(kfInterval)) kfIntervalInp.value = kfInterval.toFixed(2);

kfIntervalInp?.addEventListener('change', () => {
  const v = Number(kfIntervalInp.value);
  if (Number.isFinite(v) && v >= 0.05 && v <= 60) {
    kfInterval = parseFloat(v.toFixed(3));
    setStatus(`KFインターバル: ${kfInterval.toFixed(2)}秒 (次KF自動配置間隔)`);
  } else {
    kfIntervalInp.value = kfInterval.toFixed(2);
    setStatus('インターバルは0.05〜60秒の範囲で指定してください', 'warn');
  }
});

kfListEl?.addEventListener('change', (e) => {
  // Handle inline label editing
  if (e.target.classList.contains('kf-label-input')) {
    const kfId = e.target.dataset?.kfId;
    const kf = kfId ? poseKeyframes.find((k) => k.id === kfId) : null;
    if (kf) { kf.label = (String(e.target.value ?? '').trim() || kf.label).slice(0, 40); renderKfTimeline(); }
    return;
  }
  // Handle inline time editing
  if (e.target.classList.contains('kf-time-input')) {
    const kfId = e.target.dataset?.kfId;
    const kf = kfId ? poseKeyframes.find((k) => k.id === kfId) : null;
    const t = parseFloat(e.target.value);
    if (kf && Number.isFinite(t) && t >= 0 && t <= 3600) {
      kf.time = parseFloat(t.toFixed(3));
      poseKeyframes.sort((a, b) => a.time - b.time);
      renderKfList();
      renderKfTimeline();
    } else if (kf) {
      e.target.value = (Number.isFinite(kf.time) ? kf.time : 0).toFixed(3);
    }
    return;
  }
});

kfListEl?.addEventListener('click', (e) => {
  const applyBtn = e.target.closest('[data-kf-apply]');
  if (applyBtn) {
    const kfId = applyBtn.dataset?.kfApply;
    const kf = kfId ? poseKeyframes.find((k) => k.id === kfId) : null;
    if (kf) applyKfPose(kf);
    return;
  }
  const delBtn = e.target.closest('[data-kf-del]');
  if (delBtn) {
    const delId = delBtn.dataset?.kfDel;
    if (delId) poseKeyframes = poseKeyframes.filter((k) => k.id !== delId);
    kfCurrentKfIdx = Math.min(kfCurrentKfIdx, poseKeyframes.length - 1);
    renderKfList();
    renderKfTimeline();
    return;
  }
  // Click on dot in timeline
  const dot = e.target.closest('[data-kf-idx]');
  if (dot) {
    const i = parseInt(dot.dataset.kfIdx, 10);
    if (poseKeyframes[i]) applyKfPose(poseKeyframes[i]);
  }
});

kfListEl?.addEventListener('change', (e) => {
  const timeInput = e.target.closest('.kf-time-input');
  if (timeInput && !e._kfTimeHandled) {
    e._kfTimeHandled = true;
    const kf = poseKeyframes.find((k) => k.id === timeInput.dataset.kfId);
    if (kf) {
      const v = parseFloat(timeInput.value);
      kf.time = Number.isFinite(v) && v >= 0 ? v : 0;
      poseKeyframes.sort((a, b) => a.time - b.time);
      renderKfList();
      renderKfTimeline();
    }
  }
});

kfListEl?.addEventListener('input', (e) => {
  const labelInput = e.target.closest('.kf-label-input');
  if (labelInput) {
    const kfId = labelInput.dataset?.kfId;
    const kf = kfId ? poseKeyframes.find((k) => k.id === kfId) : null;
    if (kf) kf.label = String(labelInput.value ?? '').trim().slice(0, 40) || kf.label;
  }
});

kfTimelineEl?.addEventListener('click', (e) => {
  const dot = e.target.closest('[data-kf-idx]');
  if (dot) {
    const i = parseInt(dot.dataset.kfIdx ?? '-1', 10);
    if (Number.isFinite(i) && i >= 0 && i < poseKeyframes.length) applyKfPose(poseKeyframes[i]);
  }
});

// ── グローバル公開: ウェルカム画面からVRMを読み込むためのエントリポイント ──
window.__vtvLoadVRM = async function(url, fileName) {
  try {
    await loadModel(url, null);
    if (fileName) {
      currentModelLabel = fileName;
      currentModelKey = `custom:${normalizeModelKey(fileName)}`;
      setStoredString(STORAGE_KEYS.selectedModelKey, currentModelKey);
      currentModelSettings = getModelSettingsForKey(currentModelKey);
      applyModelSettingsToCurrentModel?.();
    }
  } catch(e) {
    console.error('[__vtvLoadVRM] failed:', e);
  }
};
